function num(v,d=1){return typeof v==='number'?v.toFixed(d):v||'0';}

function comma(v){return typeof v==='number'?v.toLocaleString():v||'0';}

function pct(v){return(typeof v==='number'?v.toFixed(1):v||'0')+'%';}

function sevBadge(s){return `<span class="badge-${s||'info'}">${(s||'info').toUpperCase()}</span>`;}

function sevIcon(s){

    if(s==='critical') return '<svg class="w-4 h-4 shrink-0 text-Cred" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clip-rule="evenodd"/></svg>';

    if(s==='warning') return '<svg class="w-4 h-4 shrink-0 text-Camber" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M8.257 3.099c.765-1.36 2.722-1.36 3.486 0l5.58 9.92c.75 1.334-.213 2.98-1.742 2.98H4.42c-1.53 0-2.493-1.646-1.743-2.98l5.58-9.92zM11 13a1 1 0 11-2 0 1 1 0 012 0zm-1-8a1 1 0 00-1 1v3a1 1 0 002 0V6a1 1 0 00-1-1z" clip-rule="evenodd"/></svg>';

    return '<svg class="w-4 h-4 shrink-0 text-Cblue" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/></svg>';

}

function hColor(s){return s>=90?'#10b981':s>=70?'#f59e0b':s>=50?'#f97316':'#ef4444';}

function hGrade(s){return s>=90?'A':s>=80?'B':s>=70?'C':s>=50?'D':'F';}



function renderGauge(val, max, size, label, color) {

    const r=size*0.38, c=Math.PI*r, pctVal=Math.min(val/max,1), offset=c-(pctVal*c);

    return `<svg width="${size}" height="${size*0.65}" viewBox="0 0 ${size} ${size*0.65}">

        <path d="M ${size*0.1} ${size*0.55} A ${r} ${r} 0 0 1 ${size*0.9} ${size*0.55}" class="gauge-bg" stroke-width="${size*0.08}"/>

        <path d="M ${size*0.1} ${size*0.55} A ${r} ${r} 0 0 1 ${size*0.9} ${size*0.55}" class="gauge-fill" stroke="${color}" stroke-width="${size*0.08}" stroke-dasharray="${c}" stroke-dashoffset="${offset}"/>

        <text x="${size/2}" y="${size*0.48}" text-anchor="middle" fill="${color}" font-size="${size*0.18}" font-weight="bold">${typeof val==='number'?val.toFixed(1):val}</text>

        <text x="${size/2}" y="${size*0.62}" text-anchor="middle" fill="#64748b" font-size="${size*0.08}">${label}</text>

    </svg>`;

}



function renderHealthRing(score, size=90) {

    const r=size*0.4, c=2*Math.PI*r, offset=c-(score/100)*c, color=hColor(score);

    return `<svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">

        <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="#1e293b" stroke-width="${size*0.08}"/>

        <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${color}" stroke-width="${size*0.08}" stroke-dasharray="${c}" stroke-dashoffset="${offset}" stroke-linecap="round" transform="rotate(-90 ${size/2} ${size/2})" class="health-ring"/>

        <text x="${size/2}" y="${size*0.47}" text-anchor="middle" fill="${color}" font-size="${size*0.24}" font-weight="bold">${score}</text>

        <text x="${size/2}" y="${size*0.63}" text-anchor="middle" fill="#94a3b8" font-size="${size*0.11}">${hGrade(score)}</text>

    </svg>`;

}



function renderBigScoreArc(score, size=130) {

    const r=size*0.38, c=2*Math.PI*r, offset=c-(score/100)*c, color=hColor(score);

    const grade = hGrade(score);

    const label = score>=90?'HEALTHY':score>=70?'FAIR':score>=50?'DEGRADED':'CRITICAL';

    const tip = 'Snapshot Health Score (0–100)\n'

        + 'Composite of 10 Oracle metrics:\n'

        + '  • Buffer Cache Hit % (ideal >99%)\n'

        + '  • Soft Parse % (ideal >95%)\n'

        + '  • Hard Parse % (ideal <5%)\n'

        + '  • Latch Hit % (ideal >99.9%)\n'

        + '  • Top Wait Event % of DB Time\n'

        + '  • Disk I/O Wait % of DB Time\n'

        + '  • Avg SQL Elapsed Time (ideal <0.5s)\n'

        + '  • Physical Reads/sec\n'

        + '  • Log File Sync avg wait (ideal <5ms)\n'

        + '  • CPU Usage %\n\n'

        + 'Score = weighted average across thresholds.\n'

        + 'Assessed independently per snapshot period.';

    return `<div class="score-arc-container" title="${tip}" style="cursor:help">

        <svg width="${size}" height="${size}" viewBox="0 0 ${size} ${size}">

            <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="#1e293b" stroke-width="${size*0.06}"/>

            <circle cx="${size/2}" cy="${size/2}" r="${r}" fill="none" stroke="${color}" stroke-width="${size*0.06}" stroke-dasharray="${c}" stroke-dashoffset="${offset}" stroke-linecap="round" transform="rotate(-90 ${size/2} ${size/2})" class="health-ring"/>

        </svg>

        <div class="score-label-overlay">

            <div style="font-size:${size*0.28}px;font-weight:900;color:${color};line-height:1">${score}</div>

            <div style="font-size:${size*0.1}px;color:#94a3b8;font-weight:600">${grade} / ${label}</div>

        </div>

    </div>`;

}



function aiNarrative(title, text, isVerdict=false) {
    return `<div class="ai-box mb-4 fade-in">
        <div class="ai-header"><div class="ai-icon"><svg class="w-3 h-3" fill="white" viewBox="0 0 20 20"><path d="M10 2a8 8 0 100 16 8 8 0 000-16zm1 11H9v-2h2v2zm0-4H9V5h2v4z"/></svg></div>
        <span class="text-sm font-bold text-Ccyan">Automated Analysis</span><span class="text-xs text-Cmuted ml-1">${esc(title)}</span>
        <span class="text-[9px] text-gray-700 ml-auto">Rule-based DBA logic</span></div>
        <div style="display:flex;flex-direction:column;gap:0">${text}</div>
    </div>`;
}



function heatmapColor(val, thresholds) {

    if (val >= thresholds[0]) return { bg: '#064e3b', text: '#6ee7b7' };

    if (val >= thresholds[1]) return { bg: '#78350f', text: '#fcd34d' };

    return { bg: '#7f1d1d', text: '#fca5a5' };

}



function deltaArrow(v1, v2, higherIsBad=true) {

    if (v1 === 0 && v2 === 0) return '<span class="text-gray-600">-</span>';

    const d = v2 - v1;

    const pctChange = v1 > 0 ? (d / v1 * 100) : (v2 > 0 ? 100 : 0);

    const bad = higherIsBad ? d > 0 : d < 0;

    const color = Math.abs(pctChange) < 5 ? 'text-Cmuted' : bad ? 'text-Cred' : 'text-Cgreen';

    const arrow = d > 0 ? '&#9650;' : d < 0 ? '&#9660;' : '';

    return `<span class="${color} text-xs font-bold">${arrow} ${Math.abs(pctChange).toFixed(0)}%</span>`;

}



// === DB INFO BANNER ===

function renderDBInfoBanner(db) {

    if (!db || !db.db_name) return '';

    const SNAP_TOL = 2;
    const STD_INTERVALS = [15, 30, 60];

    function _parseTs(ts) {
        if (!ts) return null;
        const m = ts.trim().match(/^(\d{1,2})-([A-Za-z]{3})-(\d{2,4})\s+(\d{1,2}):(\d{2}):?(\d{2})?$/);
        if (m) {
            const mon = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11}[m[2].toLowerCase()];
            let yr = parseInt(m[3]); if (yr < 100) yr += 2000;
            return new Date(yr, mon, parseInt(m[1]), parseInt(m[4]), parseInt(m[5]), parseInt(m[6]||'0'));
        }
        const d = new Date(ts); return isNaN(d.getTime()) ? null : d;
    }

    function _fmtDT(ts) {
        const d = _parseTs(ts); if (!d) return ts||'—';
        const mo = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        return ('0'+d.getDate()).slice(-2)+'-'+mo[d.getMonth()]+'-'+d.getFullYear()+' '+('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2);
    }

    const snapBegin = +(db.snap_begin || db.begin_snap || 0);
    const snapEnd   = +(db.snap_end   || db.end_snap   || 0);
    const snapIntervals = Math.max(snapEnd - snapBegin, 0);
    const durationMin   = +(db.elapsed_min || 0);
    const dtBegin = _parseTs(db.begin_time), dtEnd = _parseTs(db.end_time);
    const beginMin = dtBegin ? dtBegin.getMinutes() : 0;
    const endMin   = dtEnd   ? dtEnd.getMinutes()   : 0;
    const infInterval = snapIntervals > 0 ? durationMin / snapIntervals : durationMin;
    const crossesMidnight = dtBegin && dtEnd ? dtEnd.toDateString() !== dtBegin.toDateString() : false;

    const onBound = m => STD_INTERVALS.some(i => m % i === 0);
    const isStdInt = v => STD_INTERVALS.some(i => Math.abs(v - i) <= SNAP_TOL);

    let wcType, wcColor, wcBg, wcBorder, wcReason;
    if (!onBound(beginMin) && !onBound(endMin)) {
        wcType='JOB_SPECIFIC'; wcColor='#67e8f9'; wcBg='rgba(34,211,238,0.15)'; wcBorder='rgba(34,211,238,0.3)';
        wcReason='Start (:'+('0'+beginMin).slice(-2)+') and end (:'+('0'+endMin).slice(-2)+') are not on standard AWR snap boundaries — manual snapshot around a specific job.';
    } else if (!isStdInt(infInterval) && snapIntervals > 0) {
        wcType='JOB_SPECIFIC'; wcColor='#67e8f9'; wcBg='rgba(34,211,238,0.15)'; wcBorder='rgba(34,211,238,0.3)';
        wcReason='Inferred snap interval ('+infInterval.toFixed(1)+' min) does not match standard Oracle AWR interval (15/30/60 min). Window was manually bracketed.';
    } else if (onBound(beginMin) && onBound(endMin) && isStdInt(infInterval)) {
        wcType='STANDARD_SNAP'; wcColor='#94a3b8'; wcBg='rgba(148,163,184,0.15)'; wcBorder='rgba(148,163,184,0.3)';
        wcReason='Start (:'+('0'+beginMin).slice(-2)+'), end (:'+('0'+endMin).slice(-2)+'), and inferred interval ('+infInterval.toFixed(0)+' min) match standard Oracle AWR schedule.';
    } else {
        wcType='PARTIAL'; wcColor='#fbbf24'; wcBg='rgba(251,191,36,0.15)'; wcBorder='rgba(251,191,36,0.3)';
        wcReason='One boundary matches standard schedule, the other does not.';
    }

    const wcLabel = wcType==='JOB_SPECIFIC' ? 'JOB CAPTURE' : wcType==='STANDARD_SNAP' ? 'SCHEDULED SNAP' : 'PARTIAL';
    const wcBadge = `<span style="display:inline-flex;align-items:center;padding:1px 7px;border-radius:4px;font-size:8px;font-weight:800;background:${wcBg};color:${wcColor};border:1px solid ${wcBorder}" title="${esc(wcReason)}">${wcLabel}</span>`;
    const durColor = durationMin > 0 && durationMin < 15 ? '#fb923c' : durationMin > 180 ? '#fbbf24' : '#4ade80';

    const banners = [];
    if (wcType === 'JOB_SPECIFIC') {
        banners.push({color:'#67e8f9',bg:'rgba(34,211,238,0.08)',border:'rgba(34,211,238,0.3)',
            title:'Job-Targeted Capture',
            msg:wcReason+' Analysis reflects the targeted workload window with minimal ambient noise.'});
    } else if (wcType === 'STANDARD_SNAP') {
        banners.push({color:'#fbbf24',bg:'rgba(251,191,36,0.08)',border:'rgba(251,191,36,0.25)',
            title:'Standard Scheduled Snapshot',
            msg:'Window: '+_fmtDT(db.begin_time)+' to '+_fmtDT(db.end_time)+'. '+wcReason+' Findings reflect total database workload — any event <20% DB Time may represent background activity.'});
    }
    if (durationMin > 0 && durationMin < 15) {
        banners.push({color:'#fb923c',bg:'rgba(251,146,60,0.08)',border:'rgba(251,146,60,0.3)',
            title:'Short Capture Window — Limited Statistical Sample',
            msg:'Window is only '+durationMin.toFixed(1)+' min. Wait event percentages and SQL rankings over <15 min can be dominated by a single transient event. Treat findings as directional signals.'});
    }
    if (durationMin > 180) {
        banners.push({color:'#fbbf24',bg:'rgba(251,191,36,0.08)',border:'rgba(251,191,36,0.25)',
            title:'Extended Window — Transient Issues May Be Diluted',
            msg:'Window spans '+durationMin.toFixed(0)+' min. A short incident is diluted in aggregate averages. Peak AAS and CPU load are more reliable than window-averaged percentages.'});
    }
    if (crossesMidnight) {
        banners.push({color:'#60a5fa',bg:'rgba(96,165,250,0.08)',border:'rgba(96,165,250,0.25)',
            title:'Window Crosses Midnight',
            msg:'Capture spans midnight ('+_fmtDT(db.begin_time)+' to '+_fmtDT(db.end_time)+'). Midnight maintenance jobs (stats gathering, archiving, purges) may appear in wait event rankings.'});
    }

    const bannersHtml = banners.map(b =>
        `<div style="padding:7px 12px;border-radius:7px;background:${b.bg};border:1px solid ${b.border};margin-top:6px;display:flex;align-items:flex-start;gap:8px"><div style="flex:1;min-width:0"><div style="font-size:11px;font-weight:800;color:${b.color}">${esc(b.title)}</div><div style="font-size:10px;color:#94a3b8;margin-top:2px;line-height:1.5">${esc(b.msg)}</div></div></div>`
    ).join('');

    return `<div class="db-info-banner fade-in">

        <div class="flex items-center justify-between flex-wrap gap-2 mb-2">

            <div class="db-name">${esc(db.db_name)}</div>

            <span class="badge-info">SINGLE ANALYSIS</span>

        </div>

        <div style="background:rgba(99,102,241,0.06);border:1px solid rgba(99,102,241,0.2);border-radius:8px;padding:8px 12px">

            <div style="display:flex;flex-wrap:wrap;align-items:baseline;gap:1px 12px;line-height:1.6">

                <div class="db-info-field"><span class="field-label">Host:</span><span class="field-value" style="color:#94a3b8">${esc(db.host||'N/A')}</span></div>

                <div class="db-info-field"><span class="field-label">Instance:</span><span class="field-value">${esc(db.instance||'N/A')}</span></div>

                <div class="db-info-field"><span class="field-label">Release:</span><span class="field-value" style="color:#94a3b8">${esc(db.release||'N/A')}</span></div>

                <div class="db-info-field"><span class="field-label">CPUs:</span><span class="field-value">${db.cpus||'N/A'}</span></div>

                <div class="db-info-field"><span class="field-label">Memory:</span><span class="field-value">${db.memory_gb ? num(db.memory_gb,1)+' GB' : 'N/A'}</span></div>

            </div>

            <div style="display:flex;flex-wrap:wrap;align-items:center;gap:1px 12px;margin-top:3px;padding-top:3px;border-top:1px solid rgba(255,255,255,0.05);line-height:1.6">

                <div class="db-info-field" style="margin:0"><span class="field-label">Snap Range:</span><span class="field-value" style="font-family:monospace">${snapBegin||'?'} - ${snapEnd||'?'}</span></div>

                <div class="db-info-field" style="margin:0"><span class="field-label">Time:</span><span class="field-value">${esc(db.begin_time||'')} to ${esc(db.end_time||'')}</span></div>

                <div class="db-info-field" style="margin:0"><span class="field-label">Duration:</span><span class="field-value" style="color:${durColor};font-weight:800">${durationMin ? num(durationMin,1)+' min' : 'N/A'}</span></div>

                <div class="db-info-field" style="margin:0">${wcBadge}</div>

            </div>

        </div>

        ${bannersHtml}

    </div>`;

}
function renderComparisonDBInfoBanner(s1, s2, lbl1, lbl2) {

    if ((!s1 || !s1.db_name) && (!s2 || !s2.db_name)) return '';

    // -- AWR Window Classification Engine ----------------------------------
    const STANDARD_INTERVALS = [15, 30, 60];
    const SNAP_TOL = 2;

    function _parseAwrTs(ts) {
        if (!ts) return null;
        const s = ts.trim();
        // Try common Oracle AWR formats
        // "08-Apr-26 00:26:26" ? DD-Mon-YY HH:MM:SS
        const m1 = s.match(/^(\d{1,2})-([A-Za-z]{3})-(\d{2,4})\s+(\d{1,2}):(\d{2}):?(\d{2})?$/);
        if (m1) {
            const months = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            const mon = months[m1[2].toLowerCase()];
            let yr = parseInt(m1[3]); if (yr < 100) yr += 2000;
            return new Date(yr, mon, parseInt(m1[1]), parseInt(m1[4]), parseInt(m1[5]), parseInt(m1[6]||'0'));
        }
        // ISO format fallback
        const d = new Date(s);
        return isNaN(d.getTime()) ? null : d;
    }

    function _buildSnapMeta(s, period) {
        const snapBegin = +(s.snap_begin || s.begin_snap || 0);
        const snapEnd = +(s.snap_end || s.end_snap || 0);
        const snapIntervals = Math.max(snapEnd - snapBegin, 0);
        const durationMin = +(s.elapsed_min || 0);
        const dtBegin = _parseAwrTs(s.begin_time);
        const dtEnd = _parseAwrTs(s.end_time);
        const beginMin = dtBegin ? dtBegin.getMinutes() : 0;
        const endMin = dtEnd ? dtEnd.getMinutes() : 0;
        const beginHour = dtBegin ? dtBegin.getHours() : 0;
        const endHour = dtEnd ? dtEnd.getHours() : 0;
        const crossesMidnight = dtBegin && dtEnd
            ? (dtEnd.toDateString() !== dtBegin.toDateString()) : false;
        const inferredInterval = snapIntervals > 0
            ? durationMin / snapIntervals : durationMin;
        return { snapBegin, snapEnd, snapIntervals, durationMin, beginMin, endMin,
                 beginHour, endHour, crossesMidnight, inferredInterval, period,
                 dtBegin, dtEnd,
                 timeBegin: s.begin_time||'', timeEnd: s.end_time||'' };
    }

    function _onBoundary(minute) {
        return STANDARD_INTERVALS.some(i => minute % i === 0);
    }
    function _intervalIsStd(inf) {
        return STANDARD_INTERVALS.some(i => Math.abs(inf - i) <= SNAP_TOL);
    }

    function _classifyWindow(m) {
        const startOn = _onBoundary(m.beginMin);
        const endOn = _onBoundary(m.endMin);
        const stdInt = _intervalIsStd(m.inferredInterval);
        // PRIMARY signal: non-standard START = manually triggered begin_snap = job-targeted
        // (end landing on a boundary is coincidental — Oracle ran its scheduled snap at that moment)
        if (!startOn)
            return { type:'JOB_SPECIFIC', reason:'Start (:'+('0'+m.beginMin).slice(-2)+') is not on a standard AWR boundary (:00/:15/:30/:45) — begin_snap was manually triggered to capture a specific job or incident. End (:'+('0'+m.endMin).slice(-2)+') '+(endOn?'happened to land on a scheduled boundary':'is also non-standard')+'.' };
        // Secondary: non-standard interval on a same-DB multi-snap run
        if (!stdInt && m.snapIntervals > 0)
            return { type:'JOB_SPECIFIC', reason:'Inferred snap interval ('+m.inferredInterval.toFixed(1)+' min) does not match standard Oracle AWR interval (15/30/60 min). Window was manually bracketed around a specific workload.' };
        if (startOn && endOn && stdInt)
            return { type:'STANDARD_SNAP', reason:'Start (:'+('0'+m.beginMin).slice(-2)+'), end (:'+('0'+m.endMin).slice(-2)+'), and inferred interval ('+m.inferredInterval.toFixed(0)+' min) all match the standard Oracle AWR schedule — this is a routine ambient snapshot, not targeted at a specific job.' };
        return { type:'PARTIAL', reason:'Start (:'+('0'+m.beginMin).slice(-2)+') is on schedule but end (:'+('0'+m.endMin).slice(-2)+') is not (or interval is non-standard). Window may be partially job-targeted.' };
    }

    function _fmtHHMM(ts) { const d = _parseAwrTs(ts); return d ? ('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2) : (ts||'').substring(0,5); }
    function _fmtDT(ts) {
        const d = _parseAwrTs(ts);
        if (!d) return ts||'—';
        const months = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
        return ('0'+d.getDate()).slice(-2)+'-'+months[d.getMonth()]+'-'+d.getFullYear()+' '+('0'+d.getHours()).slice(-2)+':'+('0'+d.getMinutes()).slice(-2);
    }

    const meta1 = _buildSnapMeta(s1, 'good');
    const meta2 = _buildSnapMeta(s2, 'bad');
    const wc1 = _classifyWindow(meta1);
    const wc2 = _classifyWindow(meta2);
    const bothJob = wc1.type === 'JOB_SPECIFIC' && wc2.type === 'JOB_SPECIFIC';
    const bothStd = wc1.type === 'STANDARD_SNAP' && wc2.type === 'STANDARD_SNAP';
    const mixedTypes = wc1.type !== wc2.type;

    // Badge pill for each period
    function _badge(wc) {
        if (wc.type === 'JOB_SPECIFIC')
            return '<span style="display:inline-flex;align-items:center;gap:3px;padding:1px 6px;border-radius:4px;font-size:8px;font-weight:800;background:rgba(34,211,238,0.15);color:#67e8f9;border:1px solid rgba(34,211,238,0.3)" title="'+esc(wc.reason)+'">JOB CAPTURE</span>';
        if (wc.type === 'STANDARD_SNAP')
            return '<span style="display:inline-flex;align-items:center;gap:3px;padding:1px 6px;border-radius:4px;font-size:8px;font-weight:800;background:rgba(148,163,184,0.15);color:#94a3b8;border:1px solid rgba(148,163,184,0.3)" title="'+esc(wc.reason)+'">SCHEDULED SNAP</span>';
        return '<span style="display:inline-flex;align-items:center;gap:3px;padding:1px 6px;border-radius:4px;font-size:8px;font-weight:800;background:rgba(251,191,36,0.15);color:#fbbf24;border:1px solid rgba(251,191,36,0.3)" title="'+esc(wc.reason)+'">PARTIAL</span>';
    }

    // Duration color: teal for job captures, orange if mismatch >25%
    const gMin = meta1.durationMin || 0, bMin = meta2.durationMin || 0;
    const durDeltaPct = gMin > 0 ? ((bMin - gMin) / gMin * 100) : 0;
    function _durColor(wc, isLonger) {
        if (Math.abs(durDeltaPct) > 25 && isLonger) return '#fb923c'; // orange
        if (wc.type === 'JOB_SPECIFIC') return '#67e8f9'; // teal/cyan
        return ''; // use default color
    }
    const durColor1 = _durColor(wc1, gMin > bMin) || '#4ade80';
    const durColor2 = _durColor(wc2, bMin > gMin) || '#f87171';

    const _infoRow = (s, color, wc, durClr) => `
        <div style="display:flex;flex-wrap:wrap;align-items:baseline;gap:1px 12px;line-height:1.6">
            <div class="db-info-field"><span class="field-label">DB:</span><span class="field-value" style="color:${color};font-weight:800">${esc(s.db_name||'N/A')}</span></div>
            <div class="db-info-field"><span class="field-label">Host:</span><span class="field-value" style="word-break:break-all;white-space:normal;color:#94a3b8">${esc(s.host||'N/A')}</span></div>
            <div class="db-info-field"><span class="field-label">Instance:</span><span class="field-value">${esc(s.instance||'N/A')}</span></div>
            <div class="db-info-field"><span class="field-label">Release:</span><span class="field-value" style="color:#94a3b8">${esc(s.release||'N/A')}</span></div>
            <div class="db-info-field"><span class="field-label">CPUs:</span><span class="field-value">${s.cpus||'N/A'}</span></div>
            <div class="db-info-field"><span class="field-label">Memory:</span><span class="field-value">${s.memory_gb ? num(s.memory_gb,1)+' GB' : 'N/A'}</span></div>
        </div>
        <div style="display:flex;flex-wrap:wrap;align-items:baseline;gap:1px 12px;margin-top:3px;padding-top:3px;border-top:1px solid rgba(255,255,255,0.05);line-height:1.6">
            <div class="db-info-field" style="margin:0"><span class="field-label">Snap:</span><span class="field-value" style="font-family:monospace">${s.snap_begin||s.begin_snap||'?'}-${s.snap_end||s.end_snap||'?'}</span></div>
            <div class="db-info-field" style="margin:0"><span class="field-label">Time:</span><span class="field-value">${esc(s.begin_time||'')} to ${esc(s.end_time||'')}</span></div>
            <div class="db-info-field" style="margin:0"><span class="field-label">Duration:</span><span class="field-value" style="color:${durClr};font-weight:800">${s.elapsed_min ? num(s.elapsed_min,1)+' min' : 'N/A'}</span></div>
            <div class="db-info-field" style="margin:0">${_badge(wc)}</div>
        </div>`;

    // -- Build Banners -----------------------------------------------------
    const banners = [];
    const diffDB = (s1.db_name||'').toLowerCase() !== (s2.db_name||'').toLowerCase()
                 || (s1.db_id||'') !== (s2.db_id||'');
    const snapIdGap = diffDB ? 0 : (meta2.snapBegin - meta1.snapEnd);
    // Compute actual date gap in days using parsed timestamps
    const _gapDays = (meta1.dtEnd && meta2.dtBegin)
        ? Math.abs(meta2.dtBegin.getTime() - meta1.dtEnd.getTime()) / 86400000
        : null;
    // Time-of-day offset in minutes between the two capture starts
    const _todGoodMin = meta1.beginHour * 60 + meta1.beginMin;
    const _todBadMin  = meta2.beginHour * 60 + meta2.beginMin;
    const _todDiffMin = Math.abs(_todGoodMin - _todBadMin);
    const sameTime = _todDiffMin <= 30;

    // Banner A: Both job-specific
    if (bothJob) {
        banners.push({ sev:'positive', color:'#10b981', bg:'rgba(16,185,129,0.08)', border:'rgba(16,185,129,0.25)', icon:_iconSvg('check','#10b981'),
            title:'Job-Targeted Capture — High Confidence Comparison',
            msg:'Both windows were manually captured around a specific job. Start times (good: '+_fmtHHMM(s1.begin_time)+', bad: '+_fmtHHMM(s2.begin_time)+') confirm non-scheduled capture. Analysis reflects the targeted job workload with minimal ambient noise.' });
    }
    // Banner B: Same time of night (job only)
    if (bothJob && sameTime) {
        banners.push({ sev:'positive', color:'#10b981', bg:'rgba(16,185,129,0.08)', border:'rgba(16,185,129,0.25)', icon:_iconSvg('check','#10b981'),
            title:'Same-Time Captures — Concurrent Workload Matched',
            msg:'Both captures started within 30 min of each other (good: '+_fmtHHMM(s1.begin_time)+', bad: '+_fmtHHMM(s2.begin_time)+'). Background jobs would be at the same schedule point — high-quality apples-to-apples comparison.' });
    }
    // Banner B2: Cross-database comparison
    if (diffDB) {
        banners.push({ sev:'info', color:'#60a5fa', bg:'rgba(96,165,250,0.08)', border:'rgba(96,165,250,0.25)', icon:_iconSvg('info','#60a5fa'),
            title:'Cross-Database Comparison',
            msg:'Comparing '+esc(s1.db_name||'DB1')+' ('+esc(s1.instance||'')+') vs '+esc(s2.db_name||'DB2')+' ('+esc(s2.instance||'')+').'+(_gapDays!==null?' Periods are ~'+Math.round(_gapDays)+' day'+(Math.round(_gapDays)===1?'':'s')+' apart.':'')+' Snap IDs are unrelated across different databases — time-based comparison used.' });
    }
    // Banner A2: Both job-specific but DIFFERENT time of day — note it so user knows
    if (bothJob && !sameTime && _todDiffMin > 180) {
        const todHrDiff = (_todDiffMin / 60).toFixed(1);
        const goodHHMM = ('0'+meta1.beginHour).slice(-2)+':'+('0'+meta1.beginMin).slice(-2);
        const badHHMM  = ('0'+meta2.beginHour).slice(-2)+':'+('0'+meta2.beginMin).slice(-2);
        banners.push({ sev:'warning', color:'#fb923c', bg:'rgba(251,146,60,0.08)', border:'rgba(251,146,60,0.3)', icon:_iconSvg('warning','#fb923c'),
            title:'Different Time of Day — Workload Profile May Differ',
            msg:'Good captured at '+goodHHMM+', bad captured at '+badHHMM+' — '+todHrDiff+' hours apart. Oracle workloads differ significantly between morning batch jobs, daytime OLTP, and evening purge/reporting runs. Verify both windows target the same logical job, not just the same application.' });
    }

    // Banner C: Both standard
    if (bothStd) {
        banners.push({ sev:'info', color:'#fbbf24', bg:'rgba(251,191,36,0.08)', border:'rgba(251,191,36,0.25)', icon:_iconSvg('info','#fbbf24'),
            title:'Standard Snapshot Windows — General DB Comparison',
            msg:'Both windows follow Oracle\'s scheduled AWR snap interval (~'+meta1.inferredInterval.toFixed(0)+' min). Good: '+_fmtDT(s1.begin_time)+' to '+_fmtDT(s1.end_time)+'. Bad: '+_fmtDT(s2.begin_time)+' to '+_fmtDT(s2.end_time)+'. These were NOT manually captured for a specific job — findings reflect total database workload, not an isolated job. Any SQL or wait event under 20% DB Time may represent background activity.' });
    }
    // Banner D: Mixed types
    if (mixedTypes) {
        const jobP = wc1.type === 'JOB_SPECIFIC' ? 'good (baseline)' : 'bad (problem)';
        const schedP = wc1.type === 'STANDARD_SNAP' ? 'good (baseline)' : 'bad (problem)';
        banners.push({ sev:'critical', color:'#ef4444', bg:'rgba(239,68,68,0.08)', border:'rgba(239,68,68,0.3)', icon:_iconSvg('critical','#ef4444'),
            title:'Mismatched Capture Types — Results Unreliable',
            msg:'The '+jobP+' window was manually captured around a specific job, but the '+schedP+' window is a standard Oracle scheduled snapshot containing all concurrent activity. Comparing a curated job window against an ambient database window produces misleading rankings. Re-capture the '+schedP+' period with manual snapshots bracketing the same job.' });
    }
    // Banner D2: Standard-snap but different time of day — almost always wrong
    if (bothStd && _todDiffMin > 120) {
        const goodHHMM = ('0'+meta1.beginHour).slice(-2)+':'+('0'+meta1.beginMin).slice(-2);
        const badHHMM  = ('0'+meta2.beginHour).slice(-2)+':'+('0'+meta2.beginMin).slice(-2);
        banners.push({ sev:'critical', color:'#ef4444', bg:'rgba(239,68,68,0.08)', border:'rgba(239,68,68,0.3)', icon:_iconSvg('critical','#ef4444'),
            title:'Time-of-Day Mismatch — Invalid Comparison Baseline',
            msg:'Good window starts at '+goodHHMM+' and bad window starts at '+badHHMM+'. Standard AWR snapshots capture ALL concurrent Oracle workload. A morning OLTP snapshot vs an evening batch/purge snapshot will show completely different wait events, SQL rankings, and load profiles — the regression signal will be noise. Re-pick baseline and problem windows from the same time slot.' });
    }

    // Banner E: Duration mismatch >25%
    if (Math.abs(durDeltaPct) > 25) {
        const longerP = bMin > gMin ? 'bad (problem)' : 'good (baseline)';
        const shorterP = bMin > gMin ? 'good (baseline)' : 'bad (problem)';
        const longerMin = Math.max(gMin, bMin), shorterMin = Math.min(gMin, bMin);
        const eSev = Math.abs(durDeltaPct) > 100 ? 'critical' : 'warning';
        const eClr = eSev === 'critical' ? '#ef4444' : '#fb923c';
        const eBg = eSev === 'critical' ? 'rgba(239,68,68,0.08)' : 'rgba(251,146,60,0.08)';
        const eBrd = eSev === 'critical' ? 'rgba(239,68,68,0.3)' : 'rgba(251,146,60,0.3)';
        banners.push({ sev:eSev, color:eClr, bg:eBg, border:eBrd, icon:_iconSvg(eSev==='critical'?'critical':'warning',eClr),
            title:'Duration Mismatch: '+Math.abs(durDeltaPct).toFixed(0)+'% Difference',
            msg:'The '+longerP+' window ('+longerMin.toFixed(1)+' min) is '+Math.abs(durDeltaPct).toFixed(0)+'% longer than the '+shorterP+' window ('+shorterMin.toFixed(1)+' min). Rates (% DB Time, avg wait ms, rows/exec) are directly comparable. Cumulative totals (elapsed, reads, redo) are normalized to per-minute rates.' });
    }
    // Banner F: Period gap — always shown when dates are parseable, severity scales with gap
    const _gapDaysEst = _gapDays !== null ? _gapDays
        : (!diffDB && snapIdGap > 0 ? snapIdGap / (1440 / Math.max(meta1.inferredInterval, 1)) : null);
    if (_gapDaysEst !== null) {
        const gd = Math.round(_gapDaysEst);
        const gdSrc = _gapDays !== null ? '' : ' (estimated from snap ID gap)';
        const fmtGood = meta1.dtBegin ? _fmtDT(s1.begin_time) : 'Good';
        const fmtBad  = meta2.dtBegin ? _fmtDT(s2.begin_time) : 'Bad';
        if (_gapDaysEst >= 30) {
            banners.push({ sev:'critical', color:'#ef4444', bg:'rgba(239,68,68,0.08)', border:'rgba(239,68,68,0.3)', icon:_iconSvg('critical','#ef4444'),
                title:'Very Large Gap — Baseline Validity Suspect (~'+gd+' days'+gdSrc+')',
                msg:'Periods are '+gd+' days apart ('+fmtGood+' vs '+fmtBad+'). Over 30 days, optimizer statistics are almost certainly re-gathered, schema changes and data volume growth are likely. This baseline may not represent the same workload. Validate via dba_tab_statistics.last_analyzed and v$parameter change history.' });
        } else if (_gapDaysEst >= 7) {
            banners.push({ sev:'warning', color:'#fbbf24', bg:'rgba(251,191,36,0.08)', border:'rgba(251,191,36,0.25)', icon:_iconSvg('calendar','#fbbf24'),
                title:'Gap Between Periods: ~'+gd+' days'+gdSrc,
                msg:'Captured '+gd+' days apart ('+fmtGood+' vs '+fmtBad+'). Schema changes, optimizer statistics refresh, or parameter changes could have occurred in this window. Verify no maintenance or deployments between the two dates before attributing differences to workload change alone.' });
        } else if (_gapDaysEst >= 1) {
            banners.push({ sev:'info', color:'#60a5fa', bg:'rgba(96,165,250,0.08)', border:'rgba(96,165,250,0.25)', icon:_iconSvg('info','#60a5fa'),
                title:'Period Gap: '+gd+(gd===1?' day':' days')+gdSrc+' apart',
                msg:'Good: '+fmtGood+' · Bad: '+fmtBad+'. Same-day or next-day comparison — low risk of environmental drift. Findings are likely attributable to workload change.' });
        } else if (meta1.dtBegin && meta2.dtBegin) {
            // Same-day comparison — informational
            banners.push({ sev:'positive', color:'#10b981', bg:'rgba(16,185,129,0.08)', border:'rgba(16,185,129,0.25)', icon:_iconSvg('check','#10b981'),
                title:'Same-Day Comparison — Minimal Environmental Drift',
                msg:'Good: '+fmtGood+' · Bad: '+fmtBad+'. Both windows captured on the same day — schema, statistics, and parameters are almost certainly unchanged. Differences are directly attributable to workload.' });
        }
    }
    // Banner G/H: Midnight crossing
    if (meta2.crossesMidnight && !meta1.crossesMidnight) {
        banners.push({ sev:'info', color:'#60a5fa', bg:'rgba(96,165,250,0.08)', border:'rgba(96,165,250,0.25)', icon:_iconSvg('moon','#60a5fa'),
            title:'Bad Window Crosses Midnight',
            msg:'Bad window ('+_fmtDT(s2.begin_time)+' to '+_fmtDT(s2.end_time)+') spans midnight. Midnight maintenance jobs (stats gathering, archiving) may appear only in the bad window.' });
    }
    if (meta1.crossesMidnight && !meta2.crossesMidnight) {
        banners.push({ sev:'info', color:'#60a5fa', bg:'rgba(96,165,250,0.08)', border:'rgba(96,165,250,0.25)', icon:_iconSvg('moon','#60a5fa'),
            title:'Baseline Window Crosses Midnight',
            msg:'Good window ('+_fmtDT(s1.begin_time)+' to '+_fmtDT(s1.end_time)+') spans midnight. Midnight maintenance may inflate baseline wait categories.' });
    }
    // Banner J: Short window
    const minDur = Math.min(gMin, bMin);
    if (minDur > 0 && minDur < 15) {
        const shortP = gMin < bMin ? 'good (baseline)' : 'bad (problem)';
        banners.push({ sev:'warning', color:'#fb923c', bg:'rgba(251,146,60,0.08)', border:'rgba(251,146,60,0.3)', icon:_iconSvg('clock','#fb923c'),
            title:'Short Capture Window — Limited Statistical Sample',
            msg:'The '+shortP+' window is only '+minDur.toFixed(1)+' min. Wait event percentages and SQL rankings over <15 min can be dominated by a single transient event. Treat as directional signals.' });
    }
    // Banner K: Very long window
    const maxDur = Math.max(gMin, bMin);
    if (maxDur > 180) {
        const longP = gMin > bMin ? 'good (baseline)' : 'bad (problem)';
        banners.push({ sev:'info', color:'#fbbf24', bg:'rgba(251,191,36,0.08)', border:'rgba(251,191,36,0.25)', icon:_iconSvg('info','#fbbf24'),
            title:'Extended Window — Transient Issues May Be Diluted',
            msg:'The '+longP+' window spans '+maxDur.toFixed(0)+' min. A 20–30 min problem is diluted in aggregate averages. Peak AAS and CPU load are more reliable than window-averaged percentages.' });
    }
    // Error: bad precedes good — only valid when same DB
    if (!diffDB && snapIdGap < 0) {
        banners.unshift({ sev:'critical', color:'#ef4444', bg:'rgba(239,68,68,0.08)', border:'rgba(239,68,68,0.3)', icon:_iconSvg('critical','#ef4444'),
            title:'Window Order Error',
            msg:'Bad period snap IDs ('+meta2.snapBegin+'–'+meta2.snapEnd+') precede good period ('+meta1.snapBegin+'–'+meta1.snapEnd+'). The uploaded files may be reversed.' });
    }

    const bannersHtml = banners.map(b =>
        '<div style="padding:8px 14px;border-radius:8px;background:'+b.bg+';border:1px solid '+b.border+';margin-top:6px">'
        + '<div style="display:flex;align-items:flex-start;gap:8px">'
        + '<span style="display:inline-flex;align-items:center;flex-shrink:0">'+b.icon+'</span>'
        + '<div style="flex:1;min-width:0">'
        + '<div style="font-size:11px;font-weight:800;color:'+b.color+'">'+esc(b.title)+'</div>'
        + '<div style="font-size:10px;color:#94a3b8;margin-top:3px;line-height:1.5">'+esc(b.msg)+'</div>'
        + '</div></div></div>'
    ).join('');

    // -- Mismatch border on standard-snap card when mixed -----------------
    const goodBorder = mixedTypes && wc1.type === 'STANDARD_SNAP' ? 'border:1px solid rgba(251,146,60,0.5)' : 'border:1px solid rgba(16,185,129,0.2)';
    const badBorder  = mixedTypes && wc2.type === 'STANDARD_SNAP' ? 'border:1px solid rgba(251,146,60,0.5)' : 'border:1px solid rgba(239,68,68,0.2)';

    return `<div class="db-info-banner fade-in">

        <div class="flex items-center justify-between flex-wrap gap-2 mb-2">

            <div class="db-name">${esc(s1.db_name||s2.db_name||'Database')} - Comparison Analysis</div>

            <span class="badge-warning" style="font-size:9px;padding:3px 10px">COMPARISON MODE</span>

        </div>

        <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px">

            <div class="rounded-lg" style="padding:8px 12px;background:rgba(16,185,129,0.06);${goodBorder}">

                <div style="font-size:9px;font-weight:800;color:#4ade80;text-transform:uppercase;margin-bottom:4px;letter-spacing:0.5px">${esc(lbl1)}</div>

                ${_infoRow(s1, '#4ade80', wc1, durColor1)}

            </div>

            <div class="rounded-lg" style="padding:8px 12px;background:rgba(239,68,68,0.06);${badBorder}">

                <div style="font-size:9px;font-weight:800;color:#f87171;text-transform:uppercase;margin-bottom:4px;letter-spacing:0.5px">${esc(lbl2)}</div>

                ${_infoRow(s2, '#f87171', wc2, durColor2)}

            </div>

        </div>

        ${bannersHtml}

    </div>`;

}



// === EFFICIENCY HEATMAP HELPERS ===

function getEfficiencyMetrics() {

    return [

        { key:'buffer_cache_hit_pct', name:'Buffer Cache Hit Ratio', thresholds:[98,95], higherIsBad:false,

          explanation:'Percentage of data block requests satisfied from memory. Low values mean excessive physical I/O reads from disk.' },

        { key:'library_cache_hit_pct', name:'Library Cache Hit Ratio', thresholds:[98,95], higherIsBad:false,

          explanation:'How often SQL parse info is found in the shared pool. Low values indicate hard parsing or shared pool sizing issues.' },

        { key:'soft_parse_pct', name:'Soft Parse Ratio', thresholds:[95,85], higherIsBad:false,

          explanation:'Percentage of parse calls that are soft (reusing cached cursors). Low ratio signals literal SQL without bind variables.' },

        { key:'execute_to_parse_pct', name:'Execute to Parse Ratio', thresholds:[80,60], higherIsBad:false,

          explanation:'Ratio of executions to parses. Higher is better -- indicates cursor reuse and session caching.' },

        { key:'latch_hit_pct', name:'Latch Hit Ratio', thresholds:[99,98], higherIsBad:false,

          explanation:'Percentage of latch requests obtained without spinning/sleeping. Low values indicate contention on shared memory structures.' }

    ];

}



function effStatus(val, thresholds) {

    if (val >= thresholds[0]) return { label:'GOOD', cls:'eff-good', sev:'good' };

    if (val >= thresholds[1]) return { label:'WARNING', cls:'eff-warning', sev:'warning' };

    return { label:'CRITICAL', cls:'eff-critical', sev:'critical' };

}



function renderEfficiencyTable(eff) {

    const metrics = getEfficiencyMetrics();

    return `<div class="card p-4 mb-4 fade-in">

        <div class="text-sm font-bold text-gray-300 mb-3 uppercase tracking-wide">Instance Efficiency Metrics</div>

        <table class="eff-table">

            <thead><tr><th>Metric</th><th>Value</th><th>Threshold</th><th>Status</th><th>What It Means</th></tr></thead>

            <tbody>${metrics.map(m => {

                const val = eff[m.key]||0;

                const st = effStatus(val, m.thresholds);

                return `<tr>

                    <td class="text-white font-semibold">${m.name}</td>

                    <td class="font-bold text-lg" style="color:${st.sev==='good'?'#6ee7b7':st.sev==='warning'?'#fcd34d':'#fca5a5'}">${num(val,1)}%</td>

                    <td class="text-Cmuted">&ge; ${m.thresholds[0]}% (good) / &ge; ${m.thresholds[1]}% (warn)</td>

                    <td><span class="eff-status-badge ${st.cls}">${st.label}</span></td>

                    <td class="text-xs text-Cmuted" style="max-width:250px">${m.explanation}</td>

                </tr>`;

            }).join('')}</tbody>

        </table>

    </div>`;

}



function renderEfficiencyComparisonTable(eff1, eff2, s1, s2, lbl1, lbl2, normCtx) {
    // -- PROBABLE CAUSE + CHECK LOOKUP -----------------------------------------
    const CAUSE = {
        buffer_cache_hit_pct: { check:'v$sysstat: physical reads cache vs direct, SGA buffer_cache size, db_cache_size parameter', cause:'Working set > buffer cache, or new full table scan pattern bypassing cache' },
        soft_parse_pct:       { check:'cursor_sharing param, bind variable usage in app code, shared pool fragmentation', cause:'Literal SQL (no bind vars) causing hard parse storm, or shared pool too small' },
        library_cache_hit_pct:{ check:'v$librarycache GETHITRATIO, shared_pool_size, heavy DDL or ALTER TABLE activity', cause:'Shared pool too small, cursor eviction under memory pressure, or DDL flushing pool' },
        execute_to_parse_pct: { check:'session_cached_cursors param, open_cursors, cursor reuse in application code', cause:'Application not reusing open cursors — parse overhead on every statement execution' },
        latch_hit_pct:        { check:'v$latch: shared pool / library cache latch contention, concurrent hard parses', cause:'High concurrent hard parses serializing on shared pool latch; fix bind variables first' },
        aas:                  { check:'Top wait events by AAS, CPU count vs AAS ratio, ASH active sessions breakdown', cause:'Sessions queueing for CPU / I/O / lock — when AAS > vCPU count the resource is saturated' },
        db_time:              { check:'ADDM report, wait event contribution breakdown, top SQL by DB Time', cause:'Total work increased (volume growth) OR each unit of work is slower (contention / bad plans)' },
        physical_reads:       { check:'Buffer cache hit %, new FTS in SQL plans, index selectivity, stale optimizer stats', cause:'Cache miss (working set exceeds SGA) or new/changed execution plan hitting disk instead of cache' },
        logical_reads:        { check:'SQL execution plans, FTS on large tables, missing indexes, buffer_pool usage', cause:'Buffer gets surge — full scans, hot block access pattern, or raw workload volume increase' },
        redo_size:            { check:'DML rate (inserts/updates/deletes per sec), archiver throughput, log_buffer setting', cause:'DML volume spike — more writes, or NOLOGGING not set on bulk inserts causing redo generation' },
        hard_parses:          { check:'cursor_sharing=FORCE workaround, bind vars in app, v$sql literal SQL count', cause:'Literal SQL (no bind variables) forcing repeated parse CPU burn; leads to latch contention' },
        physical_writes:      { check:'DBWR I/O rate, checkpoint frequency (log_checkpoint_interval), dirty buffer count', cause:'High DML rate pushing dirty buffers to disk aggressively, or misconfigured checkpoint' },
        block_changes:        { check:'DML hotspots in DBA_SEGMENTS, ASSM vs MSSM, ITL waits on hot segments', cause:'High DML on hot tables/indexes — correlates directly with redo surge and physical write increase' },
        executes:             { check:'Application call rate, connection pool throughput, query frequency from top modules', cause:'Workload volume increase — more SQL executions per second amplifying all other metrics' },
        transactions:         { check:'Application throughput KPIs, commit frequency, batch job overlapping with OLTP', cause:'Business transaction rate changed — if DB Time also up: congestion pattern (more time, less output)' },
        parses:               { check:'Hard parse ratio in AWR, cursor reuse rate, open_cursors setting', cause:'Application parsing too often — cursor not cached or being invalidated (DDL, stats, flush)' },
        logons:               { check:'Connection pool settings, pool size vs peak, session churn, ORA-12519 errors', cause:'Connection pool not recycling sessions — each call opening new DB connection (overhead + resource leak)' },
        user_calls:           { check:'Application request rate, client-server round trips, PL/SQL call frequency', cause:'More client API calls per transaction or application making more round-trips to database' },
        sorts:                { check:'PGA_AGGREGATE_TARGET sizing, sort-area-size, SQL plans with SORT operations', cause:'In-memory sort exceeded PGA limit causing disk sort spill, or more ORDER BY / GROUP BY operations' },
        db_cpu:               { check:'CPU usage in OEM, v$osstat CPU metrics, parse overhead, recursive SQL rate', cause:'CPU demand increased — hard parse CPU burn, FTS operations, or more executions consuming cycles' },
    };
    const getCause = key => CAUSE[key] || { check:'Check ADDM and top wait events for this metric', cause:'Correlate with wait events and SQL workload changes for root cause' };

    const metrics = getEfficiencyMetrics();
    const aas1 = s1.aas||0, aas2 = s2.aas||0;

    // -- BUILD UNIFIED ROW ARRAY ------------------------------------------------
    const allRows = [];

    // Efficiency metrics
    metrics.forEach(m => {
        const v1 = eff1[m.key]||0, v2 = eff2[m.key]||0;
        const delta = v1 > 0 ? (v2-v1)/v1*100 : 0;
        const worse  = v2 < v1 * 0.97;
        const better = v2 > v1 * 1.01;
        const absDelta = Math.abs(delta);
        // Execute-to-parse: secondary effect metric — cap at WARN unless severely degraded (>30pp absolute drop or value <50%)
        const _effCritical = worse && absDelta > 15 && !(m.key === 'execute_to_parse_pct' && v2 >= 50 && absDelta < 30);
        const severity = _effCritical ? 'critical' : worse && absDelta > 5 ? 'warning' : better ? 'improvement' : 'stable';
        const c = getCause(m.key);
        allRows.push({
            group:'efficiency', key:m.key, label:m.name,
            v1, v2, unit:'%', delta_pct:delta, severity,
            direction: worse?'regression':better?'improvement':'stable',
            higher_is_bad:false,
            explanation:m.explanation, check:c.check, cause:c.cause,
            fmtV: v => v.toFixed(1)+'%',
        });
    });

    // AAS + DB Time
    [
        { key:'aas',     label:'Avg Active Sessions', v1:aas1, v2:aas2, higher_is_bad:true, unit:'', explanation:'Sessions actively working. AAS > CPUs means sessions queue for resources.' },
        { key:'db_time', label:'DB Time (minutes)',   v1:(s1.db_time_secs||0)/60, v2:(s2.db_time_secs||0)/60, higher_is_bad:true, unit:'min', explanation:'Total active time across all sessions. Increase = more work or more contention.' },
    ].forEach(m => {
        const delta = m.v1 > 0 ? (m.v2-m.v1)/m.v1*100 : 0;
        const worse  = m.higher_is_bad ? m.v2 > m.v1*1.1 : m.v2 < m.v1*0.9;
        const better = m.higher_is_bad ? m.v2 < m.v1*0.9 : m.v2 > m.v1*1.1;
        const severity = worse && Math.abs(delta)>100 ? 'critical' : worse && Math.abs(delta)>20 ? 'warning' : better ? 'improvement' : 'stable';
        const c = getCause(m.key);
        const fmtV = v => {
            if (Math.abs(v)>=1e6) return (v/1e6).toFixed(1)+'M'+m.unit;
            if (Math.abs(v)>=1e3) return (v/1e3).toFixed(1)+'K'+m.unit;
            return v.toFixed(1)+(m.unit?m.unit:'');
        };
        allRows.push({ group:'workload', key:m.key, label:m.label, v1:m.v1, v2:m.v2, unit:m.unit, delta_pct:delta, severity, direction:worse?'regression':better?'improvement':'stable', higher_is_bad:m.higher_is_bad, explanation:m.explanation, check:c.check, cause:c.cause, fmtV });
    });

    // LP significant metrics from normalized comparison (SSoT)
    const lpMetrics = normCtx && normCtx.significantLP ? normCtx.significantLP : [];
    lpMetrics.forEach(m => {
        const c = getCause(m.key);
        const fmtV = v => {
            if (Math.abs(v)>=1e6) return (v/1e6).toFixed(1)+'M'+m.unit;
            if (Math.abs(v)>=1e3) return (v/1e3).toFixed(1)+'K'+m.unit;
            return v.toFixed(v<10?2:1)+m.unit;
        };
        allRows.push({ group:'load_profile', key:m.key, label:m.label, v1:m.good_val, v2:m.bad_val, unit:m.unit, delta_pct:m.delta_pct, severity:m.severity, direction:m.direction, higher_is_bad:m.higher_is_bad, explanation:m.explanation, check:c.check||m.explanation, cause:c.cause||m.explanation, fmtV });
    });

    // Default sort: severity ? |delta|
    const sevOrder = { critical:0, warning:1, stable:2, improvement:3, good:3 };
    allRows.sort((a,b) => {
        const sa=sevOrder[a.severity]??5, sb=sevOrder[b.severity]??5;
        if (sa!==sb) return sa-sb;
        return Math.abs(b.delta_pct)-Math.abs(a.delta_pct);
    });

    // -- ROW RENDERER ----------------------------------------------------------
    const sevColor  = { critical:'#ef4444', warning:'#f59e0b', stable:'#475569', improvement:'#4ade80', good:'#4ade80' };
    const sevBg     = { critical:'rgba(239,68,68,0.05)', warning:'rgba(245,158,11,0.04)', stable:'transparent', improvement:'rgba(74,222,128,0.04)', good:'rgba(74,222,128,0.04)' };
    const grpPill   = { efficiency:`<span style="background:rgba(16,185,129,0.1);color:#34d399;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">EFF</span>`, workload:`<span style="background:rgba(99,102,241,0.1);color:#818cf8;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">WRK</span>`, load_profile:`<span style="background:rgba(245,158,11,0.1);color:#fbbf24;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">LP</span>` };
    const sevPill   = { critical:`<span style="background:rgba(239,68,68,0.15);color:#ef4444;font-size:7px;padding:2px 6px;border-radius:3px;font-weight:700">CRITICAL</span>`, warning:`<span style="background:rgba(245,158,11,0.15);color:#f59e0b;font-size:7px;padding:2px 6px;border-radius:3px;font-weight:700">WARN</span>`, stable:`<span style="background:rgba(71,85,105,0.15);color:#64748b;font-size:7px;padding:2px 6px;border-radius:3px;font-weight:700">STABLE</span>`, improvement:`<span style="background:rgba(74,222,128,0.15);color:#4ade80;font-size:7px;padding:2px 6px;border-radius:3px;font-weight:700">IMPROVED</span>`, good:`<span style="background:rgba(74,222,128,0.15);color:#4ade80;font-size:7px;padding:2px 6px;border-radius:3px;font-weight:700">OK</span>` };

    const rowHtml = (r, idx) => {
        const col  = sevColor[r.severity]  || '#475569';
        const bg   = sevBg[r.severity]     || 'transparent';
        const v2Col = r.direction==='regression'?'#f87171':r.direction==='improvement'?'#4ade80':'#e2e8f0';
        const ds   = r.delta_pct>0?'+':'';
        // For higher_is_bad:false (efficiency) metrics, ? = improvement (went up), ? = regression (went down)
        // For higher_is_bad:true (workload) metrics, ? = regression (went up, bad), ? = improvement (went down)
        const _upGood = r.higher_is_bad === false;
        const dirArrow = r.direction==='regression'
            ? (_upGood ? `<span style="color:#f87171;font-size:9px">▼</span>` : `<span style="color:#f87171;font-size:9px">▲</span>`)
            : r.direction==='improvement'
            ? (_upGood ? `<span style="color:#4ade80;font-size:9px">▲</span>` : `<span style="color:#4ade80;font-size:9px">▼</span>`)
            : `<span style="color:#475569;font-size:9px">→</span>`;
        return `<tr style="background:${bg};border-left:3px solid ${col}50" class="ec-row" data-severity="${r.severity}" data-delta="${r.delta_pct.toFixed(1)}" data-group="${r.group}">
            <td style="padding:6px 8px;white-space:nowrap">
                <div style="display:flex;align-items:center;gap:5px">
                    ${grpPill[r.group]||''}
                    <span style="font-size:10px;font-weight:700;color:#e2e8f0">${esc(r.label)}</span>
                </div>
            </td>
            <td style="padding:6px 8px;text-align:right;font-family:monospace;font-size:10px;color:#6ee7b7;white-space:nowrap">${esc(r.fmtV(r.v1))}</td>
            <td style="padding:4px 2px;text-align:center;color:#334155;font-size:10px">${dirArrow}</td>
            <td style="padding:6px 8px;text-align:right;font-family:monospace;font-size:10px;font-weight:700;color:${v2Col};white-space:nowrap">${esc(r.fmtV(r.v2))}</td>
            <td style="padding:6px 8px;text-align:right;white-space:nowrap">
                <span style="font-size:12px;font-weight:900;color:${col}">${ds}${r.delta_pct.toFixed(0)}%</span>
            </td>
            <td style="padding:6px 8px">${sevPill[r.severity]||''}</td>
            <td style="padding:6px 8px;white-space:nowrap">
                <button onclick="(function(el){const t=el.closest('tr').nextElementSibling;const open=t.style.display!=='none'&&t.style.display!=='';t.style.display=open?'none':'table-row';el.textContent=open?'diagnose':'diagnose'})(this)"
                    style="font-size:8px;color:#6366f1;background:rgba(99,102,241,0.1);border:1px solid rgba(99,102,241,0.25);border-radius:4px;padding:3px 7px;cursor:pointer">diagnose</button>
            </td>
        </tr>
        <tr class="ec-cause-row" style="display:none;background:rgba(6,10,22,0.95)">
            <td colspan="7" style="padding:8px 14px 10px 28px;border-left:3px solid ${col}50">
                <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:6px">
                    <div>
                        <div style="font-size:7px;color:#6366f1;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:3px">Check This First</div>
                        <div style="font-size:9px;color:#94a3b8;line-height:1.6">${esc(r.check)}</div>
                    </div>
                    <div>
                        <div style="font-size:7px;color:#f59e0b;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:3px">Probable Root Cause</div>
                        <div style="font-size:9px;color:#94a3b8;line-height:1.6">${esc(r.cause)}</div>
                    </div>
                </div>
                <div style="font-size:8px;color:#334155;border-top:1px solid #0f172a;padding-top:5px;font-style:italic">${esc(r.explanation)}</div>
            </td>
        </tr>`;
    };

    const critN = allRows.filter(r=>r.severity==='critical').length;
    const warnN = allRows.filter(r=>r.severity==='warning').length;
    const impN  = allRows.filter(r=>r.direction==='improvement').length;
    const lpN   = lpMetrics.length;
    const totalN = allRows.length;

    window._effRowPairs = null; // reset cache on each render
    return `<div class="card p-4 mb-4 fade-in" id="eff-lp-card">
        <!-- Header row -->
        <div style="display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:10px;gap:10px;flex-wrap:wrap">
            <div>
                <div style="font-size:11px;font-weight:800;color:#e2e8f0;text-transform:uppercase;letter-spacing:0.5px">
                    Performance Deep-Dive: <span style="color:#34d399">${esc(lbl1)}</span> <span style="color:#334155">vs</span> <span style="color:#f87171">${esc(lbl2)}</span>
                </div>
                <div style="font-size:9px;color:#334155;margin-top:3px">
                    <span style="background:rgba(16,185,129,0.08);color:#34d399;padding:1px 6px;border-radius:3px;margin-right:4px">EFF efficiency ratios</span>
                    <span style="background:rgba(99,102,241,0.08);color:#818cf8;padding:1px 6px;border-radius:3px;margin-right:4px">WRK workload</span>
                    <span style="background:rgba(245,158,11,0.08);color:#fbbf24;padding:1px 6px;border-radius:3px">LP load profile shifts</span>
                    <span style="color:#1e293b;margin-left:6px">· click ? diagnose to expand root cause</span>
                </div>
            </div>
            <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap">
                ${critN>0?`<span style="background:rgba(239,68,68,0.12);color:#ef4444;font-size:8px;padding:2px 9px;border-radius:4px;font-weight:700;border:1px solid rgba(239,68,68,0.2)">${critN} CRITICAL</span>`:''}
                ${warnN>0?`<span style="background:rgba(245,158,11,0.12);color:#f59e0b;font-size:8px;padding:2px 9px;border-radius:4px;font-weight:700;border:1px solid rgba(245,158,11,0.2)">${warnN} WARN</span>`:''}
                ${impN>0?`<span style="background:rgba(74,222,128,0.1);color:#4ade80;font-size:8px;padding:2px 9px;border-radius:4px;font-weight:700;border:1px solid rgba(74,222,128,0.2)">${impN} IMPROVED</span>`:''}
            </div>
        </div>
        <!-- Sort + filter controls -->
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap">
            <div style="font-size:8px;color:#334155;font-weight:700;text-transform:uppercase">Sort:</div>
            <div style="display:flex;gap:0;border:1px solid #1e293b;border-radius:5px;overflow:hidden">
                <button onclick="sortEffTable('severity')" id="eff-sort-sev" style="font-size:8px;padding:3px 9px;background:rgba(99,102,241,0.2);color:#818cf8;border:none;cursor:pointer;font-weight:700">Severity</button>
                <button onclick="sortEffTable('delta')"    id="eff-sort-del" style="font-size:8px;padding:3px 9px;background:transparent;color:#475569;border:none;border-left:1px solid #1e293b;cursor:pointer">Δ%</button>
                <button onclick="sortEffTable('group')"    id="eff-sort-grp" style="font-size:8px;padding:3px 9px;background:transparent;color:#475569;border:none;border-left:1px solid #1e293b;cursor:pointer">Group</button>
            </div>
            <div style="font-size:8px;color:#334155;font-weight:700;text-transform:uppercase;margin-left:4px">Filter:</div>
            <div style="display:flex;gap:0;border:1px solid #1e293b;border-radius:5px;overflow:hidden">
                <button onclick="filterEffTable('all')"         id="eff-fil-all"  style="font-size:8px;padding:3px 9px;background:rgba(99,102,241,0.2);color:#818cf8;border:none;cursor:pointer;font-weight:700">All (${totalN})</button>
                <button onclick="filterEffTable('critical')"    id="eff-fil-crit" style="font-size:8px;padding:3px 9px;background:transparent;color:#475569;border:none;border-left:1px solid #1e293b;cursor:pointer">Critical${critN>0?' ('+critN+')':''}</button>
                <button onclick="filterEffTable('load_profile')" id="eff-fil-lp"  style="font-size:8px;padding:3px 9px;background:transparent;color:#475569;border:none;border-left:1px solid #1e293b;cursor:pointer">LP only${lpN>0?' ('+lpN+')':''}</button>
                <button onclick="filterEffTable('improvement')" id="eff-fil-imp"  style="font-size:8px;padding:3px 9px;background:transparent;color:#475569;border:none;border-left:1px solid #1e293b;cursor:pointer">Improved${impN>0?' ('+impN+')':''}</button>
            </div>
        </div>
        <!-- Table -->
        <div style="overflow-x:auto">
        <table id="eff-lp-table" style="width:100%;border-collapse:collapse;min-width:720px">
            <thead>
                <tr style="border-bottom:2px solid #0f172a">
                    <th style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:left;white-space:nowrap">Metric</th>
                    <th style="font-size:8px;color:#34d399;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:right;white-space:nowrap">${esc(lbl1)}</th>
                    <th style="padding:5px 2px;width:20px"></th>
                    <th style="font-size:8px;color:#f87171;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:right;white-space:nowrap">${esc(lbl2)}</th>
                    <th style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:right;white-space:nowrap;cursor:pointer" onclick="sortEffTable('delta')">Δ% ⇅</th>
                    <th style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:left;white-space:nowrap;cursor:pointer" onclick="sortEffTable('severity')">Status ?</th>
                    <th style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 8px;text-align:left;white-space:nowrap">Root Cause</th>
                </tr>
            </thead>
            <tbody id="eff-lp-tbody">
                ${allRows.map((r,i)=>rowHtml(r,i)).join('')}
            </tbody>
        </table>
        </div>
        ${lpN===0?'<div style="margin-top:8px;font-size:9px;color:#1e3a5f;text-align:right;font-style:italic">All load profile metrics within 15% — no significant workload shift detected</div>':''}
    </div>`;
}

// -- EFFICIENCY TABLE SORT / FILTER (called from onclick attrs) -------------
window._effRowPairs = null;
function _getEffRowPairs(reset) {
    if (reset || !window._effRowPairs) {
        const tbody = document.getElementById('eff-lp-tbody');
        if (!tbody) return [];
        const rows = [...tbody.rows];
        const pairs = [];
        for (let i = 0; i < rows.length; i += 2) {
            if (rows[i]) pairs.push({ main:rows[i], cause:rows[i+1]||null });
        }
        window._effRowPairs = pairs;
    }
    return window._effRowPairs;
}
function _setEffBtnActive(btnId, allIds) {
    allIds.forEach(id => {
        const b = document.getElementById(id);
        if (!b) return;
        b.style.background = 'transparent';
        b.style.color = '#475569';
        b.style.fontWeight = '400';
    });
    const ab = document.getElementById(btnId);
    if (ab) { ab.style.background = 'rgba(99,102,241,0.2)'; ab.style.color = '#818cf8'; ab.style.fontWeight = '700'; }
}
function sortEffTable(by) {
    _setEffBtnActive('eff-sort-'+({severity:'sev',delta:'del',group:'grp'}[by]||'sev'), ['eff-sort-sev','eff-sort-del','eff-sort-grp']);
    const pairs = _getEffRowPairs();
    const tbody = document.getElementById('eff-lp-tbody');
    if (!tbody || !pairs.length) return;
    const sevO = { critical:0, warning:1, stable:2, improvement:3, good:3 };
    const grpO = { workload:0, efficiency:1, load_profile:2 };
    pairs.sort((a,b) => {
        const ra=a.main, rb=b.main;
        if (by==='severity') {
            const sa=sevO[ra.dataset.severity]??5, sb=sevO[rb.dataset.severity]??5;
            return sa!==sb ? sa-sb : Math.abs(+rb.dataset.delta)-Math.abs(+ra.dataset.delta);
        }
        if (by==='delta') return Math.abs(+rb.dataset.delta)-Math.abs(+ra.dataset.delta);
        if (by==='group') {
            const ga=grpO[ra.dataset.group]??9, gb=grpO[rb.dataset.group]??9;
            return ga!==gb ? ga-gb : Math.abs(+rb.dataset.delta)-Math.abs(+ra.dataset.delta);
        }
        return 0;
    });
    tbody.innerHTML = '';
    pairs.forEach(p => { tbody.appendChild(p.main); if(p.cause) tbody.appendChild(p.cause); });
}
function filterEffTable(f) {
    _setEffBtnActive('eff-fil-'+({all:'all',critical:'crit',load_profile:'lp',improvement:'imp'}[f]||'all'), ['eff-fil-all','eff-fil-crit','eff-fil-lp','eff-fil-imp']);
    const pairs = _getEffRowPairs();
    pairs.forEach(p => {
        const sev=p.main.dataset.severity, grp=p.main.dataset.group;
        const show = f==='all'||sev===f||grp===f||(f==='improvement'&&(sev==='good'||sev==='improvement'));
        p.main.style.display = show?'':'none';
        if(p.cause) p.cause.style.display='none';
        const btn=p.main.querySelector('button');
        if(btn) btn.textContent='diagnose';
    });
}


// === SINGLE DASHBOARD ===
// === SINGLE DASHBOARD ===

function renderSingleDashboard(data) {

    const rca = data.rca||{}, v = rca.verdict||{}, db = rca.db_summary||{}, h = data.health||{}, score = h.score||0;
    const d = data.data||{};
    const ctx  = window.AWRContext || {};
    const ctxE = ctx.instanceEfficiency?.bad || {};
    const ctxLP = ctx.loadProfile?.bad || {};
    const eff = d.efficiency||{};

    const bufHit    = ctxE.buffer_cache_hit_pct  || eff.buffer_cache_hit_pct  || 0;
    const libHit    = ctxE.library_cache_hit_pct || eff.library_cache_hit_pct || 0;
    const softParse = ctxE.soft_parse_pct        || eff.soft_parse_pct        || 0;
    const latchHit  = ctxE.latch_hit_pct         || eff.latch_hit_pct         || 0;
    const execParse = ctxE.execute_to_parse_pct  || eff.execute_to_parse_pct  || 0;
    const hardParses = ctxLP.hard_parses         || 0;
    const parseCpuPct = ctxE.parse_cpu_pct       || 0;

    const events = (ctx.waitEvents?.bad || d.wait_events||[]).slice(0,10);
    const sqls   = (ctx._raw?.bad?.sql_stats || d.sql_stats||[]).slice(0,10);
    const lp = ctx._raw?.bad?.load_profile || d.load_profile || [];

    const aas  = ctx.aas?.bad        || db.aas  || 0;
    const cpus = ctx.meta?.cpu_count || db.cpus || 1;
    const dbTimeSecs  = ctx.meta?.bad?.db_time_secs || db.db_time_secs || 0;
    const elapsedSecs = ctx.meta?.bad?.elapsed_min ? ctx.meta.bad.elapsed_min * 60 : (db.elapsed_secs || 0);

    const aiText = generateSingleAISummary(ctx);

    // Parse Pressure Banner
    const parsePressureBanner = (() => {
        const hp = hardParses;
        const showParse = hp > 5 || parseCpuPct > 30 || softParse < 80;
        if (!showParse) return '';
        const flags = [];
        if (hp > 5)         flags.push('Hard Parses/sec: ' + num(hp,1) + ' (threshold: >5 = concern, >50 = critical)');
        if (parseCpuPct > 30) flags.push('Parse CPU: ' + num(parseCpuPct,0) + '% of total CPU consumed by parsing');
        if (softParse < 80) flags.push('Soft Parse %: ' + num(softParse,0) + '% \u2014 bind variable usage may be low');
        return '<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 14px;background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.25);border-radius:6px;margin-bottom:12px">'
            + '<span style="font-size:14px">\u26A1</span>'
            + '<div>'
            + '<div style="color:#fbbf24;font-size:10px;font-weight:800">PARSE PRESSURE DETECTED</div>'
            + '<div style="color:#94a3b8;font-size:9px;line-height:1.5">' + flags.join(' \u00B7 ') + '</div>'
            + '</div></div>';
    })();

    const waitClassMap = {};
    events.forEach(e => {
        const wc = e.wait_class || 'Other';
        waitClassMap[wc] = (waitClassMap[wc]||0) + (e.pct_db_time||0);
    });

    // ── Severity / colour helpers ──
    const sevBadge = score >= 80 ? ['HEALTHY','#10b981'] : score >= 60 ? ['WARNING','#f59e0b'] : score >= 40 ? ['DEGRADED','#f97316'] : ['CRITICAL','#ef4444'];
    const aasRatio = cpus > 0 ? aas / cpus : 0;
    const aasCol   = aas > cpus ? '#ef4444' : aas > cpus*0.7 ? '#f59e0b' : '#10b981';
    const topEvt   = events[0] || {};
    const topSql   = sqls[0] || {};
    const critCount = (rca.findings||[]).filter(f => f.severity === 'critical').length;
    const btlType   = (ctx.bottleneck?.bad?.type || v.primary_bottleneck || 'unknown').toUpperCase();
    const btlCol    = /io/i.test(btlType)?'#3b82f6':/cpu/i.test(btlType)?'#10b981':/concurr/i.test(btlType)?'#f59e0b':/commit/i.test(btlType)?'#ef4444':/config/i.test(btlType)?'#f97316':'#8b5cf6';

    // ── Collapsible section helper ──
    const collapsible = (id, title, accentCol, contentHtml, startOpen) => {
        return '<div class="card mb-4 fade-in" style="overflow:hidden">'
            + '<div onclick="(function(el){var b=el.nextElementSibling;var a=el.querySelector(\'[data-arrow]\');if(b.style.maxHeight && b.style.maxHeight!==\'0px\'){b.style.maxHeight=\'0px\';b.style.paddingTop=\'0\';b.style.paddingBottom=\'0\';a.style.transform=\'rotate(0deg)\';}else{b.style.maxHeight=b.scrollHeight+\'px\';b.style.paddingTop=\'16px\';b.style.paddingBottom=\'16px\';a.style.transform=\'rotate(90deg)\';setTimeout(function(){b.querySelectorAll(\'canvas\').forEach(function(cv){var ch=Chart.getChart(cv);if(ch)ch.resize();});},350);}})(this)" style="padding:12px 16px;cursor:pointer;display:flex;align-items:center;gap:8px;user-select:none;background:rgba(15,23,42,0.5)">'
            + '<span data-arrow style="display:inline-block;transition:transform 0.2s;font-size:10px;color:#64748b;transform:rotate(' + (startOpen?'90':'0') + 'deg)">\u25B6</span>'
            + '<span style="display:inline-block;width:3px;height:12px;background:' + accentCol + ';border-radius:2px"></span>'
            + '<span style="font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px">' + title + '</span>'
            + '</div>'
            + '<div style="max-height:' + (startOpen ? '9999px' : '0px') + ';overflow:hidden;transition:max-height 0.3s ease;padding:' + (startOpen ? '16px' : '0') + ' 16px">'
            + contentHtml
            + '</div></div>';
    };

    // === SECTION 1: EXECUTIVE VERDICT HEADER ===
    var html = '';
    html += renderDBInfoBanner(db);

    // Merged hero: Score + Bottleneck + Severity + Confidence + Diagnosis + Top action
    html += '<div class="verdict-hero mb-4 fade-in" style="padding:18px 22px">';
    html += '<div class="flex items-center gap-6 relative z-10">';
    html += renderBigScoreArc(score, 120);
    html += '<div class="flex-1 min-w-0">';
    // Top line: severity badge + bottleneck badge
    html += '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">';
    html += '<span style="font-size:10px;font-weight:900;padding:3px 10px;border-radius:4px;background:' + sevBadge[1] + '22;color:' + sevBadge[1] + ';border:1px solid ' + sevBadge[1] + '55;letter-spacing:0.5px">' + sevBadge[0] + '</span>';
    html += '<span style="font-size:10px;font-weight:800;padding:3px 10px;border-radius:4px;background:' + btlCol + '22;color:' + btlCol + ';border:1px solid ' + btlCol + '55">' + esc(btlType) + '</span>';
    html += '<span style="font-size:10px;color:#64748b">Confidence: <b style="color:' + (function(cs){return cs>=80?'#10b981':cs>=50?'#f59e0b':'#ef4444'})(v.confidence_score||0) + '">' + (v.confidence_score||0) + '%</b></span>';
    html += '</div>';
    // Primary finding
    html += '<div style="font-size:16px;font-weight:700;color:#e2e8f0;margin-bottom:4px;line-height:1.3">' + esc(v.primary_finding||'Analysis Complete') + '</div>';
    // Root cause one-liner
    html += '<div style="font-size:12px;color:#94a3b8;line-height:1.5;margin-bottom:8px">' + esc(v.root_cause||'') + '</div>';
html += '</div></div></div>';

    // Top recommended action (if available)
    var topAction = '';
    if (rca.findings && rca.findings.length) {
        var critF = rca.findings.find(function(f){return f.severity==='critical'}) || rca.findings[0];
        if (critF && critF.recommendation) {
            topAction = '<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 14px;background:rgba(99,102,241,0.06);border:1px solid rgba(99,102,241,0.25);border-radius:6px;margin-bottom:12px">'
                + '<span style="font-size:13px;margin-top:1px">\uD83D\uDCA1</span>'
                + '<div>'
                + '<div style="font-size:10px;font-weight:800;color:#818cf8;text-transform:uppercase;margin-bottom:2px">Top Recommended Action</div>'
                + '<div style="font-size:11px;color:#cbd5e1;line-height:1.5">' + esc(critF.recommendation) + '</div>'
                + '</div></div>';
        }
    }
    html += topAction;

    // === SECTION 2: MECHANISM & INTERPRETATION ===
    html += parsePressureBanner;
        // Mechanism & Interpretation - clean narrative
    html += '<div class="card mb-4 fade-in" style="padding:16px 20px;border-left:3px solid #3b82f6">';
    html += '<div style="font-size:11px;font-weight:800;color:#3b82f6;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:8px">Mechanism & Interpretation</div>';
    html += '<div style="display:flex;flex-direction:column;gap:0">' + aiText + '</div>';
    html += '</div>';

    // === SECTION 3: EVIDENCE SUMMARY ===
    html += '<div style="font-size:13px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin:20px 0 12px;display:flex;align-items:center;gap:8px">';
    html += '<span style="display:inline-block;width:3px;height:14px;background:#3b82f6;border-radius:2px"></span>';
    html += 'Evidence Summary';
    html += '</div>';

    // Row: Wait Event Donut + Top SQL chart
    html += '<div class="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4 fade-in fade-in-d2">';
    html += '<div class="card p-4">';
    html += '<div class="text-xs font-semibold text-Cmuted mb-2 uppercase">DB Time Breakdown (Top 10 Events)</div>';
    html += '<div class="chart-wrapper" style="height:240px"><canvas id="dash-wait-donut"></canvas></div>';
    html += '</div>';
    html += '<div class="card p-4">';
    html += '<div class="text-xs font-semibold text-Cmuted mb-2 uppercase">Top SQL by Elapsed/Exec</div>';
    html += '<div class="chart-wrapper" style="height:240px"><canvas id="dash-sql-bar"></canvas></div>';
    html += '</div>';
    html += '</div>';

    // Wait Event Treemap
    html += '<div class="card p-4 mb-4 fade-in">';
    html += '<div class="text-xs font-semibold text-Cmuted mb-2 uppercase">Wait Event Treemap \u2014 Size = % DB Time</div>';
    html += '<div class="flex flex-wrap gap-1.5" id="wait-treemap">' + renderTreemap(events) + '</div>';
    html += '</div>';

    
    // Workload Pattern Analysis (inline in Evidence)
    html += (function() {
        try {
            var _ev3 = events, _lp3 = lp, _sq3 = sqls;
            var _patterns;
            if (typeof detectSingleWorkloadPatterns === 'function') {
                _patterns = detectSingleWorkloadPatterns(_ev3, _lp3);
            } else if (typeof detectWorkloadPatterns === 'function') {
                _patterns = detectWorkloadPatterns([], _ev3, [], _lp3, [], _sq3);
            }
            if (!_patterns || !_patterns.length) return '';
            var sevCol = {warning:'#f59e0b', critical:'#ef4444', info:'#6366f1'};
            var _pHtml = _patterns.map(function(p) {
                var _col3 = sevCol[p.severity] || '#6366f1';
                return '<div style="display:flex;align-items:flex-start;gap:10px;padding:9px 12px;border-radius:6px;background:' + _col3 + '11;border-left:3px solid ' + _col3 + ';margin-bottom:8px">'
                    + '<div style="margin-top:1px;flex-shrink:0">' + (p.icon||'') + '</div>'
                    + '<div><div style="font-size:11px;font-weight:700;color:' + _col3 + '">' + esc(p.title||'Pattern') + '</div>'
                    + '<div style="font-size:11px;color:#94a3b8;margin-top:3px;line-height:1.5">' + esc(p.detail||'') + '</div></div></div>';
            }).join('');
            return '<div class="card p-4 mb-4 fade-in"><div style="font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px"><span style="display:inline-block;width:3px;height:12px;background:#6366f1;border-radius:2px;margin-right:8px;vertical-align:middle"></span>Workload Pattern Analysis</div>' + _pHtml + '</div>';
        } catch(e) { console.warn('detectWorkloadPatterns failed', e); return ''; }
    })();

    // Batch Purge Detection (inline in Evidence)
    html += (function() {
        var purges = ctx.analytics?.batch_purges;
        if (!purges || !purges.length) return '';
        var rows = purges.map(function(p) {
            return '<div style="display:flex;align-items:flex-start;gap:10px;padding:9px 12px;border-radius:6px;background:rgba(249,115,22,0.08);border-left:3px solid #f97316;margin-bottom:8px">'
                + '<div><div style="font-size:11px;font-weight:700;color:#f97316">' + esc(p.sql_id || 'Unknown') + ' \u2014 Batch DELETE/Purge</div>'
                + '<div style="font-size:10px;color:#94a3b8;margin-top:3px">' + esc(p.sql_text_fragment || p.sql_text || '') + '</div>'
                + '<div style="font-size:10px;color:#64748b;margin-top:4px">Elapsed: ' + num(p.elapsed_secs || 0, 1) + 's \u00B7 Executions: ' + comma(p.executions || 0) + ' \u00B7 Physical Reads: ' + comma(p.physical_reads || 0) + '</div></div></div>';
        }).join('');
        return '<div class="card p-4 mb-4 fade-in"><div style="font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px"><span style="display:inline-block;width:3px;height:12px;background:#f97316;border-radius:2px;margin-right:8px;vertical-align:middle"></span>Batch Purge Detection</div>' + rows + '</div>';
    })();


    // SESSION PERFORMANCE INTELLIGENCE — compact 3-column
    html += (function(){
        var _lp      = ctxLP;
        var _eff     = ctxE;
        var _elMin   = ctx.meta?.bad?.elapsed_min || 1;
        var _elSec   = _elMin * 60;
        var _logons  = _lp.logons  || 0;
        var _txns    = _lp.transactions || _lp.user_commits || 0;
        var _execs   = _lp.executes || 0;
        var _hparse  = _lp.hard_parses || 0;
        var _redo    = _lp.redo_size || 0;
        var _phyR    = _lp.physical_reads || 0;
        var _softP   = _eff.soft_parse_pct || 0;
        var _bufHit  = _eff.buffer_cache_hit_pct || 0;

        var _ch = ctx.analytics?.cursor_health || {};
        var _chComps = _ch.components || [];
        var _chByName = {}; _chComps.forEach(function(c) { _chByName[c.name] = c; });
        var _statusCol = function(s) { return s === 'good' ? '#10b981' : s === 'warning' ? '#f59e0b' : '#ef4444'; };

        var _aasRatio2 = cpus > 0 ? aas / cpus : 0;
        var _aasCol2   = _aasRatio2 >= 1 ? '#ef4444' : _aasRatio2 >= 0.8 ? '#f59e0b' : '#10b981';
        var _aasLabel = _aasRatio2 >= 1 ? 'SATURATED' : _aasRatio2 >= 0.8 ? 'NEAR LIMIT' : 'OK';

        var _logonComp = _chByName['Logons/sec'] || {};
        var _logonCol  = _statusCol(_logonComp.status || (_logons > 10 ? 'critical' : _logons > 2 ? 'warning' : 'good'));
        var _logonLbl  = _logonComp.status === 'critical' ? 'LOGON STORM' : _logonComp.status === 'warning' ? 'ELEVATED' : 'NORMAL';

        var _hpComp    = _chByName['Hard Parses/sec'] || {};
        var _hpCol     = _statusCol(_hpComp.status || (_hparse > 50 ? 'critical' : _hparse > 5 ? 'warning' : 'good'));
        var _hpLbl     = _hpComp.status === 'critical' ? 'STORM' : _hpComp.status === 'warning' ? 'ELEVATED' : 'OK';

        var _spComp    = _chByName['Soft Parse %'] || {};
        var _spCol     = _statusCol(_spComp.status || (_softP >= 95 ? 'good' : _softP >= 85 ? 'warning' : 'critical'));

        var _execPerLogon = _logons > 0 ? (_execs / _logons).toFixed(0) : '\u2014';
        var _queuing = Math.max(0, aas - cpus).toFixed(1);
        var _queuingCol = parseFloat(_queuing) > 0 ? '#ef4444' : '#10b981';
        var _dbTimeMin = ctx.meta?.bad?.db_time_min || 0;
        var _totalSessions = _logons > 0 ? Math.round(_logons * _elSec) : '\u2014';

        var _mRow = function(label, value, col, note) {
            return '<tr style="border-top:1px solid rgba(30,41,59,0.5)">'
                + '<td style="padding:5px 0;font-size:10px;color:#94a3b8">' + label + '</td>'
                + '<td style="padding:5px 0;text-align:right;font-family:monospace;font-weight:700;color:' + (col||'#e2e8f0') + ';font-size:11px">' + value + '</td>'
                + (note ? '<td style="padding:5px 0 5px 8px;font-size:9px;color:#475569">' + note + '</td>' : '<td></td>')
                + '</tr>';
        };

        return '<div class="card p-4 mb-4 fade-in" style="background:rgba(15,23,42,0.7);border:1px solid rgba(100,116,139,0.2)">'
            + '<div class="flex items-center gap-2 mb-4">'
            + '<svg class="w-4 h-4" style="color:#f59e0b" fill="currentColor" viewBox="0 0 20 20"><path d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z"/></svg>'
            + '<span style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px;color:#e2e8f0">Session Performance Intelligence</span>'
            + '<span style="margin-left:auto;font-size:9px;color:#64748b">Single Period \u00B7 ' + esc(ctx.meta?.lbl2||'Current AWR') + '</span>'
            + '</div>'
            + '<div class="grid grid-cols-1 md:grid-cols-3 gap-4">'
            // Card 1: Workload Intensity
            + '<div style="background:rgba(30,41,59,0.5);border:1px solid rgba(100,116,139,0.2);border-radius:8px;padding:14px">'
            + '<div style="font-size:9px;font-weight:800;text-transform:uppercase;color:#94a3b8;margin-bottom:10px;letter-spacing:0.5px">Workload Intensity</div>'
            + '<div style="margin-bottom:8px"><div style="font-size:9px;color:#64748b;margin-bottom:2px">AAS / CPUs</div>'
            + '<div style="font-size:22px;font-weight:900;color:' + _aasCol2 + '">' + num(aas,1) + ' / ' + cpus + '</div>'
            + '<div style="font-size:10px;color:' + _aasCol2 + ';font-weight:700">' + _aasLabel + ' \u00B7 ' + num(_aasRatio2*100,0) + '% utilisation</div></div>'
            + '<div style="font-size:9px;color:#64748b;margin-top:10px;margin-bottom:3px">Queuing Sessions (AAS \u2212 CPUs)</div>'
            + '<div style="font-size:18px;font-weight:800;color:' + _queuingCol + '">' + _queuing + '</div>'
            + '<div style="font-size:9px;color:#64748b;margin-top:8px">DB Time</div>'
            + '<div style="font-size:14px;font-weight:700;color:#e2e8f0">' + num(_dbTimeMin,1) + ' min <span style="font-size:9px;color:#475569">in ' + num(_elMin,0) + ' min elapsed</span></div>'
            + '</div>'
            // Card 2: Session & Logon Pressure
            + '<div style="background:rgba(30,41,59,0.5);border:1px solid rgba(100,116,139,0.2);border-radius:8px;padding:14px">'
            + '<div style="font-size:9px;font-weight:800;text-transform:uppercase;color:#94a3b8;margin-bottom:10px;letter-spacing:0.5px">Session &amp; Logon Pressure</div>'
            + '<div class="grid grid-cols-2 gap-2" style="margin-bottom:8px">'
            + '<div><div style="font-size:9px;color:#64748b;margin-bottom:2px">Logons/sec</div><div style="font-size:18px;font-weight:900;color:' + _logonCol + '">' + num(_logons,2) + '</div><div style="font-size:9px;font-weight:700;color:' + _logonCol + '">' + _logonLbl + '</div></div>'
            + '<div><div style="font-size:9px;color:#64748b;margin-bottom:2px">Hard Parses/sec</div><div style="font-size:18px;font-weight:900;color:' + _hpCol + '">' + num(_hparse,1) + '</div><div style="font-size:9px;font-weight:700;color:' + _hpCol + '">' + _hpLbl + '</div></div>'
            + '</div>'
            + '<div style="border-top:1px solid #1e293b;padding-top:8px;margin-top:4px"><table style="width:100%;font-size:10px;border-collapse:collapse">'
            + _mRow('Transactions/sec', num(_txns,1), '#e2e8f0', '')
            + _mRow('Executes/sec', num(_execs,0), '#e2e8f0', '')
            + _mRow('Exec / Logon', _execPerLogon, '#94a3b8', 'session efficiency')
            + _mRow('Soft Parse %', num(_softP,1)+'%', _spCol, '')
            + _mRow('Total Logons in window', typeof _totalSessions==='number'?comma(_totalSessions):'\u2014', '#64748b', '')
            + '</table></div></div>'
            // Card 3: I/O & Throughput
            + '<div style="background:rgba(30,41,59,0.5);border:1px solid rgba(100,116,139,0.2);border-radius:8px;padding:14px">'
            + '<div style="font-size:9px;font-weight:800;text-transform:uppercase;color:#94a3b8;margin-bottom:10px;letter-spacing:0.5px">I/O &amp; Throughput</div>'
            + '<div style="margin-bottom:8px"><div style="font-size:9px;color:#64748b;margin-bottom:2px">Buffer Cache Hit %</div>'
            + '<div style="font-size:22px;font-weight:900;color:' + (_bufHit>=95?'#10b981':_bufHit>=90?'#f59e0b':'#ef4444') + '">' + num(_bufHit,1) + '%</div></div>'
            + '<div style="border-top:1px solid #1e293b;padding-top:8px"><table style="width:100%;font-size:10px;border-collapse:collapse">'
            + _mRow('Physical Reads/sec', num(_phyR,0), _phyR>5000?'#f59e0b':'#94a3b8', '')
            + _mRow('Redo MB/sec', num(_redo/1048576,2), '#94a3b8', '')
            + _mRow('Logical Reads/sec', num(_lp.logical_reads||0,0), '#94a3b8', '')
            + _mRow('Physical Writes/sec', num(_lp.physical_writes||0,0), '#94a3b8', '')
            + _mRow('Block Changes/sec', num(_lp.block_changes||0,0), '#94a3b8', '')
            + '</table></div></div>'
            + '</div></div>';
    })();

    // SRE Operations Intelligence panel
    html += (function() {
        var _evts = ctx.waitEvents?.bad || d.wait_events || d.top_events || events || [];
        var _lfs = _evts.find(function(e){return /log file sync/i.test(e.event_name || '')});
        var commitLat = _lfs ? (_lfs.avg_wait_ms || (_lfs.time_waited_secs && _lfs.waits ? _lfs.time_waited_secs / _lfs.waits * 1000 : 0)) : 0;
        var commitCol = commitLat > 10 ? '#ef4444' : commitLat > 5 ? '#f59e0b' : '#10b981';
        var cpuEff = ctx.timeModel?.bad?.db_cpu || 0;
        var cpuEffCol = cpuEff > 60 ? '#4ade80' : cpuEff > 30 ? '#fbbf24' : '#ef4444';
        var _sre_lp = ctxLP;
        var fmtK = function(v){return v>=1000000?num(v/1000000,1)+'M':v>=1000?num(v/1000,1)+'K':num(v,1)};
        var _redo = _sre_lp.redo_size || 0;
        var _dbTimeSecs2 = ctx.meta?.bad?.db_time_secs || (db.db_time_secs || 0) || ((db.db_time_min || d.db_time_min || 0) * 60) || 1;
        var txn = _sre_lp.transactions || 0;
        var txnLabel = txn > 500 ? 'HIGH THROUGHPUT' : txn > 100 ? 'MODERATE' : txn > 10 ? 'NORMAL' : 'LOW';
        var txnCol = txn > 500 ? '#4ade80' : txn > 100 ? '#e2e8f0' : '#f59e0b';
        var dtPerExec = _sre_lp.executes > 0 ? _dbTimeSecs2 / _sre_lp.executes * 1000 : 0;
        var dtPerExecCol = dtPerExec > 100 ? '#ef4444' : dtPerExec > 20 ? '#f59e0b' : '#10b981';

        var ioWaitPct = _evts.filter(function(e){return /read|write|direct path/i.test(e.event_name||'') && !/DB CPU/i.test(e.event_name||'')}).reduce(function(s,e){return s + (e.pct_db_time||0)}, 0);
        var conWaitPct = _evts.filter(function(e){return /latch|lock|enq.*tx|mutex|buffer busy/i.test(e.event_name||'')}).reduce(function(s,e){return s + (e.pct_db_time||0)}, 0);

        var drivers = [];
        if (cpuEff > 60) drivers.push({label:'CPU-bound', val:num(cpuEff,0)+'%', col:'#fbbf24', hint:'sessions on CPU vs waiting'});
        if (ioWaitPct > 15) drivers.push({label:'I/O wait', val:num(ioWaitPct,0)+'%', col:'#f87171', hint:'read/write waits'});
        if (conWaitPct > 10) drivers.push({label:'Concurrency', val:num(conWaitPct,0)+'%', col:'#fb923c', hint:'latch/lock contention'});
        if (commitLat > 10) drivers.push({label:'Commit', val:num(commitLat,0)+'ms', col:'#f87171', hint:'log file sync slow'});
        var topWait = _evts.filter(function(e){return !/idle/i.test(e.wait_class||'')})[0];

        var _aas2 = ctx.aas?.bad || db.aas || aas || 0;
        var _cpus2 = ctx.meta?.cpu_count || db.cpus || cpus || 1;
        var queueing = Math.max(0, _aas2 - _cpus2);
        var satPct = Math.min(200, _aas2 / _cpus2 * 100);
        var satCol = satPct > 150 ? '#ef4444' : satPct > 80 ? '#f59e0b' : '#10b981';
        var satLabel = satPct > 150 ? 'SATURATED' : satPct > 80 ? 'NEAR CAPACITY' : 'WITHIN CAPACITY';
        var execPerLogon = _sre_lp.logons > 0 ? _sre_lp.executes / _sre_lp.logons : 0;

        return '<div class="card p-4 mb-4 fade-in" style="margin-top:4px">'
            + '<div style="font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px;display:flex;align-items:center;gap:8px">'
            + '<span style="display:inline-block;width:3px;height:12px;background:#f59e0b;border-radius:2px"></span>SRE Operations Intelligence</div>'
            + '<div class="grid grid-cols-1 md:grid-cols-3 gap-4">'
            // Panel 1: Commit & Execution Health
            + '<div style="background:rgba(10,16,32,0.7);border:1px solid #1e293b;border-radius:10px;padding:16px">'
            + '<div style="font-size:10px;font-weight:800;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px">Commit &amp; Execution Health</div>'
            + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:10px">'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:4px">DB Time / Execute</div><div style="font-size:16px;font-weight:800;color:' + dtPerExecCol + '">' + (dtPerExec > 1000 ? num(dtPerExec/1000,2)+'s' : num(dtPerExec,1)+'ms') + '</div><div style="font-size:9px;color:#475569">' + (dtPerExec > 100 ? 'HIGH \u2014 sessions queuing' : dtPerExec > 20 ? 'MODERATE' : 'EFFICIENT') + '</div></div>'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:4px">Commit Latency</div><div style="font-size:16px;font-weight:800;color:' + commitCol + '">' + (commitLat > 0 ? num(commitLat,1)+'ms' : 'N/A') + '</div><div style="font-size:9px;color:#475569">' + (commitLat > 10 ? 'SLOW \u2014 check redo I/O' : commitLat > 5 ? 'ELEVATED' : 'HEALTHY') + '</div></div>'
            + '</div>'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px;margin-bottom:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:4px">CPU Efficiency</div><div style="font-size:9px;color:#475569;margin-bottom:3px">DB CPU / DB Time</div><div style="font-size:16px;font-weight:800;color:' + cpuEffCol + '">' + num(cpuEff,1) + '%</div><div style="font-size:9px;color:#475569">' + (cpuEff > 60 ? 'CPU-bound \u2014 doing real work' : cpuEff > 30 ? 'Mixed workload' : 'Wait-bound \u2014 most time in waits') + '</div></div>'
            + (drivers.length > 0 ? '<div style="border-top:1px solid #1e293b;padding-top:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:6px">Latency Drivers</div><div style="display:flex;flex-wrap:wrap;gap:4px">' + drivers.map(function(dd){return '<div title="' + esc(dd.hint) + '" style="background:' + dd.col + '15;border:1px solid ' + dd.col + '40;border-radius:5px;padding:3px 7px;font-size:10px"><span style="color:' + dd.col + ';font-weight:700">' + dd.label + '</span> <span style="color:#cbd5e1;font-family:monospace">' + dd.val + '</span></div>'}).join('') + '</div></div>' : '')
            + '</div>'
            // Panel 2: Transaction Throughput
            + '<div style="background:rgba(10,16,32,0.7);border:1px solid #1e293b;border-radius:10px;padding:16px">'
            + '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px"><div><div style="font-size:10px;font-weight:800;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px">Transactions/sec</div><div style="font-size:9px;color:#475569">AWR Load Profile</div></div><div style="background:' + txnCol + '22;border:1px solid ' + txnCol + '55;border-radius:6px;padding:3px 10px"><span style="color:' + txnCol + ';font-size:9px;font-weight:900;letter-spacing:0.5px">' + txnLabel + '</span></div></div>'
            + '<div style="font-size:28px;font-weight:900;color:' + txnCol + ';margin-bottom:8px">' + num(txn,1) + '</div>'
            + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:8px">'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:6px 8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">Executes/sec</div><div style="font-size:13px;font-weight:700;color:#e2e8f0;font-family:monospace">' + num(_sre_lp.executes||0,0) + '</div></div>'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:6px 8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">User Calls/sec</div><div style="font-size:13px;font-weight:700;color:#e2e8f0;font-family:monospace">' + num(_sre_lp.user_calls||0,0) + '</div></div>'
            + '</div>'
            + '<div style="border-top:1px solid #1e293b;padding-top:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:6px;display:flex;align-items:center;gap:4px">\u26A1 Workload Signals</div>'
            + [
                {lbl:'Top Wait', val: topWait ? esc(topWait.event_name||'').substring(0,25) + ' ' + num(topWait.pct_db_time||0,0) + '%' : 'N/A', col: (topWait?.pct_db_time||0) > 30 ? '#ef4444' : '#94a3b8'},
                {lbl:'Hard Parses/s', val: num(_sre_lp.hard_parses||0,1), col: (_sre_lp.hard_parses||0) > 5 ? '#ef4444' : '#94a3b8'},
                {lbl:'Logical Reads/s', val: fmtK(_sre_lp.logical_reads||0), col:'#94a3b8'},
                {lbl:'Physical Reads/s', val: fmtK(_sre_lp.physical_reads||0), col: (_sre_lp.physical_reads||0) > 5000 ? '#f59e0b' : '#94a3b8'},
                {lbl:'Redo/s', val: fmtK(_redo)+'B', col: (_redo||0)/1048576 > 100 ? '#f59e0b' : '#94a3b8'},
                {lbl:'Soft Parse %', val: num(ctxE?.soft_parse_pct||softParse||0,1)+'%', col: (ctxE?.soft_parse_pct||softParse||0) < 90 ? '#f59e0b' : '#94a3b8'},
            ].map(function(s){return '<div style="display:flex;align-items:center;justify-content:space-between;padding:2px 0;border-bottom:1px dotted rgba(71,85,105,0.2)"><span style="color:#94a3b8;font-size:10px">' + s.lbl + '</span><span style="font-family:monospace;font-size:10px;color:' + s.col + ';font-weight:600">' + s.val + '</span></div>'}).join('')
            + '</div></div>'
            // Panel 3: Workload Assessment
            + '<div style="background:rgba(10,16,32,0.7);border:1px solid #1e293b;border-radius:10px;padding:16px">'
            + '<div style="font-size:10px;font-weight:800;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px">Workload Assessment</div>'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px;margin-bottom:8px;border-left:3px solid ' + satCol + '">'
            + '<div style="display:flex;align-items:center;justify-content:space-between"><div><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">CPU Utilisation</div><div style="font-size:16px;font-weight:800;color:' + satCol + '">' + num(satPct,0) + '%</div></div><div style="background:' + satCol + '22;border:1px solid ' + satCol + '55;border-radius:5px;padding:2px 8px"><span style="color:' + satCol + ';font-size:9px;font-weight:800">' + satLabel + '</span></div></div>'
            + '<div style="font-size:9px;color:#475569;margin-top:3px">AAS ' + num(_aas2,1) + ' / ' + _cpus2 + ' CPUs \u00B7 ' + (queueing > 0 ? num(queueing,0) + ' sessions queuing' : 'no queuing') + '</div></div>'
            + '<div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:8px">'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:6px 8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">Exec/Logon</div><div style="font-size:13px;font-weight:700;color:' + (execPerLogon < 10 ? '#ef4444' : '#e2e8f0') + ';font-family:monospace">' + num(execPerLogon,0) + '</div><div style="font-size:9px;color:#475569">' + (execPerLogon < 10 ? 'LOW \u2014 short-lived sessions' : execPerLogon > 200 ? 'GOOD \u2014 reusing connections' : 'session efficiency') + '</div></div>'
            + '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:6px 8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">Logons/sec</div><div style="font-size:13px;font-weight:700;color:' + ((_sre_lp.logons||0) > 10 ? '#ef4444' : (_sre_lp.logons||0) > 2 ? '#f59e0b' : '#10b981') + ';font-family:monospace">' + num(_sre_lp.logons||0,1) + '</div><div style="font-size:9px;color:#475569">' + ((_sre_lp.logons||0) > 10 ? 'STORM \u2014 no pool' : (_sre_lp.logons||0) > 2 ? 'ELEVATED' : 'NORMAL') + '</div></div>'
            + '</div>'
            + '<div style="border-top:1px solid #1e293b;padding-top:8px"><div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700;margin-bottom:4px">Quick Assessment</div><div style="font-size:10px;color:#94a3b8;line-height:1.5">'
            + (satPct > 150 ? 'Database is <b style="color:#ef4444">saturated</b> \u2014 sessions are queuing for resources. ' + (cpuEff < 30 ? 'Most time spent waiting (not on CPU). Fix the dominant wait event.' : 'CPU-bound workload. Review top SQL for optimization.') : satPct > 80 ? 'Database is <b style="color:#f59e0b">near capacity</b>. Workload growth will cause queuing. Plan for capacity or optimise top SQL.' : 'Database is <b style="color:#10b981">within capacity</b>. Headroom available for workload growth.')
            + '</div></div></div>'
            + '</div></div>';
    })();

    // === SECTION 4: DEEP DIAGNOSTICS (collapsible) ===
    html += '<div style="font-size:13px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin:20px 0 12px;display:flex;align-items:center;gap:8px">';
    html += '<span style="display:inline-block;width:3px;height:14px;background:#8b5cf6;border-radius:2px"></span>';
    html += 'Deep Diagnostics';
    html += '<span style="font-size:9px;color:#475569;font-weight:400;text-transform:none;letter-spacing:0">\u2014 click to expand</span>';
    html += '</div>';

    // Wait Class Distribution (collapsible)
    html += collapsible('diag-wclass', 'Wait Class Distribution', '#3b82f6',
        '<div class="chart-wrapper" style="height:200px"><canvas id="dash-wclass-bar"></canvas></div>', false);

    // Load Profile Chart (collapsible)
    html += collapsible('diag-loadchart', 'Load Profile Chart', '#a5b4fc',
        '<div class="chart-wrapper" style="height:260px"><canvas id="dash-load-bar"></canvas></div>', false);

    // Set innerHTML
    document.getElementById('dashboard-content').innerHTML = html;

    // Render charts
    setTimeout(function() { renderSingleDashboardCharts(events, sqls, lp, waitClassMap); }, 80);

    // === POST-RENDER APPENDED SECTIONS (collapsible) ===
    var _el = document.getElementById('dashboard-content');

    // Time Model (collapsible)
    var timeModel = d.time_model || [];
    if (timeModel.length) {
        var _dbTS = (db.db_time_secs||0) || (db.db_time_min||0)*60 || 1;
        var tmRows = timeModel.slice(0, 10).map(function(tm) {
            var pct2 = _dbTS > 0 ? Math.min(100, ((tm.value_secs||tm.time_secs||0) / _dbTS * 100)) : 0;
            var barColor = pct2 > 50 ? '#ef4444' : pct2 > 20 ? '#f59e0b' : '#3b82f6';
            return '<div style="display:flex;align-items:center;gap:10px;padding:6px 0;border-bottom:1px solid #1e293b">'
                + '<div style="width:180px;font-size:11px;color:#cbd5e1;flex-shrink:0">' + esc(tm.stat_name||tm.name||'') + '</div>'
                + '<div style="flex:1;background:#0f172a;border-radius:3px;height:10px;overflow:hidden"><div style="height:100%;background:' + barColor + ';width:' + pct2.toFixed(1) + '%;border-radius:3px;transition:width 0.4s"></div></div>'
                + '<div style="width:50px;text-align:right;font-size:11px;font-weight:700;color:' + barColor + '">' + pct2.toFixed(1) + '%</div>'
                + '<div style="width:70px;text-align:right;font-size:10px;color:#64748b">' + num(tm.value_secs||tm.time_secs||0,1) + 's</div></div>';
        }).join('');
        _el.insertAdjacentHTML('beforeend', collapsible('diag-timemodel', 'Time Model \u2014 % of DB Time', '#38bdf8', tmRows, false));
    }

    // Cursor Health Score (collapsible)
    (function() {
        var ch = ctx.analytics?.cursor_health;
        if (!ch || !ch.components) return;
        var gradeCol = ch.color === 'green' ? '#10b981' : ch.color === 'amber' ? '#f59e0b' : ch.color === 'orange' ? '#f97316' : '#ef4444';
        var compRows = ch.components.map(function(c) {
            var stCol = c.status === 'good' ? '#10b981' : c.status === 'warning' ? '#f59e0b' : '#ef4444';
            var stLbl = c.status === 'good' ? '\u2713 OK' : c.status === 'warning' ? '\u26A0 WARN' : '\u2717 LOW';
            var pct3 = c.weight > 0 ? (c.score / c.weight * 100).toFixed(0) : 0;
            return '<div style="display:flex;align-items:center;gap:10px;padding:6px 0;border-bottom:1px solid rgba(30,41,59,0.5)">'
                + '<div style="width:140px;font-size:11px;color:#cbd5e1">' + esc(c.name) + '</div>'
                + '<div style="flex:1;background:#0f172a;border-radius:3px;height:8px;overflow:hidden"><div style="height:100%;background:' + stCol + ';width:' + pct3 + '%;border-radius:3px"></div></div>'
                + '<div style="width:70px;text-align:right;font-family:monospace;font-weight:700;color:' + stCol + ';font-size:11px">' + c.value + c.unit + '</div>'
                + '<div style="width:50px;text-align:right;font-size:9px;font-weight:700;color:' + stCol + '">' + stLbl + '</div>'
                + '<div style="width:40px;text-align:right;font-size:9px;color:#475569">' + c.score + '/' + c.weight + '</div></div>';
        }).join('');
        var headerHtml = '<div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px">'
            + '<span style="font-size:10px;color:#64748b">Composite score from Execute-to-Parse %, Soft Parse %, Hard Parse rate, and Logon rate</span>'
            + '<div style="display:flex;align-items:center;gap:8px"><span style="font-size:24px;font-weight:900;color:' + gradeCol + '">' + ch.score + '</span><span style="font-size:13px;font-weight:800;color:' + gradeCol + ';padding:2px 8px;background:' + gradeCol + '22;border:1px solid ' + gradeCol + '55;border-radius:4px">' + ch.grade + '</span></div></div>';
        _el.insertAdjacentHTML('beforeend', collapsible('diag-cursor', 'Cursor Health Score', '#a78bfa', headerHtml + compRows, false));
    })();

    // Workload Composition (collapsible)
    (function() {
        var wl = ctx.analytics?.workload_composition;
        if (!wl || !wl.length) return;
        var total = wl.reduce(function(s, w) { return s + (w.elapsed_secs || 0); }, 0) || 1;
        var catCols = {
            'Application': '#3b82f6', 'Application (JDBC)': '#3b82f6',
            'Oracle Maintenance': '#f59e0b', 'Ad-hoc (SQL*Plus)': '#8b5cf6',
            'Ad-hoc (PL/SQL Dev)': '#8b5cf6', 'Ad-hoc (Toad)': '#8b5cf6',
            'Ad-hoc (SQL Developer)': '#8b5cf6', 'Ad-hoc (No Module)': '#6b7280',
            'Monitoring (OEM)': '#06b6d4', 'DataPump': '#f97316', 'RMAN Backup': '#ec4899',
        };
        var bars = wl.sort(function(a, b) { return (b.pct_db_time || 0) - (a.pct_db_time || 0); }).map(function(w) {
            var pctW = w.pct_db_time || (w.elapsed_secs / total * 100);
            var col = catCols[w.category] || '#64748b';
            return '<div style="display:flex;align-items:center;gap:10px;padding:5px 0;border-bottom:1px solid rgba(30,41,59,0.4)">'
                + '<div style="width:10px;height:10px;border-radius:2px;background:' + col + ';flex-shrink:0"></div>'
                + '<div style="width:160px;font-size:11px;color:#cbd5e1;flex-shrink:0">' + esc(w.category) + '</div>'
                + '<div style="flex:1;background:#0f172a;border-radius:3px;height:8px;overflow:hidden"><div style="height:100%;background:' + col + ';width:' + pctW.toFixed(1) + '%;border-radius:3px"></div></div>'
                + '<div style="width:55px;text-align:right;font-family:monospace;font-weight:700;color:' + col + ';font-size:11px">' + pctW.toFixed(1) + '%</div>'
                + '<div style="width:45px;text-align:right;font-size:10px;color:#64748b">' + w.sql_count + ' SQL</div></div>';
        }).join('');
        _el.insertAdjacentHTML('beforeend', collapsible('diag-workload', 'Workload Composition', '#3b82f6',
            '<div style="font-size:10px;color:#64748b;margin-bottom:10px">SQL classified by module &amp; purpose. Shows where DB time is being consumed.</div>' + bars, false));
    })();

    // Performance Deep-Dive Table (collapsible)
    (function() {
        var _lp2   = ctxLP;
        var _eff2  = ctxE;
        var _aasV = aas;
        var _dbTm = ctx.meta?.bad?.db_time_min || 0;

        var _col2 = function(v, good, warn) { return v >= good ? '#10b981' : v >= warn ? '#f59e0b' : '#ef4444'; };
        var _colHigh = function(v, warn, crit) { return v <= warn ? '#10b981' : v <= crit ? '#f59e0b' : '#ef4444'; };
        var _lbl2 = function(v, good, warn) { return v >= good ? 'OK' : v >= warn ? 'WARN' : 'LOW'; };
        var _lblH = function(v, warn, crit) { return v <= warn ? 'OK' : v <= crit ? 'WARN' : 'HIGH'; };

        var rows = [
            { cat:'Workload',   label:'DB Time (min)',        val:num(_dbTm,1),                         col: _colHigh(_aasV, cpus*0.8, cpus), lbl: _aasV>=cpus?'CRITICAL':_aasV>=cpus*0.8?'WARN':'OK' },
            { cat:'Workload',   label:'Avg Active Sessions',  val:num(_aasV,1)+' / '+cpus+' CPUs',      col: _colHigh(_aasV, cpus*0.8, cpus), lbl: _aasV>=cpus?'SATURATED':_aasV>=cpus*0.8?'NEAR LIMIT':'OK' },
            { cat:'Efficiency', label:'Buffer Cache Hit %',   val:num(_eff2.buffer_cache_hit_pct||0,1)+'%',  col: _col2(_eff2.buffer_cache_hit_pct||0,95,90), lbl: _lbl2(_eff2.buffer_cache_hit_pct||0,95,90) },
            { cat:'Efficiency', label:'Library Cache Hit %',  val:num(_eff2.library_cache_hit_pct||0,1)+'%', col: _col2(_eff2.library_cache_hit_pct||0,99,95), lbl: _lbl2(_eff2.library_cache_hit_pct||0,99,95) },
            { cat:'Efficiency', label:'Soft Parse %',         val:num(_eff2.soft_parse_pct||0,1)+'%',       col: _col2(_eff2.soft_parse_pct||0,95,85), lbl: _lbl2(_eff2.soft_parse_pct||0,95,85) },
            { cat:'Efficiency', label:'Execute to Parse %',   val:num(_eff2.execute_to_parse_pct||0,1)+'%', col: _col2(_eff2.execute_to_parse_pct||0,95,80), lbl: _lbl2(_eff2.execute_to_parse_pct||0,95,80) },
            { cat:'Efficiency', label:'Latch Hit %',          val:num(_eff2.latch_hit_pct||0,2)+'%',        col: _col2(_eff2.latch_hit_pct||0,99,98), lbl: _lbl2(_eff2.latch_hit_pct||0,99,98) },
            { cat:'Throughput', label:'Transactions/sec',     val:num(_lp2.transactions||_lp2.user_commits||0,1), col:'#94a3b8', lbl:'' },
            { cat:'Throughput', label:'Executes/sec',         val:num(_lp2.executes||0,0), col:'#94a3b8', lbl:'' },
            { cat:'Throughput', label:'Logical Reads/sec',    val:num(_lp2.logical_reads||0,0), col:'#94a3b8', lbl:'' },
            { cat:'Throughput', label:'User Calls/sec',       val:num(_lp2.user_calls||0,0), col:'#94a3b8', lbl:'' },
            { cat:'Parse',      label:'Parses/sec',           val:num(_lp2.parses||0,1), col:'#94a3b8', lbl:'' },
            { cat:'Parse',      label:'Hard Parses/sec',      val:num(_lp2.hard_parses||0,1), col: _colHigh(_lp2.hard_parses||0,5,50), lbl: _lblH(_lp2.hard_parses||0,5,50) },
            { cat:'Logon',      label:'Logons/sec',           val:num(_lp2.logons||0,2), col: _colHigh(_lp2.logons||0,2,10), lbl: _lblH(_lp2.logons||0,2,10) },
            { cat:'I/O',        label:'Physical Reads/sec',   val:num(_lp2.physical_reads||0,0), col:'#94a3b8', lbl:'' },
            { cat:'I/O',        label:'Physical Writes/sec',  val:num(_lp2.physical_writes||0,0), col:'#94a3b8', lbl:'' },
            { cat:'I/O',        label:'Redo Size MB/sec',     val:num((_lp2.redo_size||0)/1048576,2), col:'#94a3b8', lbl:'' },
            { cat:'I/O',        label:'Block Changes/sec',    val:num(_lp2.block_changes||0,0), col:'#94a3b8', lbl:'' },
        ];

        var lastCat = '';
        var tableRows = rows.map(function(r) {
            var catRow = r.cat !== lastCat ? '<tr style="background:rgba(30,41,59,0.8)"><td colspan="3" style="padding:5px 10px;font-size:9px;font-weight:800;text-transform:uppercase;color:#475569;letter-spacing:0.5px">' + esc(r.cat) + '</td></tr>' : '';
            lastCat = r.cat;
            return catRow + '<tr style="border-top:1px solid rgba(30,41,59,0.4)"><td style="padding:6px 10px;font-size:11px;color:#cbd5e1">' + esc(r.label) + '</td><td style="padding:6px 10px;text-align:right;font-family:monospace;font-weight:700;font-size:12px;color:' + r.col + '">' + r.val + '</td><td style="padding:6px 10px;text-align:right;font-size:9px;font-weight:700;color:' + r.col + '">' + r.lbl + '</td></tr>';
        }).join('');

        var tableHtml = '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;min-width:400px">'
            + '<thead><tr style="background:rgba(15,23,42,0.9)"><th style="padding:6px 10px;text-align:left;color:#64748b;font-size:10px;font-weight:700;text-transform:uppercase">Metric</th><th style="padding:6px 10px;text-align:right;color:#64748b;font-size:10px;font-weight:700;text-transform:uppercase">Value</th><th style="padding:6px 10px;text-align:right;color:#64748b;font-size:10px;font-weight:700;text-transform:uppercase">Status</th></thead>'
            + '<tbody>' + tableRows + '</tbody></table></div>';
        _el.insertAdjacentHTML('beforeend', collapsible('diag-deepdive', 'Performance Deep-Dive \u2014 All Metrics', '#8b5cf6', tableHtml, false));
    })();

    // Snapshot Mechanism & Coverage (collapsible)
    (function() {
        var snapBegin = +(db.snap_id_begin || db.begin_snap || db.snap_begin || 0);
        var snapEnd   = +(db.snap_id_end   || db.end_snap   || db.snap_end   || 0);
        var snapDelta = Math.max(snapEnd - snapBegin, 0);
        var durationMin = +(db.elapsed_secs||0)/60 || +(db.elapsed_min||0);
        var inferredInt = snapDelta > 0 ? durationMin / snapDelta : durationMin;
        var STANDARD_INTERVALS = [15, 30, 60];
        var SNAP_TOL = 2;
        function _parseTs(ts) {
            if (!ts) return null;
            var s = ts.trim();
            var m1 = s.match(/^(\d{1,2})-([A-Za-z]{3})-(\d{2,4})\s+(\d{1,2}):(\d{2}):?(\d{2})?$/);
            if (m1) {
                var mo = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
                var yr = parseInt(m1[3]); if (yr < 100) yr += 2000;
                return new Date(yr, mo[m1[2].toLowerCase()], parseInt(m1[1]), parseInt(m1[4]), parseInt(m1[5]), parseInt(m1[6]||'0'));
            }
            var dd = new Date(s); return isNaN(dd.getTime()) ? null : dd;
        }
        var dtB = _parseTs(db.begin_time || db.snap_begin_time || '');
        var dtE = _parseTs(db.end_time   || db.snap_end_time   || '');
        var beginMin = dtB ? dtB.getMinutes() : -1;
        var endMin   = dtE ? dtE.getMinutes() : -1;
        var startOn  = beginMin >= 0 && STANDARD_INTERVALS.some(function(i){return beginMin % i === 0});
        var endOn    = endMin   >= 0 && STANDARD_INTERVALS.some(function(i){return endMin   % i === 0});
        var stdInt   = STANDARD_INTERVALS.some(function(i){return Math.abs(inferredInt - i) <= SNAP_TOL});
        var wType, wReason, wColor, wBg, wBorder;
        if (!startOn && !endOn && beginMin >= 0) {
            wType = 'JOB-TARGETED CAPTURE'; wReason = 'Start (:' + ('0'+beginMin).slice(-2) + ') and end (:' + ('0'+(endMin>=0?endMin:0)).slice(-2) + ') are not on standard AWR schedule boundaries \u2014 this window was manually bracketed around a specific job or incident.'; wColor = '#67e8f9'; wBg = 'rgba(34,211,238,0.07)'; wBorder = 'rgba(34,211,238,0.25)';
        } else if (startOn && endOn && stdInt) {
            wType = 'STANDARD SCHEDULED SNAPSHOT'; wReason = 'Both boundaries match Oracle AWR snap schedule (~' + inferredInt.toFixed(0) + ' min interval). Regular AWR window.'; wColor = '#fbbf24'; wBg = 'rgba(251,191,36,0.07)'; wBorder = 'rgba(251,191,36,0.25)';
        } else {
            wType = 'PARTIAL / UNKNOWN BOUNDARY'; wReason = 'Snap boundaries could not be fully classified. Duration: ' + durationMin.toFixed(1) + ' min.'; wColor = '#94a3b8'; wBg = 'rgba(148,163,184,0.07)'; wBorder = 'rgba(148,163,184,0.2)';
        }
        var banners = '<div style="padding:8px 14px;border-radius:6px;background:' + wBg + ';border:1px solid ' + wBorder + '"><div style="font-size:11px;font-weight:800;color:' + wColor + '">' + wType + '</div><div style="font-size:10px;color:#94a3b8;margin-top:3px;line-height:1.5">' + esc(wReason) + '</div></div>';
        var metaStrip = '<div style="display:flex;flex-wrap:wrap;gap:14px;margin-bottom:10px;font-size:11px">'
            + '<span style="color:#64748b">Snap IDs: <b style="color:#e2e8f0;font-family:monospace">' + esc(String(snapBegin)) + '\u2013' + esc(String(snapEnd)) + '</b></span>'
            + '<span style="color:#64748b">Duration: <b style="color:#e2e8f0">' + durationMin.toFixed(1) + ' min</b></span>'
            + '<span style="color:#64748b">Begin: <b style="color:#e2e8f0">' + esc(db.begin_time||db.snap_begin_time||'\u2013') + '</b></span>'
            + '<span style="color:#64748b">End: <b style="color:#e2e8f0">' + esc(db.end_time||db.snap_end_time||'\u2013') + '</b></span></div>';
        _el.insertAdjacentHTML('beforeend', collapsible('diag-snapshot', 'Snapshot Mechanism & Coverage', '#67e8f9', metaStrip + banners, false));
    })();

    // Load Profile Table (collapsible)
    if (lp.length) {
        var _lpVal2 = function(kw) {
            var r = lp.find(function(r2){return (r2.name||r2.stat_name||r2.statistic||'').toLowerCase().includes(kw)});
            return r ? { per_s: r.per_sec||r.per_second||0, per_tx: r.per_txn||r.per_transaction||0, total: r.total||0 } : null;
        };
        var _logonVal = _lpVal2('logon');

        // Logon pressure banner
        var logonBanner = '';
        if (_logonVal && (_logonVal.per_s||0) > 0) {
            var lps = _logonVal.per_s || 0;
            var lpSev2 = lps > 10 ? 'critical' : lps > 2 ? 'warning' : 'ok';
            var lpCol2 = lps > 10 ? '#ef4444' : lps > 2 ? '#f59e0b' : '#10b981';
            var lpBg2  = lps > 10 ? 'rgba(239,68,68,0.07)' : lps > 2 ? 'rgba(245,158,11,0.07)' : 'rgba(16,185,129,0.07)';
            var lpBord2= lps > 10 ? 'rgba(239,68,68,0.3)' : lps > 2 ? 'rgba(245,158,11,0.3)' : 'rgba(16,185,129,0.2)';
            var lpLabel2 = lps > 10 ? 'LOGON STORM \u2014 Connection Pool Absent or Broken' : lps > 2 ? 'ELEVATED LOGON RATE \u2014 Connection Pool May Be Undersized' : 'Logon Rate Normal';
            var lpDetail2 = lps > 10
                ? num(lps,1) + ' logons/sec indicates the application is NOT using a connection pool. Fix: implement a connection pool (HikariCP, DRCP, Oracle UCP).'
                : lps > 2
                ? num(lps,1) + ' logons/sec is elevated. Validate pool size vs peak concurrent users.'
                : num(lps,1) + ' logons/sec \u2014 within normal range.';
            logonBanner = '<div style="padding:9px 13px;border-radius:6px;background:' + lpBg2 + ';border:1px solid ' + lpBord2 + ';margin-bottom:10px"><div style="font-size:11px;font-weight:800;color:' + lpCol2 + '">' + lpLabel2 + '</div><div style="font-size:11px;color:#94a3b8;margin-top:3px;line-height:1.55">' + esc(lpDetail2) + '</div></div>';
        }

        var lpRows = lp.slice(0, 30).map(function(r) {
            var name = r.name || r.stat_name || r.statistic || '\u2013';
            var ps   = r.per_sec != null ? r.per_sec : r.per_second;
            var ptx  = r.per_txn != null ? r.per_txn : r.per_transaction;
            var tot  = r.total;
            var isHigh = name.toLowerCase().includes('logon') && (ps||0) > 2;
            var isWarn = name.toLowerCase().includes('hard parse') && (ps||0) > 5;
            var rowStyle = isHigh ? 'background:rgba(239,68,68,0.05)' : isWarn ? 'background:rgba(245,158,11,0.05)' : '';
            return '<tr style="' + rowStyle + '"><td style="font-weight:600;color:#cbd5e1">' + esc(name) + '</td><td style="font-family:monospace;text-align:right;font-weight:700;color:' + (isHigh?'#f87171':isWarn?'#fbbf24':'#e2e8f0') + '">' + (ps!=null?num(ps,2):'\u2013') + '</td><td style="font-family:monospace;text-align:right;color:#94a3b8">' + (ptx!=null?num(ptx,2):'\u2013') + '</td><td style="font-family:monospace;text-align:right;color:#64748b;font-size:10.5px">' + (tot!=null?num(tot,0):'\u2013') + '</td></tr>';
        }).join('');

        var lpTableHtml = logonBanner
            + '<div style="overflow-x:auto"><table style="width:100%;border-collapse:collapse;font-size:12px"><thead><tr style="background:rgba(15,23,42,0.9)"><th style="padding:7px 10px;text-align:left;color:#64748b;font-size:10px;text-transform:uppercase">Statistic</th><th style="padding:7px 10px;text-align:right;color:#64748b;font-size:10px;text-transform:uppercase">Per Second</th><th style="padding:7px 10px;text-align:right;color:#64748b;font-size:10px;text-transform:uppercase">Per Txn</th><th style="padding:7px 10px;text-align:right;color:#64748b;font-size:10px;text-transform:uppercase">Total</th></thead><tbody>'
            + lpRows + '</tbody></table></div>';
        _el.insertAdjacentHTML('beforeend', collapsible('diag-loadprofile', 'Load Profile Table', '#a5b4fc', lpTableHtml, false));
    }

    // Session Intelligence Panel
    if (typeof renderSessionIntelligencePanel === 'function') {
        setTimeout(function() {
            try {
                var _ctx2 = window.AWRContext || {};
                renderSessionIntelligencePanel(_ctx2);
            } catch(e) { console.warn('renderSessionIntelligencePanel failed', e); }
        }, 200);
    }
}





function renderTreemap(events) {

    if (!events.length) return '<div class="text-gray-600 text-sm p-4">No wait event data</div>';

    const colors = ['#dc2626','#ea580c','#d97706','#ca8a04','#65a30d','#16a34a','#0d9488','#0891b2','#2563eb','#7c3aed'];

    const maxPct = Math.max(...events.map(e=>e.pct_db_time||0), 1);

    return events.map((e,i) => {

        const pctVal = e.pct_db_time||0;

        const w = Math.max(80, Math.min(300, (pctVal/maxPct)*300));

        const h = Math.max(50, Math.min(90, 40 + pctVal*1.2));

        return `<div class="treemap-tile" style="width:${w}px;height:${h}px;background:${colors[i%10]}20;border:1px solid ${colors[i%10]}60">

            <div class="text-[9px] font-semibold" style="color:${colors[i%10]}">${pctVal.toFixed(1)}% DB Time</div>

            <div class="text-[10px] text-white font-medium mt-0.5 truncate">${esc(e.event_name)}</div>

            <div class="text-[8px] text-Cmuted">${e.wait_class||''} | ${comma(e.total_waits||0)} waits</div>

        </div>`;

    }).join('');

}



function generateSingleAISummary(ctxArg) {
    // === RICH SINGLE-AWR NARRATIVE — 6-block structure matching compare mode ===
    let v, aas, cpus, events, sqls, eff, lp, tm, dbTimeSecs;
    if (ctxArg && (ctxArg._isSingle !== undefined || ctxArg.verdicts)) {
        const ctx = ctxArg;
        v      = ctx.verdicts?.bad    || ctx.verdict || {};
        aas    = ctx.aas?.bad         || 0;
        cpus   = ctx.meta?.cpu_count  || 1;
        events = ctx.waitEvents?.bad  || [];
        sqls   = ctx._raw?.bad?.sql_stats || [];
        eff    = ctx.instanceEfficiency?.bad || {};
        lp     = ctx.loadProfile?.bad || {};
        tm     = ctx.timeModel?.bad   || {};
        dbTimeSecs = ctx.meta?.bad?.db_time_secs || 0;
    } else {
        v      = ctxArg || {};
        const db2 = arguments[1] || {};
        aas    = db2.aas || 0; cpus = db2.cpus || 1;
        events = arguments[2] || []; sqls = arguments[3] || [];
        eff    = arguments[4] || {}; lp = {}; tm = {};
        dbTimeSecs = 0;
    }

    const f1 = n => (+n||0).toFixed(1);
    const f0 = n => (+n||0).toFixed(0);
    const comma = n => (+n||0).toLocaleString();
    const btl = (v.primary_bottleneck || '').toLowerCase();
    let html = '';

    // ── Block 1: VERDICT HEADER — severity badge + load characterization ──────
    const ratio = cpus > 0 ? aas / cpus : 0;
    const sevClass = ratio > 2 ? 'CRITICAL' : ratio > 1 ? 'DEGRADED' : ratio > 0.7 ? 'WARNING' : 'HEALTHY';
    const sevColor = { CRITICAL:'#ef4444', DEGRADED:'#f59e0b', WARNING:'#eab308', HEALTHY:'#10b981' }[sevClass];
    const score = v.health_score || v.score || 0;
    const grade = v.grade || (score>=90?'A':score>=75?'B':score>=60?'C':score>=40?'D':'F');

    html += '<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">'
        + '<span style="padding:3px 10px;border-radius:4px;font-size:11px;font-weight:700;color:white;background:' + sevColor + ';letter-spacing:0.5px">' + sevClass + '</span>'
        + '<span style="font-size:13px;font-weight:600;color:#e2e8f0">Health ' + f0(score) + '/' + grade + '</span>'
        + '<span style="font-size:12px;color:#94a3b8">AAS ' + f1(aas) + ' / ' + cpus + ' CPUs (' + f1(ratio) + 'x)</span>'
        + '</div>';

    // Load characterization
    if (ratio > 2)
        html += '<div style="font-size:12px;color:#fca5a5;margin-bottom:8px;line-height:1.6">The database is <b>severely overloaded</b> at ' + f1(aas) + ' Average Active Sessions against ' + cpus + ' CPUs (' + f1(ratio) + 'x capacity). Sessions are queueing for resources.</div>';
    else if (ratio > 1)
        html += '<div style="font-size:12px;color:#fde68a;margin-bottom:8px;line-height:1.6">The database is <b>overloaded</b> at ' + f1(aas) + ' AAS against ' + cpus + ' CPUs. Active sessions exceed CPU capacity.</div>';
    else if (ratio > 0.7)
        html += '<div style="font-size:12px;color:#fef08a;margin-bottom:8px;line-height:1.6">The database is under <b>moderate pressure</b> at ' + f1(aas) + ' AAS against ' + cpus + ' CPUs.</div>';
    else
        html += '<div style="font-size:12px;color:#86efac;margin-bottom:8px;line-height:1.6">The database is <b>running within capacity</b> at ' + f1(aas) + ' AAS against ' + cpus + ' CPUs.</div>';

    // ── Block 2: TOP CULPRIT SQL — classification + metrics table ─────────────
    const topSql = (sqls||[]).slice().sort(function(a,b){return (b.pct_db_time||0)-(a.pct_db_time||0)})[0];
    if (topSql && (topSql.pct_db_time||0) > 3) {
        const pdb = topSql.pct_db_time || 0;
        const execs = topSql.executions || 1;
        const epe = topSql.avg_elapsed_secs || ((topSql.elapsed_time_secs||0)/Math.max(execs,1));
        const gets = topSql.buffer_gets_per_exec || topSql.buffer_gets || 0;
        const topWait = (events||[]).find(function(e){return !/DB CPU/i.test(e.event_name||'')});
        const topWaitName = topWait ? topWait.event_name : '';

        // Classification
        var sqlClass = 'HIGH_RESOURCE', classColor = '#f59e0b';
        if (gets > 50000) { sqlClass = 'FULL_SCAN_CANDIDATE'; classColor = '#ef4444'; }
        else if (topWaitName && /lock|enq|buffer busy|free buffer/i.test(topWaitName)) { sqlClass = 'CONTENTION_VICTIM'; classColor = '#ef4444'; }
        else if (epe > 10) { sqlClass = 'SLOW_EXECUTION'; classColor = '#ef4444'; }
        else if (execs > 50000) { sqlClass = 'HIGH_FREQUENCY'; classColor = '#3b82f6'; }

        html += '<div style="margin:12px 0;padding:10px 14px;background:rgba(239,68,68,0.06);border-radius:6px;border-left:3px solid ' + classColor + '">'
            + '<div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">'
            + '<span style="font-size:11px;font-weight:700;color:#e2e8f0">TOP IMPACT SQL</span>'
            + '<code style="font-size:12px;color:#fbbf24;background:rgba(251,191,36,0.1);padding:2px 6px;border-radius:3px">' + esc(topSql.sql_id||'') + '</code>'
            + '<span style="padding:2px 8px;border-radius:3px;font-size:10px;font-weight:700;color:white;background:' + classColor + '">' + sqlClass.replace(/_/g,' ') + '</span>'
            + '</div>'
            + '<table style="width:100%;font-size:11px;color:#cbd5e1;border-collapse:collapse">'
            + '<tr><td style="padding:3px 8px;color:#94a3b8">DB Time%</td><td style="padding:3px 8px;font-weight:600">' + f1(pdb) + '%</td>'
            + '<td style="padding:3px 8px;color:#94a3b8">Elapsed/Exec</td><td style="padding:3px 8px;font-weight:600">' + f1(epe) + 's</td></tr>'
            + '<tr><td style="padding:3px 8px;color:#94a3b8">Executions</td><td style="padding:3px 8px;font-weight:600">' + comma(execs) + '</td>'
            + '<td style="padding:3px 8px;color:#94a3b8">Buffer Gets/Exec</td><td style="padding:3px 8px;font-weight:600">' + comma(Math.round(gets)) + '</td></tr>'
            + (topWaitName ? '<tr><td style="padding:3px 8px;color:#94a3b8">Correlated Wait</td><td colspan="3" style="padding:3px 8px;font-weight:600;color:#fca5a5">' + esc(topWaitName) + ' (' + f1(topWait.pct_db_time||0) + '%)</td></tr>' : '')
            + '</table></div>';
    }

    // ── Block 3: BOTTLENECK DIAGNOSIS — primary bottleneck with evidence ──────
    const btlMap = {
        cpu: { icon:'\u{1F534}', label:'CPU Saturation', detail:'DB CPU dominates wait profile. Optimize top SQL to reduce logical reads per execution.' },
        cpu_saturation: { icon:'\u{1F534}', label:'CPU Saturation', detail:'DB CPU dominates. Reduce buffer gets per execution in top SQL.' },
        io: { icon:'\u{1F7E0}', label:'I/O Bottleneck', detail:'Physical I/O waits dominate. Check storage latency, segment statistics, and consider adding indexes.' },
        concurrency: { icon:'\u{1F7E1}', label:'Concurrency / Latch Contention', detail:'Lock or latch waits indicate shared-resource contention. Check V$LATCH and V$LOCK.' },
        configuration: { icon:'\u{1F535}', label:'Configuration / Resource Sizing', detail:'Enqueue or resource waits suggest undersized parameters (redo buffer, undo, SGA). DDL/admin changes needed.' },
        commit: { icon:'\u{1F7E0}', label:'Commit / Redo Bottleneck', detail:'Log file sync waits dominate. Reduce commit frequency (batch commits) or move redo to faster storage.' },
        mixed: { icon:'\u26AA', label:'Mixed Workload', detail:'No single wait class dominates. Multiple resource pressures present.' },
    };
    // ── CPU Scheduling Override: detect AAS >> CPUs with low wait coverage ──
    // When AAS massively exceeds CPUs but no single wait class dominates,
    // the real bottleneck is OS run-queue contention — sessions waiting for CPU scheduling.
    // Oracle wait events don't capture OS scheduling delays, so waits appear low.
    const totalWaitPct = events.reduce((s,e) => s + (e.pct_db_time||0), 0);
    const totalGets = sqls.reduce((s,q) => s + (q.buffer_gets||0), 0);
    let effectiveBtl = btl;
    if (ratio > 1.5 && totalWaitPct < 30) {
        effectiveBtl = 'cpu_runqueue';
        btlMap['cpu_runqueue'] = {
            icon:'\u{1F534}', label:'CPU Scheduling Bottleneck (OS Run Queue)',
            detail:'AAS of ' + f1(aas) + ' on ' + cpus + ' CPUs (' + f0(ratio*100) + '% utilization). '
                + 'Only ' + f1(totalWaitPct) + '% of DB Time appears in Oracle wait events \u2014 the remaining '
                + f0(100 - totalWaitPct) + '% is OS run-queue time (sessions queued for CPU scheduling, invisible to Oracle). '
                + (totalGets > 1e9 ? 'Root cause: ' + (totalGets/1e9).toFixed(1) + 'B buffer gets from top SQL creating massive logical I/O demand. ' : '')
                + 'Fix the top SQL to reduce buffer gets/exec; this will lower AAS and relieve CPU pressure.'
        };
    } else if (ratio > 1.5 && (btl === '' || btl === 'unknown' || btl === 'mixed')) {
        effectiveBtl = 'cpu';
    }
    const btlInfo = btlMap[effectiveBtl] || btlMap[btl] || btlMap['mixed'];

    html += '<div style="margin:8px 0;font-size:12px;color:#e2e8f0;line-height:1.6">'
        + '<b>Primary Bottleneck:</b> <span style="font-weight:600">' + btlInfo.icon + ' ' + btlInfo.label + '</span> &mdash; ' + btlInfo.detail
        + '</div>';

    // Variables for action recommendations (efficiency thresholds)
    const bp = eff.buffer_cache_hit_pct || 0;
    const sp = eff.soft_parse_pct || 0;
    const la = eff.latch_hit_pct || 0;
    // ── Block 5: IMMEDIATE ACTION — remediation steps ───────────────────────
    var actions = [];
    if (topSql && (topSql.pct_db_time||0) > 5) {
        actions.push('<code style="font-size:10px;background:rgba(99,102,241,0.1);padding:2px 5px;border-radius:3px;color:#a5b4fc">SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR(\'' + esc(topSql.sql_id) + '\'))</code>');
        actions.push('Run SQL Tuning Advisor on <b>' + esc(topSql.sql_id) + '</b> &mdash; target ' + f1(topSql.pct_db_time||0) + '% DB Time reduction');
    }
    if (btl === 'io' || btl === 'configuration')
        actions.push('Check <code style="font-size:10px;background:rgba(99,102,241,0.1);padding:2px 5px;border-radius:3px;color:#a5b4fc">V$SYSSTAT</code> for physical reads &mdash; correlate with segment statistics');
    if (bp > 0 && bp < 95)
        actions.push('Buffer cache hit at ' + f1(bp) + '% &mdash; consider increasing <b>DB_CACHE_SIZE</b> or reviewing full-table scans');
    if (sp > 0 && sp < 90)
        actions.push('Soft parse at ' + f1(sp) + '% &mdash; check for literal SQL. Set <code style="font-size:10px;background:rgba(99,102,241,0.1);padding:2px 5px;border-radius:3px;color:#a5b4fc">CURSOR_SHARING=FORCE</code> or add bind variables.');
    // PE Field Knowledge — deeper optimization actions
    if (topSql && (topSql.buffer_gets_per_exec||0) > 100000)
        actions.push('INDEX REVIEW: Top SQL (' + esc(topSql.sql_id) + ') has ' + comma(Math.round(topSql.buffer_gets_per_exec||0)) + ' gets/exec. Check execution plan for Full Table Scans, add indexes on WHERE clause columns.');
    if (topSql && (topSql.rows_processed||0) > 0 && (topSql.buffer_gets_per_exec||0)/(topSql.rows_processed||1) > 500)
        actions.push('CARDINALITY CHECK: Top SQL gets/row ratio is ' + comma(Math.round((topSql.buffer_gets_per_exec||0)/(topSql.rows_processed||1))) + '. Verify E-Rows vs A-Rows in plan. Gather stats: <code style="font-size:10px;background:rgba(99,102,241,0.1);padding:2px 5px;border-radius:3px;color:#a5b4fc">EXEC DBMS_STATS.GATHER_TABLE_STATS(ownname=>USER, tabname=>\'...\', method_opt=>\'FOR ALL COLUMNS SIZE AUTO\');</code>');
    if (events.length > 0 && events[0] && (events[0].event_name||'').indexOf('db file scattered') >= 0)
        actions.push('FULL SCAN DETECTED: Top wait is db file scattered read (multi-block I/O). Review SQL plans for missing indexes. Consider partitioning hot tables if filtering on a partition-friendly column.');
    if (events.length > 0 && events[0] && (events[0].event_name||'').indexOf('db file sequential') >= 0 && events[0].avg_wait_ms > 20)
        actions.push('SLOW INDEX I/O: db file sequential read avg ' + f1(events[0].avg_wait_ms) + 'ms (threshold: <10ms). Check storage performance, IOPS capacity, and Tablespace I/O stats.');
    if (lp.hard_parses > 50)
        actions.push('PARSE STORM: ' + f1(lp.hard_parses) + ' hard parses/sec is critical. Deploy bind variables or <code style="font-size:10px;background:rgba(99,102,241,0.1);padding:2px 5px;border-radius:3px;color:#a5b4fc">ALTER SYSTEM SET CURSOR_SHARING=FORCE</code>. Check Library Cache Hit % and Shared Pool Advisory.');

    if (actions.length > 0) {
        html += '<div style="margin:10px 0;padding:8px 12px;background:rgba(99,102,241,0.05);border-radius:5px;border-left:3px solid #6366f1">'
            + '<div style="font-size:10px;font-weight:700;color:#818cf8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">Immediate Actions</div>'
            + '<ol style="margin:0;padding-left:18px;font-size:11px;color:#cbd5e1;line-height:1.8">';
        actions.forEach(function(a) { html += '<li>' + a + '</li>'; });
        html += '</ol></div>';
    }

    // PE Warehouse Diagnostic Queries — Oracle metadata catalog
    // Injected into generateSingleAISummary after Block 5 (Immediate Actions)
    // Context-aware: selects relevant queries based on bottleneck type, SQL issues, wait events
    
    // ── Block 5b: PE WAREHOUSE — Oracle Diagnostic Queries ─────────────────
    var peQueries = [];
    
    // Always relevant: AWR SQL history sorted by resource usage
    peQueries.push({
        title: 'AWR SQL History — Top CPU Consumers',
        when: 'Always applicable — augments AWR SQL section with aggregate resource data from DBA_HIST_SQLSTAT',
        sql: 'SELECT a.sql_id,\n'
           + '       dbms_lob.substr(t.sql_text, 100, 1) statement,\n'
           + '       SUM(a.cpu_time_delta) cpu_time\n'
           + 'FROM   dba_hist_sqlstat a, dba_hist_snapshot s, dba_hist_sqltext t\n'
           + 'WHERE  s.snap_id = a.snap_id AND a.sql_id = t.sql_id\n'
           + '       AND s.begin_interval_time > SYSDATE - 1\n'
           + 'GROUP BY a.sql_id, dbms_lob.substr(t.sql_text, 100, 1)\n'
           + 'ORDER BY SUM(a.cpu_time_delta) DESC;',
        category: 'sql'
    });
    
    // ASH real-time — longest wait times
    peQueries.push({
        title: 'ASH — SQL with Longest Wait Times (Real-Time)',
        when: 'Use during active performance incidents — shows who is waiting and on what',
        sql: 'SELECT ash.sample_time, ash.sql_id, u.username, sqa.sql_text,\n'
           + '       SUM(ash.wait_time + ash.time_waited) total_wait_time,\n'
           + '       ROUND(SUM(ash.delta_read_io_bytes/(ash.delta_time/1000000))) io_read,\n'
           + '       ROUND(SUM(ash.delta_read_mem_bytes/(ash.delta_time/1000000))) mem_reads\n'
           + 'FROM   v$active_session_history ash, v$sqlarea sqa, dba_users u\n'
           + 'WHERE  ash.sql_id = sqa.sql_id AND ash.user_id = u.user_id\n'
           + '       AND u.username != \'SYS\'\n'
           + '       AND ash.sample_time > SYSDATE - 3/24\n'
           + 'GROUP BY ash.sample_time, ash.sql_id, u.username, sqa.sql_text\n'
           + 'ORDER BY 5 DESC;',
        category: 'wait'
    });
    
    // Busiest objects since restart
    peQueries.push({
        title: 'Hottest Objects — Reads & Scans Since Restart',
        when: 'Identifies over-accessed tables/indexes — helps validate indexing strategy',
        sql: 'SELECT vss.owner, vss.object_name, vss.object_type, vss.tablespace_name,\n'
           + '  SUM(CASE statistic_name WHEN \'logical reads\' THEN value ELSE 0 END\n'
           + '    + CASE statistic_name WHEN \'physical reads\' THEN value ELSE 0 END) reads,\n'
           + '  SUM(CASE statistic_name WHEN \'logical reads\' THEN value ELSE 0 END) logical_reads,\n'
           + '  SUM(CASE statistic_name WHEN \'physical reads\' THEN value ELSE 0 END) physical_reads,\n'
           + '  SUM(CASE statistic_name WHEN \'segment scans\' THEN value ELSE 0 END) segment_scans,\n'
           + '  SUM(CASE statistic_name WHEN \'physical writes\' THEN value ELSE 0 END) writes\n'
           + 'FROM   v$segment_statistics vss\n'
           + 'WHERE  vss.owner NOT IN (\'SYS\',\'SYSTEM\')\n'
           + '       AND vss.object_type IN (\'TABLE\',\'INDEX\')\n'
           + 'GROUP BY vss.owner, vss.object_name, vss.object_type,\n'
           + '         vss.subobject_name, vss.tablespace_name\n'
           + 'ORDER BY reads DESC;',
        category: 'io'
    });
    
    // AWR segment history — time-bounded
    peQueries.push({
        title: 'AWR Segment History — Table I/O in Time Window',
        when: 'Narrow focus on which tables drove physical/logical reads during the problem window',
        sql: 'SELECT o.object_name,\n'
           + '       SUM(s.physical_reads_delta) physical_reads,\n'
           + '       SUM(s.logical_reads_delta) logical_reads\n'
           + 'FROM   dba_hist_seg_stat s, dba_hist_seg_stat_obj o, dba_hist_snapshot sn\n'
           + 'WHERE  o.obj# = s.obj# AND o.dataobj# = s.dataobj#\n'
           + '       AND s.snap_id = sn.snap_id\n'
           + '       AND sn.begin_interval_time > SYSDATE - 1\n'
           + '       AND o.object_type = \'TABLE\'\n'
           + 'GROUP BY o.object_name\n'
           + 'ORDER BY 3 DESC;',
        category: 'io'
    });
    
    // SQL plan history for a specific SQL_ID
    if (topSql && topSql.sql_id) {
        peQueries.push({
            title: 'Plan History for Top SQL — ' + esc(topSql.sql_id),
            when: 'Execution plan stability check — detects plan flips causing performance regression',
            sql: 'SELECT snap_id, sql_id, plan_hash_value, end_interval_time,\n'
               + '       executions_delta,\n'
               + '       ROUND(elapsed_time_delta/(CASE executions_delta WHEN 0 THEN 1\n'
               + '             ELSE executions_delta END * 1000),1) "Elapsed Avg ms",\n'
               + '       ROUND(cpu_time_delta/(CASE executions_delta WHEN 0 THEN 1\n'
               + '             ELSE executions_delta END * 1000),1) "CPU Avg ms",\n'
               + '       ROUND(iowait_delta/(CASE executions_delta WHEN 0 THEN 1\n'
               + '             ELSE executions_delta END * 1000),1) "IO Avg ms",\n'
               + '       ROUND(buffer_gets_delta/(CASE executions_delta WHEN 0 THEN 1\n'
               + '             ELSE executions_delta END),1) "Avg Buffer Gets",\n'
               + '       ROUND(rows_processed_delta/(CASE executions_delta WHEN 0 THEN 1\n'
               + '             ELSE executions_delta END),1) "Avg Rows"\n'
               + 'FROM   (SELECT ss.snap_id, ss.sql_id, ss.plan_hash_value,\n'
               + '               sn.end_interval_time, ss.executions_delta,\n'
               + '               elapsed_time_delta, cpu_time_delta, iowait_delta,\n'
               + '               buffer_gets_delta, rows_processed_delta\n'
               + '        FROM   dba_hist_sqlstat ss, dba_hist_snapshot sn\n'
               + '        WHERE  ss.sql_id = \'' + esc(topSql.sql_id) + '\'\n'
               + '               AND ss.snap_id = sn.snap_id\n'
               + '               AND ss.instance_number = sn.instance_number)\n'
               + 'WHERE  elapsed_time_delta > 0\n'
               + 'ORDER BY snap_id DESC;',
            category: 'sql'
        });
    
        peQueries.push({
            title: 'Execution Plan Stability — ' + esc(topSql.sql_id),
            when: 'Check all historical execution plans for this SQL — plan flip is a top cause of SQL regression',
            sql: 'SELECT * FROM dba_hist_sql_plan\n'
               + 'WHERE  sql_id = \'' + esc(topSql.sql_id) + '\';',
            category: 'sql'
        });
    }
    
    // Long-running queries from AWR history
    peQueries.push({
        title: 'AWR — Longest Running Queries (Last 7 Days)',
        when: 'Identifies SQL with highest cumulative elapsed time — best for finding batch/report offenders',
        sql: 'SELECT t.sql_id,\n'
           + '       MIN(sn.begin_interval_time) snap_begin,\n'
           + '       MAX(sn.end_interval_time) snap_end,\n'
           + '       MAX(CAST(dbms_lob.substr(t.sql_text,200) AS NVARCHAR2(200))) sql_text,\n'
           + '       SUM(s.executions_delta) executions,\n'
           + '       SUM(s.elapsed_time_delta)/1000/1000 elapsed_secs\n'
           + 'FROM   dba_hist_sqlstat s, dba_hist_sqltext t, dba_hist_snapshot sn\n'
           + 'WHERE  t.sql_id = s.sql_id AND s.snap_id = sn.snap_id\n'
           + '       AND sn.begin_interval_time > SYSDATE - 7\n'
           + '       AND parsing_schema_name NOT IN (\'SYS\')\n'
           + 'GROUP BY t.sql_id\n'
           + 'ORDER BY elapsed_secs DESC;',
        category: 'sql'
    });
    
    // Filter queries by relevance to detected bottleneck
    var relevantQueries = peQueries.filter(function(q) {
        if (btl === 'io' || btl === 'configuration') return true; // all relevant for I/O
        if (btl === 'cpu' && q.category === 'sql') return true;
        if (btl === 'concurrency' && (q.category === 'wait' || q.category === 'sql')) return true;
        if (btl === 'memory' && (q.category === 'io' || q.category === 'sql')) return true;
        return true; // show all by default
    });
    
    if (relevantQueries.length > 0) {
        html += '<div style="margin:12px 0 6px;padding:10px 14px;background:rgba(16,185,129,0.04);border-radius:6px;border:1px solid rgba(16,185,129,0.15)">'
            + '<div style="display:flex;align-items:center;gap:6px;margin-bottom:8px">'
            + '<svg style="width:14px;height:14px;flex-shrink:0" fill="none" stroke="#10b981" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M4 7v10c0 2 1 3 3 3h10c2 0 3-1 3-3V7c0-2-1-3-3-3H7C5 4 4 5 4 7z"/><path stroke-linecap="round" stroke-width="2" d="M9 12h6M9 8h6M9 16h3"/></svg>'
            + '<span style="font-size:10px;font-weight:800;text-transform:uppercase;color:#10b981;letter-spacing:0.5px">Oracle PE Warehouse — Diagnostic Queries</span>'
            + '</div>'
            + '<div style="font-size:9px;color:#64748b;margin-bottom:8px;line-height:1.4">'
            + 'Run these queries against the database catalog to deep-dive beyond AWR snapshots. '
            + 'Source: DBA_HIST_*, V$ACTIVE_SESSION_HISTORY, V$SEGMENT_STATISTICS'
            + '</div>';
    
        relevantQueries.forEach(function(q, qi) {
            var isOpen = qi < 2 ? 'true' : 'false';
            html += '<details style="margin:4px 0;border:1px solid rgba(100,116,139,0.15);border-radius:4px;overflow:hidden"' + (qi < 2 ? ' open' : '') + '>'
                + '<summary style="padding:6px 10px;font-size:10px;font-weight:700;color:#e2e8f0;cursor:pointer;background:rgba(30,41,59,0.5);user-select:none">'
                + '<span style="color:#10b981;margin-right:4px">\u25B6</span> '
                + q.title
                + ' <span style="float:right;font-size:9px;font-weight:400;color:#64748b;font-style:italic">' + q.when.substring(0,60) + (q.when.length > 60 ? '...' : '') + '</span>'
                + '</summary>'
                + '<div style="padding:6px 10px;font-size:9px;color:#94a3b8;background:rgba(15,23,42,0.6);line-height:1.3">'
                + '<div style="margin-bottom:4px;color:#64748b;font-style:italic">' + q.when + '</div>'
                + '<pre style="margin:0;padding:6px 8px;background:rgba(0,0,0,0.3);border-radius:3px;font-size:9px;color:#a5b4fc;overflow-x:auto;white-space:pre-wrap;font-family:\'JetBrains Mono\',\'Fira Code\',monospace;line-height:1.5;border:1px solid rgba(99,102,241,0.15)">'
                + q.sql.replace(/</g, '&lt;').replace(/>/g, '&gt;')
                + '</pre>'
                + '</div></details>';
        });
    
        html += '</div>';
    }
    

    // ── Block 6: CONTEXT NOTES — window metadata ─────────────────────────────
    var ctxNotes = [];
    if (aas > cpus * 3) ctxNotes.push('AAS ' + f1(ratio) + 'x CPU count &mdash; system is severely saturated');
    if (events.length > 0 && events[0]) ctxNotes.push('Top wait: ' + (events[0].event_name||'') + ' at ' + f1(events[0].pct_db_time||0) + '% DB Time');
    if (lp.hard_parses > 5) ctxNotes.push('Hard parses: ' + f1(lp.hard_parses) + '/sec (concern threshold: 5/sec)');
    if (ctxNotes.length > 0) {
        html += '<div style="margin-top:8px;font-size:10px;color:#64748b;line-height:1.6">';
        ctxNotes.forEach(function(n) { html += '\u25B8 ' + n + '<br>'; });
        html += '</div>';
    }

    return html || 'No analysis data available.';
}



// -------------------------------------------------------------------
//  BACKEND INTELLIGENCE ENGINE — polls /api/intelligence/{upload_id}
//  Displays structured, evidence-backed findings (not HTML blobs).
//  The engineer sees exactly what IS the problem and what to do.
// -------------------------------------------------------------------

// -------------------------------------------------------------------
//  BACKEND INTELLIGENCE ENGINE — polls /api/intelligence/{upload_id}
//  Displays structured, evidence-backed findings (not HTML blobs).
//  The engineer sees exactly what IS the problem and what to do.
// -------------------------------------------------------------------

const _SEVERITY_STYLE = {
    CRITICAL: { bg: 'rgba(239,68,68,0.12)',  border: 'rgba(239,68,68,0.45)',  badge: '#ef4444', dot: '#ef4444' },
    WARNING:  { bg: 'rgba(245,158,11,0.10)', border: 'rgba(245,158,11,0.40)', badge: '#f59e0b', dot: '#f59e0b' },
    INFO:     { bg: 'rgba(99,102,241,0.08)', border: 'rgba(99,102,241,0.30)', badge: '#818cf8', dot: '#818cf8' },
};

function _renderV4IntelCard(f) {
    const s = _SEVERITY_STYLE[f.severity] || _SEVERITY_STYLE.INFO;
    const evidenceLi = (f.evidence || []).filter(Boolean)
        .map(e => `<li style="margin:2px 0;color:#94a3b8">${esc(e)}</li>`).join('');
    const sqlBadges = (f.sql_ids || []).map(id =>
        `<code style="background:rgba(99,102,241,0.2);padding:1px 6px;border-radius:3px;font-size:10px;color:#a5b4fc">${esc(id)}</code>`
    ).join(' ');

    return `<div style="margin:10px 0;background:${s.bg};border:1px solid ${s.border};border-radius:8px;overflow:hidden">
        <div style="display:flex;align-items:center;gap:8px;padding:8px 14px;border-bottom:1px solid ${s.border}">
            <div style="width:8px;height:8px;border-radius:50%;background:${s.dot};flex-shrink:0"></div>
            <span style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.8px;color:${s.badge}">${esc(f.severity)}</span>
            <span style="font-size:10px;color:#64748b">•</span>
            <span style="font-size:10px;color:#94a3b8">${esc(f.category)}</span>
            <span style="margin-left:auto;font-size:10px;color:#475569">impact ${Math.round(f.impact_score||0)}/100 · ${esc(f.confidence||'MEDIUM')}</span>
        </div>
        <div style="padding:10px 14px">
            <div style="font-size:12px;font-weight:700;color:#e2e8f0;margin-bottom:4px">${esc(f.title)}</div>
            <div style="font-size:12px;color:#cbd5e1;margin-bottom:8px;font-style:italic">${esc(f.headline)}</div>

            ${evidenceLi ? `<details style="margin-bottom:8px">
                <summary style="font-size:10px;color:#6366f1;cursor:pointer;user-select:none;font-weight:600">Evidence</summary>
                <ul style="margin:6px 0 0 16px;padding:0;font-size:11px;list-style:disc">${evidenceLi}</ul>
            </details>` : ''}

            <div style="margin-bottom:6px">
                <span style="font-size:9px;text-transform:uppercase;letter-spacing:0.6px;color:#6366f1;font-weight:700">Root Cause</span>
                <div style="font-size:11px;color:#94a3b8;margin-top:2px">${esc(f.root_cause)}</div>
            </div>
            <div style="background:rgba(74,222,128,0.08);border:1px solid rgba(74,222,128,0.2);border-radius:5px;padding:7px 10px">
                <span style="font-size:9px;text-transform:uppercase;letter-spacing:0.6px;color:#4ade80;font-weight:700">Fix</span>
                <div style="font-size:11px;color:#86efac;margin-top:2px;white-space:pre-wrap">${esc(f.fix)}</div>
            </div>
            ${sqlBadges ? `<div style="margin-top:6px">${sqlBadges}</div>` : ''}
        </div>
    </div>`;
}

function _renderIntelligencePanel(report) {
    const hsCfg = {
        CRITICAL: { color: '#ef4444', border: 'rgba(239,68,68,0.35)', bg: 'rgba(239,68,68,0.07)', label: 'CRITICAL' },
        WARNING:  { color: '#f59e0b', border: 'rgba(245,158,11,0.35)', bg: 'rgba(245,158,11,0.07)', label: 'WARNING'  },
        OK:       { color: '#4ade80', border: 'rgba(74,222,128,0.35)', bg: 'rgba(74,222,128,0.07)', label: 'HEALTHY'  },
    };
    const hs = hsCfg[report.overall_health] || hsCfg.OK;
    const findings = report.findings || [];
    const critCount = findings.filter(f => f.severity === 'CRITICAL').length;
    const warnCount = findings.filter(f => f.severity === 'WARNING').length;
    const corrNotes = report.correlation_notes || [];
    const trendNotes = report.trend_notes || [];

    const findingCards = findings.slice(0, 8).map((f) => {
        const sevCol = f.severity === 'CRITICAL' ? '#f87171' : f.severity === 'WARNING' ? '#fbbf24' : '#60a5fa';
        const sevBg  = f.severity === 'CRITICAL' ? 'rgba(239,68,68,0.07)' : f.severity === 'WARNING' ? 'rgba(245,158,11,0.07)' : 'rgba(59,130,246,0.05)';
        const sevBdr = f.severity === 'CRITICAL' ? 'rgba(239,68,68,0.22)' : f.severity === 'WARNING' ? 'rgba(245,158,11,0.2)' : 'rgba(59,130,246,0.15)';
        const trendBadge = f.trend === 'WORSENING' ? `<span style="font-size:7px;background:rgba(239,68,68,0.15);color:#f87171;padding:1px 6px;border-radius:3px">▲ WORSENING</span>` :
                           f.trend === 'IMPROVING' ? `<span style="font-size:7px;background:rgba(74,222,128,0.15);color:#4ade80;padding:1px 6px;border-radius:3px">▼ IMPROVING</span>` : '';
        const zBadge = (f.anomaly_z||0) > 1.5 ? `<span style="font-size:7px;background:rgba(168,85,247,0.15);color:#c084fc;padding:1px 6px;border-radius:3px">Z=${(f.anomaly_z||0).toFixed(1)}</span>` : '';
        const evidLines = (f.evidence || []).slice(0, 3).map(ev => `<div style="font-size:9px;color:#64748b;padding:1px 0 1px 6px;border-left:2px solid #1e3a5f">• ${esc(ev)}</div>`).join('');
        const causalLine = (f.causal_chain || []).length ? `<div style="font-size:8px;color:#475569;margin-top:3px">↳ Causal chain: ${esc(f.causal_chain.join(' ? '))}</div>` : '';
        const oracleRef = f.oracle_ref ? `<div style="margin-top:5px;font-size:8px;color:#6366f1;border-top:1px solid rgba(99,102,241,0.1);padding-top:4px">${esc(f.oracle_ref)}</div>` : '';
        const sqlBadges = (f.sql_ids || []).map(id => `<code style="background:rgba(99,102,241,0.2);color:#a5b4fc;font-size:8px;padding:1px 5px;border-radius:3px">${esc(id)}</code>`).join(' ');
        return `<div style="background:${sevBg};border:1px solid ${sevBdr};border-radius:8px;padding:10px 14px;margin-bottom:7px">
            <div style="display:flex;align-items:center;gap:6px;flex-wrap:wrap;margin-bottom:5px">
                <span style="font-size:8px;font-weight:800;color:${sevCol};background:${sevCol}20;padding:1px 7px;border-radius:3px;text-transform:uppercase">${esc(f.severity)}</span>
                <span style="font-size:11px;font-weight:700;color:#e2e8f0;flex:1">${esc(f.title)}</span>
                ${trendBadge}${zBadge}
                <span style="font-size:8px;color:#475569">impact ${Math.round(f.impact_score||0)}/100</span>
            </div>
            <div style="font-size:10px;color:#94a3b8;font-style:italic;margin-bottom:6px">${esc(f.headline||'')}</div>
            ${evidLines ? `<div style="margin-bottom:6px">${evidLines}</div>` : ''}
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px">
                <div style="background:rgba(15,23,42,0.6);border-radius:5px;padding:7px 10px">
                    <div style="font-size:7px;color:#6366f1;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:3px">Root Cause</div>
                    <div style="font-size:10px;color:#94a3b8;line-height:1.4">${esc(f.root_cause||'')}</div>
                    ${causalLine}
                </div>
                <div style="background:rgba(16,185,129,0.07);border:1px solid rgba(16,185,129,0.18);border-radius:5px;padding:7px 10px">
                    <div style="font-size:7px;color:#4ade80;font-weight:700;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:3px">Fix</div>
                    <div style="font-size:10px;color:#86efac;line-height:1.4">${esc(f.fix||'')}</div>
                    ${sqlBadges ? `<div style="margin-top:4px">${sqlBadges}</div>` : ''}
                </div>
            </div>
            ${oracleRef}
        </div>`;
    }).join('');

    const corrSection = corrNotes.length ? `
        <div style="border-top:1px solid rgba(99,102,241,0.12);padding-top:10px;margin-top:10px">
            <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.8px;color:#6366f1;font-weight:700;margin-bottom:6px">CORRELATION ANALYSIS — Pearson / Cross-Metric</div>
            ${corrNotes.map(n => `<div style="font-size:10px;color:#94a3b8;padding:3px 0 3px 8px;border-left:2px solid rgba(99,102,241,0.3);margin-bottom:3px">${esc(n)}</div>`).join('')}
        </div>` : '';

    const trendSection = trendNotes.length ? `
        <div style="border-top:1px solid rgba(74,222,128,0.12);padding-top:10px;margin-top:10px">
            <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.8px;color:#4ade80;font-weight:700;margin-bottom:6px">TREND ANALYSIS — Linear Regression / IQR</div>
            ${trendNotes.map(n => `<div style="font-size:10px;color:#94a3b8;padding:3px 0 3px 8px;border-left:2px solid rgba(74,222,128,0.3);margin-bottom:3px">${esc(n)}</div>`).join('')}
        </div>` : '';

    return `<div id="intelligence-panel" style="margin:14px 0 0;background:linear-gradient(135deg,rgba(10,16,40,0.99),rgba(15,23,42,0.96));border:1px solid ${hs.border};border-radius:12px;overflow:hidden">

        <!-- Header -->
        <div style="display:flex;align-items:center;gap:12px;padding:12px 18px;background:${hs.bg};border-bottom:1px solid ${hs.border}">
            <div style="width:34px;height:34px;border-radius:50%;background:linear-gradient(135deg,#6366f1,#8b5cf6);display:flex;align-items:center;justify-content:center;font-size:16px;flex-shrink:0"><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="#ffffff" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M9 3H5a2 2 0 00-2 2v4m6-6h10a2 2 0 012 2v4M9 3v18m0 0h10a2 2 0 002-2V9M9 21H5a2 2 0 01-2-2V9m0 0h18"/></svg></div>
            <div style="flex:1;min-width:0">
                <div style="font-size:11px;font-weight:800;color:#a5b4fc;text-transform:uppercase;letter-spacing:1px">AWR Intelligence Engine</div>
                <div style="font-size:9px;color:#6366f1;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${esc(report.db_name)} · ${esc(report.snap_range)} · ${esc(report.analysis_model)}</div>
            </div>
            <div style="display:flex;flex-direction:column;align-items:flex-end;gap:2px;flex-shrink:0">
                <span style="font-size:13px;font-weight:800;color:${hs.color}">${hs.label}</span>
                <div style="font-size:8px;color:#475569">${critCount} critical · ${warnCount} warning · ${report.pipeline_ms||0}ms</div>
            </div>
        </div>

        <!-- Verdict -->
        <div style="padding:10px 18px 9px;background:rgba(99,102,241,0.05);border-bottom:1px solid rgba(99,102,241,0.1)">
            <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.8px;color:#6366f1;font-weight:700;margin-bottom:3px">FINAL VERDICT — PRIMARY BOTTLENECK: ${esc((report.primary_bottleneck||'').toUpperCase())}</div>
            <div style="font-size:11px;color:#cbd5e1;line-height:1.6">${esc(report.verdict)}</div>
        </div>

        <!-- Confirmed issues + actions -->
        <div style="padding:12px 18px 14px">
            <div style="font-size:8px;text-transform:uppercase;letter-spacing:0.8px;color:#475569;font-weight:700;margin-bottom:9px">CONFIRMED ROOT CAUSES &amp; ACTION PLAN (${findings.length} findings · ranked by severity × impact)</div>
            ${findingCards || '<div style="color:#4ade80;font-size:11px;text-align:center;padding:16px">No significant issues detected.</div>'}
            ${corrSection}
            ${trendSection}
        </div>

        <div style="padding:4px 18px 8px;font-size:8px;color:#1e3a5f;border-top:1px solid rgba(15,23,42,0.9);text-align:right">
            Algorithms: Z-score · IQR (Tukey) · CUSUM (Page) · Pearson r · OLS Regression · BFS/DFS Causal DAG · Oracle KB — ${report.pipeline_ms||0}ms pipeline
        </div>
    </div>`;
}

// ----------------------------------------------------------------------------
// PEEngine — Rule Engine + Template System for the PE Narrative
// Decision-tree style ruleset that turns the AWRContext into a structured
// evidence model, evaluates against ordered rules, and produces:
//   • RCA Confidence Scorecard (severity / confidence / session-risk / projected recovery)
//   • Action Priority Queue   (impact × effort × time, ranked, copy-pasteable SQL)
//   • Fix Impact Simulator    (post-fix AAS projection on a CPU-saturation gauge)
// All three views read from the same evidence model + rule output, so they
// stay coherent. No backend dependency — runs entirely in the browser.
// ----------------------------------------------------------------------------
window.PEEngine = (function () {
    const $f = (n, d) => (n == null || isNaN(+n)) ? (d || 0) : (+n);
    const _esc = s => String(s == null ? '' : s).replace(/[&<>"']/g, c => ({ "&":"&amp;","<":"&lt;",">":"&gt;",'"':"&quot;","'":"&#39;" }[c]));
    const _fmtTime = m => !m ? 'ongoing' : (m < 60 ? `~${m} min` : (m % 60 ? `~${Math.floor(m/60)}h ${m%60}m` : `~${Math.floor(m/60)}h`));

    // -- EVIDENCE EXTRACTOR — single source of truth read from AWRContext ----
    function extract(ctx, report) {
        const lp1 = ctx.loadProfile?.good || {};
        const lp2 = ctx.loadProfile?.bad  || {};
        const ev1 = ctx.waitEvents?.good || [];
        const ev2 = ctx.waitEvents?.bad  || [];
        const ie1 = ctx.instanceEfficiency?.good || {};
        const ie2 = ctx.instanceEfficiency?.bad  || {};

        // sqlAttribution is a flat array in the canonical AWRContext shape
        // built by buildAWRContext(); some legacy paths nest it under .top10
        // / .bad / .good — handle all three without a hard dependency on
        // either layout.
        const _sa = ctx.sqlAttribution;
        const top = (Array.isArray(_sa) ? _sa
                  : (_sa && (_sa.top10 || _sa.bad || _sa.good)) || [])
                  .filter(s => s);
        const dom = top[0] || {};
        // Pull the SQL row from raw stats so we can detect DML-vs-SELECT
        // (Concurrent INSERT / UPDATE / DELETE patterns are the canonical
        // driver for free-buffer-waits + FB-enq + buffer-busy storms).
        const _sqlStatsBad = (ctx._raw?.bad || {}).sql_stats || [];
        const _domStat = _sqlStatsBad.find(s => s.sql_id === (dom.id || dom.sql_id)) || _sqlStatsBad[0] || {};
        const _domSqlText = String(_domStat.sql_text || _domStat.sql_text_full || '').trim();
        const _domSqlVerb = (_domSqlText.match(/^\s*(INSERT|UPDATE|DELETE|MERGE|SELECT|WITH|CALL|BEGIN)/i) || [, ''])[1].toUpperCase();
        const _domIsDML  = /^(INSERT|UPDATE|DELETE|MERGE)$/.test(_domSqlVerb);

        const cpus = $f(ctx.meta?.cpu_count || ctx._raw?.s2?.cpus || ctx._raw?.bad?.cpus, 1);
        const aasG = $f(ctx.aas?.good);
        const aasB = $f(ctx.aas?.bad);
        const topW2 = ev2[0] || {};

        // Wait-class aggregation — sum %DB Time per signature pattern.
        const sumPctIf = (events, re) => events.filter(e => re.test((e.wait_class||'') + ' ' + (e.event_name||''))).reduce((s,e) => s + $f(e.pct_db_time), 0);
        const findEv   = (events, re) => events.find(e => re.test(e.event_name || '')) || null;
        const ioPct       = sumPctIf(ev2, /User I\/O|System I\/O|db file|direct path/i);
        const cpuPct      = sumPctIf(ev2, /DB CPU/i);
        const commitPct   = sumPctIf(ev2, /log file sync/i);
        // Buffer-cache write pressure signatures — `free buffer waits` is the
        // canonical signal that DBWR cannot drain dirty buffers fast enough.
        // `buffer busy waits` and the FB (Format Block) enqueue are downstream
        // symptoms that almost always co-occur with the primary signal.
        const freeBufPct  = sumPctIf(ev2, /free buffer waits/i);
        const bufBusyPct  = sumPctIf(ev2, /buffer busy waits/i);
        const fbEnqPct    = sumPctIf(ev2, /enq:\s*FB\s*-\s*contention/i);
        const usEnqPct    = sumPctIf(ev2, /enq:\s*US\s*-\s*contention/i);   // Undo segment expansion
        const txEnqPct    = sumPctIf(ev2, /enq:\s*TX\s*-/i);
        const logBufPct   = sumPctIf(ev2, /log buffer space/i);
        // Segment / serialisation enqueues — each pinpoints a *different* fix.
        //   HW  – High-Water-mark   ? segment can't extend fast enough during
        //                              concurrent INSERT.  Fix: uniform extents,
        //                              pre-allocate, ASSM tuning, partition.
        //   TX-index contention     ? hot index block / branch split.  Fix:
        //                              hash-partition or reverse-key index.
        //   TX-row lock contention  ? application row-lock waits.
        //   TM                      ? DDL / FK / parallel DML lock.
        //   SQ                      ? sequence cache too small.
        const hwEnqPct    = sumPctIf(ev2, /enq:\s*HW\s*-\s*contention/i);
        const txIdxPct    = sumPctIf(ev2, /enq:\s*TX\s*-\s*index contention/i);
        const txRowPct    = sumPctIf(ev2, /enq:\s*TX\s*-\s*row lock/i);
        const txItlPct    = sumPctIf(ev2, /enq:\s*TX\s*-\s*allocate ITL/i);
        const tmEnqPct    = sumPctIf(ev2, /enq:\s*TM\s*-/i);
        const sqEnqPct    = sumPctIf(ev2, /enq:\s*SQ\s*-/i);
        // Library-cache / shared-pool family
        const libCachePct = sumPctIf(ev2, /library cache:|cursor:.*pin\s*S\s*wait\s*on\s*X/i);
        const sharedPoolLatchPct = sumPctIf(ev2, /latch:\s*shared pool|latch:\s*row cache/i);
        // Latch / true CPU-side concurrency — separated from buffer-write symptoms.
        const latchPct    = sumPctIf(ev2, /latch:|cursor:.*pin/i);
        // CPU saturation must be measured against actual host CPU capacity,
        // not against AAS (which includes wait time).  cpuUtilPct = DB CPU
        // seconds / available CPU seconds.
        const cpuUtilPct  = cpus > 0 ? Math.min(100, $f(lp2.db_cpu_s) / cpus * 100) : 0;

        const dbT1 = $f(lp1.db_time_s);
        const dbT2 = $f(lp2.db_time_s);
        const dbTimeDelta = dbT1 > 0 ? ((dbT2 - dbT1) / dbT1 * 100) : (dbT2 > 0 ? 100 : 0);
        const bufferHitDrop = Math.max(0, $f(ie1.buffer_hit_pct || ie1.buffer_cache_hit_pct, 100) - $f(ie2.buffer_hit_pct || ie2.buffer_cache_hit_pct, 100));

        // Workload deltas that distinguish "real concurrency contention" from
        // "DBWR backlog under heavy DML" — when transactions, block changes
        // and physical writes all jump together, the system is write-bound.
        const txnDelta    = $f(lp1.transactions) > 0 ? (($f(lp2.transactions) - $f(lp1.transactions)) / $f(lp1.transactions) * 100) : 0;
        const blockChgDelta = $f(lp1.block_changes) > 0 ? (($f(lp2.block_changes) - $f(lp1.block_changes)) / $f(lp1.block_changes) * 100) : 0;
        const physWriteDelta = $f(lp1.physical_writes) > 0 ? (($f(lp2.physical_writes) - $f(lp1.physical_writes)) / $f(lp1.physical_writes) * 100) : 0;
        const redoDelta   = $f(lp1.redo_size) > 0 ? (($f(lp2.redo_size) - $f(lp1.redo_size)) / $f(lp1.redo_size) * 100) : 0;

        return {
            cpus, aasG, aasB, aasRatio: cpus > 0 ? aasB / cpus : 0,
            cpuUtilPct,
            domSqlId: dom.id || dom.sql_id || null,
            domSqlPct: $f(dom.pctDb || dom.pct_db_time),
            domEpe1: $f(dom.epe1), domEpe2: $f(dom.epe2),
            domIsNew: !!(dom.isNew || dom.is_new),
            domPlanChange: !!(dom.isPlanChg || dom.is_plan_change),
            domIsRegressed: !!(dom.isRegressed || dom.is_regressed),
            domSqlVerb:  _domSqlVerb,
            domIsDML:    _domIsDML,
            domTable:    (Array.isArray(_domStat.tables_referenced) && _domStat.tables_referenced[0]) || _domStat.table_name || '',
            topWaitName: topW2.event_name || '',
            topWaitPct:  $f(topW2.pct_db_time),
            topWaitClass: topW2.wait_class || '',
            ioPct, cpuPct, commitPct,
            // Refined: concPct = TRUE concurrency only (latches + cursor: pins)
            // Buffer-busy + FB-enq are accounted under freeBufPct's rule so we
            // do not double-count them as generic CONCURRENCY contention.
            concPct:     latchPct,
            freeBufPct, bufBusyPct, fbEnqPct, usEnqPct, txEnqPct, logBufPct, latchPct,
            hwEnqPct, txIdxPct, txRowPct, txItlPct, tmEnqPct, sqEnqPct,
            libCachePct, sharedPoolLatchPct,
            txnDelta, blockChgDelta, physWriteDelta, redoDelta,
            dbTimeDelta, dbT1, dbT2, bufferHitDrop,
            isParallel: !!(ctx._raw?.is_parallel || ctx.bottleneck?.bad?.parallel),
            bottleneckType: ctx.bottleneck?.bad?.type || '',
            lblG: ctx.meta?.lbl1 || 'Good',
            lblB: ctx.meta?.lbl2 || 'Bad',
            dbName: ctx.meta?.db_name || (report && report.db_name) || 'database'
        };
    }

    // -- DECISION TREE / RULE SET — ordered, weighted ------------------------
    //
    // Generic guard used by several rules below — when the topmost wait is
    // anything other than DB CPU and absorbs = 40 % of DB Time, while DB CPU
    // itself sits at = 25 %, the dominant SQL becomes a *symptom carrier*
    // rather than a tunable per-statement defect.  The actionable fix is on
    // the wait, not on the SQL.
    const _waitDominated = ev =>
        ev.topWaitName && !/DB\s*CPU/i.test(ev.topWaitName)
        && ev.topWaitPct >= 40 && ev.cpuPct <= 25;

    const RULES = [
        { id: 'PLAN_REGRESSION', label: 'Plan regression on dominant SQL',
          match:   ev => ev.domPlanChange && ev.domSqlPct >= 15,
          weight:  ev => Math.min(1, 0.6 + ev.domSqlPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(85, ev.domSqlPct * 0.9),
              sessionsFreed: ev.aasB * (ev.domSqlPct * 0.9 / 100),
              rationale: `Pinning the prior plan recovers ~${(ev.domSqlPct*0.9).toFixed(1)}% of DB Time consumed by SQL ${ev.domSqlId} after the regression.`
          }) },
        { id: 'NEW_SQL_DEPLOY', label: 'Untested SQL deployed',
          match:   ev => ev.domIsNew && ev.domSqlPct >= 15,
          weight:  ev => Math.min(1, 0.55 + ev.domSqlPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(75, ev.domSqlPct * 0.75),
              sessionsFreed: ev.aasB * (ev.domSqlPct * 0.75 / 100),
              rationale: `Tuning new SQL ${ev.domSqlId} or rolling back the deploy reclaims most of its ${ev.domSqlPct.toFixed(1)}% DB Time share.`
          }) },

        // -- SEGMENT / SERIALISATION ENQUEUE family ------------------------
        // These rules MUST out-rank SQL_DOMINANT because the SQL touching the
        // segment is a symptom-carrier — tuning the statement does nothing,
        // the segment-level configuration must be fixed.
        { id: 'HW_ENQUEUE_CONTENTION', label: 'Segment HWM extension bottleneck',
          match:   ev => ev.hwEnqPct >= 15,
          weight:  ev => Math.min(1, 0.7 + ev.hwEnqPct/150),
          project: ev => ({
              dbTimeReductionPct: Math.min(85, ev.hwEnqPct * 0.9),
              sessionsFreed: ev.aasB * (ev.hwEnqPct * 0.9 / 100),
              rationale: `enq: HW - contention absorbs ${ev.hwEnqPct.toFixed(1)}% of DB Time${ev.domTable?` on segment hosting ${ev.domTable}`:''}. Concurrent ${ev.domSqlVerb||'INSERT'} sessions are queueing on segment-extension while the holder formats blocks above HWM. Fix on the segment side: pre-allocate extents, switch to uniform LMT extents, raise NEXT/PCTINCREASE, enable parallel space-management, partition the table, or move LOB/IOT to dedicated tablespaces.`
          }) },
        { id: 'TX_INDEX_CONTENTION', label: 'Hot index block / branch-split contention',
          match:   ev => ev.txIdxPct >= 5 || (/index/i.test(ev.topWaitName||'') && ev.topWaitPct >= 10),
          weight:  ev => Math.min(1, 0.6 + (ev.txIdxPct + ev.bufBusyPct/2)/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(70, (ev.txIdxPct + Math.min(ev.bufBusyPct, 10)) * 0.8),
              sessionsFreed: ev.aasB * Math.min(0.5, (ev.txIdxPct/100) * 0.8),
              rationale: `enq: TX - index contention at ${ev.txIdxPct.toFixed(1)}% DB Time indicates concurrent DML on the same index leaf block (right-growing key or branch split). Hash-partition the index, switch to a reverse-key index, or increase the index INITRANS / PCTFREE.`
          }) },
        { id: 'TX_ROW_LOCK_CONTENTION', label: 'Application row-lock contention',
          match:   ev => ev.txRowPct >= 10 || (ev.txEnqPct >= 15 && ev.txIdxPct < 2 && ev.txItlPct < 2),
          weight:  ev => Math.min(1, 0.55 + ev.txEnqPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(70, ev.txEnqPct * 0.7),
              sessionsFreed: ev.aasB * (ev.txEnqPct * 0.7 / 100),
              rationale: `enq: TX - row lock contention (${ev.txRowPct.toFixed(1)}%) — sessions are blocking on application-level row locks. Identify the holder via blocking-tree, review transaction scoping and commit cadence.`
          }) },
        { id: 'UNDO_SEGMENT_EXTENSION', label: 'Undo segment expansion (US-enq)',
          match:   ev => ev.usEnqPct >= 10,
          weight:  ev => Math.min(1, 0.55 + ev.usEnqPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(60, ev.usEnqPct * 0.8),
              sessionsFreed: ev.aasB * (ev.usEnqPct * 0.8 / 100),
              rationale: `enq: US - contention at ${ev.usEnqPct.toFixed(1)}% — undo tablespace cannot expand fast enough. Enlarge UNDO tablespace, raise UNDO_RETENTION, or switch UNDO datafile to autoextend with larger NEXT.`
          }) },
        { id: 'LIBRARY_CACHE_PRESSURE', label: 'Library cache / shared pool contention',
          match:   ev => (ev.libCachePct + ev.sharedPoolLatchPct) >= 10,
          weight:  ev => Math.min(1, 0.5 + (ev.libCachePct + ev.sharedPoolLatchPct)/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(60, (ev.libCachePct + ev.sharedPoolLatchPct) * 0.7),
              sessionsFreed: ev.aasB * ((ev.libCachePct + ev.sharedPoolLatchPct) * 0.7 / 100),
              rationale: `Library cache / shared-pool contention at ${(ev.libCachePct+ev.sharedPoolLatchPct).toFixed(1)}% DB Time. Investigate hard-parse rate, bind-variable usage, and shared_pool_size; eliminate non-sharable SQL.`
          }) },
        { id: 'SQL_DOMINANT', label: 'Single SQL dominant',
          // Stand down when the SQL is a *symptom carrier*: another wait
          // event absorbs the time, the SQL just inherits the share because
          // every execution blocks inside that wait.  The actionable fix is
          // on the wait, not on the statement.
          //   • Buffer-cache write pressure (free_buffer_waits = 15 or 25 %)
          //   • HW / TX-index / TX-row / US enqueue serialisation
          //   • Any wait absorbing = 40 % DB Time while DB CPU = 25 %
          match:   ev => ev.domSqlPct >= 25 && !ev.domPlanChange && !ev.domIsNew
                          && !(ev.freeBufPct >= 15 && ev.domIsDML)
                          && !(ev.freeBufPct >= 25)
                          && !(ev.hwEnqPct >= 15)
                          && !(ev.txIdxPct >= 5)
                          && !(ev.txRowPct >= 10)
                          && !(ev.usEnqPct >= 10)
                          && !_waitDominated(ev),
          weight:  ev => Math.min(1, 0.5 + ev.domSqlPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(60, ev.domSqlPct * 0.6),
              sessionsFreed: ev.aasB * (ev.domSqlPct * 0.6 / 100),
              rationale: `Reducing per-execution cost of SQL ${ev.domSqlId} (${ev.domSqlPct.toFixed(1)}% DB Time) recovers most of its accumulated load.`
          }) },

        // -- BUFFER-CACHE WRITE PRESSURE family ----------------------------
        // Two specialised rules: the combined CONCURRENT_DML_BOTTLENECK fires
        // when the DBWR-backlog signature is paired with a top DML statement
        // (the canonical "concurrent INSERT into a hot table" pattern).
        // BUFFER_CACHE_WRITE_PRESSURE catches the same DBWR backlog when the
        // workload spread is broader and no single DML statement dominates.
        // Both must out-rank CONCURRENCY because buffer-busy / FB-enq / TX-enq
        // observed alongside high free-buffer-waits are downstream symptoms
        // of an overwhelmed DBWR — not independent latch contention.
        { id: 'CONCURRENT_DML_BOTTLENECK', label: 'Concurrent DML overwhelming buffer cache',
          match:   ev => ev.freeBufPct >= 15 && ev.domIsDML && ev.domSqlPct >= 20,
          weight:  ev => Math.min(1, 0.7 + (ev.freeBufPct + ev.domSqlPct/2) / 200),
          project: ev => {
              const reclaim = Math.min(ev.freeBufPct + ev.fbEnqPct + ev.bufBusyPct + ev.commitPct * 0.5, 80);
              return {
                  dbTimeReductionPct: reclaim * 0.7,
                  sessionsFreed: ev.aasB * (reclaim * 0.7 / 100),
                  rationale: `Concurrent ${ev.domSqlVerb} statement ${ev.domSqlId}${ev.domTable?` on ${ev.domTable}`:''} (${ev.domSqlPct.toFixed(1)}% DB Time) is generating dirty buffers faster than DBWR can drain them — driving free buffer waits ${ev.freeBufPct.toFixed(1)}%${ev.fbEnqPct?`, FB-enq ${ev.fbEnqPct.toFixed(1)}%`:''}${ev.bufBusyPct?`, buffer busy ${ev.bufBusyPct.toFixed(1)}%`:''}, and back-pressure on LGWR (log file sync ${ev.commitPct.toFixed(1)}%). Increase db_writer_processes, raise db_cache_size, and consider partitioning or APPEND hint review.`
              };
          } },
        { id: 'BUFFER_CACHE_WRITE_PRESSURE', label: 'DBWR / buffer cache write throughput exhausted',
          match:   ev => ev.freeBufPct >= 15 || (ev.freeBufPct >= 8 && ev.bufBusyPct >= 5),
          weight:  ev => Math.min(1, 0.55 + (ev.freeBufPct + ev.bufBusyPct + ev.fbEnqPct) / 150),
          project: ev => {
              const reclaim = Math.min(ev.freeBufPct + ev.bufBusyPct + ev.fbEnqPct, 70);
              return {
                  dbTimeReductionPct: reclaim * 0.65,
                  sessionsFreed: ev.aasB * (reclaim * 0.65 / 100),
                  rationale: `Free buffer waits dominate (${ev.freeBufPct.toFixed(1)}% DB Time) — DBWR throughput / buffer cache size is the bottleneck. The downstream symptoms${ev.bufBusyPct?` (buffer busy waits ${ev.bufBusyPct.toFixed(1)}%`:''}${ev.fbEnqPct?`${ev.bufBusyPct?', ':' ('}FB-enq ${ev.fbEnqPct.toFixed(1)}%`:''}${(ev.bufBusyPct||ev.fbEnqPct)?')':''} resolve once DBWR catches up. Increase db_writer_processes, raise db_cache_size, or relocate datafiles to faster storage.`
              };
          } },

        { id: 'CPU_SATURATION', label: 'CPU saturation',
          // Real CPU saturation: db_cpu / cpus > 70%.  aasRatio alone over-fires
          // because it counts session-time-on-wait (e.g. free buffer waits)
          // toward an apparent "CPU" pressure that is not actually CPU-bound.
          match:   ev => ev.cpuUtilPct >= 70 && ev.cpuPct >= 30,
          weight:  ev => Math.min(1, 0.5 + ev.cpuUtilPct/200 + ev.cpuPct/200),
          project: ev => {
              const target = Math.max(ev.cpus * 0.7, 1);
              const reducePct = Math.max(0, (ev.aasB - target) / Math.max(ev.aasB, 1) * 100);
              return {
                  dbTimeReductionPct: Math.min(50, reducePct * 0.7),
                  sessionsFreed: Math.max(0, ev.aasB - target),
                  rationale: `DB CPU utilisation is ${ev.cpuUtilPct.toFixed(0)}% of host capacity (${ev.cpus} CPUs). Bringing AAS from ${ev.aasB.toFixed(1)} down to ${target.toFixed(1)} (CPU×0.7) frees ${(ev.aasB-target).toFixed(1)} session-equivalents.`
              };
          } },
        { id: 'IO_PRESSURE', label: 'I/O pressure',
          match:   ev => ev.ioPct >= 30,
          weight:  ev => Math.min(1, 0.4 + ev.ioPct/100),
          project: ev => ({
              dbTimeReductionPct: Math.min(60, ev.ioPct * 0.55),
              sessionsFreed: ev.aasB * (ev.ioPct * 0.55 / 100),
              rationale: `Cutting top-I/O segment hotspots reduces ~${(ev.ioPct*0.55).toFixed(1)}% of DB Time concentrated in I/O waits.`
          }) },
        { id: 'REDO_COMMIT', label: 'Commit / redo storm',
          // Demote when free_buffer_waits dominates — log file sync at >10%
          // alongside free_buffer_waits >= 20% is almost always a *symptom*
          // of LGWR back-pressure caused by the DBWR backlog, not a primary
          // commit-overhead cause.
          match:   ev => ev.commitPct >= 10 && ev.freeBufPct < 20,
          weight:  ev => Math.min(1, 0.4 + ev.commitPct/50),
          project: ev => ({
              dbTimeReductionPct: Math.min(40, ev.commitPct * 0.7),
              sessionsFreed: ev.aasB * (ev.commitPct * 0.7 / 100),
              rationale: `Batching commits drops log file sync from ${ev.commitPct.toFixed(1)}% toward <2% DB Time.`
          }) },
        { id: 'CONCURRENCY', label: 'Concurrency hotspot',
          // True latch / cursor-pin concurrency only.  Buffer-busy + FB-enq
          // are routed to the BUFFER_CACHE_WRITE_PRESSURE family because
          // they almost never appear without a DBWR backlog driving them.
          match:   ev => ev.latchPct >= 8 && ev.freeBufPct < 15,
          weight:  ev => Math.min(1, 0.35 + ev.latchPct/50),
          project: ev => ({
              dbTimeReductionPct: Math.min(30, ev.latchPct * 0.6),
              sessionsFreed: ev.aasB * (ev.latchPct * 0.6 / 100),
              rationale: `Resolving the concurrency hotspot (${ev.latchPct.toFixed(1)}% DB Time on latches/cursors) frees blocked sessions from CPU-side contention.`
          }) },
        { id: 'GENERIC_LOAD_INCREASE', label: 'Generic load increase',
          match:   ev => ev.dbTimeDelta >= 30,
          weight:  ev => Math.min(0.45, 0.2 + ev.dbTimeDelta/300),
          project: ev => ({
              dbTimeReductionPct: 15,
              sessionsFreed: ev.aasB * 0.15,
              rationale: 'Workload throttling and query consolidation typically reclaim 10–20% in mixed-workload spikes.'
          }) }
    ];

    function evaluate(ev) {
        const matches = RULES
            .map(r => r.match(ev) ? { rule: r, weight: r.weight(ev) } : null)
            .filter(Boolean)
            .sort((a, b) => b.weight - a.weight);
        const top = matches[0] || null;
        const projection = top ? top.rule.project(ev) : null;

        // Severity (P-tier)
        let pTier = 'P3', pColor = '#10b981';
        if (ev.dbTimeDelta >= 100 || ev.aasRatio >= 1.5 || ev.domSqlPct >= 50) { pTier = 'P1'; pColor = '#ef4444'; }
        else if (ev.dbTimeDelta >= 50 || ev.aasRatio >= 1.0 || ev.domSqlPct >= 30 || ev.commitPct >= 20 || ev.ioPct >= 50) { pTier = 'P2'; pColor = '#f59e0b'; }

        // Confidence
        const baseConf = Math.round(50 + (top?.weight || 0) * 40);
        const confidence = Math.max(35, Math.min(95, baseConf + Math.min(matches.length * 3, 12)));
        let confLabel = 'MEDIUM', confColor = '#f59e0b';
        if (confidence >= 80) { confLabel = 'HIGH'; confColor = '#10b981'; }
        else if (confidence < 60) { confLabel = 'LOW'; confColor = '#94a3b8'; }

        // Session-risk countdown.  AAS includes wait time, so a high aasRatio
        // does NOT prove CPU saturation — a database can have AAS = 18 × CPUs
        // while DB CPU itself sits at 5 % when sessions are stuck in
        // free-buffer-waits / I/O / locks.  Determining the *true* constraint
        // requires looking at the dominant wait class:
        //   • Pure CPU-bound  : topWait == DB CPU AND cpuUtilPct = 70
        //   • Pure wait-bound : cpuPct (DB CPU's share of DB Time) < 30
        //   • Hybrid          : both — the wait drives the CPU spillover; the
        //                       wait-bound narrative is the actionable one.
        const isCpuTopWait = /DB\s*CPU/i.test(ev.topWaitName || '');
        const cpuBound = isCpuTopWait && ev.cpuUtilPct >= 70 && ev.cpuPct >= 30;
        let sessionRisk = { label: 'STABLE', color: '#10b981',
                            detail: `AAS ${ev.aasB.toFixed(1)} / ${ev.cpus} CPUs · DB CPU ${ev.cpuUtilPct.toFixed(0)}% utilised` };
        if (ev.aasRatio >= 1.5)       sessionRisk = { label: cpuBound ? 'SATURATED NOW' : 'WAIT-SATURATED', color: '#ef4444',
                                                      detail: cpuBound
                                                          ? `Run-queue building — every new session adds CPU delay (${ev.aasRatio.toFixed(2)}× CPU, ${ev.cpuUtilPct.toFixed(0)}% utilised)`
                                                          : `${Math.max(0, ev.aasB-ev.cpus).toFixed(0)} sessions stuck on ${ev.topWaitName||'wait events'} (${ev.topWaitPct?.toFixed?.(1)||'?'}% DB Time) — DB CPU only ${ev.cpuPct.toFixed(1)}% of DB Time` };
        else if (ev.aasRatio >= 1.0)  sessionRisk = { label: cpuBound ? 'CPU-BOUND' : 'WAIT-BOUND', color: '#ef4444',
                                                      detail: cpuBound
                                                          ? `At capacity — ${(ev.aasB-ev.cpus).toFixed(1)} sessions queueing for CPU`
                                                          : `${(ev.aasB-ev.cpus).toFixed(1)} sessions queued on ${ev.topWaitName||'waits'} — DB CPU only ${ev.cpuPct.toFixed(1)}% of DB Time` };
        else if (ev.aasRatio >= 0.85) sessionRisk = { label: '< 30 min HEADROOM', color: '#f59e0b',
                                                      detail: `Approaching capacity (${(ev.aasRatio*100).toFixed(0)}% of CPU envelope)` };
        else if (ev.aasRatio >= 0.7)  sessionRisk = { label: 'WARMING',       color: '#fbbf24',
                                                      detail: `Elevated load (${(ev.aasRatio*100).toFixed(0)}% of CPU envelope)` };

        return { matches, top, projection, pTier, pColor, confidence, confLabel, confColor, sessionRisk };
    }

    // -- ACTION PRIORITY QUEUE — decorate existing actions[] with metadata --
    function decorateActions(actions, ev, evaln) {
        const _classify = (a) => {
            const t = (a.title || '').toLowerCase();
            if (/pin|spm|baseline plan|load_plans/.test(t))               return { impact:'HIGH',    effort:'LOW',  timeMin:15,  dot:'#10b981' };
            if (/gather|refresh stat|gather_table_stats/.test(t))         return { impact:'HIGH',    effort:'LOW',  timeMin:15,  dot:'#10b981' };
            if (/rebuild index/.test(t))                                  return { impact:'MED',     effort:'MED',  timeMin:45,  dot:'#f59e0b' };
            if (/tune dominant|tune.*sql|tune top|cpu sql/.test(t))       return { impact:'HIGH',    effort:'HIGH', timeMin:120, dot:'#f97316' };
            if (/db_cache_size|sga|pga|increase.*cache|memory/.test(t))   return { impact:'MED',     effort:'HIGH', timeMin:60,  dot:'#f59e0b' };
            if (/allocate extent|pre-allocate|uniform.*extent|hwm/.test(t)) return { impact:'HIGH',   effort:'LOW',  timeMin:10,  dot:'#10b981' };
            if (/hash-partition|reverse-key|initrans/.test(t))            return { impact:'HIGH',    effort:'MED',  timeMin:60,  dot:'#10b981' };
            if (/holder.*blocker|blocking.session|blocking_session/.test(t)) return { impact:'TRIAGE', effort:'LOW',  timeMin:10,  dot:'#06b6d4' };
            if (/undo.*tablespace|undo_retention/.test(t))                return { impact:'HIGH',    effort:'MED',  timeMin:30,  dot:'#10b981' };
            if (/cpu consumer/.test(t))                                     return { impact:'HIGH',    effort:'LOW',  timeMin:15,  dot:'#ef4444' };
            if (/identify|review|attribut|ash analysis/.test(t))          return { impact:'TRIAGE',  effort:'LOW',  timeMin:10,  dot:'#06b6d4' };
            if (/track|monitor|trend/.test(t))                            return { impact:'MONITOR', effort:'LOW',  timeMin:0,   dot:'#6366f1' };
            if (/batch|reduce commit|forall/.test(t))                     return { impact:'HIGH',    effort:'HIGH', timeMin:240, dot:'#f97316' };
            if (/throttl|reduce concur|schedule/.test(t))                 return { impact:'MED',     effort:'MED',  timeMin:60,  dot:'#f59e0b' };
            if (/storage|relocate|tier|san|disk/.test(t))                 return { impact:'HIGH',    effort:'HIGH', timeMin:480, dot:'#f97316' };
            if (/index|hint/.test(t))                                     return { impact:'MED',     effort:'MED',  timeMin:30,  dot:'#f59e0b' };
            return { impact:'MED', effort:'MED', timeMin:30, dot:'#f59e0b' };
        };
        // PE context enrichment — why this action, what to look for, conclusive path
        const _peContext = (a) => {
            const t = (a.title || '').toLowerCase();
            const p = (a.prio  || '').toUpperCase();
            // SPM / Plan Management
            if (/pin|spm|baseline plan|load_plans/.test(t)) return {
                rcaAlignment: 'RCA verdict identified an execution plan change — the plan hash shifted between baseline and problem windows, causing per-execution cost to multiply. SPM is Oracle\'s official mechanism to lock a known-good plan without touching application code.',
                whatToLookFor: 'After loading: verify DBA_SQL_PLAN_BASELINES shows ACCEPTED=YES, ENABLED=YES for the target sql_id. Run DBMS_XPLAN.DISPLAY_SQL_PLAN_BASELINE to confirm the pinned plan matches the baseline hash.',
                conclusiveAction: 'If plan loads successfully → monitor next AWR period for DB Time% to return to baseline. If DBMS_SPM returns 0 plans loaded → baseline snapshot may have been purged; use DBMS_SPM.LOAD_PLANS_FROM_CURSOR_CACHE as fallback.'
            };
            // Statistics
            if (/gather|refresh stat|gather_table_stats/.test(t)) return {
                rcaAlignment: 'Physical reads increased or plan regression detected without a clean plan-hash change — stale CBO statistics are the most common silent trigger. When num_rows in DBA_TAB_STATISTICS diverges from actual table volume by >10%, the optimizer picks the wrong access path.',
                whatToLookFor: 'Check DBA_TAB_STATISTICS: stale_stats=YES or last_analyzed > 7 days before the problem window. Compare num_rows against COUNT(*). For join predicates, verify histograms exist on filter columns (NUM_DISTINCT > 1 in DBA_TAB_COL_STATISTICS).',
                conclusiveAction: 'If stale_stats=YES → gather immediately (no_invalidate=>FALSE forces instant cursor re-parse). If stats are current → statistics are not the issue; escalate to clustering_factor or access-path investigation.'
            };
            // HWM / Extent pre-allocation
            if (/allocate extent|pre-allocate|uniform.*extent|hwm/.test(t)) return {
                rcaAlignment: 'enq: HW - contention is the RCA verdict root cause. This wait fires when sessions queue to format blocks above the segment\'s high-water mark. Pre-allocating extents moves the HWM ahead of the workload, eliminating the serialisation point immediately.',
                whatToLookFor: 'Run DBA_SEGMENTS after ALLOCATE EXTENT — confirm EXTENTS increased and BYTES grew. Verify no ORA-01652 (temp space) or ORA-01653 (table extend) errors. Check ASH: enq: HW wait count should drop to near-zero within one AWR interval after the fix.',
                conclusiveAction: 'If HW waits drop in next AWR → fix confirmed. If HW waits persist → the NEXT extent being allocated is still too small (AUTOALLOCATE giving 64K extents); switch tablespace to UNIFORM SIZE 64M. Long-term: partition the table so no single partition absorbs all inserts.'
            };
            // Index contention
            if (/hash-partition|reverse-key|initrans/.test(t)) return {
                rcaAlignment: 'enq: TX - index contention means concurrent DML sessions are queuing on the same index leaf block — Oracle\'s TX lock at block level serialises every session that needs to modify that block. Redistributing inserts across leaves eliminates the single-block bottleneck.',
                whatToLookFor: 'After rebuild: query V$SEGMENT_STATISTICS WHERE statistic_name=\'buffer busy waits\' — the hot index should show near-zero buffer_busy after the structural change. Confirm in next AWR: enq:TX-index contention drops from its current DB Time%.'
                ,conclusiveAction: 'If buffer busy waits on the index drop → contention eliminated. If still high → a second hot index exists; re-run the ASH query for current_obj# to identify the remaining contender.'
            };
            // Blocking session / row lock
            if (/holder.*blocker|blocking.session|blocking_session/.test(t)) return {
                rcaAlignment: 'enq: TX - row lock contention is an application-level issue — one session holds a row lock for an extended time while others queue. The blocker identification query uses ASH\'s blocking_session column to find which session held the lock during the problem window.',
                whatToLookFor: 'If blocking_session is consistently the same SID across multiple ASH samples → single long-running transaction. If many different blockers → pattern is short-lived locks at high frequency (row-by-row DML without proper batching).',
                conclusiveAction: 'Single long-running blocker → audit that session\'s transaction boundary and commit frequency; likely a missing COMMIT in a loop. Many short blockers → application must batch DML into set operations or use SELECT FOR UPDATE SKIP LOCKED / NOWAIT for concurrent access patterns.'
            };
            // UNDO
            if (/undo.*tablespace|undo_retention/.test(t)) return {
                rcaAlignment: 'enq: US - contention fires when the UNDO tablespace cannot allocate or extend fast enough. Every active transaction needs undo space to support read-consistency; when the pool is exhausted, new transactions serialise on US enqueue.',
                whatToLookFor: 'Query V$UNDOSTAT: check UNEXPIREDSTOLEN > 0 (Oracle is stealing unexpired undo to service new transactions — UNDO_RETENTION is being violated). Check DBA_DATA_FILES for the undo tablespace: AUTOEXTENSIBLE=YES and MAXBYTES not hit.',
                conclusiveAction: 'If UNEXPIREDSTOLEN > 0 → tablespace is actively too small; add a datafile immediately. If AUTOEXTENSIBLE=NO → enable autoextend. If AUTOEXTENSIBLE=YES but still failing → MAXSIZE is capped; increase it. Set UNDO_RETENTION = duration_of_longest_query_in_seconds.'
            };
            // SQL tuning advisor / plan display
            if (/display_awr|xplan|tuning.*task|sqltune/.test(t)) return {
                rcaAlignment: 'The dominant SQL is consuming a disproportionate share of DB Time. Before any fix, the execution plan must be understood — specifically which plan step has the worst cost and whether the optimizer\'s cardinality estimates match actual row counts.',
                whatToLookFor: 'In DBMS_XPLAN output: look for (1) TABLE ACCESS FULL on a large table, (2) E-Rows vs A-Rows diverging by 10×+, (3) nested-loop joins where the inner loop is probed millions of times, (4) missing predicates (\'filter\' predicates that are not \'access\' predicates on an index).',
                conclusiveAction: 'If FTS on a large table → evaluate adding a covering index on filter+select columns. If E-Rows << A-Rows → gather stats with histograms (SKEWONLY). If nested-loop with high inner-loop count → consider HASH JOIN hint or join order change. Always pin the fix via SPM before deploying to production.'
            };
            // CPU / hard parse
            if (/hard parse|cursor_sharing|literal sql|bind variable/.test(t)) return {
                rcaAlignment: 'Hard parse rate > 100/s in the Load Profile confirms bind variable bypass — the application submits unique SQL text per invocation, forcing Oracle to recompile every statement through the full CBO evaluation pipeline instead of reusing the cached plan.',
                whatToLookFor: 'Query V$SQL WHERE executions = 1 — high count of single-execution statements with identical structure but different literal values confirms missing bind variables. Check MODULE column to identify the offending application layer.',
                conclusiveAction: 'Immediate (test first): ALTER SYSTEM SET cursor_sharing=FORCE SCOPE=MEMORY — converts literals to system-generated binds. Permanent: instrument application to use bind variables (:p1, :p2). Remove cursor_sharing=FORCE after code fix is deployed.'
            };
            // Physical I/O segments
            if (/segment.*hotspot|physical.*read|dba_hist_seg|seg_stat/.test(t)) return {
                rcaAlignment: 'Physical I/O dominates DB Time. The segment hotspot query identifies which tables or indexes are generating the most disk reads — this is Oracle\'s definitive method for tracing I/O pressure to the specific object before deciding whether the fix is an index, a cache sizing change, or a storage tier move.',
                whatToLookFor: 'Top segment by physical_reads — if it\'s a TABLE with no index on the filter predicate → add index. If it\'s an INDEX that\'s already selective → check avg_read_ms (>20ms = storage latency issue). If the object is a PARTITION → check partition pruning in the execution plan.',
                conclusiveAction: 'High reads on un-indexed table → add covering index. High reads on already-indexed object + avg_read_ms > 20ms → storage tier issue, escalate to storage team. High reads on indexed object + avg_read_ms < 10ms → excessive read volume; fix access path in the SQL.'
            };
            // Commit / LGWR
            if (/commit|lgwr|redo log|log file sync/.test(t)) return {
                rcaAlignment: 'log file sync is the RCA verdict root cause — every COMMIT forces LGWR to flush redo from the log buffer to the online redo log file before the session proceeds. The application\'s commit frequency is exceeding what LGWR can service, creating a synchronous I/O queue.',
                whatToLookFor: 'Average log file sync wait time: > 20ms = storage too slow (move redo to SSD). < 10ms = commit frequency too high (application fix needed). Query V$SYSMETRIC for User Commits Per Sec — baseline vs problem period shows how many more commits/sec the problem period generates.',
                conclusiveAction: 'avg_wait > 20ms → move redo logs to fastest available storage tier (dedicated SSD, separate from data files). avg_wait < 10ms → batch commits in the application: target 1 COMMIT per 1,000–10,000 rows. Consider INSERT /*+ APPEND NOLOGGING */ for bulk loads where recoverability allows.'
            };
            // Monitor / track
            if (/track|monitor|trend/.test(t)) return {
                rcaAlignment: 'The secondary wait event identified in the RCA verdict warrants post-fix surveillance. After resolving the primary bottleneck, secondary waits sometimes escalate as the workload redistributes — this query establishes the trend baseline.',
                whatToLookFor: 'Plot wait_secs_fg over snap_id. A flat or declining trend confirms the primary fix also relieved this secondary risk. A rising trend after the primary fix means this wait was partially masked and is now emerging as the new bottleneck.',
                conclusiveAction: 'Stable or declining → no further action, continue monitoring. Rising > 5% DB Time → re-run RCA comparison for the new period; this wait is now the primary bottleneck requiring its own diagnosis.'
            };
            // CPU saturation — top consumers
            if (/cpu consumer/.test(t)) return {
                rcaAlignment: 'RCA verdict is CPU saturation \u2014 AAS exceeds available CPU cores with DB CPU dominating DB Time. No single SQL is the root cause; the bottleneck is aggregate CPU pressure across concurrent sessions. This combined module+SQL query pinpoints exactly where CPU time is spent so you can act on the right target.',
                whatToLookFor: 'If a single module (DBMS_SCHEDULER, batch application) accounts for >50% CPU samples \u2192 schedule off-peak to reduce concurrent pressure. If CPU is spread across OLTP modules \u2192 target top 3 SQL IDs for plan analysis via DBMS_XPLAN.DISPLAY_AWR. NULL module = direct connections consuming CPU.',
                conclusiveAction: 'Batch-dominant \u2192 reschedule to off-peak and re-run AWR comparison to validate. OLTP-dominant \u2192 tune top SQL (target FTS\u2192index, nested-loop\u2192hash join, excessive buffer gets). No tunable inefficiency \u2192 CPU capacity is the constraint; add cores or RAC node.'
            };
            // ASH module attribution
            if (/module|action|attribut|originating/.test(t)) return {
                rcaAlignment: 'The dominant SQL appeared in the problem window without baseline history. Before tuning, the originating module must be identified — application module attribution determines whether this is a new deployment, a triggered batch, or a runaway query that bypassed query review.',
                whatToLookFor: 'High sample count for a BATCH or SCHEDULER module → this SQL is part of a batch job that should run off-peak. High count for an OLTP module → the SQL is on the critical user path and must be tuned for sub-second response. NULL module → direct connection, likely DBA or migration script.',
                conclusiveAction: 'Batch/scheduler module → co-ordinate with application team to move off-peak or add resource manager plan. OLTP module → tune immediately (plan display, statistics refresh, index evaluation). Direct connection → investigate who ran it and block if unauthorised.'
            };
            // Default
            return {
                rcaAlignment: 'This action is ranked based on the RCA verdict primary bottleneck category and evidence strength from AWR data.',
                whatToLookFor: 'Compare the metric values returned against the Oracle 19c thresholds noted in the Action row above. Any value outside the acceptable range confirms the diagnosis.',
                conclusiveAction: 'If results confirm the root cause → execute the recommended fix and re-run AWR comparison after one full workload cycle to validate DB Time reduction.'
            };
        };
        const impactRank  = { HIGH:3, MED:2, TRIAGE:2, LOW:1, MONITOR:0 };
        const effortPenalty = { LOW:0, MED:1, HIGH:2 };
        return actions
            .map(a => Object.assign({}, a, _classify(a), _peContext(a)))
            .map(a => Object.assign(a, { _rank: impactRank[a.impact] * 10 - effortPenalty[a.effort] }))
            .sort((a, b) => b._rank - a._rank);
    }

    // -- RENDERERS ----------------------------------------------------------
    function renderScorecard(ev, evaln) {
        const projDb   = evaln.projection ? evaln.projection.dbTimeReductionPct.toFixed(1) : '–';
        const projSess = evaln.projection ? Math.max(0, evaln.projection.sessionsFreed).toFixed(1) : '–';
        const tile = (lbl, val, sub, col) =>
            `<div style="flex:1;min-width:180px;padding:10px 14px;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.18);border-left:3px solid ${col};border-radius:6px"><div style="font-size:9px;color:#94a3b8;font-weight:700;text-transform:uppercase;letter-spacing:0.6px">${_esc(lbl)}</div><div style="font-size:18px;font-weight:900;color:${col};margin-top:3px;line-height:1.1">${val}</div><div style="font-size:9.5px;color:#64748b;margin-top:2px;line-height:1.4">${sub}</div></div>`;
        return `
<div style="margin-bottom:14px;padding:12px;background:linear-gradient(135deg,rgba(8,12,28,0.95),rgba(15,23,42,0.85));border:1px solid rgba(99,102,241,0.25);border-radius:10px">
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
        <div style="width:8px;height:8px;border-radius:50%;background:${evaln.pColor};box-shadow:0 0 8px ${evaln.pColor}"></div>
        <span style="font-size:10.5px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.7px">RCA Confidence Scorecard</span>
        <span style="font-size:9px;color:#64748b;margin-left:auto">${_esc(ev.dbName)} · ${_esc(ev.lblG)} → ${_esc(ev.lblB)}${evaln.top?` · top rule <b style="color:#a5b4fc">${_esc(evaln.top.rule.id)}</b>`:''}</span>
    </div>
    <div style="display:flex;gap:10px;flex-wrap:wrap">
        ${tile('Severity',   evaln.pTier, ev.dbTimeDelta>=0?`DB Time +${ev.dbTimeDelta.toFixed(0)}% vs ${_esc(ev.lblG)}`:`DB Time ${ev.dbTimeDelta.toFixed(0)}%`, evaln.pColor)}
        ${tile('Confidence', evaln.confidence + '%', evaln.confLabel + ' · ' + evaln.matches.length + ' rule' + (evaln.matches.length !== 1 ? 's' : '') + ' matched', evaln.confColor)}
        ${tile('Session Risk', evaln.sessionRisk.label, evaln.sessionRisk.detail, evaln.sessionRisk.color)}
        ${tile('Projected Recovery', '-' + projDb + '%', '~' + projSess + ' sessions freed if fix applied', '#34d399')}
    </div>
</div>`;
    }

    function renderImpactSimulator(ev, evaln) {
        if (!evaln.projection) {
            // Graceful placeholder — no rule fired with sufficient confidence.
            // Common when the workload delta is mild or the dominant cause is
            // outside the rule library. Shows the current AAS vs CPU envelope
            // so the panel still anchors the user visually on the RCA tab.
            const aasNow = ev.aasB, danger = ev.cpus, safe = Math.max(ev.cpus * 0.7, 0.1);
            const maxScale = Math.max(aasNow * 1.1, danger * 1.3, 1);
            const pct = v => Math.min(100, Math.max(0, v / maxScale * 100));
            return `
<div style="margin-top:14px;padding:14px 18px;background:linear-gradient(135deg,rgba(15,23,42,0.85),rgba(8,12,28,0.7));border:1px solid rgba(99,102,241,0.2);border-left:3px solid #6366f1;border-radius:8px">
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(99,102,241,0.15)">
        <span style="display:inline-flex;align-items:center"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065zM15 12a3 3 0 11-6 0 3 3 0 016 0z"/></svg></span>
        <span style="font-size:12.5px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.8px">Fix Impact Simulator</span>
        <span style="font-size:9px;color:#64748b;margin-left:auto">No high-confidence rule matched · showing current load envelope</span>
    </div>
    <div style="font-size:11.5px;color:#cbd5e1;line-height:1.65;margin-bottom:12px">
        The rule engine did not find a dominant cause with high confidence in this workload. Likely reasons: mild delta vs baseline, or a cause outside the current rule library (multi-tenant noise, infra event, application change). The chart below anchors the current AAS against the CPU envelope so you can still gauge headroom.
    </div>
    <div style="position:relative;height:46px;margin:6px 4px;padding-top:8px">
        <div style="position:relative;height:14px;background:rgba(2,6,23,0.7);border-radius:7px;overflow:hidden;border:1px solid rgba(99,102,241,0.15)">
            <div style="position:absolute;left:0;top:0;height:100%;width:${pct(safe).toFixed(1)}%;background:linear-gradient(90deg,rgba(16,185,129,0.45),rgba(16,185,129,0.15))"></div>
            <div style="position:absolute;left:${pct(safe).toFixed(1)}%;top:0;height:100%;width:${(pct(danger)-pct(safe)).toFixed(1)}%;background:linear-gradient(90deg,rgba(245,158,11,0.4),rgba(245,158,11,0.2))"></div>
            <div style="position:absolute;left:${pct(danger).toFixed(1)}%;top:0;height:100%;width:${(100-pct(danger)).toFixed(1)}%;background:linear-gradient(90deg,rgba(239,68,68,0.45),rgba(239,68,68,0.2))"></div>
            <div style="position:absolute;left:${pct(aasNow).toFixed(1)}%;top:-3px;width:3px;height:20px;background:#a5b4fc;box-shadow:0 0 6px #a5b4fc" title="Now"></div>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:9px;color:#64748b;margin-top:5px;font-weight:700">
            <span style="color:#10b981">Safe ${safe.toFixed(1)}</span>
            <span style="color:#a5b4fc">Now AAS ${aasNow.toFixed(1)}</span>
            <span style="color:#f59e0b">CPU ${danger}</span>
        </div>
    </div>
</div>`;
        }
        const p = evaln.projection;
        const aasNow   = ev.aasB;
        const aasAfter = Math.max(0, aasNow * (1 - p.dbTimeReductionPct / 100));
        const safe     = Math.max(ev.cpus * 0.7, 0.1);
        const danger   = ev.cpus;
        const maxScale = Math.max(aasNow * 1.1, danger * 1.3, 1);
        const pct = v => Math.min(100, Math.max(0, v / maxScale * 100));
        const mark = (v, color, label, top) =>
            `<div style="position:absolute;left:${pct(v).toFixed(1)}%;top:${top};transform:translateX(-50%);font-size:9px;color:${color};white-space:nowrap;font-weight:700"><div style="width:1px;height:6px;background:${color};margin:0 auto"></div>${_esc(label)}</div>`;
        return `
<div style="margin-top:14px;padding:14px 18px;background:linear-gradient(135deg,rgba(15,23,42,0.85),rgba(8,12,28,0.7));border:1px solid rgba(52,211,153,0.25);border-left:3px solid #10b981;border-radius:8px">
    <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(52,211,153,0.15)">
        <span style="display:inline-flex;align-items:center"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065zM15 12a3 3 0 11-6 0 3 3 0 016 0z"/></svg></span>
        <span style="font-size:12.5px;font-weight:900;color:#34d399;text-transform:uppercase;letter-spacing:0.8px">Fix Impact Simulator — Projected Post-Fix State</span>
        <span style="font-size:9px;color:#64748b;margin-left:auto">Rule <b style="color:#a5b4fc">${_esc(evaln.top.rule.id)}</b> · weight ${(evaln.top.weight*100).toFixed(0)}%</span>
    </div>
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:14px">
        <div style="padding:9px 12px;background:rgba(2,6,23,0.5);border-radius:6px"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;font-weight:700">DB Time Reduction</div><div style="font-size:22px;font-weight:900;color:#34d399;margin-top:2px">-${p.dbTimeReductionPct.toFixed(1)}%</div></div>
        <div style="padding:9px 12px;background:rgba(2,6,23,0.5);border-radius:6px"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;font-weight:700">AAS After Fix</div><div style="font-size:22px;font-weight:900;color:#a5b4fc;margin-top:2px">${aasAfter.toFixed(1)}<span style="font-size:11px;color:#64748b;margin-left:5px">from ${aasNow.toFixed(1)}</span></div></div>
        <div style="padding:9px 12px;background:rgba(2,6,23,0.5);border-radius:6px"><div style="font-size:9px;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;font-weight:700">Sessions Freed</div><div style="font-size:22px;font-weight:900;color:#fbbf24;margin-top:2px">~${Math.max(0,p.sessionsFreed).toFixed(1)}</div></div>
    </div>
    <div style="position:relative;height:62px;margin:10px 4px 6px;padding-top:18px">
        <div style="position:relative;height:14px;background:rgba(2,6,23,0.7);border-radius:7px;overflow:hidden;border:1px solid rgba(99,102,241,0.15)">
            <div style="position:absolute;left:0;top:0;height:100%;width:${pct(safe).toFixed(1)}%;background:linear-gradient(90deg,rgba(16,185,129,0.45),rgba(16,185,129,0.15))"></div>
            <div style="position:absolute;left:${pct(safe).toFixed(1)}%;top:0;height:100%;width:${(pct(danger)-pct(safe)).toFixed(1)}%;background:linear-gradient(90deg,rgba(245,158,11,0.4),rgba(245,158,11,0.2))"></div>
            <div style="position:absolute;left:${pct(danger).toFixed(1)}%;top:0;height:100%;width:${(100-pct(danger)).toFixed(1)}%;background:linear-gradient(90deg,rgba(239,68,68,0.45),rgba(239,68,68,0.2))"></div>
            <div style="position:absolute;left:${pct(aasNow).toFixed(1)}%;top:-3px;width:3px;height:20px;background:#ef4444;box-shadow:0 0 6px #ef4444" title="Now"></div>
            <div style="position:absolute;left:${pct(aasAfter).toFixed(1)}%;top:-3px;width:3px;height:20px;background:#34d399;box-shadow:0 0 6px #34d399" title="After fix"></div>
        </div>
        ${mark(safe,    '#10b981', `Safe ${safe.toFixed(1)}`,    '20px')}
        ${mark(danger,  '#f59e0b', `CPU ${danger}`,              '20px')}
        ${mark(aasNow,  '#ef4444', `Now ${aasNow.toFixed(1)}`,   '34px')}
        ${mark(aasAfter,'#34d399', `After ${aasAfter.toFixed(1)}`,'34px')}
    </div>
    <div style="font-size:11.5px;color:#cbd5e1;line-height:1.65;margin-top:6px"><b style="color:#34d399">Why:</b> ${_esc(p.rationale)}</div>
</div>`;
    }

    function renderActionQueue(actions) {
        if (!actions || !actions.length) return '<div style="color:#64748b;font-size:11px;padding:10px">No actions generated.</div>';
        const impactColor = { HIGH:'#10b981', MED:'#f59e0b', TRIAGE:'#06b6d4', MONITOR:'#6366f1', LOW:'#64748b' };
        const prioOrder = { IMMEDIATE:0, IMPORTANT:1, INVESTIGATE:2, MONITOR:3 };
        const sortedActions = [...actions].sort((a,b) => (prioOrder[a.prio]??5) - (prioOrder[b.prio]??5));
        return `<div style="display:flex;flex-direction:column;gap:12px">${
            sortedActions.map((a, i) => {
                const dot = impactColor[a.impact] || a.dot || '#6366f1';
                const prioCol = a.prio==='IMMEDIATE'?'#ef4444':a.prio==='IMPORTANT'?'#f59e0b':a.prio==='INVESTIGATE'?'#06b6d4':'#6366f1';
                // Section label helpers
                const lbl = (txt, col) => `<span style="font-size:8px;font-weight:900;color:${col};text-transform:uppercase;letter-spacing:0.8px;padding:2px 7px;border-radius:3px;border:1px solid ${col}40;background:${col}0e">${txt}</span>`;
                return `
                <div style="background:rgba(10,14,30,0.85);border:1px solid ${prioCol}30;border-left:4px solid ${prioCol};border-radius:8px;overflow:hidden">
                    <!-- ── CARD HEADER ── -->
                    <div style="display:flex;align-items:center;gap:10px;padding:10px 16px;background:${prioCol}08;border-bottom:1px solid ${prioCol}20;flex-wrap:wrap">
                        <span style="display:inline-flex;align-items:center;justify-content:center;width:24px;height:24px;border-radius:50%;background:${prioCol}20;color:${prioCol};font-size:12px;font-weight:900;border:1px solid ${prioCol}50;flex-shrink:0">${i+1}</span>
                        <span style="font-size:13px;color:#f1f5f9;font-weight:800;flex:1;min-width:220px;line-height:1.3">${_esc(a.title)}</span>
                        <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">
                            <span style="font-size:10px;color:${prioCol};font-weight:900;text-transform:uppercase;letter-spacing:0.6px;background:${prioCol}1d;padding:3px 10px;border-radius:4px;border:1px solid ${prioCol}40">${_esc(a.prio||'ACTION')}</span>
                            <span style="font-size:9.5px;color:${dot};font-weight:800;background:${dot}18;padding:3px 8px;border-radius:4px;border:1px solid ${dot}30">IMPACT ${_esc(a.impact||'—')}</span>
                            <span style="font-size:9px;color:#94a3b8;background:rgba(99,102,241,0.09);border:1px solid rgba(99,102,241,0.18);padding:3px 7px;border-radius:4px">EFFORT ${_esc(a.effort||'—')}</span>
                            <span style="font-size:9px;color:#cbd5e1;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.15);padding:3px 7px;border-radius:4px;font-family:monospace">${_esc(_fmtTime(a.timeMin||0))}</span>
                        </div>
                    </div>
                    <!-- ── WHY THIS ACTION (RCA alignment) ── -->
                    ${a.rcaAlignment ? `<div style="padding:8px 16px 6px;background:rgba(2,6,23,0.5);border-bottom:1px solid rgba(99,102,241,0.10)">
                        <div style="margin-bottom:4px">${lbl('Why this action aligns with the RCA verdict','#818cf8')}</div>
                        <div style="font-size:11.5px;color:#94a3b8;line-height:1.65">${_esc(a.rcaAlignment)}</div>
                    </div>` : ''}
                    <!-- ── ORACLE DIAGNOSTIC QUERY ── -->
                    <div style="padding:8px 16px 6px">
                        <div style="margin-bottom:4px;display:flex;align-items:center;justify-content:space-between">
                            ${lbl('Oracle Diagnostic Query','#38bdf8')}
                            <span style="font-size:8px;color:#334155;font-style:italic">Copy-paste ready · scoped to problem window snap IDs</span>
                        </div>
                        <pre style="margin:4px 0 0;padding:10px 12px;background:rgba(0,0,0,0.5);border:1px solid rgba(56,189,248,0.12);border-radius:5px;font-size:11px;color:#bfdbfe;font-family:monospace;white-space:pre-wrap;line-height:1.6;overflow-x:auto">${_esc(a.sql)}</pre>
                    </div>
                    <!-- ── WHAT TO LOOK FOR ── -->
                    ${a.whatToLookFor ? `<div style="padding:6px 16px 6px;border-top:1px dashed rgba(99,102,241,0.12)">
                        <div style="margin-bottom:4px">${lbl('What to look for in the results','#a5b4fc')}</div>
                        <div style="font-size:11.5px;color:#94a3b8;line-height:1.65">${_esc(a.whatToLookFor)}</div>
                    </div>` : ''}
                    <!-- ── CONCLUSIVE ACTION PATH ── -->
                    <div style="padding:6px 16px 10px;background:rgba(${a.prio==='IMMEDIATE'?'239,68,68':a.prio==='IMPORTANT'?'245,158,11':'99,102,241'},0.04);border-top:1px dashed rgba(99,102,241,0.12)">
                        <div style="margin-bottom:4px">${lbl('Conclusive action','#34d399')}</div>
                        <div style="font-size:11.5px;color:#6ee7b7;line-height:1.65">${_esc(a.conclusiveAction || a.expect || '')}</div>
                    </div>
                </div>`;
            }).join('')
        }</div>`;
    }

    return { extract, evaluate, decorateActions, renderScorecard, renderImpactSimulator, renderActionQueue, RULES };
})();

// --- FULL TABULAR RCA VERDICT ----------------------------------------------
// Called after intelligence poll completes AND AWRContext is available.
// Renders the complete multi-section intelligence table into rca-intel-anchor.
function _renderRCAVerdictTabular(report, ctx) {
    if (!ctx) return '';
    const d1 = ctx._raw.good || {}, d2 = ctx._raw.bad || {};
    const _isSingle = ctx._isSingle || false;
    const _lbl1 = _isSingle ? '' : (ctx.meta.lbl1 || 'Baseline');
    const lbl1 = ctx.meta.lbl1, lbl2 = ctx.meta.lbl2;
    const ev1 = ctx.waitEvents.good, ev2 = ctx.waitEvents.bad;
    const lp1 = ctx.loadProfile.good, lp2 = ctx.loadProfile.bad;
    const sql1 = d1.sql_stats || [], sql2 = d2.sql_stats || [];
    const addm = d2.addm_findings || ctx.addmFindings?.bad || [];
    const effGood = ctx.instanceEfficiency?.good || {};
    const effBad  = ctx.instanceEfficiency?.bad  || {};
    // ● REDESIGNED: Crisp, delta-focused, correlated — no data walls

    const findings = report.findings || [];
    const corrNotes = report.correlation_notes || [];

    // -- HEALTH CONFIG ---------------------------------------------------------
    const hsCfg = {
        CRITICAL:{ color:'#ef4444', border:'rgba(239,68,68,0.45)', bg:'rgba(239,68,68,0.07)' },
        WARNING: { color:'#f59e0b', border:'rgba(245,158,11,0.45)', bg:'rgba(245,158,11,0.07)' },
        OK:      { color:'#4ade80', border:'rgba(74,222,128,0.45)', bg:'rgba(74,222,128,0.07)' },
    };
    const hs = hsCfg[report.overall_health] || hsCfg.OK;

    // -- HELPERS ---------------------------------------------------------------
    const pD   = (a,b) => a>0 ? ((b-a)/a*100) : (b>0?100:0);
    const f1   = v => (+v||0).toFixed(1);
    const fN   = (v,dp=1) => {
        if (v===null||v===undefined||isNaN(+v)) return '–';
        const n=+v;
        if(Math.abs(n)>=1e6)return(n/1e6).toFixed(1)+'M';
        if(Math.abs(n)>=1e3)return(n/1e3).toFixed(1)+'K';
        return n.toFixed(dp);
    };
    const chip = (d) => {
        if (d===null||d===undefined) return `<span style="color:#c084fc;font-weight:800;font-size:9px">NEW</span>`;
        const a=Math.abs(d);
        const col=d>50?'#ef4444':d>20?'#f59e0b':d>5?'#94a3b8':d<-20?'#4ade80':'#475569';
        const arr=d>0?'?':'?';
        return `<span style="color:${col};font-weight:800">${arr}${a.toFixed(0)}%</span>`;
    };
    const sev = (d) => {
        const a=Math.abs(d||0);
        if(a>=100)return`<span style="background:rgba(239,68,68,0.2);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">CRITICAL</span>`;
        if(a>=50)return`<span style="background:rgba(245,158,11,0.18);color:#f59e0b;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">HIGH</span>`;
        if(a>=20)return`<span style="background:rgba(148,163,184,0.12);color:#94a3b8;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">MOD</span>`;
        return '';
    };
    const TH  = `style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:3px 8px;text-align:right;white-space:nowrap;border-bottom:1px solid rgba(71,85,105,0.25)"`;
    const THL = `style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:3px 8px;text-align:left;white-space:nowrap;border-bottom:1px solid rgba(71,85,105,0.25)"`;
    const TD  = `style="font-size:9px;padding:4px 8px;text-align:right;border-bottom:1px solid rgba(15,23,42,0.5)"`;
    const TDL = `style="font-size:9px;padding:4px 8px;text-align:left;border-bottom:1px solid rgba(15,23,42,0.5)"`;

    // -- BASELINE/PROBLEM INDEXES ----------------------------------------------
    const sql1Map = {}; sql1.forEach(s=>sql1Map[s.sql_id]=s);
    const ev1Map  = {}; ev1.forEach(e=>ev1Map[e.event_name]=e);

    const elGood = ctx.meta.good.elapsed_min||1;
    const elBad  = ctx.meta.bad.elapsed_min ||1;
    const elDiffPct = Math.abs(elBad-elGood)/elGood*100;

    // -- LOAD PROFILE: only metrics with |?| = 10% ----------------------------
    const allLPKeys = Array.from(new Set([...Object.keys(lp1||{}),...Object.keys(lp2||{})]));
    const lpAll = allLPKeys
        .map(k=>({key:k,g:lp1[k]||0,b:lp2[k]||0}))
        .filter(m=>m.g>0||m.b>0)
        .map(m=>({...m,d:pD(m.g,m.b)}))
        .filter(m=>Math.abs(m.d)>=10)
        .sort((a,b)=>Math.abs(b.d)-Math.abs(a.d));

    // -- HARD PARSE RATE (Rule-of-Three threshold: >100/s = CRITICAL) ----------
    const hardParseRateB = lp2.hard_parses||0;
    const hardParseRateG = lp1.hard_parses||0;
    // Guardrail: only alert if soft parse ALSO dropped below 90%
    // High hard-parse count with soft parse still >90% = volume increase, not a parse storm
    const _softParsePctBad = (effBad.soft_parse_pct||0);
    const hardParseAlert = hardParseRateB > 100 && (_softParsePctBad === 0 || _softParsePctBad < 90);

    // -- WAIT EVENTS: materialized with baseline join --------------------------
    const allWaits = ev2.map(e=>{
        const prev=ev1Map[e.event_name]||{};
        return {
            ...e,
            pct_good: prev.pct_db_time||0,
            avg_ms_good: prev.avg_wait_ms||0,
            isNew: !ev1Map[e.event_name],
            dPct: ev1Map[e.event_name] ? pD(prev.pct_db_time||0,e.pct_db_time||0) : null,
        };
    }).filter(e=>(e.pct_db_time||0)>0.5||(e.pct_good||0)>0.5)
      .sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));

    // Rule-of-Three latency threshold checks on BAD period
    const seqRead    = allWaits.find(e=>(e.event_name||'').toLowerCase().includes('db file sequential read'));
    const logSync    = allWaits.find(e=>(e.event_name||'').toLowerCase().includes('log file sync'));
    const seqAlert   = seqRead && (seqRead.avg_wait_ms||0) > 20;
    const syncAlert  = logSync && (logSync.avg_wait_ms||0) > 20;

    // Detect causal correlations between LP and waits
    const corrLinks = [];
    if (hardParseAlert) {
        const libCache = allWaits.find(e=>(e.event_name||'').toLowerCase().includes('library cache'));
        const latch    = allWaits.find(e=>(e.event_name||'').toLowerCase().includes('latch'));
        if (libCache||latch) corrLinks.push({ signal:'Hard Parses >100/s', effect:(libCache?libCache.event_name||'library cache':latch.event_name||'latch contention'), type:'PARSE_STORM', color:'#f87171' });
    }
    if (seqAlert) {
        const sqlWithIO = sql2.slice(0,10).find(s=>(s.disk_reads_total||s.disk_reads||0)>10000||(s.buffer_gets_total||s.buffer_gets||0)>500000);
        if (sqlWithIO) corrLinks.push({ signal:'db file sequential read >20ms', effect:'SQL '+sqlWithIO.sql_id+' index scan', type:'INDEX_SCAN_IO', color:'#f59e0b' });
    }
    if (syncAlert) {
        const redoLPD = lpAll.find(m=>m.key.includes('redo'));
        if (redoLPD) corrLinks.push({ signal:'log file sync >20ms', effect:'Redo size ? '+(redoLPD.d>0?'+':'')+redoLPD.d.toFixed(0)+'%', type:'REDO_PRESSURE', color:'#f59e0b' });
    }

    // -- LP NORM CHAIN — map ctx._norm.significantLP to observed wait events ------
    const normSigLP = (ctx._norm && ctx._norm.significantLP) ? ctx._norm.significantLP : [];
    const _LP_WAIT_MAP = {
        physical_reads:  ['db file sequential read','db file scattered read','direct path read'],
        logical_reads:   ['buffer busy','read by other session'],
        redo_size:       ['log file sync','log file parallel write','log buffer space'],
        hard_parses:     ['library cache','latch: shared pool','library cache lock'],
        physical_writes: ['db file parallel write'],
        block_changes:   ['buffer busy','log file sync'],
        db_cpu:          [],
        executes:        [],
    };
    const lpCausalLinks = [];
    normSigLP.filter(m=>m.direction==='regression'&&m.severity!=='info').forEach(m=>{
        const wNames = _LP_WAIT_MAP[m.key]||[];
        const foundW = wNames.map(wn=>allWaits.find(e=>(e.event_name||'').toLowerCase().includes(wn.toLowerCase()))).find(Boolean);
        if (foundW) {
            lpCausalLinks.push({ lpMetric:m.label, lpDelta:m.delta_pct, lpKey:m.key, severity:m.severity, waitEvent:foundW.event_name, waitPct:foundW.pct_db_time||0, waitMs:foundW.avg_wait_ms||0 });
            // Enrich corrLinks if not already present
            if (!corrLinks.find(c=>c.type===m.key.toUpperCase())) {
                corrLinks.push({ signal:m.label+' '+(m.delta_pct>0?'+':'')+m.delta_pct.toFixed(0)+'%', effect:foundW.event_name+' ('+f1(foundW.pct_db_time||0)+'% DB Time)', type:m.key.toUpperCase(), color:m.severity==='critical'?'#ef4444':'#f59e0b' });
            }
        }
    });

    // -- SQL: join baseline, compute s/exec, flag silent offenders -------------
    const allSqls = sql2.map(s=>{
        const prev=sql1Map[s.sql_id];
        const epe2=s.avg_elapsed_secs||((s.elapsed_time_secs||0)/Math.max(s.executions||1,1));
        const epe1=prev?(prev.avg_elapsed_secs||((prev.elapsed_time_secs||0)/Math.max(prev.executions||1,1))):null;
        const isNew=!prev;
        const isPlanChg=!!(prev&&s.plan_hash_value&&prev.plan_hash_value&&s.plan_hash_value!==prev.plan_hash_value);
        const isReg=!isNew&&epe1!==null&&epe2>epe1*1.2;
        // "Silent offender": low exec count but very high elapsed/exec
        const isSilent=!isNew&&(s.executions||0)<50&&epe2>5&&(s.pct_db_time||0)>2;
        return {...s,prev,epe1,epe2,isNew,isPlanChg,isReg,isSilent};
    }).sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));

    const n_new   = allSqls.filter(s=>s.isNew).length;
    const critCount = findings.filter(f=>f.severity==='CRITICAL').length;
    const warnCount = findings.filter(f=>f.severity==='WARNING').length;

    // -- TOP FINDINGS (max 2 — CRITICAL first) --------------------------------
    const topFindings = findings.slice(0,2);
    const topFinding  = topFindings[0]||{};

    // -- STAGE RENDERER --------------------------------------------------------
    const stage = (num,col,title,body,isLast=false) => `
    <div style="display:flex;align-items:flex-start;gap:0;padding-bottom:${isLast?'0':'14'}px">
        <div style="flex-shrink:0;display:flex;flex-direction:column;align-items:center;width:28px">
            <div style="width:26px;height:26px;border-radius:50%;background:${col}18;border:2px solid ${col};display:flex;align-items:center;justify-content:center;font-size:10px;font-weight:900;color:${col};flex-shrink:0">${num}</div>
            ${!isLast?`<div style="width:2px;flex:1;min-height:16px;background:linear-gradient(to bottom,${col}50,transparent);margin-top:3px"></div>`:''}
        </div>
        <div style="flex:1;margin-left:10px">
            <div style="font-size:8px;color:${col};font-weight:700;text-transform:uppercase;letter-spacing:0.7px;margin-bottom:5px">${title}</div>
            ${body}
        </div>
    </div>`;

    // waitDiag: concise causal label — KB-first via WAIT_EVENT_CATALOG, then fallback
    const waitDiag = ev => {
        // KB-first: pull mechanism from WAIT_EVENT_CATALOG when available
        if (ev && typeof WAIT_EVENT_CATALOG !== 'undefined') {
            const exactEntry = WAIT_EVENT_CATALOG[ev];
            if (exactEntry && exactEntry.mechanism) {
                const m = exactEntry.mechanism.replace(/<[^>]*>/g, '').split(/[.!]/)[0].trim();
                if (m && m.length > 4) return m.substring(0, 90) + (m.length > 90 ? '...' : '');
            }
            const partialKey = Object.keys(WAIT_EVENT_CATALOG).find(k =>
                (ev||'').toLowerCase().includes(k.toLowerCase()) && WAIT_EVENT_CATALOG[k].mechanism
            );
            if (partialKey) {
                const m = WAIT_EVENT_CATALOG[partialKey].mechanism.replace(/<[^>]*>/g, '').split(/[.!]/)[0].trim();
                if (m && m.length > 4) return m.substring(0, 90) + (m.length > 90 ? '...' : '');
            }
        }
        // Fallback: hardcoded diagnostics
        const n=(ev||'').toLowerCase();
        if(n.includes('direct path read temp')||n.includes('direct path write temp')) return 'sort/hash spill — disk';
        if(n.includes('direct path read'))  return 'direct read — bypass buffer cache';
        if(n.includes('log file sync'))     return 'commit rate too high — redo I/O';
        if(n.includes('log file parallel')) return 'redo log disk I/O';
        if(n.includes('db file sequential'))return 'index range scan — single-block I/O';
        if(n.includes('db file scattered')) return 'FTS/FFS — multi-block I/O';
        if(n.includes('db file parallel'))  return 'parallel query — multi-block I/O';
        if(n.includes('read by other'))     return 'hot block — buffer busy contention';
        if(n.includes('buffer busy'))       return 'hot block contention';
        if(n.includes('library cache'))     return 'parse storm — hard parse serialization';
        if(n.includes('latch'))             return 'latch contention — CPU serialize';
        if(n.includes('enq: tx'))           return 'row lock / ITL exhaustion';
        if(n.includes('enq: hw'))           return 'HWM contention — segment extend';
        if(n.includes('gc '))               return 'RAC cross-instance transfer';
        if(n.includes('resmgr'))            return 'CPU throttled by Resource Manager';
        if(n.includes('sql*net'))           return 'network / client latency';
        return '–';
    };

    // -- STAGE 1: LOAD PROFILE — top deltas only -------------------------------
    const lpLabel = k => ({
        db_time_s:'DB Time /s',db_cpu_s:'DB CPU /s',logical_reads:'Logical Reads /s',
        physical_reads:'Physical Reads /s',redo_size:'Redo Size /s',hard_parses:'Hard Parses /s',
        executes:'Executions /s',transactions:'Transactions /s',parses:'Parses /s',
        user_calls:'User Calls /s',logons:'Logons /s',block_changes:'Block Changes /s',
        physical_writes:'Physical Writes /s'
    }[k]||k);

    const s1Body = lpAll.length ? `
    <table style="width:100%;border-collapse:collapse;background:rgba(10,16,30,0.8)">
        <thead><tr>
            <th ${THL}>Metric</th>
            <th ${TH}>Baseline /s</th>
            <th ${TH}>Problem /s</th>
            <th ${TH}>Δ</th>
        </tr></thead>
        <tbody>${lpAll.map(m=>{
            const dCol=m.d>50?'#ef4444':m.d>20?'#f59e0b':m.d<-30?'#4ade80':'#94a3b8';
            const corr=corrLinks.find(c=>c.type.includes('PARSE')&&m.key.includes('hard'))||
                       corrLinks.find(c=>c.type.includes('REDO')&&m.key.includes('redo'));
            const corrBadge=corr?`<span style="color:${corr.color};font-size:7px;margin-left:4px;font-weight:700">${corr.type.replace('_',' ')}</span>`:'';
            return `<tr style="${Math.abs(m.d)>=50?'background:rgba(239,68,68,0.04)':''}">
                <td ${TDL} style="color:#cbd5e1">${lpLabel(m.key)}${corrBadge}</td>
                <td ${TD}  style="color:#64748b">${fN(m.g)}</td>
                <td ${TD}  style="color:${dCol};font-weight:700">${fN(m.b)}</td>
                <td ${TD}>${chip(m.d)}${sev(m.d)}</td>
            </tr>`;
        }).join('')}</tbody>
    </table>
    ${hardParseAlert?`<div style="margin-top:4px;padding:4px 8px;background:rgba(239,68,68,0.08);border-left:3px solid #ef4444;border-radius:3px;font-size:9px;color:#fca5a5">Hard Parses ${fN(hardParseRateB)}/s > 100 threshold — Shared Pool CPU burn: ensure bind variables are used (cursor_sharing=FORCE or app fix)</div>`:''}
    ${elDiffPct>15?`<div style="margin-top:4px;font-size:8px;color:#f59e0b;padding:3px 6px;background:rgba(245,158,11,0.07);border-radius:3px">Note: Windows differ ${elDiffPct.toFixed(0)}% (${elGood.toFixed(1)} vs ${elBad.toFixed(1)} min) — /s rates comparable; raw counts are not</div>`:''}
    ` : `<div style="font-size:9px;color:#475569;padding:4px 0">No load profile shifts =10% — input pressure unchanged.</div>`;

    // -- STAGE 2: WAIT SIGNATURE — only events >0.5% with key thresholds ------
    const s2Body = allWaits.length ? `
    <table style="width:100%;border-collapse:collapse;background:rgba(10,16,30,0.8)">
        <thead><tr>
            <th ${THL}>Event</th>
            <th ${TH}>Class</th>
            <th ${TH}>Base%</th>
            <th ${TH}>Prob%</th>
            <th ${TH}>Δ</th>
            <th ${TH}>Avg ms</th>
            <th ${THL}>Cause</th>
        </tr></thead>
        <tbody>${allWaits.map(e=>{
            const pct=e.pct_db_time||0;
            const avgMs=e.avg_wait_ms||0;
            const pCol=pct>20?'#ef4444':pct>10?'#f59e0b':pct>3?'#94a3b8':'#475569';
            // Threshold breaches (Rule of Three)
            const msAlert=(e.event_name||'').toLowerCase().includes('db file sequential')&&avgMs>20
                         ||(e.event_name||'').toLowerCase().includes('log file sync')&&avgMs>20;
            const msCol=msAlert?'#ef4444':'#94a3b8';
            const msBadge=msAlert?`<span style="color:#ef4444;font-weight:800"> !</span>`:'';
            const dStr=e.dPct===null?`<span style="color:#c084fc;font-weight:800">NEW</span>`:chip(e.dPct);
            // Correlation marker
            const corrLink=corrLinks.find(c=>c.effect.toLowerCase().includes((e.event_name||'').toLowerCase().split(' ').slice(0,2).join(' ')));
            const corrMark=corrLink?`<span style="color:${corrLink.color};font-size:7px;font-weight:700;margin-left:3px">${corrLink.signal.split('>')[0].trim()}</span>`:'';
            return `<tr data-rca-wait="${esc(e.event_name||'')}" data-pct="${f1(pct)}" data-ms="${f1(avgMs)}" data-diag="${waitDiag(e.event_name||'').replace(/"/g,"'")}" style="cursor:pointer;${msAlert?'background:rgba(239,68,68,0.04)':pct>10?'background:rgba(245,158,11,0.03)':''}">
                <td ${TDL} style="font-family:monospace;color:#e2e8f0;font-size:9px">${esc(e.event_name||'')}${corrMark}</td>
                <td ${TD}  style="color:#475569;font-size:8px">${esc(e.wait_class||'')}</td>
                <td ${TD}  style="color:#64748b">${f1(e.pct_good)}</td>
                <td ${TD}  style="color:${pCol};font-weight:700">${f1(pct)}</td>
                <td ${TD}>${dStr}</td>
                <td ${TD}  style="color:${msCol};font-weight:${msAlert?700:400}">${f1(avgMs)}${msBadge}</td>
                <td ${TDL} style="color:#475569;font-size:8px;font-style:italic">${waitDiag(e.event_name||'')}</td>
            </tr>`;
        }).join('')}</tbody>
    </table>
    ${seqAlert?`<div style="margin-top:4px;padding:4px 8px;background:rgba(239,68,68,0.07);border-left:3px solid #ef4444;border-radius:3px;font-size:9px;color:#fca5a5">db file sequential read ${fN(seqRead.avg_wait_ms,0)}ms > 20ms — check stale stats / unselective index scans / fragmentation</div>`:''}
    ${syncAlert?`<div style="margin-top:3px;padding:4px 8px;background:rgba(245,158,11,0.07);border-left:3px solid #f59e0b;border-radius:3px;font-size:9px;color:#fde68a">log file sync ${fN(logSync.avg_wait_ms,0)}ms > 20ms — move redo logs to fastest storage tier / reduce commit frequency</div>`:''}
    ` : `<div style="font-size:9px;color:#475569;padding:4px 0">No wait events above threshold.</div>`;

    // -- STAGE 3: SQL ATTRIBUTION — silent offenders prominently marked ---------
    // Sort: prioritise NEW+PLAN CHG+REGRESSED, then by %DB time; limit to 15
    const sqlDisplay = allSqls
        .sort((a,b)=>{
            const pa=(a.isNew||a.isPlanChg)?1:0, pb=(b.isNew||b.isPlanChg)?1:0;
            if(pb!==pa)return pb-pa;
            if(b.isSilent!==a.isSilent)return b.isSilent?1:-1;
            return (b.pct_db_time||0)-(a.pct_db_time||0);
        }).slice(0,15);

    const s3Body = sqlDisplay.length ? `
    <table style="width:100%;border-collapse:collapse;background:rgba(10,16,30,0.8)">
        <thead><tr>
            <th ${THL}>SQL ID</th>
            <th ${TH}>Base%</th>
            <th ${TH}>Prob%</th>
            <th ${TH}>Δ%</th>
            <th ${TH}>B s/exec</th>
            <th ${TH}>P s/exec</th>
            <th ${TH}>exec</th>
            <th ${TH}>Execs</th>
            <th ${THL}>Status / Module</th>
        </tr></thead>
        <tbody>${sqlDisplay.map(s=>{
            const pct=s.pct_db_time||0;
            const pctPrev=s.prev?(s.prev.pct_db_time||0):null;
            const dPct=pctPrev!==null?pD(pctPrev,pct):null;
            const pCol=pct>20?'#ef4444':pct>10?'#f59e0b':'#94a3b8';
            const epe2s=fN(s.epe2||0,2);
            const epe1s=s.epe1!==null?fN(s.epe1,2):'–';
            const epeD=s.epe1!==null?pD(s.epe1,s.epe2||0):null;
            const badge=s.isNew?`<span style="background:rgba(192,132,252,0.2);color:#c084fc;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">NEW</span>`:
                        s.isPlanChg?`<span style="background:rgba(239,68,68,0.2);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">PLAN CHG</span>`:
                        s.isReg?`<span style="background:rgba(245,158,11,0.2);color:#f59e0b;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">REGRESSED</span>`:'';
            const silentBadge=s.isSilent?`<span style="background:rgba(99,102,241,0.15);color:#818cf8;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:3px">SILENT</span>`:'';
            const rowBg=s.isSilent?'background:rgba(99,102,241,0.04)':s.isNew||s.isPlanChg?'background:rgba(239,68,68,0.03)':'';
            const statusTxt=s.isNew?'NEW':s.isPlanChg?'PLAN CHG':s.isReg?'REGRESSED':s.isSilent?'SILENT OFFENDER':'';
            return `<tr data-rca-sql="${esc(s.sql_id||'')}" data-pct="${f1(pct)}" data-epe1="${s.epe1!==null?fN(s.epe1,2):'–'}" data-epe2="${fN(s.epe2||0,2)}" data-status="${statusTxt}" style="cursor:pointer;${rowBg}">
                <td ${TDL} style="font-family:monospace;color:#a5b4fc;font-size:9px;font-weight:700">${esc(s.sql_id||'–')}</td>
                <td ${TD}  style="color:#64748b">${pctPrev!==null?f1(pctPrev):'–'}</td>
                <td ${TD}  style="color:${pCol};font-weight:700">${f1(pct)}</td>
                <td ${TD}>${dPct!==null?chip(dPct):`<span style="color:#c084fc;font-weight:800">NEW</span>`}</td>
                <td ${TD}  style="color:#64748b">${epe1s}</td>
                <td ${TD}  style="color:#e2e8f0;font-weight:${s.isReg||s.isNew||s.isSilent?700:400}">${epe2s}</td>
                <td ${TD}>${epeD!==null?chip(epeD):'–'}</td>
                <td ${TD}  style="color:#64748b">${comma(s.executions||0)}</td>
                <td ${TDL} style="font-size:8px">${badge}${silentBadge} <span style="color:#475569">${esc((s.module||'').slice(0,18)||'–')}</span></td>
            </tr>`;
        }).join('')}</tbody>
    </table>
    ${elDiffPct>15?`<div style="margin-top:4px;font-size:8px;color:#64748b;padding:2px 6px">Note: s/exec is comparable; Execs are raw totals (windows differ ${elDiffPct.toFixed(0)}%)</div>`:''}
    ${allSqls.some(s=>s.isSilent)?`<div style="margin-top:3px;font-size:8px;color:#818cf8;padding:3px 6px;background:rgba(99,102,241,0.05);border-radius:3px;border:1px solid rgba(99,102,241,0.15)">● SILENT offenders: low exec count but high elapsed/exec — real ROI is here, not in high-frequency queries</div>`:''}
    ` : `<div style="font-size:9px;color:#475569;padding:4px 0">No SQL attribution data available.</div>`;

    // -- STAGE 4: STRUCTURED FIX VERDICTS — evidence-traceable, root-cause-specific --
    const s4Body = `<div style="display:flex;flex-direction:column;gap:8px">
    ${topFindings.map(f=>{
        const fd = f.fix_detail || {};
        const sc = f.severity==='CRITICAL'?'#ef4444':f.severity==='WARNING'?'#f59e0b':'#60a5fa';
        const tBadge = (f.trend||'').includes('WORSENING')
            ? `<span style="background:rgba(239,68,68,0.15);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">▲ WORSENING</span>` : '';
        const rctColor = {
            sql_regression:'#f59e0b', new_sql:'#a855f7', workload_growth:'#3b82f6',
            latch_contention:'#f97316', io_bottleneck:'#06b6d4', commit_bottleneck:'#f59e0b',
            cpu_pressure:'#f87171', locking:'#ef4444', mixed:'#8b5cf6', inconclusive:'#475569'
        }[fd.root_cause_type||'inconclusive'] || '#475569';
        const rctLabel = (fd.root_cause_type||'inconclusive').replace(/_/g,' ').toUpperCase();
        const impS = Math.round(f.impact_score||0);
        const confBadge = fd.confidence==='HIGH'
            ? `<span style="background:rgba(74,222,128,0.12);color:#4ade80;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">● HIGH</span>`
            : `<span style="background:rgba(251,191,36,0.12);color:#fbbf24;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">~ MEDIUM</span>`;
        const expandId = 'fix-exp-' + (f.id||'').replace(/[^a-z0-9]/gi,'');
        const chainRow = (f.causal_chain||[]).length
            ? `<div style="font-size:8px;color:#475569;margin-top:4px;font-family:monospace;padding:2px 6px;background:rgba(99,102,241,0.05);border-radius:3px">↳ causal chain: ${esc((f.causal_chain||[]).join(' ? '))}</div>` : '';
        const notesRow = fd.notes
            ? `<div style="font-size:8px;color:#475569;margin-top:3px;font-style:italic">${esc(fd.notes)}</div>` : '';
        return `<div style="background:rgba(10,16,30,0.95);border:1px solid ${sc}30;border-left:3px solid ${sc};border-radius:6px;padding:8px 11px">
            <!-- Header row -->
            <div style="display:flex;align-items:center;gap:6px;margin-bottom:6px;flex-wrap:wrap">
                <span style="background:${sc}18;color:${sc};font-size:8px;font-weight:700;padding:1px 7px;border-radius:3px;border:1px solid ${sc}35">${esc(f.severity)}</span>
                <span style="color:#e2e8f0;font-size:10px;font-weight:700;flex:1">${esc(fd.title||f.title||'–')}</span>
                ${tBadge}
                ${confBadge}
                <span style="background:${rctColor}15;color:${rctColor};font-size:7px;padding:1px 6px;border-radius:3px;font-weight:700;border:1px solid ${rctColor}30">${rctLabel}</span>
                <span style="font-size:11px;font-weight:900;color:${sc}">${impS}<span style="font-size:7px;color:#334155;font-weight:400">/100</span></span>
            </div>
            <!-- Fix statement (the decisive verdict line) -->
            <div style="font-size:10px;color:#e2e8f0;font-weight:600;line-height:1.5;margin-bottom:6px;padding:5px 8px;background:rgba(99,102,241,0.08);border-radius:4px;border-left:2px solid rgba(99,102,241,0.4)">
                ${esc(fd.fix_statement||f.fix||'–')}
            </div>
            <!-- Why / Reasoning (collapsed by default) -->
            <div style="display:flex;gap:8px;margin-bottom:5px">
                <button onclick="(function(el){el.nextElementSibling.style.display=el.nextElementSibling.style.display==='none'?'block':'none';el.textContent=el.textContent==='reasoning'?'reasoning':'reasoning'})(this)"
                    style="font-size:8px;color:#6366f1;background:none;border:none;padding:0;cursor:pointer;flex-shrink:0">reasoning</button>
                <div style="font-size:9px;color:#94a3b8;line-height:1.5">${esc(f.root_cause||'–')}</div>
            </div>
            <div style="display:none;font-size:9px;color:#64748b;line-height:1.6;padding:5px 8px;background:rgba(15,23,42,0.7);border-radius:4px;margin-bottom:5px">
                ${esc(fd.fix_reasoning||'–')}
            </div>
            <!-- 3 actions + validate -->
            <div style="display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:4px">
                <div style="background:rgba(15,23,42,0.8);border-radius:4px;padding:5px 7px">
                    <div style="font-size:7px;color:#6366f1;font-weight:700;text-transform:uppercase;margin-bottom:2px">ACTION 1</div>
                    <div style="font-size:8px;color:#cbd5e1;font-family:monospace;white-space:pre-wrap;word-break:break-all">${esc(fd.action_1||'–')}</div>
                </div>
                <div style="background:rgba(15,23,42,0.8);border-radius:4px;padding:5px 7px">
                    <div style="font-size:7px;color:#6366f1;font-weight:700;text-transform:uppercase;margin-bottom:2px">ACTION 2</div>
                    <div style="font-size:8px;color:#cbd5e1;font-family:monospace;white-space:pre-wrap;word-break:break-all">${esc(fd.action_2||'–')}</div>
                </div>
            </div>
            <div style="background:rgba(15,23,42,0.8);border-radius:4px;padding:5px 7px;margin-bottom:4px">
                <div style="font-size:7px;color:#6366f1;font-weight:700;text-transform:uppercase;margin-bottom:2px">ACTION 3</div>
                <div style="font-size:8px;color:#cbd5e1;font-family:monospace;white-space:pre-wrap;word-break:break-all">${esc(fd.action_3||'–')}</div>
            </div>
            <div style="padding:3px 7px;background:rgba(52,211,153,0.06);border:1px solid rgba(52,211,153,0.2);border-radius:4px">
                <span style="font-size:7px;color:#34d399;font-weight:700;text-transform:uppercase">VALIDATE: </span>
                <span style="font-size:8px;color:#64748b">${esc(fd.validate_by||'–')}</span>
            </div>
            ${chainRow}
            ${notesRow}
        </div>`;
    }).join('')}
    ${addm.slice(0,2).length?`<div style="padding:5px 8px;background:rgba(52,211,153,0.05);border:1px solid rgba(52,211,153,0.18);border-radius:4px">
        <div style="font-size:8px;color:#34d399;font-weight:700;text-transform:uppercase;margin-bottom:2px">ADDM Corroborates</div>
        ${addm.slice(0,2).map(a=>`<div style="font-size:9px;color:#64748b;margin-bottom:1px">• <span style="color:#a5b4fc;font-weight:700">${esc(a.finding_name||a.finding||'–')}</span> <span style="color:#4ade80">${f1(a.avg_active_sessions||0)} AAS</span>${a.task_name?` <span style="color:#334155;font-size:8px;font-family:monospace">${esc(a.task_name)}</span>`:''}</div>`).join('')}
    </div>`:''}
    </div>`;

    // -- CORRELATION CALLOUT ---------------------------------------------------
    const corrBox = corrLinks.length ? `
    <div style="margin-top:10px;padding:8px 12px;background:rgba(239,68,68,0.07);border:1px solid rgba(239,68,68,0.25);border-radius:6px">
        <div style="font-size:8px;color:#f87171;font-weight:700;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:5px">CORRELATED SIGNALS — These Are Connected</div>
        ${corrLinks.map(c=>`<div style="display:flex;align-items:center;gap:8px;margin-bottom:4px;font-size:9px">
            <span style="color:${c.color};font-weight:700;background:${c.color}15;padding:1px 6px;border-radius:3px">${esc(c.signal)}</span>
            <span style="color:#334155">→</span>
            <span style="color:#e2e8f0;font-weight:700">${esc(c.effect)}</span>
            <span style="color:#64748b;font-size:7px;text-transform:uppercase;margin-left:auto">${esc(c.type.replace(/_/g,' '))}</span>
        </div>`).join('')}
    </div>` : '';

    // -- VERDICT CATEGORY (from 10-category classifier) ------------------------
    const vd = ctx.verdict || {};
    const catColors = {
        PLAN_CHANGE:'#ef4444', NEW_SQL:'#a855f7', SQL_REGRESSION:'#f59e0b',
        WORKLOAD_GROWTH:'#3b82f6', IO_BOTTLENECK:'#f97316', COMMIT_LOGGING:'#f59e0b',
        CONCURRENCY_LOCK:'#ef4444', CPU_SATURATION:'#f87171',
        SCHEDULER_APP_WAIT:'#64748b', INCONCLUSIVE:'#475569'
    };
    const catC = catColors[vd.category||'INCONCLUSIVE'] || '#475569';
    const catLabel = (vd.category||'INCONCLUSIVE').replace(/_/g,' ');

    // -- ACTION BOX ------------------------------------------------------------
    const actionBox = `<div style="margin-top:10px;background:linear-gradient(135deg,rgba(99,102,241,0.1),rgba(139,92,246,0.05));border:1px solid rgba(99,102,241,0.3);border-radius:7px;padding:10px 14px">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
            <div style="font-size:8px;color:#6366f1;font-weight:700;text-transform:uppercase;letter-spacing:0.8px">WHAT TO DO NOW</div>
            <span style="background:${catC}18;color:${catC};font-size:8px;font-weight:700;padding:2px 8px;border-radius:4px;border:1px solid ${catC}35;text-transform:uppercase">${catLabel}</span>
            ${vd.confidence_reason?`<button onclick="document.getElementById('rca-evidence-pane').style.display=document.getElementById('rca-evidence-pane').style.display==='none'?'block':'none'" style="margin-left:auto;font-size:8px;color:#6366f1;background:rgba(99,102,241,0.1);border:1px solid rgba(99,102,241,0.3);border-radius:3px;padding:2px 7px;cursor:pointer">Evidence chain</button>`:''}
        </div>
        <div style="font-size:12px;color:#e2e8f0;font-weight:700;line-height:1.4">${esc(topFinding.fix||report.verdict||'Review findings above.')}</div>
        ${topFinding.oracle_ref?`<div style="font-size:9px;color:#6366f1;margin-top:4px">${esc(topFinding.oracle_ref)}</div>`:''}
        ${corrNotes.slice(0,1).map(n=>`<div style="margin-top:4px;font-size:9px;color:#475569;padding:2px 8px;background:rgba(99,102,241,0.06);border-radius:3px">${esc(n)}</div>`).join('')}
        ${vd.confidence_reason?`<div id="rca-evidence-pane" style="display:none;margin-top:8px;padding:7px 10px;background:rgba(15,23,42,0.8);border:1px solid rgba(99,102,241,0.2);border-radius:5px">
            <div style="font-size:8px;color:#818cf8;font-weight:700;text-transform:uppercase;margin-bottom:4px">Classification Evidence</div>
            <div style="font-size:9px;color:#94a3b8;line-height:1.6">${esc(vd.confidence_reason||'')}</div>
            ${(vd.evidence_fields||[]).length?`<div style="margin-top:5px;display:flex;flex-wrap:wrap;gap:4px">${(vd.evidence_fields||[]).map(f=>`<span style="background:rgba(99,102,241,0.12);color:#818cf8;font-size:8px;padding:1px 6px;border-radius:3px;font-family:monospace">${esc(f)}</span>`).join('')}</div>`:''}
        </div>`:''}
    </div>`;

    // -- CROSS-LINK JAVASCRIPT -------------------------------------------------
    // Builds a per-SQL ? waits correlation map and a per-wait ? SQLs map from
    // the already-parsed data so clicking a row cross-highlights related rows.
    const sqlIdList = JSON.stringify(allSqls.map(s=>s.sql_id));
    const sqlWaitMap = JSON.stringify((() => {
        const m = {};
        allSqls.forEach(s => {
            // Associate SQL with wait events via module name or top wait in class
            const mods = (s.module||'').toLowerCase();
            const related = allWaits
                .filter(e => {
                    const en = (e.event_name||'').toLowerCase();
                    // Direct I/O read ? db file sequential
                    if ((s.disk_reads_total||s.disk_reads||0) > 5000 && en.includes('db file sequential')) return true;
                    // BG/BHR high ? buffer busy
                    if ((s.buffer_gets_total||s.buffer_gets||0) > 200000 && en.includes('buffer busy')) return true;
                    return false;
                }).map(e=>e.event_name);
            if (related.length) m[s.sql_id] = related;
        });
        return m;
    })());
    const waitSqlMap = JSON.stringify((() => {
        const m = {};
        allWaits.forEach(e => {
            const en = (e.event_name||'').toLowerCase();
            const related = allSqls.filter(s => {
                if (en.includes('db file sequential') && (s.disk_reads_total||s.disk_reads||0)>5000) return true;
                if (en.includes('buffer busy') && (s.buffer_gets_total||s.buffer_gets||0)>200000) return true;
                if (en.includes('library cache') && (s.pct_db_time||0)>2 && s.isNew) return true;
                return false;
            }).map(s=>s.sql_id);
            if (related.length) m[e.event_name] = related;
        });
        return m;
    })());

    // Store cross-link maps on window so _initRCAClickHandlers can access them
    window._rcaSqlWaitMap = JSON.parse(sqlWaitMap);
    window._rcaWaitSqlMap = JSON.parse(waitSqlMap);

    // --------------------------------------------------------------------------
    // REDESIGNED: CONCLUSIVE PE VERDICT — single connected argument
    // --------------------------------------------------------------------------

    // -- CLASSIFY: Primary vs Secondary vs Symptom -----------------------------
    const primaryCause = topFindings[0] || {};
    const primaryFd = primaryCause.fix_detail || {};

    // Determine dominant bottleneck type
    const dbCpuEv = allWaits.find(e=>(e.event_name||'').toLowerCase()==='db cpu');
    const dbCpuPct = dbCpuEv ? (dbCpuEv.pct_db_time||0) : 0;
    const ioPct = allWaits.filter(e=>/db file|direct path/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const concPct = allWaits.filter(e=>/latch|lock|buffer busy|enq/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const commitPct = allWaits.filter(e=>/log file sync/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);

    // Top 3 waits that actually matter
    const topWaits = allWaits.filter(e=>(e.pct_db_time||0)>1).slice(0,3);

    // Top 3 SQL that actually matter
    const topSqls = allSqls.filter(s=>(s.pct_db_time||0)>1 || s.isNew || s.isPlanChg).slice(0,5);

    // Top 3 LP shifts that matter
    const topLP = lpAll.filter(m=>Math.abs(m.d)>=30).slice(0,5);

    // -- CAUSAL CHAIN: build one connected narrative ---------------------------
    const chainSteps = [];

    // Step 1: What changed in workload (LP signals)
    if (topLP.length > 0) {
        chainSteps.push({ label: 'Workload Shift', detail: topLP.slice(0,2).map(m=>lpLabel(m.key)+' '+(m.d>0?'+':'')+m.d.toFixed(0)+'%').join(', '), color: '#6366f1' });
    }
    // Step 2: Which SQL drove it
    if (topSqls.length > 0) {
        const s = topSqls[0];
        chainSteps.push({ label: s.isNew?'New SQL':'SQL '+s.sql_id, detail: f1(s.pct_db_time||0)+'% DB Time'+(s.isPlanChg?' · PLAN CHG':''), color: '#a855f7' });
    }
    // Step 3: What wait event resulted
    if (topWaits.length > 0) {
        const w = topWaits[0];
        chainSteps.push({ label: w.event_name||'', detail: f1(w.pct_db_time||0)+'% DB Time · '+f1(w.avg_wait_ms||0)+'ms avg', color: '#f59e0b' });
    }
    // Step 4: What bottleneck type
    const bottleneckType = report.primary_bottleneck || (dbCpuPct>ioPct&&dbCpuPct>concPct?'CPU':ioPct>concPct?'I/O':'Concurrency');
    chainSteps.push({ label: 'Bottleneck', detail: bottleneckType.toUpperCase(), color: hs.color });

    const chainHtml = chainSteps.length > 0 ? `<div style="display:flex;align-items:center;gap:0;flex-wrap:wrap;row-gap:6px;margin:12px 0">
        ${chainSteps.map((box,bi) => `<div style="background:${box.color}08;border:1px solid ${box.color}25;border-radius:6px;padding:6px 12px;min-width:100px">
            <div style="font-size:7px;color:${box.color};font-weight:800;text-transform:uppercase;letter-spacing:0.3px;margin-bottom:2px">${esc(box.label)}</div>
            <div style="font-size:9px;color:#94a3b8;font-family:monospace">${esc(box.detail)}</div>
        </div>${bi<chainSteps.length-1?'<div style="padding:0 4px;color:#334155;font-size:16px;font-weight:bold;flex-shrink:0">→</div>':''}
        `).join('')}
    </div>` : '';

    // -- CONFIDENCE MODEL ------------------------------------------------------
    let confScore = 0;
    let confFactors = [];
    // Cross-validation: how many AWR sections agree?
    if (topLP.length > 0) { confScore += 20; confFactors.push('Load Profile confirms'); }
    if (topWaits.length > 0) { confScore += 20; confFactors.push('Wait events confirm'); }
    if (topSqls.length > 0) { confScore += 20; confFactors.push('SQL attribution confirms'); }
    if (addm.length > 0) { confScore += 15; confFactors.push('ADDM corroborates'); }
    if (corrLinks.length > 0) { confScore += 15; confFactors.push(corrLinks.length+' causal link(s)'); }
    if (primaryCause.severity === 'CRITICAL') { confScore += 10; confFactors.push('Critical severity'); }
    const confLevel = confScore >= 80 ? 'HIGH' : confScore >= 50 ? 'MEDIUM' : 'LOW';
    const confColor = confScore >= 80 ? '#34d399' : confScore >= 50 ? '#fbbf24' : '#f87171';

    // -- TOP SQL CONTRIBUTORS (with dominance hierarchy) ----------------------
    // DOMINANT (=25% DB Time) = full-width hero card + fingerprint
    // SIGNIFICANT (5-25%) = standard card
    // MINOR (<5%) = collapsed single-line row
    const _verdict = ctx.verdict || {};
    const _isParallelVerdict = _verdict.isParallel || false;
    const _sideEffectsVerdict = _verdict.sideEffects || [];
    const _dominantSQLId = _verdict.dominantSQL || null;

    const sqlContribHtml = topSqls.length > 0 ? `
    <div style="margin-top:14px">
        <div style="font-size:9px;color:#818cf8;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:8px">Top SQL Contributors</div>
        <div style="display:flex;flex-direction:column;gap:6px">
        ${topSqls.slice(0,5).map(s => {
            const pctDb = s.pct_db_time || 0;
            const dominance = pctDb >= 25 ? 'DOMINANT' : pctDb >= 5 ? 'SIGNIFICANT' : 'MINOR';
            const badge = s.isNew ? 'NEW' : s.isPlanChg ? 'PLAN CHG' : s.isReg ? 'REGRESSED' : s.isSilent ? 'SILENT' : 'ACTIVE';
            const badgeCol = s.isNew ? '#c084fc' : s.isPlanChg ? '#ef4444' : s.isReg ? '#f59e0b' : s.isSilent ? '#818cf8' : '#64748b';
            const painType = (s.disk_reads_total||s.disk_reads||0) > 10000 ? 'I/O (reads)' :
                             (s.buffer_gets_total||s.buffer_gets||0) > 200000 ? 'Logical I/O (gets)' :
                             (s.cpu_time_secs||0) > 60 ? 'CPU' : 'Elapsed Time';
            const gets = s.buffer_gets_per_exec||s.buffer_gets||0;
            const cpuPct = s.pct_cpu||0;
            const fingerprint = [
                f1(pctDb)+'% DB Time',
                cpuPct > 0 ? f1(cpuPct)+'% CPU' : null,
                gets > 0 ? comma(Math.round(gets))+' gets/exec' : null,
                (s.disk_reads_per_exec||0) > 100 ? comma(Math.round(s.disk_reads_per_exec))+' reads/exec' : null
            ].filter(Boolean).join(' · ');
            const action = s.isPlanChg ? 'Compare execution plans via DBA_HIST_SQL_PLAN' :
                           s.isNew ? 'Review new SQL source; check bind variables' :
                           s.isReg ? 'Check for stale stats / missing indexes' : 'Monitor';

            // PARALLEL tag for dominant SQL
            const parallelTag = (_isParallelVerdict && s.sql_id === _dominantSQLId)
                ? '<span style="background:rgba(129,140,248,0.15);color:#818cf8;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700;margin-left:4px">PARALLEL</span>' : '';

            // -- DOMINANT CARD: full-width hero + fingerprint details ------
            if (dominance === 'DOMINANT') {
                return '<div style="padding:10px 14px;background:linear-gradient(135deg,rgba(168,85,247,0.06),rgba(99,102,241,0.03));border:1px solid ' + badgeCol + '30;border-left:4px solid ' + badgeCol + ';border-radius:6px">' +
                    '<div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px">' +
                        '<div style="display:flex;align-items:center;gap:8px">' +
                            '<span style="font-family:monospace;font-size:12px;color:#a5b4fc;font-weight:900">' + esc(s.sql_id||'–') + '</span>' +
                            '<span style="background:' + badgeCol + '18;color:' + badgeCol + ';font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">' + badge + '</span>' +
                            '<span style="background:rgba(239,68,68,0.15);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:800">DOMINANT</span>' +
                            parallelTag +
                        '</div>' +
                        '<div style="font-size:20px;font-weight:900;color:#ef4444">' + f1(pctDb) + '%<span style="font-size:9px;color:#475569;margin-left:3px">DB Time</span></div>' +
                    '</div>' +
                    '<div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:6px">' +
                        '<div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">' + fN(s.epe2||0,2) + 's</div><div style="font-size:7px;color:#475569">Elapsed/Exec</div></div>' +
                        '<div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">' + comma(Math.round(gets)) + '</div><div style="font-size:7px;color:#475569">Gets/Exec</div></div>' +
                        '<div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">' + comma(s.executions||0) + '</div><div style="font-size:7px;color:#475569">Executions</div></div>' +
                        '<div style="text-align:center"><div style="font-size:13px;font-weight:800;color:' + (cpuPct>10?'#f59e0b':'#e2e8f0') + '">' + f1(cpuPct) + '%</div><div style="font-size:7px;color:#475569">CPU Share</div></div>' +
                    '</div>' +
                    '<div style="font-size:9px;color:#818cf8;font-family:monospace;margin-bottom:4px">' + fingerprint + '</div>' +
                    '<div style="font-size:8px;color:#94a3b8">' + esc(painType) + ' · ' + esc(action) + '</div>' +
                    (_isParallelVerdict && s.sql_id === _dominantSQLId ?
                        '<div style="margin-top:6px;padding:4px 8px;background:rgba(129,140,248,0.06);border:1px solid rgba(129,140,248,0.15);border-radius:4px;font-size:8px;color:#818cf8">' +
                        'PARALLEL SQL — downstream symptoms (redo surge, E2P drop, logon spike, PX waits) are EXPECTED side-effects of parallel execution, not independent issues.' +
                        '</div>' : '') +
                '</div>';
            }

            // -- SIGNIFICANT CARD: standard grid row ----------------------
            if (dominance === 'SIGNIFICANT') {
                return '<div style="display:grid;grid-template-columns:100px 1fr 90px 90px;gap:8px;padding:6px 10px;background:rgba(10,16,30,0.9);border:1px solid ' + badgeCol + '20;border-left:3px solid ' + badgeCol + ';border-radius:5px;align-items:center">' +
                    '<div>' +
                        '<div style="font-family:monospace;font-size:10px;color:#a5b4fc;font-weight:700">' + esc(s.sql_id||'–') + '</div>' +
                        '<div style="margin-top:2px"><span style="background:' + badgeCol + '18;color:' + badgeCol + ';font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">' + badge + '</span></div>' +
                    '</div>' +
                    '<div>' +
                        '<div style="font-size:9px;color:#cbd5e1">' + painType + ' · ' + fN(s.epe2||0,2) + 's/exec' + (s.epe1!==null?' (was '+fN(s.epe1,2)+'s)':'') + '</div>' +
                        '<div style="font-size:8px;color:#818cf8;margin-top:1px;font-family:monospace">' + fingerprint + '</div>' +
                        '<div style="font-size:8px;color:#475569;margin-top:1px">' + esc(action) + '</div>' +
                    '</div>' +
                    '<div style="text-align:right">' +
                        '<div style="font-size:11px;font-weight:900;color:#f59e0b">' + f1(pctDb) + '%</div>' +
                        '<div style="font-size:7px;color:#475569">DB Time</div>' +
                    '</div>' +
                    '<div style="text-align:right">' +
                        '<div style="font-size:9px;color:#64748b;font-family:monospace">' + comma(s.executions||0) + '</div>' +
                        '<div style="font-size:7px;color:#475569">Execs</div>' +
                    '</div>' +
                '</div>';
            }

            // -- MINOR ROW: collapsed single line -------------------------
            return '<div style="display:flex;align-items:center;gap:8px;padding:3px 10px;border-left:2px solid #334155;border-radius:0 3px 3px 0;opacity:0.7">' +
                '<span style="font-family:monospace;font-size:9px;color:#64748b;width:80px">' + esc(s.sql_id||'–') + '</span>' +
                '<span style="background:' + badgeCol + '18;color:' + badgeCol + ';font-size:6px;padding:1px 4px;border-radius:2px;font-weight:700">' + badge + '</span>' +
                '<span style="font-size:8px;color:#475569;flex:1">' + f1(pctDb) + '% DB Time · ' + fN(s.epe2||0,2) + 's/exec</span>' +
                '<span style="font-size:8px;color:#334155">' + comma(s.executions||0) + ' execs</span>' +
            '</div>';
        }).join('')}
        </div>
    </div>` : '';

    // -- WAIT EVENT MEANING (causal, not percentages) --------------------------
    // Side-effect detection: if verdict tags certain waits as side-effects of dominant SQL,
    // label them accordingly instead of showing as independent root causes
    const _sideEffectWaitPatterns = {
        'db_file_sequential_read': /db file sequential/i,
        'direct_path_read': /direct path read/i,
        'px_waits': /^PX|px deq|parallel/i,
        'redo_size_spike': /log file|redo/i,
        'latch_contention': /latch|buffer busy|cursor.*pin/i,
        'hard_parse_increase': /library cache|shared pool/i,
    };
    const _isSideEffect = (evName) => {
        if (!_sideEffectsVerdict.length) return false;
        return _sideEffectsVerdict.some(se => {
            const pat = _sideEffectWaitPatterns[se];
            return pat && pat.test(evName || '');
        });
    };

    const waitMeaningHtml = topWaits.length > 0 ? `
    <div style="margin-top:14px">
        <div style="font-size:9px;color:#f59e0b;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:8px">Wait Event Diagnosis</div>
        <div style="display:flex;flex-direction:column;gap:5px">
        ${topWaits.slice(0,4).map(e => {
            const pct = e.pct_db_time||0;
            const diag = waitDiag(e.event_name||'');
            const isSE = _isSideEffect(e.event_name||'');
            const isRoot = !isSE && pct > 15;
            const role = isSE ? 'SIDE-EFFECT' : isRoot ? 'ROOT CAUSE' : pct > 5 ? 'CONTRIBUTING' : 'BACKGROUND';
            const roleCol = isSE ? '#818cf8' : isRoot ? '#ef4444' : pct > 5 ? '#f59e0b' : '#475569';
            const corrLink = corrLinks.find(c=>c.effect.toLowerCase().includes((e.event_name||'').toLowerCase().split(' ').slice(0,2).join(' ')));
            return `<div style="display:flex;align-items:center;gap:10px;padding:5px 10px;background:${isSE?'rgba(129,140,248,0.04)':isRoot?'rgba(239,68,68,0.04)':'rgba(15,23,42,0.5)'};border-left:3px solid ${roleCol};border-radius:0 5px 5px 0${isSE?';opacity:0.7':''}">
                <div style="width:60px;flex-shrink:0">
                    <div style="font-size:13px;font-weight:900;color:${roleCol}">${f1(pct)}%</div>
                    <div style="font-size:6px;color:${roleCol};font-weight:700;text-transform:uppercase">${role}</div>
                </div>
                <div style="flex:1;min-width:0">
                    <div style="font-size:10px;color:#e2e8f0;font-weight:600">${esc(e.event_name||'')}${isSE?' <span style="color:#818cf8;font-size:7px;font-weight:700;margin-left:4px">↳ SIDE-EFFECT of '+esc(_dominantSQLId||'dominant SQL')+'</span>':''}</div>
                    <div style="font-size:8px;color:#94a3b8;margin-top:1px">${isSE?'Expected downstream symptom — not an independent issue':diag !== '–' ? diag : ''}</div>
                </div>
                <div style="text-align:right;flex-shrink:0">
                    <div style="font-size:9px;color:#64748b;font-family:monospace">${f1(e.avg_wait_ms||0)}ms</div>
                    ${e.isNew?'<div style="color:#c084fc;font-size:7px;font-weight:700">NEW</div>':
                     e.dPct!==null?'<div style="font-size:8px">'+chip(e.dPct)+'</div>':''}
                </div>
                ${corrLink?`<div style="font-size:7px;color:${corrLink.color};font-weight:700;flex-shrink:0">? ${esc(corrLink.signal.split('>')[0].trim())}</div>`:''}
            </div>`;
        }).join('')}
        </div>
    </div>` : '';

    // -- LOAD PROFILE: only signals that matter (ranked) ----------------------
    // Side-effect LP patterns: dominant SQL explains certain LP shifts
    const _lpSideEffectKeys = {
        'redo_size_spike': ['redo_size','redo'],
        'hard_parse_increase': ['hard_parses','hard_parse'],
        'buffer_gets_surge': ['buffer_gets','logical_reads'],
        'logon_spike': ['logons'],
        'execute_to_parse_ratio_drop': ['execute_to_parse'],
    };
    const _isLPSideEffect = (lpKey) => {
        if (!_sideEffectsVerdict.length) return false;
        const lk = (lpKey||'').toLowerCase();
        return _sideEffectsVerdict.some(se => {
            const keys = _lpSideEffectKeys[se] || [];
            return keys.some(k => lk.includes(k));
        });
    };

    const lpSignalHtml = topLP.length > 0 ? `
    <div style="margin-top:14px">
        <div style="font-size:9px;color:#6366f1;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:8px">Load Profile — Significant Shifts Only</div>
        <div style="display:grid;grid-template-columns:repeat(${Math.min(topLP.length,5)},1fr);gap:6px">
        ${topLP.slice(0,5).map(m => {
            const dCol = m.d>100?'#ef4444':m.d>50?'#f59e0b':m.d<-30?'#4ade80':'#94a3b8';
            const isRelevant = corrLinks.find(c=>c.type.toLowerCase().includes(m.key.split('_')[0]));
            const lpSE = _isLPSideEffect(m.key);
            return `<div style="background:${Math.abs(m.d)>=100?'rgba(239,68,68,0.06)':'rgba(10,16,30,0.8)'};border:1px solid ${dCol}25;border-radius:6px;padding:7px 10px${isRelevant?';border-bottom:2px solid '+dCol:''}${lpSE?';opacity:0.6':''}">
                <div style="font-size:7px;color:#64748b;font-weight:700;text-transform:uppercase;letter-spacing:0.3px;margin-bottom:3px">${lpLabel(m.key)}${lpSE?' <span style="color:#818cf8;font-size:6px">✓ EXPLAINED</span>':''}</div>
                <div style="font-size:14px;font-weight:900;color:${lpSE?'#818cf8':dCol}">${m.d>0?'+':''}${m.d.toFixed(0)}%</div>
                <div style="font-size:8px;color:#475569;font-family:monospace">${fN(m.g)} → ${fN(m.b)}/s</div>
                ${lpSE?'<div style="font-size:6px;color:#818cf8;margin-top:2px;font-weight:700">SIDE-EFFECT of '+esc(_dominantSQLId||'dominant SQL')+'</div>'
                :isRelevant?'<div style="font-size:6px;color:'+dCol+';margin-top:2px;font-weight:700">✓ LINKED TO VERDICT</div>':''}
            </div>`;
        }).join('')}
        </div>
        ${elDiffPct>15?`<div style="margin-top:4px;font-size:8px;color:#f59e0b;padding:3px 6px;background:rgba(245,158,11,0.07);border-radius:3px">Note: Windows differ ${elDiffPct.toFixed(0)}% — /s rates comparable; raw counts are not</div>`:''}
    </div>` : '';

    // -- GUARDRAIL 1: latch share < 5% ? demote to SIDE_EFFECT ------------------
    const _latchPct = allWaits.filter(e=>/latch|buffer busy|cursor.*pin|enq/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);

    // Buffer-cache write-pressure signature — sums the canonical DBWR-backlog
    // family of waits.  When freeBufPct dominates, latch / FB-enq / buffer-busy
    // observed alongside it are downstream symptoms — not independent causes.
    const _freeBufPct = allWaits.filter(e=>/free buffer waits/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _bufBusyPct = allWaits.filter(e=>/buffer busy waits/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _fbEnqPct   = allWaits.filter(e=>/enq:\s*FB\s*-\s*contention/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    // Segment / serialisation enqueues — each pinpoints a different fix.
    const _hwEnqPct   = allWaits.filter(e=>/enq:\s*HW\s*-\s*contention/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _txIdxPct   = allWaits.filter(e=>/enq:\s*TX\s*-\s*index contention/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _txRowPct   = allWaits.filter(e=>/enq:\s*TX\s*-\s*row lock/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _usEnqPct   = allWaits.filter(e=>/enq:\s*US\s*-\s*contention/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _domSqlText = String(topSqls[0]?.sql_text || topSqls[0]?.sql_text_full || '').trim();
    const _domSqlVerb = (_domSqlText.match(/^\s*(INSERT|UPDATE|DELETE|MERGE|SELECT)/i) || [, ''])[1].toUpperCase();
    const _domIsDML   = /^(INSERT|UPDATE|DELETE|MERGE)$/.test(_domSqlVerb);

    // -- GUARDRAIL 2: dominant SQL >= 25% ? all others are side effects / secondary --
    const _dominantSqlPct = topSqls.length > 0 ? (topSqls[0].pct_db_time||0) : 0;
    const _dominantSqlGte25 = _dominantSqlPct >= 25;

    // -- PRIMARY CAUSE CLASSIFICATION (respects guardrails) -------------------
    // Priority order matters: serialisation / segment-extension waits are
    // checked BEFORE SQL dominance because the dominant SQL is a *symptom
    // carrier* — every execution stalls inside that wait.  Tuning the SQL
    // does nothing; the segment / index / undo configuration must be fixed.
    let _primaryCauseCategory;
    if (_hwEnqPct >= 15) {
        _primaryCauseCategory = 'HW_ENQUEUE_CONTENTION';
    } else if (_txIdxPct >= 5) {
        _primaryCauseCategory = 'TX_INDEX_CONTENTION';
    } else if (_txRowPct >= 10) {
        _primaryCauseCategory = 'TX_ROW_LOCK_CONTENTION';
    } else if (_usEnqPct >= 10) {
        _primaryCauseCategory = 'UNDO_SEGMENT_EXTENSION';
    } else if (_freeBufPct >= 15 && _dominantSqlGte25 && _domIsDML) {
        _primaryCauseCategory = 'CONCURRENT_DML_BOTTLENECK';
    } else if (_freeBufPct >= 15 || (_freeBufPct >= 8 && _bufBusyPct >= 5)) {
        _primaryCauseCategory = 'BUFFER_WRITE_PRESSURE';
    } else if (_dominantSqlGte25) {
        _primaryCauseCategory = topSqls[0].isNew ? 'NEW_SQL' : topSqls[0].isPlanChg ? 'PLAN_CHANGE' : 'SQL_DOMINANT';
    } else if (dbCpuPct >= 40) {
        _primaryCauseCategory = 'CPU_SATURATION';
    } else if (ioPct >= 30) {
        _primaryCauseCategory = 'IO_PRESSURE';
    } else if (commitPct >= 10) {
        _primaryCauseCategory = 'REDO_COMMIT';
    } else if (_latchPct >= 5) {
        _primaryCauseCategory = 'CONCURRENCY';
    } else if (topSqls.length > 0 && _dominantSqlPct >= 15) {
        _primaryCauseCategory = 'SQL_DOMINANT';
    } else {
        _primaryCauseCategory = 'UNKNOWN';
    }

    // Guardrail: never show LATCH/CONCURRENCY when latch < 5%
    if (_latchPct < 5 && (_primaryCauseCategory === 'CONCURRENCY')) {
        _primaryCauseCategory = dbCpuPct >= ioPct ? 'CPU_SATURATION' : 'IO_PRESSURE';
    }

    // -- DOMINANT SQL CARD (for the new layout) -------------------------------
    const _domSql = topSqls.length > 0 ? topSqls[0] : null;
    const _domSqlPct = _domSql ? (_domSql.pct_db_time || 0) : 0;
    const _minorSqls = topSqls.filter(s=>(s.pct_db_time||0)<5);
    const _majorSqls = topSqls.filter(s=>(s.pct_db_time||0)>=5);

    const _domSqlCardHtml = _domSql ? (() => {
        const s = _domSql;
        const pdb = s.pct_db_time || 0;
        const gets = s.buffer_gets_per_exec || s.buffer_gets || 0;
        const cpuPctS = s.pct_cpu || 0;
        const badge = s.isNew ? 'NEW' : s.isPlanChg ? 'PLAN CHG' : s.isReg ? 'REGRESSED' : 'ACTIVE';
        const badgeCol = s.isNew ? '#c084fc' : s.isPlanChg ? '#ef4444' : s.isReg ? '#f59e0b' : '#64748b';
        const minorToggleId = 'sql-minor-toggle-' + Date.now();
        return `<div style="margin-bottom:14px">
        <div style="font-size:9px;color:#818cf8;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">Dominant SQL</div>
        <div style="padding:12px 16px;background:linear-gradient(135deg,rgba(168,85,247,0.06),rgba(99,102,241,0.03));border:1px solid ${badgeCol}35;border-left:4px solid ${badgeCol};border-radius:6px">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
                <div style="display:flex;align-items:center;gap:8px">
                    <span style="font-family:monospace;font-size:13px;color:#a5b4fc;font-weight:900">${esc(s.sql_id||'–')}</span>
                    <span style="background:${badgeCol}18;color:${badgeCol};font-size:7px;padding:1px 5px;border-radius:3px;font-weight:700">${badge}</span>
                    ${_dominantSqlGte25?'<span style="background:rgba(239,68,68,0.15);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:800">DOMINANT</span>':''}
                </div>
                <div style="font-size:20px;font-weight:900;color:#ef4444">${f1(pdb)}%<span style="font-size:9px;color:#475569;margin-left:3px">DB Time</span></div>
            </div>
            <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:8px">
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${fN(s.epe2||0,2)}s</div><div style="font-size:7px;color:#475569">Elapsed/Exec</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${comma(Math.round(gets))}</div><div style="font-size:7px;color:#475569">Gets/Exec</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${comma(s.executions||0)}</div><div style="font-size:7px;color:#475569">Executions</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:${cpuPctS>10?'#f59e0b':'#e2e8f0'}">${f1(cpuPctS)}%</div><div style="font-size:7px;color:#475569">CPU Share</div></div>
            </div>
            ${_majorSqls.slice(1).length > 0 ? `<div style="margin-top:6px;padding-top:6px;border-top:1px solid rgba(255,255,255,0.05)">
                <div style="font-size:7px;color:#475569;font-weight:700;margin-bottom:4px">SIGNIFICANT CONTRIBUTORS</div>
                ${_majorSqls.slice(1).map(sq=>`<div style="display:flex;align-items:center;gap:8px;font-size:8px;padding:2px 0">
                    <span style="font-family:monospace;color:#a5b4fc;width:90px">${esc(sq.sql_id||'–')}</span>
                    <span style="color:#f59e0b;font-weight:700">${f1(sq.pct_db_time||0)}%</span>
                    <span style="color:#64748b">${fN(sq.epe2||0,2)}s/exec · ${comma(sq.executions||0)} execs</span>
                    ${sq.isNew?'<span style="color:#c084fc;font-size:7px;font-weight:700">NEW</span>':sq.isPlanChg?'<span style="color:#ef4444;font-size:7px;font-weight:700">PLAN CHG</span>':''}
                </div>`).join('')}
            </div>` : ''}
            ${_minorSqls.length > 0 ? `<details style="margin-top:6px"><summary style="font-size:8px;color:#475569;cursor:pointer;user-select:none">Minor Contributors (${_minorSqls.length} SQLs &lt;5% DB Time)</summary>
                <div style="margin-top:4px;display:flex;flex-direction:column;gap:2px">
                ${_minorSqls.map(sq=>`<div style="display:flex;align-items:center;gap:8px;font-size:8px;padding:1px 4px;opacity:0.6">
                    <span style="font-family:monospace;color:#64748b;width:90px">${esc(sq.sql_id||'–')}</span>
                    <span style="color:#64748b">${f1(sq.pct_db_time||0)}%</span>
                    <span style="color:#475569">${fN(sq.epe2||0,2)}s/exec · ${comma(sq.executions||0)} execs</span>
                </div>`).join('')}
                </div>
            </details>` : ''}
        </div></div>`;
    })() : '';

    // -- THREE-ITEM CAUSAL WAIT STRIP ------------------------------------------
    // ROOT = highest pct not classified as side-effect, AMBER = explained by root, BLUE = next risk
    const _waitsSorted = [...allWaits].sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));
    const _rootWait = _waitsSorted[0] || null;
    const _sideWait = _waitsSorted.slice(1).find(e => _isSideEffect(e.event_name||'') || (e.pct_db_time||0) > 1) || _waitsSorted[1] || null;
    const _monitorWait = _waitsSorted.slice(2).find(e => !_isSideEffect(e.event_name||'') && (e.pct_db_time||0) > 0.5) || _waitsSorted[2] || null;

    const _waitStripHtml = (_rootWait||_sideWait||_monitorWait) ? `<div style="margin-bottom:14px">
        <div style="font-size:9px;color:#f59e0b;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">Wait Causality</div>
        <div style="display:flex;flex-direction:column;gap:4px">
        ${_rootWait ? `<div style="display:grid;grid-template-columns:70px 1fr auto;gap:10px;align-items:center;padding:8px 12px;background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.3);border-left:4px solid #ef4444;border-radius:0 6px 6px 0">
            <div><div style="font-size:12px;font-weight:900;color:#ef4444">${f1(_rootWait.pct_db_time||0)}%</div><div style="font-size:6px;color:#ef4444;font-weight:700;text-transform:uppercase">ROOT CAUSE</div></div>
            <div><div style="font-size:10px;color:#e2e8f0;font-weight:600">${esc(_rootWait.event_name||'')}</div><div style="font-size:8px;color:#94a3b8;margin-top:2px">${waitDiag(_rootWait.event_name||'')}</div></div>
            <div style="font-size:9px;color:#64748b;font-family:monospace">${f1(_rootWait.avg_wait_ms||0)}ms</div>
        </div>` : ''}
        ${_sideWait ? `<div style="display:grid;grid-template-columns:70px 1fr auto;gap:10px;align-items:center;padding:8px 12px;background:rgba(245,158,11,0.04);border:1px solid rgba(245,158,11,0.25);border-left:4px solid #f59e0b;border-radius:0 6px 6px 0">
            <div><div style="font-size:12px;font-weight:900;color:#f59e0b">${f1(_sideWait.pct_db_time||0)}%</div><div style="font-size:6px;color:#f59e0b;font-weight:700;text-transform:uppercase">SIDE EFFECT</div></div>
            <div><div style="font-size:10px;color:#e2e8f0;font-weight:600">${esc(_sideWait.event_name||'')} <span style="font-size:8px;color:#f59e0b;font-weight:700">↳ side effect of ${esc(_rootWait?(_rootWait.event_name||'root cause'):'root cause')}</span></div><div style="font-size:8px;color:#94a3b8;margin-top:2px">${waitDiag(_sideWait.event_name||'')}</div></div>
            <div style="font-size:9px;color:#64748b;font-family:monospace">${f1(_sideWait.avg_wait_ms||0)}ms</div>
        </div>` : ''}
        ${_monitorWait ? `<div style="display:grid;grid-template-columns:70px 1fr auto;gap:10px;align-items:center;padding:8px 12px;background:rgba(99,102,241,0.04);border:1px solid rgba(99,102,241,0.2);border-left:4px solid #6366f1;border-radius:0 6px 6px 0">
            <div><div style="font-size:12px;font-weight:900;color:#6366f1">${f1(_monitorWait.pct_db_time||0)}%</div><div style="font-size:6px;color:#6366f1;font-weight:700;text-transform:uppercase">MONITOR</div></div>
            <div><div style="font-size:10px;color:#e2e8f0;font-weight:600">${esc(_monitorWait.event_name||'')} <span style="font-size:8px;color:#6366f1">monitor</span></div><div style="font-size:8px;color:#94a3b8;margin-top:2px">${waitDiag(_monitorWait.event_name||'')}</div></div>
            <div style="font-size:9px;color:#64748b;font-family:monospace">${f1(_monitorWait.avg_wait_ms||0)}ms</div>
        </div>` : ''}
        ${allWaits.length > 3 ? `<details style="margin-top:2px"><summary style="font-size:8px;color:#475569;cursor:pointer;user-select:none">Full Wait Event List (${allWaits.length} events)</summary>
            <div style="margin-top:6px">${s2Body}</div>
        </details>` : ''}
        </div>
    </div>` : '';

    // -- RECOMMENDED ACTIONS TABLE (clean 3-row, no raw SQL in main view) ------
    // Derive DBA toolkit queries to hide in collapsed expander
    const _dbaTkRows = [];
    if (primaryFd.action_1) _dbaTkRows.push({ label:'Action 1', sql: primaryFd.action_1 });
    if (primaryFd.action_2) _dbaTkRows.push({ label:'Action 2', sql: primaryFd.action_2 });
    if (primaryFd.action_3) _dbaTkRows.push({ label:'Action 3', sql: primaryFd.action_3 });
    // Always include standard DBA toolkit queries
    if (_domSql) {
        _dbaTkRows.push({ label:'View AWR Execution Plan', sql:`SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('${_domSql.sql_id||'?'}'));` });
    }
    _dbaTkRows.push({ label:'Latch Detail', sql:`SELECT origin, gets, misses, spin_gets FROM v$latch_children WHERE misses > 0 ORDER BY misses DESC FETCH FIRST 20 ROWS ONLY;` });
    if (addm.length > 0) {
        _dbaTkRows.push({ label:'ADDM Detail', sql: addm.slice(0,3).map(a=>`-- ${a.finding_name||a.finding||''}: ${a.avg_active_sessions||0} AAS`).join('\n') });
    }

    // Build 3 clean action rows (no raw SQL visible)
    const _actRows = [];
    if (_domSql) {
        const _a1outcome = _domSql.isPlanChg
            ? 'Lock good plan via SQL Plan Baseline — prevents further plan regressions'
            : _domSql.isNew
            ? 'Identify access path and resource cost — enables targeted tuning decision'
            : 'Identify plan regressions and missing index opportunities — reduce gets/exec';
        const _a1action = _domSql.isPlanChg
            ? `Run SQL Tuning Advisor on SQL ${_domSql.sql_id||'?'} — compare old and new plan via DBA_HIST_SQL_PLAN`
            : _domSql.isNew
            ? `Capture and review execution plan for SQL ${_domSql.sql_id||'?'} — check bind variables and access path via SQL Monitor`
            : `Run SQL Tuning Advisor on SQL ${_domSql.sql_id||'?'} — identify access path improvements and stale statistics`;
        _actRows.push({ prio:'1 — Critical', action: _a1action, outcome: _a1outcome, color:'#ef4444' });
    } else if (topFindings.length > 0 && primaryFd.fix_statement) {
        _actRows.push({ prio:'1 — Critical', action: primaryFd.fix_statement, outcome: primaryFd.validate_by||'Verify DB Time reduction in next AWR period', color:'#ef4444' });
    }
    // Row 2: infrastructure/schema
    const _infAction = _primaryCauseCategory === 'CPU_SATURATION'
        ? `Reduce buffer gets per execution — verify bind variable usage; check cursor_sharing and hard parse rate`
        : _primaryCauseCategory === 'IO_PRESSURE'
        ? `Review physical I/O access path — check DBA_HIST_SEG_STAT for top segments; evaluate missing indexes`
        : _primaryCauseCategory === 'REDO_COMMIT'
        ? `Reduce commit frequency — evaluate batch commit patterns; move redo logs to fastest storage tier`
        : _primaryCauseCategory === 'CONCURRENCY'
        ? `Investigate latch/lock contention — check V$EVENT_HISTOGRAM; review hot block segments`
        : `Review top wait event access path and check for stale object statistics`;
    const _infOutcome = _primaryCauseCategory === 'CPU_SATURATION'
        ? `Lower CPU utilisation — AAS should drop below CPU count threshold`
        : `Reduce DB Time contribution of identified wait category`;
    _actRows.push({ prio:'2 — Important', action: _infAction, outcome: _infOutcome, color:'#f59e0b' });
    // Row 3: monitor/validate
    const _monAction = _monitorWait
        ? `Track "${_monitorWait.event_name||''}" wait across next 3 AWR periods — alert if DB Time% exceeds 5%`
        : `Re-run AWR comparison after fix to confirm DB Time reduction and wait event normalisation`;
    const _monOutcome = `Prevent secondary risk from escalating to primary bottleneck`;
    _actRows.push({ prio:'3 — Monitor', action: _monAction, outcome: _monOutcome, color:'#6366f1' });

    const _validateStr = primaryFd.validate_by || 'Re-run AWR comparison after fix; confirm DB Time reduction and wait event normalization';

    const fixHtml = `<div style="margin-bottom:14px">
        <div style="font-size:9px;color:#10b981;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">Recommended Actions</div>
        <table style="width:100%;border-collapse:collapse;background:rgba(10,16,30,0.9);border:1px solid rgba(30,41,59,0.8);border-radius:6px;overflow:hidden">
            <thead><tr>
                <th style="font-size:7px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 10px;text-align:left;border-bottom:1px solid rgba(30,41,59,0.8);width:100px">Priority</th>
                <th style="font-size:7px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 10px;text-align:left;border-bottom:1px solid rgba(30,41,59,0.8)">Action</th>
                <th style="font-size:7px;color:#475569;font-weight:700;text-transform:uppercase;padding:5px 10px;text-align:left;border-bottom:1px solid rgba(30,41,59,0.8)">Expected Outcome</th>
            </tr></thead>
            <tbody>${_actRows.map(r=>`<tr>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(15,23,42,0.6)"><span style="font-size:8px;font-weight:800;color:${r.color}">${r.prio}</span></td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(15,23,42,0.6);font-size:9px;color:#cbd5e1;line-height:1.4">${esc(r.action)}</td>
                <td style="padding:6px 10px;border-bottom:1px solid rgba(15,23,42,0.6);font-size:9px;color:#64748b;line-height:1.4">${esc(r.outcome)}</td>
            </tr>`).join('')}</tbody>
        </table>
        <details style="margin-top:6px">
            <summary style="font-size:8px;color:#475569;cursor:pointer;user-select:none;padding:4px 8px;background:rgba(15,23,42,0.5);border-radius:4px;border:1px solid rgba(30,41,59,0.5)">DBA Investigation Toolkit — click to expand</summary>
            <div style="margin-top:6px;padding:8px 12px;background:rgba(10,16,30,0.95);border:1px solid rgba(30,41,59,0.8);border-radius:4px">
                ${_dbaTkRows.map(r=>`<div style="margin-bottom:8px"><div style="font-size:7px;color:#475569;font-weight:700;text-transform:uppercase;margin-bottom:2px">${esc(r.label)}</div><pre style="font-family:monospace;font-size:8px;color:#94a3b8;white-space:pre-wrap;word-break:break-all;margin:0;padding:4px 8px;background:rgba(15,23,42,0.8);border-radius:3px">${esc(r.sql)}</pre></div>`).join('')}
                ${(vd.evidence_fields||[]).length?`<div style="margin-top:6px;display:flex;flex-wrap:wrap;gap:4px"><div style="font-size:7px;color:#475569;font-weight:700;text-transform:uppercase;width:100%;margin-bottom:2px">Evidence Chain</div>${(vd.evidence_fields||[]).map(f=>`<span style="background:rgba(99,102,241,0.12);color:#818cf8;font-size:8px;padding:1px 6px;border-radius:3px;font-family:monospace">${esc(f)}</span>`).join('')}</div>`:''}
            </div>
        </details>
    </div>`;

    // -- ADDM: single-line badge only ------------------------------------------
    const _addmNames = [...new Set(addm.map(a=>a.finding_name||a.finding||'').filter(Boolean))];
    const addmHtml = _addmNames.length > 0 ? `<div style="margin-bottom:10px;padding:5px 10px;background:rgba(52,211,153,0.06);border:1px solid rgba(52,211,153,0.2);border-radius:5px;display:flex;align-items:center;gap:8px">
        <span style="font-size:8px;color:#34d399;font-weight:700;text-transform:uppercase;flex-shrink:0">ADDM Confirmed:</span>
        <span style="font-size:9px;color:#64748b">${esc(_addmNames.slice(0,3).join(' + '))} findings corroborate this verdict</span>
    </div>` : '';

    // -- DB TIME WATERFALL — shows how DB Time is consumed --------------------
    // Horizontal stacked bar: [DOMINANT SQL %] + [SIGNIFICANT SQLs %] + [Minor %] + [Unexplained %]
    const _waterfallSegments = [];
    let _accounted = 0;
    topSqls.forEach(s => {
        const pdb = s.pct_db_time || 0;
        if (pdb < 0.5) return;
        const dom = pdb >= 25 ? 'DOMINANT' : pdb >= 5 ? 'SIGNIFICANT' : 'MINOR';
        const col = dom === 'DOMINANT' ? '#a855f7' : dom === 'SIGNIFICANT' ? '#f59e0b' : '#475569';
        _waterfallSegments.push({ label: s.sql_id || '?', pct: pdb, col, dom, isNew: !!s.isNew });
        _accounted += pdb;
    });
    // Add "Other" segment
    const _otherPct = Math.max(0, 100 - _accounted);
    if (_otherPct > 0.5) {
        _waterfallSegments.push({ label: 'Other/Background', pct: _otherPct, col: '#1e293b', dom: 'OTHER', isNew: false });
    }

    const waterfallHtml = _waterfallSegments.length > 1 ? `
    <div style="margin-top:14px">
        <div style="font-size:9px;color:#a5b4fc;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:8px">DB Time Decomposition</div>
        <div style="position:relative;height:28px;border-radius:5px;overflow:hidden;display:flex;background:#0f172a;border:1px solid rgba(99,102,241,0.15)">
            ${_waterfallSegments.map(seg => {
                const w = Math.max(seg.pct, 2); // min width for visibility
                return '<div style="width:' + w + '%;background:' + seg.col + '20;border-right:1px solid rgba(15,23,42,0.8);display:flex;flex-direction:column;justify-content:center;align-items:center;overflow:hidden;position:relative" title="' + esc(seg.label) + ': ' + f1(seg.pct) + '% DB Time">' +
                    (seg.pct >= 8 ? '<div style="font-size:7px;color:' + seg.col + ';font-weight:800;white-space:nowrap;overflow:hidden;text-overflow:ellipsis;max-width:90%;text-align:center">' + esc(seg.label) + '</div>' : '') +
                    (seg.pct >= 5 ? '<div style="font-size:9px;font-weight:900;color:' + seg.col + '">' + f1(seg.pct) + '%</div>' : '') +
                '</div>';
            }).join('')}
        </div>
        <div style="display:flex;gap:10px;margin-top:4px;flex-wrap:wrap">
            ${_waterfallSegments.filter(s=>s.pct>=2).map(seg =>
                '<div style="display:flex;align-items:center;gap:3px"><div style="width:8px;height:8px;border-radius:2px;background:' + seg.col + '40"></div><span style="font-size:7px;color:#64748b">' + esc(seg.label) + (seg.isNew?' (NEW)':'') + ' · ' + f1(seg.pct) + '%</span></div>'
            ).join('')}
        </div>
    </div>` : '';

    // --------------------------------------------------------------------------
    // FINAL ASSEMBLED VERDICT — 7-section layout
    // 1. CONCLUSIVE VERDICT BOX
    // 2. DOMINANT SQL CARD
    // 3. THREE-ITEM WAIT CAUSALITY STRIP
    // 4. PE NARRATIVE (four-part, injected externally via compNarrative)
    // 5. RECOMMENDED ACTIONS TABLE
    // 6. DBA INVESTIGATION TOOLKIT (collapsed)
    // 7. AWR CONFIRMATION FOOTER
    // --------------------------------------------------------------------------

    // -- DISQUALIFIED line -----------------------------------------------------
    const _ev = ctx.verdict || {};
    const _disqParts = (_ev.disqualifiedCategories||[]).slice(0,3).map(d=>`${d.category}: ${d.reason.split('.')[0]}`);
    // Guardrail: always add latch disqualification if latch < 5%
    if (_latchPct < 5 && !_disqParts.some(d=>d.startsWith('LATCH'))) {
        _disqParts.push(`LATCH rejected — ${f1(_latchPct)}% DB Time, below 5% threshold`);
    }
    const _disqLine = _disqParts.length > 0
        ? `<div style="margin-top:8px;padding-top:6px;border-top:1px solid rgba(255,255,255,0.05)"><span style="font-size:7px;color:#334155;font-weight:700;text-transform:uppercase">Disqualified: </span><span style="font-size:8px;color:#475569">${esc(_disqParts.join('; '))}</span></div>` : '';

    // -- CONCLUSIVE VERDICT BOX ------------------------------------------------
    const _causeLabel = _primaryCauseCategory.replace(/_/g,' ');
    const _causeCol = {
        CONCURRENT_DML_BOTTLENECK:'#ef4444', BUFFER_WRITE_PRESSURE:'#f59e0b',
        HW_ENQUEUE_CONTENTION:'#dc2626', TX_INDEX_CONTENTION:'#ef4444',
        TX_ROW_LOCK_CONTENTION:'#f43f5e', UNDO_SEGMENT_EXTENSION:'#fb923c',
        LIBRARY_CACHE_PRESSURE:'#ec4899',
        SQL_DOMINANT:'#a855f7', NEW_SQL:'#c084fc', PLAN_CHANGE:'#ef4444',
        CPU_SATURATION:'#f87171', IO_PRESSURE:'#f97316', REDO_COMMIT:'#f59e0b',
        CONCURRENCY:'#ef4444', TEMP_SPILL:'#06b6d4', UNKNOWN:'#475569'
    }[_primaryCauseCategory] || '#475569';

    const _mechText = _primaryCauseCategory === 'HW_ENQUEUE_CONTENTION'
        ? `Concurrent ${esc(_domSqlVerb||'INSERT')} sessions are queueing on the High-Water mark (HW) enqueue while one session formats blocks above HWM in the target segment${_domSql && _domSql.sql_id?` (SQL ${esc(_domSql.sql_id)})`:''}. enq: HW - contention absorbs <b>${f1(_hwEnqPct)}% DB Time</b> with average waits in the multi-second range. The SQL itself is a symptom carrier — every execution stalls at extent boundary. The actionable fix is on the segment: switch to uniform LMT extents, pre-allocate space, raise NEXT extent size, enable parallel space-management, partition the table, or relocate LOB segments to dedicated tablespaces.`
        : _primaryCauseCategory === 'TX_INDEX_CONTENTION'
        ? `enq: TX - index contention at <b>${f1(_txIdxPct)}% DB Time</b> indicates concurrent DML on the same index leaf block — typically a right-growing key (sequence-based), a hot range, or a branch-block split. The fix is on the index: hash-partition the index, use a reverse-key index for sequence-based primary keys, or raise the index INITRANS / PCTFREE so multiple transactions can update the same block without serialising.`
        : _primaryCauseCategory === 'TX_ROW_LOCK_CONTENTION'
        ? `enq: TX - row lock contention at <b>${f1(_txRowPct)}% DB Time</b> — sessions are blocking on application-level row locks. Identify the holder via the blocking-session tree (V$SESSION.BLOCKING_SESSION) and review transaction scoping, commit cadence, and SELECT FOR UPDATE patterns in the application.`
        : _primaryCauseCategory === 'UNDO_SEGMENT_EXTENSION'
        ? `enq: US - contention at <b>${f1(_usEnqPct)}% DB Time</b> — UNDO tablespace cannot expand fast enough to keep pace with concurrent DML. Enlarge UNDO tablespace, raise UNDO_RETENTION, or switch the UNDO datafile to autoextend with a larger NEXT increment.`
        : (_primaryCauseCategory === 'CONCURRENT_DML_BOTTLENECK' || _primaryCauseCategory === 'BUFFER_WRITE_PRESSURE')
        ? `DBWR cannot drain dirty buffers fast enough — sessions stall on free buffer waits (${f1(_freeBufPct)}% DB Time)${_bufBusyPct?`, downstream buffer-busy waits (${f1(_bufBusyPct)}%)`:''}${_fbEnqPct?` and FB-enqueue contention (${f1(_fbEnqPct)}%)`:''}. ${(_primaryCauseCategory === 'CONCURRENT_DML_BOTTLENECK' && _domSql)?`The concurrent <b>${esc(_domSqlVerb)}</b> on ${esc(_domSql.sql_id||'?')} is producing dirty blocks faster than the database writer can flush them.`:'A high-DML workload is producing dirty blocks faster than the database writer can flush them.'} Tuning the SQL alone will not help — the buffer cache size and DBWR throughput must be addressed.`
        : _primaryCauseCategory === 'SQL_DOMINANT' || _primaryCauseCategory === 'NEW_SQL' || _primaryCauseCategory === 'PLAN_CHANGE'
        ? (_domSql ? `SQL ${esc(_domSql.sql_id||'?')} is consuming ${f1(_domSqlPct)}% of DB Time via ${((_domSql.disk_reads_total||_domSql.disk_reads||0)>5000?'physical I/O reads':(_domSql.buffer_gets_per_exec||_domSql.buffer_gets||0)>50000?'high buffer gets':'CPU-intensive execution')}. ${_primaryCauseCategory==='PLAN_CHANGE'?'An execution plan change caused a significant increase in per-execution resource cost.':_primaryCauseCategory==='NEW_SQL'?'This SQL was not present in the baseline period — it introduced new workload.':'Execution volume combined with resource cost per execution is driving the bottleneck.'}` : `Dominant SQL pattern is the primary resource consumer.`)
        : _primaryCauseCategory === 'CPU_SATURATION'
        ? `Database CPU is fully saturated — AAS is meeting or exceeding CPU count. ${topSqls.length>0?'The top SQL workload is the primary CPU consumer.':''} Sessions are queuing for CPU time rather than waiting on I/O.`
        : _primaryCauseCategory === 'IO_PRESSURE'
        ? `Physical I/O waits are dominating DB Time — disk reads are the primary constraint. ${topSqls.length>0?'Top SQL statements are generating excessive block reads.':''}`
        : _primaryCauseCategory === 'REDO_COMMIT'
        ? `Commit frequency is driving log file sync waits. High DML rate is pushing redo I/O to become the primary constraint.`
        : `Session workload is generating resource contention across multiple categories.`;

    const _sideEffectList = (_ev.sideEffects||[]).length > 0 ? (_ev.sideEffects||[]).slice(0,4).join(', ') :
        [_latchPct > 0.5 && _latchPct < 5 ? 'latch contention (minor)' : null,
         commitPct > 2 && _primaryCauseCategory !== 'REDO_COMMIT' ? 'log file sync' : null,
        ].filter(Boolean).join(', ') || 'none significant';

    const _bizImpact = _domSqlPct >= 25
        ? `End-user transactions dependent on the dominant SQL workload are experiencing elevated response times proportional to the ${f1(_domSqlPct)}% DB Time consumption.`
        : dbCpuPct >= 40
        ? `Database CPU saturation is causing all sessions to queue for compute resources, increasing latency across the entire application.`
        : `Performance degradation is concentrated in workloads that depend on the affected Oracle resource category.`;

    const _verdictBoxHtml = `<div style="background:${hs.bg};border:1px solid ${hs.border};border-left:4px solid ${_causeCol};border-radius:8px;padding:14px 18px;margin-bottom:14px">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px">
            <div style="width:10px;height:10px;border-radius:50%;background:${_causeCol};box-shadow:0 0 8px ${_causeCol}"></div>
            <span style="font-size:11px;font-weight:900;color:${_causeCol};text-transform:uppercase;letter-spacing:0.8px">${_causeLabel}</span>
            ${_isParallelVerdict?'<span style="background:rgba(129,140,248,0.15);color:#818cf8;font-size:8px;padding:2px 6px;border-radius:3px;font-weight:800">⟥ PARALLEL</span>':''}
            <div style="margin-left:auto;display:flex;align-items:center;gap:6px">
                <span style="font-size:7px;color:#64748b;text-transform:uppercase;font-weight:700">Confidence</span>
                <span style="font-size:11px;font-weight:900;color:${confColor}">${confLevel}</span>
            </div>
        </div>
        <table style="width:100%;border-collapse:collapse">
            <tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 0;width:120px;vertical-align:top">Primary Cause</td>
                <td style="font-size:10px;color:#e2e8f0;font-weight:600;padding:4px 0;line-height:1.4">${esc(report.verdict||_causeLabel)}</td></tr>
            ${_domSql ? `<tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 0;vertical-align:top">Dominant SQL</td>
                <td style="font-size:10px;color:#a5b4fc;font-family:monospace;padding:4px 0"><b>${esc(_domSql.sql_id||'?')}</b> — ${f1(_domSqlPct)}% DB Time · ${comma(_domSql.executions||0)} execs · ${comma(Math.round(_domSql.buffer_gets_per_exec||_domSql.buffer_gets||0))} gets/exec</td></tr>` : ''}
            <tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 0;vertical-align:top">Mechanism</td>
                <td style="font-size:9px;color:#94a3b8;padding:4px 0;line-height:1.5">${esc(_mechText)}</td></tr>
            <tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 0;vertical-align:top">Business Impact</td>
                <td style="font-size:9px;color:#94a3b8;padding:4px 0;line-height:1.5">${esc(_bizImpact)}</td></tr>
            <tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 0;vertical-align:top">Side Effects</td>
                <td style="font-size:9px;color:#64748b;padding:4px 0">${esc(_sideEffectList)}</td></tr>
        </table>
        ${_disqLine}
        ${addmHtml}
        <div style="display:flex;gap:12px;padding-top:8px;margin-top:4px;border-top:1px solid rgba(255,255,255,0.05)">
            <span style="font-size:7px;color:#64748b">${confFactors.join(' · ')}</span>
        </div>
    </div>`;

    // ---------------------------------------------------------------------------
    // UNIFIED DETERMINISTIC CONCLUSIVE FLOW
    // Synthesizes signals from ALL tabs into a single conclusive direction.
    // Layers: TL;DR ? KEY SIGNAL ? WHY ? CONFIDENCE ? NEXT ACTION ? VALIDATION
    // ---------------------------------------------------------------------------
    // Hoisted: shared between the inner conclusive-flow IIFE (which populates
    // it) and the outer Action Priority Queue / Fix Impact Simulator wiring
    // (which consumes it). Must live in function scope, not the IIFE.
    let actions = [];
    const _conclusiveFlowHtml = (() => {
        // Local formatting helpers (f1/fN/comma/esc are in outer scope)
        const f0 = v => Math.round(+v||0).toLocaleString();
        const f2 = v => (+v||0).toFixed(2);
        const cat = _primaryCauseCategory;
        const sev = report.overall_health || 'WARNING';
        const sevCol = hs.color;

        // -- Signal aggregation across tabs ----------------------------------
        const dbTimeG = (lp1.db_time_s||0), dbTimeB = (lp2.db_time_s||0);
        const dbTimeDeltaPct = dbTimeG > 0 ? ((dbTimeB - dbTimeG)/dbTimeG*100) : 0;
        const aasG = ctx.aas?.good || 0, aasB = ctx.aas?.bad || 0;
        const cpus = ctx.meta?.cpu_count || 0;
        const cpuUtilB = cpus > 0 ? (aasB/cpus*100) : 0;
        const elapsedG = (ctx.meta?.good?.elapsed_min||0), elapsedB = (ctx.meta?.bad?.elapsed_min||0);
        const sessHrG = elapsedG > 0 ? ((d1.snapshot_info?.total_sessions||0)/(elapsedG/60)) : 0;
        const sessHrB = elapsedB > 0 ? ((d2.snapshot_info?.total_sessions||0)/(elapsedB/60)) : 0;

        // Top wait events (problem period, sorted)
        const topW1 = allWaits[0] || null;
        const topW2 = allWaits[1] || null;
        const topW3 = allWaits[2] || null;

        // Side-effect tagging for top wait
        const isSideEffect = topW1 && (_ev.sideEffects||[]).some(se =>
            (topW1.event_name||'').toLowerCase().includes((se||'').toLowerCase().replace(/_/g,' ')));

        // Load profile shifts (top 3)
        const lpShifts = topLP.slice(0,3);

        // Plan change detection on dominant SQL
        const _domPlanChg = _domSql && _domSql.isPlanChg;
        const _domIsNew = _domSql && _domSql.isNew;
        const _domIsReg = _domSql && _domSql.isReg;

        // Efficiency degradation
        const cacheDegPct = (effGood.buffer_cache_hit_pct||0) - (effBad.buffer_cache_hit_pct||0);
        const parseDegPct = (effGood.soft_parse_pct||0) - (effBad.soft_parse_pct||0);

        // -- LAYER 1: TL;DR — 2-3 line conclusive synthesis -----------------
        let tldr = '';
        if (cat === 'HW_ENQUEUE_CONTENTION') {
            const _domTbl = _domSql ? ((Array.isArray(_domSql.tables_referenced) && _domSql.tables_referenced[0]) || _domSql.table_name || '') : '';
            tldr = `<b>Segment HWM extension is the bottleneck</b> — <b>enq: HW - contention</b> absorbs <b style="color:${sevCol}">${f1(_hwEnqPct)}%</b> DB Time${_domSql?` while concurrent <b>${esc(_domSqlVerb||'INSERT')}</b> on SQL <b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b>${_domTbl?` (target ${esc(_domTbl)})`:''} accumulates ${f1(_domSqlPct)}% DB Time as a symptom carrier`:''}. Sessions queue while one extends the segment above the high-water mark. <b>Tuning the SQL will not help</b> — fix the segment: switch to uniform LMT extents, pre-allocate space (<code>ALTER TABLE … ALLOCATE EXTENT</code>), raise NEXT extent size, partition the table, or relocate LOB segments to a dedicated tablespace.`;
        } else if (cat === 'TX_INDEX_CONTENTION') {
            tldr = `<b>Hot index block / branch-split contention</b> — <b>enq: TX - index contention</b> at <b style="color:${sevCol}">${f1(_txIdxPct)}%</b> DB Time. Concurrent DML on the same index leaf block is serialising sessions (typically a sequence-based right-growing key). Hash-partition the index, switch sequence-keyed indexes to reverse-key, or raise the index INITRANS / PCTFREE so multiple transactions can update the same block.`;
        } else if (cat === 'TX_ROW_LOCK_CONTENTION') {
            tldr = `<b>Application row-lock contention</b> — <b>enq: TX - row lock contention</b> at <b style="color:${sevCol}">${f1(_txRowPct)}%</b> DB Time. Sessions are blocking on application-level row locks. Identify the holder via the blocking-session tree and review transaction scoping, commit cadence, and SELECT FOR UPDATE patterns.`;
        } else if (cat === 'UNDO_SEGMENT_EXTENSION') {
            tldr = `<b>Undo segment expansion bottleneck</b> — <b>enq: US - contention</b> at <b style="color:${sevCol}">${f1(_usEnqPct)}%</b> DB Time. The UNDO tablespace cannot expand fast enough for the concurrent DML rate. Enlarge UNDO tablespace, raise UNDO_RETENTION, or switch the UNDO datafile to autoextend with a larger NEXT increment.`;
        } else if (cat === 'CONCURRENT_DML_BOTTLENECK' && _domSql) {
            const _domTbl = (Array.isArray(_domSql.tables_referenced) && _domSql.tables_referenced[0]) || _domSql.table_name || '';
            tldr = `Concurrent <b>${esc(_domSqlVerb)}</b> ${_domTbl?`into <b>${esc(_domTbl)}</b>`:''} (SQL <b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b>, ${f1(_domSqlPct)}% DB Time across ${comma(_domSql.executions||0)} execs) is producing dirty buffers faster than DBWR can drain them — driving <b>free buffer waits ${f1(_freeBufPct)}%</b>${_fbEnqPct?`, FB-enq ${f1(_fbEnqPct)}%`:''}${_bufBusyPct?`, buffer busy ${f1(_bufBusyPct)}%`:''}, and back-pressuring LGWR (log file sync ${f1(commitPct)}%). The SQL itself is a <b>symptom carrier</b>, not a tunable per-statement defect — increase <code>db_writer_processes</code>, raise <code>db_cache_size</code>, and review concurrent-INSERT pattern (partitioning / APPEND hint) before tuning the statement.`;
        } else if (cat === 'BUFFER_WRITE_PRESSURE') {
            tldr = `<b>DBWR / buffer-cache write throughput is exhausted</b> — <b>free buffer waits ${f1(_freeBufPct)}% DB Time</b>${_bufBusyPct?` (with buffer busy waits ${f1(_bufBusyPct)}%`:''}${_fbEnqPct?`${_bufBusyPct?', ':' ('}FB-enq ${f1(_fbEnqPct)}%`:''}${(_bufBusyPct||_fbEnqPct)?')':''} as downstream symptoms. Sessions are stalled waiting for free buffers. Increase <code>db_writer_processes</code>, raise <code>db_cache_size</code>, and check write-IO latency before tuning individual SQL.`;
        } else if (cat === 'PLAN_CHANGE' && _domSql) {
            tldr = `Execution plan regression on SQL <b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b> is consuming <b style="color:${sevCol}">${f1(_domSqlPct)}%</b> of DB Time. Plan hash changed between baseline and problem windows, multiplying per-execution cost. Pin the prior plan via SQL Plan Management to restore baseline performance.`;
        } else if (cat === 'NEW_SQL' && _domSql) {
            tldr = `New SQL <b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b> appeared in the problem window and now consumes <b style="color:${sevCol}">${f1(_domSqlPct)}%</b> of DB Time. This statement was not present in the baseline. Identify the originating module/job and tune predicates, indexes, or hints before promoting workload.`;
        } else if (cat === 'SQL_DOMINANT' && _domSql) {
            tldr = `SQL <b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b> dominates with <b style="color:${sevCol}">${f1(_domSqlPct)}%</b> DB Time across ${comma(_domSql.executions||0)} executions. ${_domIsReg?'Per-execution elapsed time has regressed >20% versus baseline. ':''}Tune this single statement first — it accounts for the majority of database time.`;
        } else if (cat === 'CPU_SATURATION') {
            tldr = `Database CPU is saturated — <b style="color:${sevCol}">${f1(cpuUtilB)}%</b> CPU utilisation (AAS ${f1(aasB)} on ${cpus} cores). DB CPU consumes ${f1(dbCpuPct)}% of DB Time. All sessions queue for compute. Reduce concurrent workload or add CPU capacity.`;
        } else if (cat === 'IO_PRESSURE') {
            const ioEv = allWaits.find(e => /db file|direct path/i.test(e.event_name||''));
            tldr = `Physical I/O dominates DB Time at <b style="color:${sevCol}">${f1(ioPct)}%</b>${ioEv?` led by <b>${esc(ioEv.event_name)}</b> (${f1(ioEv.avg_wait_ms||0)} ms/wait)`:''}. Storage subsystem latency or buffer-cache miss rate is the primary constraint. Investigate segment hotspots and cache sizing.`;
        } else if (cat === 'REDO_COMMIT') {
            tldr = `Commit overhead is the primary bottleneck — <b>log file sync</b> accounts for <b style="color:${sevCol}">${f1(commitPct)}%</b> of DB Time. High DML/commit frequency is driving redo I/O. Batch commits or relocate LGWR storage tier.`;
        } else if (cat === 'CONCURRENCY' || cat === 'CONCURRENCY_LOCK') {
            tldr = `Concurrency contention dominates — latch/lock waits at <b style="color:${sevCol}">${f1(_latchPct + concPct)}%</b> DB Time. Sessions are blocking on shared resources. Investigate ITL settings, hot blocks, or transaction patterns.`;
        } else {
            tldr = `No single dominant signal — DB Time grew <b style="color:${sevCol}">${f1(dbTimeDeltaPct)}%</b> with workload distributed across multiple categories. Manual ASH analysis recommended to identify session-level patterns.`;
        }

        // -- LAYER 2: KEY SIGNAL — single most important metric with cross-refs -
        let keySigLabel = '', keySigValue = '', keySigContext = '', keySigRef = '';
        if (cat === 'HW_ENQUEUE_CONTENTION') {
            const _hwEv = allWaits.find(e => /enq:\s*HW\s*-/i.test(e.event_name||''));
            keySigLabel = 'Segment HWM Enqueue';
            keySigValue = `${f1(_hwEnqPct)}% DB Time`;
            keySigContext = `${_hwEv?`avg ${f1(_hwEv.avg_wait_ms||0)} ms/wait · `:''}DB CPU only ${f1(dbCpuPct)}% · workload ${f1(dbTimeDeltaPct||0)>0?'+':''}${f1(dbTimeDeltaPct||0)}%${_domSql?` · symptom-carrier SQL ${esc(_domSql.sql_id)} ${f1(_domSqlPct)}%`:''}`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="waits" style="color:#818cf8;text-decoration:underline">Wait Events</a> + <a href="#" data-rca-tab="sql" style="color:#818cf8;text-decoration:underline">SQL Comparison</a> (target table for segment-level fix).`;
        } else if (cat === 'TX_INDEX_CONTENTION') {
            keySigLabel = 'Hot Index Block Serialisation';
            keySigValue = `${f1(_txIdxPct)}% DB Time`;
            keySigContext = `enq: TX - index contention${_bufBusyPct?` · buffer busy ${f1(_bufBusyPct)}%`:''} · DB CPU only ${f1(dbCpuPct)}%${_domSql?` · DML SQL ${esc(_domSql.sql_id)}`:''}`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="sql" style="color:#818cf8;text-decoration:underline">SQL Comparison</a> for the dominant DML statement and target index.`;
        } else if (cat === 'TX_ROW_LOCK_CONTENTION') {
            keySigLabel = 'Application Row-Lock Contention';
            keySigValue = `${f1(_txRowPct)}% DB Time`;
            keySigContext = `enq: TX - row lock contention · DB CPU only ${f1(dbCpuPct)}%`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="waits" style="color:#818cf8;text-decoration:underline">Wait Events</a> + ASH blocking-session tree.`;
        } else if (cat === 'UNDO_SEGMENT_EXTENSION') {
            keySigLabel = 'Undo Tablespace Expansion';
            keySigValue = `${f1(_usEnqPct)}% DB Time`;
            keySigContext = `enq: US - contention · DB CPU only ${f1(dbCpuPct)}%`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="profile" style="color:#818cf8;text-decoration:underline">Load Profile</a> (block changes, transactions).`;
        } else if (cat === 'CONCURRENT_DML_BOTTLENECK' || cat === 'BUFFER_WRITE_PRESSURE') {
            keySigLabel = 'DBWR Backlog Signature';
            keySigValue = `${f1(_freeBufPct)}% free buffer waits`;
            keySigContext = `${_bufBusyPct?`buffer busy ${f1(_bufBusyPct)}% · `:''}${_fbEnqPct?`FB-enq ${f1(_fbEnqPct)}% · `:''}log file sync ${f1(commitPct)}% · DB CPU only ${f1(dbCpuPct)}% · DB Time +${f1(dbTimeDeltaPct||0)}%`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="waits" style="color:#818cf8;text-decoration:underline">Wait Events</a> + <a href="#" data-rca-tab="profile" style="color:#818cf8;text-decoration:underline">Load Profile</a> (transactions, block changes, physical writes).`;
        } else if (_domSql && _domSqlPct >= 15) {
            keySigLabel = 'Dominant SQL DB Time Share';
            keySigValue = f1(_domSqlPct) + '% DB Time';
            const epe = _domSql.epe2 || _domSql.avg_elapsed_secs || 0;
            keySigContext = `<b style="font-family:monospace;color:#a5b4fc">${esc(_domSql.sql_id)}</b> · ${comma(_domSql.executions||0)} execs · ${f2(epe)} s/exec · ${comma(Math.round(_domSql.buffer_gets_per_exec||0))} gets/exec`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="sql" style="color:#818cf8;text-decoration:underline">SQL Comparison tab</a> for full plan, predicates, and execution details.`;
        } else if (cat === 'CPU_SATURATION') {
            keySigLabel = 'CPU Utilisation';
            keySigValue = f1(cpuUtilB) + '%';
            keySigContext = `AAS ${f1(aasB)} on ${cpus} CPUs · DB CPU ${f1(dbCpuPct)}% of DB Time`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="profile" style="color:#818cf8;text-decoration:underline">Load Profile</a> + <a href="#" data-rca-tab="time" style="color:#818cf8;text-decoration:underline">Time Model</a>.`;
        } else if (topW1) {
            keySigLabel = 'Top Wait Event';
            keySigValue = f1(topW1.pct_db_time||0) + '% DB Time';
            keySigContext = `<b>${esc(topW1.event_name)}</b> · ${f1(topW1.avg_wait_ms||0)} ms/wait · ${comma(topW1.total_waits||0)} waits${topW1.isNew?' · <span style="color:#c084fc">NEW</span>':''}`;
            keySigRef = `Cross-reference: <a href="#" data-rca-tab="waits" style="color:#818cf8;text-decoration:underline">Wait Events tab</a>.`;
        } else {
            keySigLabel = 'DB Time Growth';
            keySigValue = (dbTimeDeltaPct>=0?'+':'') + f1(dbTimeDeltaPct) + '%';
            keySigContext = `Baseline ${f0(dbTimeG)} s ? Problem ${f0(dbTimeB)} s · AAS ${f1(aasG)} → ${f1(aasB)}`;
            keySigRef = '';
        }

        // -- LAYER 3: WHY — multi-evidence causal chain --------------------
        const whyBullets = [];
        // Workload volume
        if (lpShifts.length > 0) {
            const ls = lpShifts[0];
            whyBullets.push({ icon:_iconSvg('chart','#94a3b8'), label:'Workload', text:`${esc(lpLabel(ls.key))} shifted ${ls.d>0?'+':''}${f1(ls.d)}% (${esc(ls.evidence||'')})`, ref:'profile' });
        }
        // SQL fingerprint
        if (_domSql) {
            const fp = (_domSql.disk_reads_total||_domSql.disk_reads||0) > 5000 ? 'Physical I/O signature' :
                       (_domSql.buffer_gets_per_exec||_domSql.buffer_gets||0) > 50000 ? 'Logical I/O (buffer gets) signature' :
                       (_domSql.cpu_time_secs||0)/Math.max(_domSql.elapsed_time_secs||1,1) > 0.7 ? 'CPU-bound signature' :
                       'Elapsed-time signature';
            const planTag = _domPlanChg ? ' · <span style="color:#ef4444;font-weight:800">PLAN CHANGED</span>' :
                            _domIsNew ? ' · <span style="color:#c084fc;font-weight:800">NEW SQL</span>' :
                            _domIsReg ? ' · <span style="color:#f59e0b;font-weight:800">REGRESSED >20%</span>' : '';
            whyBullets.push({ icon:_iconSvg('database','#94a3b8'), label:'SQL Driver', text:`<span style="font-family:monospace">${esc(_domSql.sql_id)}</span> — ${esc(fp)}${planTag}`, ref:'sql' });
        }
        // Wait causality
        if (topW1) {
            const waitDiagText = (typeof waitDiag === 'function') ? (waitDiag(topW1.event_name||'')||'') : '';
            const sideTag = isSideEffect ? ' · <span style="color:#94a3b8;font-style:italic">(side-effect of dominant SQL)</span>' : '';
            whyBullets.push({ icon:_iconSvg('clock','#94a3b8'), label:'Wait', text:`<b>${esc(topW1.event_name)}</b> at ${f1(topW1.pct_db_time||0)}% DB Time${waitDiagText?` — ${esc(waitDiagText)}`:''}${sideTag}`, ref:'waits' });
        }
        // Efficiency degradation
        if (cacheDegPct > 1 || parseDegPct > 2) {
            whyBullets.push({ icon:_iconSvg('chip','#94a3b8'), label:'Efficiency', text:`${cacheDegPct>1?`Buffer cache hit dropped ${f2(cacheDegPct)}pp`:''}${cacheDegPct>1&&parseDegPct>2?'; ':''}${parseDegPct>2?`Soft parse % dropped ${f1(parseDegPct)}pp`:''}`, ref:'eff' });
        }
        // ADDM corroboration
        if (addm.length > 0) {
            const top = addm.slice(0,2).map(a => esc(a.finding_name||a.finding||'')).filter(Boolean);
            if (top.length > 0) {
                whyBullets.push({ icon:_iconSvg('chip','#94a3b8'), label:'ADDM', text:`Confirms: ${top.join(' + ')}`, ref:'addm' });
            }
        }
        // Session intelligence
        const sessIntel = report.session_intelligence || {};
        if (sessIntel.delta && Math.abs(sessIntel.delta.churn_pct||0) > 10) {
            whyBullets.push({ icon:_iconSvg('users','#94a3b8'), label:'Sessions', text:`Session churn ${(sessIntel.delta.churn_pct>0?'+':'')+f1(sessIntel.delta.churn_pct)}% — ${esc(sessIntel.delta.churn_desc||'')}`, ref:'sessions' });
        }

        // Mechanism conclusion (synthesis)
        const whyConclusion = _mechText;

        // -- LAYER 4: CONFIDENCE — score + factor breakdown ----------------
        const confEvidence = [];
        if (topLP.length > 0) confEvidence.push({ ok:true, label:`Load Profile signals (${topLP.length})` });
        if (allWaits.length > 0) confEvidence.push({ ok:true, label:`Wait events ranked (${allWaits.length})` });
        if (topSqls.length > 0) confEvidence.push({ ok:true, label:`SQL attribution (top ${Math.min(topSqls.length,5)})` });
        if (addm.length > 0) confEvidence.push({ ok:true, label:`ADDM corroborates (${addm.length} findings)` }); else confEvidence.push({ ok:null, label:'ADDM findings absent' });
        if (corrLinks.length > 0) confEvidence.push({ ok:true, label:`${corrLinks.length} causal LP?Wait link(s)` });
        if (_domSql && _domPlanChg) confEvidence.push({ ok:true, label:'Plan hash change detected' });
        if (cacheDegPct > 1 || parseDegPct > 2) confEvidence.push({ ok:true, label:'Efficiency degradation confirmed' });
        const tsIO = (d1._tablespace_io||d2._tablespace_io);
        if (tsIO) confEvidence.push({ ok:true, label:'Tablespace I/O data available' }); else confEvidence.push({ ok:null, label:'Tablespace I/O not provided' });

        // -- LAYER 5: NEXT ACTION — context-aware specific actions ---------
        // Pull real snap-id boundaries from the AWR context so the SQL is copy-paste runnable.
        const _s1raw = (ctx._raw && (ctx._raw.s1 || ctx._raw.good)) || {};
        const _s2raw = (ctx._raw && (ctx._raw.s2 || ctx._raw.bad )) || {};
        const _snG_b = _s1raw.snap_begin || _s1raw.begin_snap || '<good_begin_snap>';
        const _snG_e = _s1raw.snap_end   || _s1raw.end_snap   || '<good_end_snap>';
        const _snB_b = _s2raw.snap_begin || _s2raw.begin_snap || '<bad_begin_snap>';
        const _snB_e = _s2raw.snap_end   || _s2raw.end_snap   || '<bad_end_snap>';
        const _tsB_b = _s2raw.snap_begin_time || _s2raw.begin_time || '<bad_start_time>';
        const _tsB_e = _s2raw.snap_end_time   || _s2raw.end_time   || '<bad_end_time>';
        // `actions` is hoisted to outer function scope — re-bind here.
        actions = [];
        if ((cat === 'PLAN_CHANGE' || _domPlanChg) && _domSql) {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Pin baseline execution plan via SQL Plan Management',
                sql:`-- Load baseline plan from AWR for SQL ${_domSql.sql_id}
-- Baseline window: ${_snG_b} → ${_snG_e}
DECLARE
  l_plans NUMBER;
BEGIN
  l_plans := DBMS_SPM.LOAD_PLANS_FROM_AWR(
    begin_snap => ${_snG_b},
    end_snap   => ${_snG_e},
    basic_filter => q'[sql_id = '${_domSql.sql_id}']'
  );
  DBMS_OUTPUT.PUT_LINE('Plans loaded: '||l_plans);
END;
/`,
                expect:'Forces optimizer to use the prior (good) plan, restoring baseline elapsed time.'
            });
            actions.push({
                prio:'IMPORTANT', col:'#f59e0b',
                title:'Validate object statistics on referenced tables/indexes',
                sql:`-- Identify segments referenced by the SQL\nSELECT object_owner, object_name, object_type\nFROM   v$sql_plan\nWHERE  sql_id = '${_domSql.sql_id}'\nAND    object_owner IS NOT NULL;\n\n-- Then refresh stats:\nEXEC DBMS_STATS.GATHER_TABLE_STATS('<owner>','<table>', cascade => TRUE);`,
                expect:'Stale statistics are a primary trigger of plan regressions; refreshing restores plan stability.'
            });
        } else if (cat === 'NEW_SQL' && _domSql) {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Identify originating module/action and tune predicates',
                sql:`-- Source attribution — problem window samples
SELECT module, action, parsing_schema_name, COUNT(*) samples
FROM   dba_hist_active_sess_history
WHERE  sql_id = '${_domSql.sql_id}'
AND    snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY module, action, parsing_schema_name
ORDER BY samples DESC FETCH FIRST 20 ROWS ONLY;`,
                expect:'Identifies the application module driving the new workload. Coordinate with application team before tuning.'
            });
            actions.push({
                prio:'IMPORTANT', col:'#f59e0b',
                title:'Review execution plan and add appropriate indexes/hints',
                sql:`-- Review plan\nSELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('${_domSql.sql_id}'));`,
                expect:'Confirms whether full table scans or sub-optimal joins are present. Add covering index or hint as needed.'
            });
        } else if (cat === 'HW_ENQUEUE_CONTENTION') {
            const _domTbl = _domSql ? ((Array.isArray(_domSql.tables_referenced) && _domSql.tables_referenced[0]) || _domSql.table_name || '') : '';
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:`Identify the segment generating HW-enqueue waits${_domTbl?` (suspect: ${_domTbl})`:''}`,
                sql:`-- Segments with HW-enq contention during the problem window
SELECT o.owner, o.object_name, o.object_type, o.subobject_name,
       COUNT(*) ash_samples, ROUND(SUM(ash.time_waited)/1e6,1) waited_secs
FROM   dba_hist_active_sess_history ash
JOIN   dba_objects o ON o.object_id = ash.current_obj#
WHERE  ash.event = 'enq: HW - contention'
AND    ash.snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY o.owner, o.object_name, o.object_type, o.subobject_name
ORDER BY waited_secs DESC FETCH FIRST 10 ROWS ONLY;`,
                expect:'Pinpoints the exact segment whose extension is causing the HW enqueue. The fix is on this segment.'
            });
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Pre-allocate extents on the hot segment to skip ahead of the high-water mark',
                sql:`-- Replace <owner>.<table> with the segment from the previous query
ALTER TABLE <owner>.<table> ALLOCATE EXTENT (SIZE 512M);
-- For partitioned segments, target the active partition:
-- ALTER TABLE <owner>.<table> MODIFY PARTITION <part> ALLOCATE EXTENT (SIZE 512M);
-- For LOB segments:
-- ALTER TABLE <owner>.<table> MODIFY LOB (<col>) (ALLOCATE EXTENT (SIZE 512M));`,
                expect:'Eliminates HW-enqueue immediately by extending the segment in advance of the INSERT workload.'
            });
            actions.push({
                prio:'IMPORTANT', col:'#f59e0b',
                title:'Switch tablespace to uniform large extents (long-term fix)',
                sql:`-- Check current tablespace allocation
SELECT tablespace_name, extent_management, allocation_type, initial_extent, next_extent
FROM   dba_tablespaces WHERE tablespace_name IN
       (SELECT tablespace_name FROM dba_segments WHERE segment_name = '<TABLE_NAME>');
-- If allocation is SYSTEM, recreate as UNIFORM SIZE 64M (or larger, sized for write rate)`,
                expect:'Uniform extents prevent the storm of small extent-extensions that drives HW contention.'
            });
            if (_domSql) {
                actions.push({
                    prio:'INVESTIGATE', col:'#06b6d4',
                    title:`Confirm SQL ${_domSql.sql_id} is the symptom carrier (not the root cause)`,
                    sql:`SELECT sql_id, executions_delta execs,
       ROUND(elapsed_time_delta/GREATEST(executions_delta,1)/1e6, 3) avg_elap_s,
       ROUND(SUM(elapsed_time_delta) OVER ()/1e6,1) total_elap_s
FROM   dba_hist_sqlstat
WHERE  sql_id = '${_domSql.sql_id}' AND snap_id BETWEEN ${_snB_b} AND ${_snB_e};`,
                    expect:`Confirms per-execution time is multi-second only because each execution stalls on HW enqueue. After the segment fix, this SQL should drop to baseline elapsed time without any plan or predicate change.`
                });
            }
        } else if (cat === 'TX_INDEX_CONTENTION') {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Identify the hot index causing TX-index contention',
                sql:`SELECT o.owner, o.object_name index_name, o.subobject_name,
       COUNT(*) ash_samples, ROUND(SUM(ash.time_waited)/1e6,1) waited_secs
FROM   dba_hist_active_sess_history ash
JOIN   dba_objects o ON o.object_id = ash.current_obj#
WHERE  ash.event = 'enq: TX - index contention'
AND    ash.snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY o.owner, o.object_name, o.subobject_name
ORDER BY waited_secs DESC FETCH FIRST 10 ROWS ONLY;`,
                expect:'Identifies the specific index whose right-edge or hot leaf block is the bottleneck.'
            });
            actions.push({
                prio:'IMPORTANT', col:'#f59e0b',
                title:'Hash-partition the hot index OR convert sequence-keyed index to reverse-key',
                sql:`-- Option 1: hash-partition (preferred for sequence-keyed PK indexes)
ALTER INDEX <owner>.<idx> REBUILD PARTITION BY HASH (<key_col>) PARTITIONS 16;
-- Option 2: reverse-key (lighter-touch, single statement)
ALTER INDEX <owner>.<idx> REBUILD REVERSE;
-- Option 3: raise INITRANS so multiple txns can occupy the same block
ALTER INDEX <owner>.<idx> REBUILD INITRANS 16;`,
                expect:'Distributes inserts across multiple leaf blocks, eliminating the single-block contention point.'
            });
        } else if (cat === 'TX_ROW_LOCK_CONTENTION') {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Identify the holder/blocker tree for row-lock contention',
                sql:`SELECT blocking_session, COUNT(*) blocked_samples,
       MIN(sample_time) first_seen, MAX(sample_time) last_seen
FROM   dba_hist_active_sess_history
WHERE  event = 'enq: TX - row lock contention'
AND    snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY blocking_session
ORDER BY blocked_samples DESC FETCH FIRST 10 ROWS ONLY;`,
                expect:'Identifies which sessions held row locks long enough to block others — typically a long-running transaction or app design issue.'
            });
        } else if (cat === 'UNDO_SEGMENT_EXTENSION') {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Enlarge UNDO tablespace and raise UNDO_RETENTION',
                sql:`SELECT tablespace_name, file_name, autoextensible, increment_by, maxbytes/1024/1024/1024 max_gb
FROM   dba_data_files WHERE tablespace_name = (SELECT value FROM v$parameter WHERE name='undo_tablespace');
-- Then:
-- ALTER DATABASE DATAFILE '<file>' AUTOEXTEND ON NEXT 1G MAXSIZE UNLIMITED;
-- ALTER SYSTEM SET undo_retention = 7200;`,
                expect:'Eliminates US-enq waits by allowing the undo tablespace to grow without contention.'
            });
        } else if ((cat === 'SQL_DOMINANT' || _domSqlPct >= 15) && _domSql) {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Tune dominant SQL — review plan, predicates, and index usage',
                sql:`SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('${_domSql.sql_id}', NULL, NULL, 'ALL'));`,
                expect:'Reveals access path, cardinality estimates, and join order. Target the most expensive plan step.'
            });
            actions.push({
                prio:'IMPORTANT', col:'#f59e0b',
                title:'Refresh statistics on top segments referenced by this SQL',
                sql:`-- Top segments\nSELECT object_name, object_type, sub_object_name\nFROM   v$sql_plan\nWHERE  sql_id = '${_domSql.sql_id}' AND object_owner IS NOT NULL;`,
                expect:'Stable plans require accurate statistics. Refresh restores cardinality estimates.'
            });
        } else if (cat === 'CPU_SATURATION') {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Identify top CPU consumers by module and SQL',
                sql:`-- Top CPU consumers by module + SQL during problem window
SELECT module, sql_id, COUNT(*) cpu_samples,
       ROUND(COUNT(*)*100/SUM(COUNT(*)) OVER(),1) pct_cpu
FROM   dba_hist_active_sess_history
WHERE  session_state = 'ON CPU'
AND    snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY module, sql_id
ORDER BY cpu_samples DESC FETCH FIRST 15 ROWS ONLY;`,
                expect:'Cross-reference module with SQL — batch modules can be deferred off-peak, top SQL tuned via DBMS_XPLAN.DISPLAY_AWR.'
            });
        } else if (cat === 'IO_PRESSURE') {
            const ioEv = allWaits.find(e => /db file|direct path/i.test(e.event_name||''));
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Identify segment hotspots driving physical I/O',
                sql:`-- Top segments by physical reads during problem window
SELECT o.owner, o.object_name, o.object_type,
       SUM(ss.physical_reads_delta) phys_reads
FROM   dba_hist_seg_stat ss
JOIN   dba_hist_seg_stat_obj o
         ON o.dataobj#=ss.dataobj# AND o.obj#=ss.obj# AND o.dbid=ss.dbid
WHERE  ss.snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY o.owner, o.object_name, o.object_type
ORDER BY phys_reads DESC FETCH FIRST 10 ROWS ONLY;`,
                expect:'Top segments by physical I/O — candidates for caching, partitioning, or storage tier change.'
            });
            if (ioEv) {
                actions.push({
                    prio:'IMPORTANT', col:'#f59e0b',
                    title:`Review storage latency for "${ioEv.event_name}"`,
                    sql:`-- Tablespace I/O latency during problem window
SELECT tsname,
       SUM(phyrds)                                              reads,
       ROUND(SUM(readtim)/GREATEST(SUM(phyrds),1)*10,2)         avg_read_ms,
       SUM(phywrts)                                             writes,
       ROUND(SUM(writetim)/GREATEST(SUM(phywrts),1)*10,2)       avg_write_ms
FROM   dba_hist_filestatxs
WHERE  snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY tsname
ORDER BY avg_read_ms DESC;`,
                    expect:'Avg read latency >10ms indicates storage bottleneck. >20ms is critical — check SAN/disk subsystem.'
                });
            }
        } else if (cat === 'REDO_COMMIT') {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Reduce commit frequency — batch DML where possible',
                sql:`-- Modules driving commits per second during problem window
SELECT TO_CHAR(begin_time,'HH24:MI') ts,
       ROUND(value,1) commits_per_sec
FROM   dba_hist_sysmetric_history
WHERE  metric_name = 'User Commits Per Sec'
AND    snap_id BETWEEN ${_snB_b} AND ${_snB_e}
ORDER BY begin_time;

-- Top commit-issuing modules:
SELECT module, COUNT(*) commit_samples
FROM   dba_hist_active_sess_history
WHERE  event = 'log file sync'
AND    snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY module ORDER BY commit_samples DESC FETCH FIRST 10 ROWS ONLY;`,
                expect:'Application-level batching reduces redo write pressure and log file sync wait.'
            });
        } else {
            actions.push({
                prio:'IMMEDIATE', col:'#ef4444',
                title:'Run ASH analysis to identify session-level patterns',
                sql:`-- Dominant session activity in problem window
SELECT session_state, event, wait_class, COUNT(*) samples
FROM   dba_hist_active_sess_history
WHERE  snap_id BETWEEN ${_snB_b} AND ${_snB_e}
GROUP BY session_state, event, wait_class
ORDER BY samples DESC FETCH FIRST 15 ROWS ONLY;`,
                expect:'Reveals dominant session activity not visible in aggregate AWR ranking.'
            });
        }
        // Always: Monitor row
        if (topW2 || _monitorWait) {
            const mw = _monitorWait || topW2;
            actions.push({
                prio:'MONITOR', col:'#6366f1',
                title:`Track "${mw.event_name||''}" across next 3 AWR periods`,
                sql:`-- Trend the wait event across recent snapshots
SELECT snap_id,
       ROUND(time_waited_micro_fg/1e6,2) wait_secs_fg,
       total_waits_fg                    waits
FROM   dba_hist_system_event
WHERE  event_name = '${(mw.event_name||'').replace(/'/g,"''")}'
AND    snap_id BETWEEN ${_snB_e} - 30 AND ${_snB_e}
ORDER BY snap_id;`,
                expect:'Alert if % DB Time exceeds 5% sustained — prevents secondary risk from escalating.'
            });
        }

        // -- LAYER 6: VALIDATION — success criteria ------------------------
        const validationCriteria = [];
        if (_domSql) {
            const epe = _domSql.epe2 || _domSql.avg_elapsed_secs || 0;
            const baseEpe = _domSql.epe1 || epe * 0.5;
            validationCriteria.push(`SQL <span style="font-family:monospace">${esc(_domSql.sql_id)}</span> elapsed/exec = ${f2(baseEpe*1.10)} s (currently ${f2(epe)} s)`);
        }
        if (cat === 'CPU_SATURATION' || cpuUtilB > 70) {
            validationCriteria.push(`AAS = ${f1(cpus*0.7)} (CPU count × 0.7) — currently ${f1(aasB)}`);
        }
        if (cat === 'IO_PRESSURE' && topW1) {
            validationCriteria.push(`<b>${esc(topW1.event_name)}</b> = 25% DB Time (currently ${f1(topW1.pct_db_time||0)}%)`);
        }
        if (cat === 'REDO_COMMIT') {
            validationCriteria.push(`log file sync = 5% DB Time (currently ${f1(commitPct)}%)`);
        }
        validationCriteria.push(`Overall DB Time = baseline × 1.10 (currently ${dbTimeDeltaPct>=0?'+':''}${f1(dbTimeDeltaPct)}% vs baseline)`);

        // --- RENDER ---------------------------------------------------------
        const layerCss = 'background:linear-gradient(135deg,rgba(15,23,42,0.85),rgba(8,12,28,0.7));border:1px solid rgba(99,102,241,0.18);border-radius:8px;padding:14px 18px;margin-bottom:12px';
        const layerHdr = (icon, title, color) => `<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(99,102,241,0.12)"><span style="font-size:16px">${icon}</span><span style="font-size:12.5px;font-weight:900;color:${color};text-transform:uppercase;letter-spacing:0.8px">${title}</span></div>`;

        // -- PEEngine: build evidence model + evaluate the rule set ---------
        // Drives the Confidence Scorecard, Action Priority Queue, and Fix Impact Simulator.
        let _peScorecardHtml = '';
        try {
            const _peEv    = window.PEEngine.extract(ctx, report);
            const _peEval  = window.PEEngine.evaluate(_peEv);
            // Stash for the Fix Impact Simulator anchor in renderComparisonRCA.
            window._peLastEvaluation = { ev: _peEv, evaln: _peEval };
            _peScorecardHtml = window.PEEngine.renderScorecard(_peEv, _peEval);
        } catch (e) { console.warn('PEEngine evaluate failed', e); }

        return `
        ${_peScorecardHtml}
        <!-- --- HEADER STRIP: Cause + Severity + Confidence --- -->
        <div style="display:flex;align-items:center;gap:12px;padding:12px 16px;background:${hs.bg};border:1px solid ${hs.border};border-left:4px solid ${_causeCol};border-radius:8px;margin-bottom:12px">
            <div style="width:10px;height:10px;border-radius:50%;background:${_causeCol};box-shadow:0 0 10px ${_causeCol};flex-shrink:0"></div>
            <div style="flex:1;min-width:0">
                <div style="font-size:13px;font-weight:900;color:${_causeCol};text-transform:uppercase;letter-spacing:0.8px">${_causeLabel}${_isParallelVerdict?' <span style="background:rgba(129,140,248,0.15);color:#818cf8;font-size:10px;padding:2px 6px;border-radius:3px;font-weight:800;margin-left:6px">⟥ PARALLEL</span>':''}</div>
                <div style="font-size:10.5px;color:#94a3b8;margin-top:3px">Severity: <b style="color:${sevCol}">${esc(sev)}</b> · ${esc(report.db_name||'')} · ${esc(lbl1)} → ${esc(lbl2)}</div>
            </div>
            <div style="display:flex;flex-direction:column;align-items:flex-end;gap:2px">
                <div style="font-size:9px;color:#64748b;text-transform:uppercase;font-weight:700">Confidence</div>
                <div style="font-size:16px;font-weight:900;color:${confColor}">${confLevel} <span style="font-size:11px;color:#64748b">(${confScore}/100)</span></div>
            </div>
        </div>

        <!-- --- LAYER 1: TL;DR --- -->
        <div style="${layerCss};border-left:3px solid ${sevCol}">
            ${layerHdr(_iconSvg('eye','#a5b4fc'),'TL;DR — Conclusive Direction','#a5b4fc')}
            <div style="font-size:13.5px;color:#e2e8f0;line-height:1.75">${tldr}</div>
        </div>

        <!-- --- LAYER 2: KEY SIGNAL --- -->
        <div style="${layerCss};border-left:3px solid #f59e0b">
            ${layerHdr(_iconSvg('lightning','#fbbf24'),'Key Signal — #1 Metric','#fbbf24')}
            <div style="display:flex;align-items:baseline;gap:14px;flex-wrap:wrap;margin-bottom:8px">
                <span style="font-size:11px;color:#94a3b8;text-transform:uppercase;font-weight:700;min-width:160px">${esc(keySigLabel)}</span>
                <span style="font-size:24px;font-weight:900;color:${sevCol}">${keySigValue}</span>
            </div>
            <div style="font-size:12px;color:#cbd5e1;line-height:1.6;margin-bottom:6px">${keySigContext}</div>
            ${keySigRef?`<div style="font-size:10.5px;color:#94a3b8;margin-top:8px;padding-top:6px;border-top:1px solid rgba(99,102,241,0.1)">${keySigRef}</div>`:''}
        </div>

        <!-- --- LAYER 5: NEXT ACTION --- -->
        <!-- Moved to end of RCA tab — see #rca-next-action-anchor below the PE Narrative -->

        <!-- --- LAYER 3: PE KNOWLEDGE REFERENCE (KB-sourced, deterministic) --- -->
        ${(() => {
            const _kb = (typeof KB_DETERMINISTIC !== 'undefined') ? (KB_DETERMINISTIC[cat] || null) : null;
            if (!_kb) return '';
            const _kbRows = [
                _kb.threshold   ? `<tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 8px;vertical-align:top;width:110px;white-space:nowrap">Threshold</td><td style="font-size:9.5px;color:#cbd5e1;padding:4px 8px;line-height:1.5">${esc(_kb.threshold)}</td></tr>` : '',
                _kb.antiPattern ? `<tr><td style="font-size:8px;color:#f87171;font-weight:700;text-transform:uppercase;padding:4px 8px;vertical-align:top;white-space:nowrap">Avoid</td><td style="font-size:9.5px;color:#fca5a5;padding:4px 8px;line-height:1.5">${esc(_kb.antiPattern)}</td></tr>` : '',
                _kb.statisticsNote ? `<tr><td style="font-size:8px;color:#475569;font-weight:700;text-transform:uppercase;padding:4px 8px;vertical-align:top;white-space:nowrap">Stats Check</td><td style="font-size:9.5px;color:#94a3b8;padding:4px 8px;line-height:1.5">${esc(_kb.statisticsNote)}</td></tr>` : '',
            ].filter(Boolean).join('');
            if (!_kbRows) return '';
            return `<details style="margin-bottom:12px" open>
                <summary style="cursor:pointer;user-select:none;padding:8px 14px;background:linear-gradient(135deg,rgba(16,185,129,0.05),rgba(6,95,70,0.04));border:1px solid rgba(16,185,129,0.2);border-radius:6px;display:flex;align-items:center;gap:8px;list-style:none">
                    <span style="font-size:11px;font-weight:900;color:#34d399;text-transform:uppercase;letter-spacing:0.7px">PE Knowledge Reference</span>
                    <span style="font-size:9px;color:#475569;margin-left:4px">Oracle 19c PTG + Oracle 12c SQL Tuning for Developers</span>
                    <span style="font-size:9px;color:#475569;margin-left:auto;font-style:italic">${esc(_kb.oracleRef||'')}</span>
                </summary>
                <div style="padding:0;background:rgba(10,16,30,0.6);border:1px solid rgba(16,185,129,0.12);border-top:none;border-radius:0 0 6px 6px">
                    <table style="width:100%;border-collapse:collapse">${_kbRows}</table>
                </div>
            </details>`;
        })()}

        <!-- --- LAYER 6: VALIDATION removed — success criteria are inline within Next Action's "Expected" lines --- -->`;    })();

    // -- Build the standalone Next Action card (rendered last on the RCA tab,
    // after PE Narrative + corroborating signals so the user sees the fix
    // recommendation only after digesting all interpretation layers). --------
    const _nextActionLayerCss = 'background:linear-gradient(135deg,rgba(15,23,42,0.85),rgba(8,12,28,0.7));border:1px solid rgba(99,102,241,0.18);border-radius:8px;padding:14px 18px';
    const _nextActionHdr = `<div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(99,102,241,0.12)"><span style="display:inline-flex;align-items:center"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg></span><span style="font-size:12.5px;font-weight:900;color:#34d399;text-transform:uppercase;letter-spacing:0.8px">Action Priority Queue — Recommended Fix</span><span style="font-size:9px;color:#64748b;margin-left:auto">Ranked by impact × effort · queries scoped to actual snap-id range</span></div>`;

    // Use PEEngine to decorate + sort actions by impact/effort, then render.
    let _peQueueHtml = '';
    try {
        const _peState = window._peLastEvaluation || {};
        const _peActionsRanked = window.PEEngine.decorateActions(actions, _peState.ev || {}, _peState.evaln || {});
        _peQueueHtml = window.PEEngine.renderActionQueue(_peActionsRanked);
    } catch (e) {
        console.warn('PEEngine renderActionQueue failed, falling back to plain list', e);
        _peQueueHtml = `<div style="display:flex;flex-direction:column;gap:8px">${actions.map(a => `
            <div style="background:rgba(15,23,42,0.7);border:1px solid ${a.col}30;border-left:3px solid ${a.col};border-radius:6px;padding:10px 14px">
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
                    <span style="font-size:9.5px;color:${a.col};font-weight:900;text-transform:uppercase;letter-spacing:0.6px;background:${a.col}18;padding:2px 8px;border-radius:3px">${a.prio}</span>
                    <span style="font-size:12px;color:#e2e8f0;font-weight:700">${esc(a.title)}</span>
                </div>
                <pre style="margin:6px 0 6px;padding:9px 11px;background:rgba(0,0,0,0.4);border-radius:4px;font-size:10.5px;color:#cbd5e1;font-family:monospace;white-space:pre-wrap;line-height:1.5;overflow-x:auto">${esc(a.sql)}</pre>
                <div style="font-size:10.5px;color:#94a3b8;line-height:1.55"><b style="color:#cbd5e1">Expected:</b> ${esc(a.expect)}</div>
            </div>`).join('')}</div>`;
    }
    const _nextActionHtml = `
        <div style="margin-top:18px;${_nextActionLayerCss};border-left:3px solid #10b981">
            ${_nextActionHdr}
            ${_peQueueHtml}
        </div>`;

    // Side-effect: populate the bottom anchor on the RCA tab. Use rAF so the
    // outerHTML replacement of #rca-intel-anchor (done by the caller) settles
    // before we touch sibling elements.
    requestAnimationFrame(() => {
        const naAnchor = document.getElementById('rca-next-action-anchor');
        if (naAnchor) naAnchor.innerHTML = _nextActionHtml;
    });

    return `<div id="rca-intel-anchor" data-init-handlers="1" style="margin-bottom:16px;background:linear-gradient(135deg,rgba(8,12,28,0.99),rgba(10,16,40,0.97));border:1px solid ${hs.border};border-radius:10px;overflow:hidden">

        <!-- --- HEADER BAR --- -->
        <div style="display:flex;align-items:center;gap:10px;padding:9px 16px;background:rgba(99,102,241,0.08);border-bottom:1px solid rgba(99,102,241,0.15)">
            <span style="display:inline-flex;align-items:center"><svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" fill="none" viewBox="0 0 24 24" stroke="#a5b4fc" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M15 12a3 3 0 11-6 0 3 3 0 016 0zM2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z"/></svg></span>
            <div style="flex:1">
                <span style="font-size:11px;font-weight:800;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.8px">OraVision RCA Verdict</span>
                <span style="font-size:9px;color:#475569;margin-left:8px">${esc(report.db_name||'')} · ${esc(lbl1)} vs ${esc(lbl2)}</span>
            </div>
            <span style="font-size:8px;color:#f59e0b;background:rgba(245,158,11,0.08);border:1px solid rgba(245,158,11,0.2);border-radius:4px;padding:2px 8px;white-space:nowrap">Tool-assisted analysis</span>
        </div>
        <!-- --- DISCLAIMER BANNER (verdict header) — readable type --- -->
        <div style="display:flex;align-items:flex-start;gap:12px;padding:12px 18px;background:rgba(245,158,11,0.08);border-bottom:1px solid rgba(245,158,11,0.25)">
            <span style="display:inline-flex;align-items:flex-start;flex-shrink:0;margin-top:2px"><svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" fill="none" viewBox="0 0 24 24" stroke="#fbbf24" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"/></svg></span>
            <p style="margin:0;font-size:12px;color:#fde68a;line-height:1.65;letter-spacing:0.1px">
                <strong style="color:#fbbf24;font-weight:800">Disclaimer — Tool-Assisted Analysis:</strong>
                This verdict is generated automatically by parsing AWR snapshot data using heuristic rules, statistical thresholds, and pattern matching.
                It represents the tool's best interpretation of the available data and
                <strong style="color:#fbbf24;font-weight:800">should not be treated as a definitive diagnosis</strong>.
                Findings must be validated by a qualified DBA or Performance Engineer against the full database context,
                application behaviour, and any environmental changes not captured in the AWR snapshot.
                False positives and missed signals are possible — always apply professional judgement before acting on these recommendations.
            </p>
        </div>

        <div style="padding:16px 20px">

            <!-- UNIFIED DETERMINISTIC CONCLUSIVE FLOW -->
            <!-- TL;DR -> Key Signal -> Why -> Confidence -> Next Action -> Validation -->
            <!-- Replaces legacy sections 1, 1b, 2, 3, 3b, 3c, 5, 7 with a single coherent -->
            <!-- flow synthesised across ALL tabs (LP, waits, SQL, eff, time model, sessions, -->
            <!-- ADDM, tablespace I/O). PE Narrative below remains rendered externally. -->
            ${_conclusiveFlowHtml}

            <!-- 4. PE NARRATIVE - rendered externally as compNarrative -->
            <!-- (see generateComparisonVerdictNarrative - the four-part diagnosis block) -->

        </div>

        <!-- Cross-link pane -->
        <div id="rca-ctx-pane" style="display:none;margin:0 20px 12px;padding:9px 12px;background:rgba(10,16,40,0.95);border:1px solid rgba(99,102,241,0.3);border-radius:6px;font-size:9px;color:#94a3b8;position:relative"></div>
    </div>`;
}

// --- RCA CROSS-LINK CLICK HANDLERS ----------------------------------------
// Called once after _renderRCAVerdictTabular injects HTML into the DOM.
// Reads correlation maps stored on window by _renderRCAVerdictTabular.
let _rcaHandlersBound = false;
function _initRCAClickHandlers() {
    // Remove previous listeners by replacing the tracking flag
    _rcaHandlersBound = false;
    const sqlWaitMap = window._rcaSqlWaitMap || {};
    const waitSqlMap = window._rcaWaitSqlMap || {};

    function _clearHL(scope) {
        document.querySelectorAll('[data-rca-sql],[data-rca-wait]').forEach(r => {
            r.style.background = ''; r.style.outline = ''; r.style.opacity = '';
        });
        const pane = document.getElementById('rca-ctx-pane');
        if (pane && scope === 'all') pane.style.display = 'none';
    }
    function _showPane(html) {
        const pane = document.getElementById('rca-ctx-pane');
        if (!pane) return;
        pane.innerHTML = html;
        pane.style.display = 'block';
    }

    function _onDocClick(e) {
        // SQL row
        const sqlRow = e.target.closest('[data-rca-sql]');
        if (sqlRow) {
            const sqlId   = sqlRow.getAttribute('data-rca-sql');
            const relWaits = sqlWaitMap[sqlId] || [];
            _clearHL('');
            document.querySelectorAll('[data-rca-wait]').forEach(wr => {
                const wn = wr.getAttribute('data-rca-wait');
                if (relWaits.includes(wn)) {
                    wr.style.background = 'rgba(239,68,68,0.12)';
                    wr.style.outline = '1px solid rgba(239,68,68,0.4)';
                    wr.style.opacity = '1';
                } else { wr.style.opacity = '0.3'; }
            });
            sqlRow.style.background = 'rgba(99,102,241,0.18)';
            sqlRow.style.outline = '1px solid rgba(99,102,241,0.6)';
            sqlRow.style.opacity = '1';
            const epe1 = sqlRow.getAttribute('data-epe1') || '–';
            const epe2 = sqlRow.getAttribute('data-epe2') || '–';
            const pct  = sqlRow.getAttribute('data-pct') || '–';
            const st   = sqlRow.getAttribute('data-status') || '';
            _showPane(
                '<div style="font-size:8px;color:#818cf8;font-weight:700;text-transform:uppercase;margin-bottom:5px">Selected SQL: <span style="color:#a5b4fc;font-family:monospace">' + esc(sqlId) + '</span></div>'
                + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:5px">'
                + '<div style="font-size:9px;color:#64748b">% DB Time: <span style="color:#e2e8f0;font-weight:700">' + pct + '%</span></div>'
                + '<div style="font-size:9px;color:#64748b">B s/exec: <span style="color:#e2e8f0">' + epe1 + 's</span></div>'
                + '<div style="font-size:9px;color:#64748b">P s/exec: <span style="color:#e2e8f0;font-weight:700">' + epe2 + 's</span></div>'
                + '</div>'
                + (st ? '<div style="font-size:9px;color:#94a3b8;margin-bottom:5px">Status: <span style="font-weight:700;color:#e2e8f0">' + esc(st) + '</span></div>' : '')
                + (relWaits.length ? '<div style="font-size:9px;color:#f87171">Related wait events: <span style="font-family:monospace">' + relWaits.map(w=>esc(w)).join(', ') + '</span></div>'
                                   : '<div style="font-size:9px;color:#475569">No direct wait correlation found for this SQL.</div>')
                + '<div style="margin-top:5px;font-size:8px;color:#334155;cursor:pointer;padding:2px 6px;background:rgba(30,41,59,0.5);border-radius:3px;display:inline-block" onclick="_rcaClear()">× clear</div>'
            );
            e.stopPropagation();
            return;
        }
        // Wait event row
        const wRow = e.target.closest('[data-rca-wait]');
        if (wRow) {
            const wName   = wRow.getAttribute('data-rca-wait');
            const relSqls = waitSqlMap[wName] || [];
            _clearHL('');
            document.querySelectorAll('[data-rca-sql]').forEach(sr => {
                const sid = sr.getAttribute('data-rca-sql');
                if (relSqls.includes(sid)) {
                    sr.style.background = 'rgba(239,68,68,0.12)';
                    sr.style.outline = '1px solid rgba(239,68,68,0.4)';
                    sr.style.opacity = '1';
                } else { sr.style.opacity = '0.3'; }
            });
            wRow.style.background = 'rgba(248,113,113,0.15)';
            wRow.style.outline = '1px solid rgba(248,113,113,0.5)';
            wRow.style.opacity = '1';
            const wpct  = wRow.getAttribute('data-pct') || '–';
            const wms   = wRow.getAttribute('data-ms') || '–';
            const wdiag = wRow.getAttribute('data-diag') || '';
            _showPane(
                '<div style="font-size:8px;color:#f87171;font-weight:700;text-transform:uppercase;margin-bottom:5px">Selected Wait: <span style="color:#fca5a5;font-family:monospace">' + esc(wName) + '</span></div>'
                + '<div style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px;margin-bottom:5px">'
                + '<div style="font-size:9px;color:#64748b">% DB Time: <span style="color:#e2e8f0;font-weight:700">' + wpct + '%</span></div>'
                + '<div style="font-size:9px;color:#64748b">Avg ms: <span style="color:#e2e8f0">' + wms + '</span></div>'
                + '<div style="font-size:9px;color:#64748b">Cause: <span style="color:#94a3b8;font-style:italic">' + esc(wdiag) + '</span></div>'
                + '</div>'
                + (relSqls.length ? '<div style="font-size:9px;color:#a5b4fc">Correlated SQLs: <span style="font-family:monospace">' + relSqls.map(s=>esc(s)).join(', ') + '</span></div>'
                                  : '<div style="font-size:9px;color:#475569">No correlated SQLs identified for this wait event.</div>')
                + '<div style="margin-top:5px;font-size:8px;color:#334155;cursor:pointer;padding:2px 6px;background:rgba(30,41,59,0.5);border-radius:3px;display:inline-block" onclick="_rcaClear()">× clear</div>'
            );
            e.stopPropagation();
            return;
        }
        // Click outside ? clear
        if (!e.target.closest('#rca-ctx-pane') && !e.target.closest('#rca-evidence-pane')) {
            _clearHL('all');
        }
    }

    // Remove previous listener if any, then add fresh
    if (window._rcaClickHandler) document.removeEventListener('click', window._rcaClickHandler);
    window._rcaClickHandler = _onDocClick;
    document.addEventListener('click', _onDocClick);
}

window._rcaClear = function() {
    document.querySelectorAll('[data-rca-sql],[data-rca-wait]').forEach(r => {
        r.style.background = ''; r.style.outline = ''; r.style.opacity = '';
    });
    const pane = document.getElementById('rca-ctx-pane');
    if (pane) pane.style.display = 'none';
};

// Poll until ready, then render the conclusive intelligence report
async function startIntelligencePoller(uploadId) {
    const isComparison = uploadId.includes('_vs_');

    // -- PERMANENT FIX: render verdict immediately from parsed AWRContext data --
    // Backend intelligence (Z-score/CUSUM/Pearson/BFS) runs in background and
    // silently upgrades the verdict when complete. User never sees a spinner.
    if (isComparison && typeof AWRContext !== 'undefined' && AWRContext) {
        const el = document.getElementById('rca-intel-anchor');
        if (el) {
            const fallback = _buildFallbackReport(AWRContext);
            el.outerHTML = _renderRCAVerdictTabular(fallback, AWRContext);
            _initRCAClickHandlers();
            // Subtle badge — removed silently when backend completes
            const anchor = document.getElementById('rca-intel-anchor');
            if (anchor) {
                const badge = document.createElement('div');
                badge.id = 'intel-enhance-badge';
                badge.style.cssText = 'padding:4px 16px;background:rgba(99,102,241,0.04);border-bottom:1px solid rgba(99,102,241,0.1);font-size:9px;color:#818cf8;display:flex;align-items:center;gap:8px';
                badge.innerHTML = `<span style="display:inline-block;width:7px;height:7px;border:1.5px solid #818cf8;border-top-color:transparent;border-radius:50%;animation:spin 0.8s linear infinite;flex-shrink:0"></span>\u00a0Backend intelligence enhancing (Z-score \xb7 CUSUM \xb7 Pearson \xb7 BFS) — verdict will auto-update when complete`;
                anchor.insertBefore(badge, anchor.firstChild);
            }
        }
    }

    let attempts = 0;
    let missingCount = 0;
    let triggered = false;
    const maxAttempts = 90; // 4.5 min background wait

    async function _poll() {
        attempts++;
        try {
            const statusR = await fetch(`/api/intelligence/status/${uploadId}`);
            const status = await statusR.json();

            if (status.status === 'ready') {
                const reportR = await fetch(`/api/intelligence/${uploadId}`);
                if (!reportR.ok) throw new Error(`HTTP ${reportR.status}`);
                const report = await reportR.json();
                if (isComparison && AWRContext) {
                    const el = document.getElementById('rca-intel-anchor');
                    if (el) {
                        el.outerHTML = _renderRCAVerdictTabular(report, AWRContext);
                        _initRCAClickHandlers();
                    }
                }
                return; // done — backend upgraded the verdict
            }

            // Auto-trigger if analysis never started (silent failure recovery)
            if (status.status === 'missing') {
                missingCount++;
                if (missingCount >= 3 && !triggered && isComparison) {
                    triggered = true;
                    try {
                        await fetch('/api/intelligence/trigger-compare/uploaded_good/uploaded_bad', {
                            method: 'POST',
                            headers: {'Content-Type': 'application/json'},
                            body: JSON.stringify({})
                        });
                    } catch (te) { console.warn('Auto-trigger failed:', te); }
                }
            }
        } catch (e) {
            console.warn('Intelligence poll error:', e);
        }

        if (attempts < maxAttempts) {
            setTimeout(_poll, 3000);
        } else {
            // Backend timed out — verdict already showing from local data.
            // Just update the badge to indicate backend didn't complete.
            const badge = document.getElementById('intel-enhance-badge');
            if (badge) {
                badge.style.color = '#f59e0b';
                badge.innerHTML = `\u26a0 Backend intelligence timed out \u2014 verdict built from parsed AWR data. <a href="#" onclick="startIntelligencePoller('${uploadId}');return false" style="color:#6366f1;margin-left:8px">Retry full analysis</a>`;
            }
        }
    }

    setTimeout(_poll, 2000);
}

// --- FALLBACK REPORT BUILDER --------------------------------------------------
// Synthesises a FindingReport-compatible object entirely from AWRContext data.
// Used when the backend intelligence engine times out.
// Produces a richer verdict than "timed out" by using all parsed AWR data
// already available in the browser.
// ── SINGLE-MODE FALLBACK REPORT — threshold-based (no baseline needed) ──────
function _buildSingleFallbackReport(ctx) {
    const ev2  = ctx.waitEvents?.bad  || [];
    const sql2 = (ctx._raw?.bad || {}).sql_stats || [];
    const lp2  = ctx.loadProfile?.bad || {};
    const s2   = ctx._raw?.s2 || ctx._raw?.bad || {};
    const cpus = ctx.meta?.cpu_count || 1;
    const aas2 = ctx.aas?.bad || s2.aas || 0;
    const f1   = v => (+v||0).toFixed(1);
    const comma = n => (+n||0).toLocaleString();

    // -- Bottleneck classification (absolute thresholds, no delta) ---------------
    const dbCpuPct  = (ev2.find(e=>/DB CPU/i.test(e.event_name||''))||{}).pct_db_time || 0;
    const ioPct     = ev2.filter(e=>/db file|direct path/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const concPct   = ev2.filter(e=>/latch|lock|buffer busy|enq|free buffer/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const commitPct = ev2.filter(e=>/log file sync/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const primaryBottleneck = dbCpuPct>=35?'cpu':ioPct>=30?'io':concPct>=10?'concurrency':commitPct>=10?'commit':'mixed';
    const overallHealth = aas2>cpus?'CRITICAL':aas2>cpus*0.7?'WARNING':'OK';

    const findings = [];

    // -- SQL dominant finding (absolute — no baseline comparison) ----------------
    const sqlSorted = (sql2||[]).slice().sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));
    const topSql = sqlSorted[0];
    if (topSql && (topSql.pct_db_time||0) > 5) {
        const epe2 = topSql.avg_elapsed_secs || ((topSql.elapsed_time_secs||0)/Math.max(topSql.executions||1,1));
        const gets = topSql.buffer_gets_per_exec || topSql.buffer_gets || 0;
        const pdb  = topSql.pct_db_time || 0;
        const action1fix = "SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('" + topSql.sql_id + "'))";
        const action2fix = gets>50000
            ? 'Check for missing index \u2014 ' + comma(Math.round(gets)) + ' buffer gets/exec is excessive.'
            : "Run SQL Tuning Advisor: EXEC DBMS_SQLTUNE.CREATE_TUNING_TASK(sql_id=>'" + topSql.sql_id + "')";
        const evidence = [
            f1(pdb) + '% of DB Time',
            f1(epe2) + 's per execution',
            gets>0 ? comma(Math.round(gets)) + ' buffer gets/exec' : '',
            comma(topSql.executions||0) + ' executions in window',
        ].filter(Boolean);
        findings.push({
            id:'sql_dominant', severity:pdb>=25?'CRITICAL':'WARNING',
            category:'sql_analysis', trend:'DOMINANT',
            title:'SQL ' + topSql.sql_id + ' \u2014 dominant ' + primaryBottleneck.toUpperCase() + ' consumer',
            headline:'SQL ' + topSql.sql_id + ': ' + f1(pdb) + '% DB Time \u00B7 ' + comma(topSql.executions||0) + ' execs \u00B7 ' + f1(epe2) + 's/exec',
            evidence: evidence,
            root_cause:'SQL ' + topSql.sql_id + ' consumes ' + f1(pdb) + '% of DB Time at ' + f1(epe2) + 's per execution \u2014 primary tuning target',
            fix:'Run SQL Tuning Advisor on SQL ID ' + topSql.sql_id,
            impact_score:Math.min(100, pdb*2), confidence:'HIGH', sql_ids:[topSql.sql_id],
            causal_chain:[], oracle_ref:'Oracle Performance Tuning Guide \u2014 SQL Tuning',
            fix_detail:{
                title:'SQL ' + topSql.sql_id,
                fix_statement:'Run SQL Tuning Advisor to identify access path improvements',
                fix_reasoning:'SQL dominates ' + f1(pdb) + '% of DB Time \u2014 first tuning target',
                action_1:action1fix, action_2:action2fix,
                action_3:'Re-run AWR after tuning \u2014 confirm DB Time% drops',
                validate_by:'Confirm SQL DB Time% below ' + Math.max(5,Math.round(pdb/3)) + '% in next AWR window',
                confidence:'HIGH', root_cause_type:'sql_analysis'
            }
        });

        // Secondary SQLs
        const minorSqls = sqlSorted.slice(1,4).filter(s=>(s.pct_db_time||0)>2);
        if (minorSqls.length > 0)
            findings.push({
                id:'sql_secondary', severity:'WARNING', category:'sql_analysis', trend:'CONTRIBUTING',
                title:minorSqls.length + ' contributing SQL statement(s)',
                headline:minorSqls.map(s=>s.sql_id+': '+f1(s.pct_db_time||0)+'%').join(' \u00B7 '),
                evidence:minorSqls.map(s=>'SQL '+s.sql_id+': '+f1(s.pct_db_time||0)+'% DB Time \u00B7 '+comma(s.executions||0)+' execs'),
                root_cause:'Secondary SQL workload contributing to total DB Time',
                fix:'Review access paths after addressing dominant SQL',
                impact_score:Math.min(60, minorSqls.reduce((s,sq)=>s+(sq.pct_db_time||0),0)),
                confidence:'MEDIUM', sql_ids:minorSqls.map(s=>s.sql_id), causal_chain:[],
                fix_detail:{ title:'Secondary SQL contributors', fix_statement:'Review after dominant SQL is tuned',
                    fix_reasoning:'Secondary SQLs add to total DB Time', action_1:'Review execution plans',
                    action_2:'Compare buffer gets/exec', action_3:'Monitor in next AWR period',
                    validate_by:'Confirm total SQL DB Time normalises', confidence:'MEDIUM', root_cause_type:'sql_analysis' }
            });
    }

    // -- Wait event findings (absolute thresholds, no delta) --------------------
    const waitDiagMap = {
        'log file sync':     { rct:'commit_bottleneck', fix:'Reduce commit frequency \u2014 batch commits; move redo logs to faster storage' },
        'db file sequential':{ rct:'io_bottleneck',     fix:'Check for unselective index scans \u2014 single-block I/O. Review DBA_HIST_SEG_STAT.' },
        'db file scattered': { rct:'io_bottleneck',     fix:'Full table/index scans \u2014 multi-block I/O. Verify index coverage.' },
        'buffer busy':       { rct:'latch_contention',  fix:'Hot blocks \u2014 consider reverse-key index or partitioning' },
        'free buffer':       { rct:'io_bottleneck',     fix:'DBWR cannot write dirty blocks fast enough. Increase DB_WRITER_PROCESSES or check I/O.' },
        'latch:':            { rct:'latch_contention',  fix:'Check V$LATCH for top miss category' },
        'cursor pin s':      { rct:'latch_contention',  fix:'Hard parse storm \u2014 enable bind variables, increase SESSION_CACHED_CURSORS' },
        'library cache':     { rct:'latch_contention',  fix:'Parse storm \u2014 CURSOR_SHARING=FORCE or add bind variables' },
        'enq: hw':           { rct:'concurrency_lock',  fix:'HWM contention \u2014 pre-allocate extents via DBMS_SPACE.EXTEND' },
        'enq: tx':           { rct:'concurrency_lock',  fix:'Row-level lock conflict \u2014 check V$LOCK for blocking session' },
        'enq: us':           { rct:'concurrency_lock',  fix:'Undo segment contention \u2014 increase UNDO_RETENTION' },
        'direct path read temp':{ rct:'temp_spill',     fix:'Sort/hash spill to temp \u2014 increase PGA_AGGREGATE_TARGET' },
        'db cpu':            { rct:'cpu_saturation',    fix:'CPU saturated \u2014 reduce logical reads per exec; use bind variables' },
    };
    ev2.filter(e=>(e.pct_db_time||0)>3).slice(0,5).forEach(ev => {
        const thisPct = ev.pct_db_time||0;
        const sev = thisPct>20?'CRITICAL':thisPct>8?'WARNING':'INFO';
        const diagKey = Object.keys(waitDiagMap).find(k=>(ev.event_name||'').toLowerCase().includes(k.toLowerCase()));
        const diag = diagKey ? waitDiagMap[diagKey] : { rct:'inconclusive', fix:'Investigate ' + ev.event_name };
        if (findings.some(f=>f.id==='sql_dominant') && thisPct < 10) return; // skip minor waits if SQL dominates
        findings.push({
            id:'wait_' + (ev.event_name||'').replace(/[^a-z0-9]/gi,'_').slice(0,20),
            severity:sev, category:diag.rct, trend:'DOMINANT',
            title:ev.event_name + ' \u2014 ' + f1(thisPct) + '% DB Time',
            headline:ev.event_name + ': ' + f1(thisPct) + '% DB Time \u00B7 ' + comma(ev.total_waits||0) + ' waits \u00B7 ' + f1(ev.avg_wait_ms||0) + 'ms avg',
            evidence:[
                f1(thisPct) + '% of DB Time',
                (ev.avg_wait_ms||0)>0 ? 'Avg wait: '+f1(ev.avg_wait_ms)+'ms' + ((ev.avg_wait_ms||0)>20?' (exceeds 20ms threshold)':' (within threshold)') : '',
                (ev.total_waits||0)>0 ? comma(ev.total_waits)+' total waits' : '',
                'Wait class: ' + (ev.wait_class||'Other')
            ].filter(Boolean),
            root_cause:ev.event_name + ' at ' + f1(thisPct) + '% of DB Time \u2014 ' + (thisPct>20?'dominant':'significant') + ' bottleneck contributor',
            fix:diag.fix,
            impact_score:Math.min(100, thisPct*1.5), confidence:'MEDIUM',
            sql_ids:[], causal_chain:[],
            fix_detail:{
                title:ev.event_name,
                fix_statement:diag.fix,
                fix_reasoning:ev.event_name + ' consumes ' + f1(thisPct) + '% DB Time \u2014 ' + diag.rct + ' category',
                action_1:diag.fix,
                action_2:'Cross-reference with top SQL \u2014 check if dominant SQL drives this wait',
                action_3:'Monitor in next AWR period',
                validate_by:'Confirm ' + ev.event_name + ' below 5% DB Time',
                confidence:'MEDIUM', root_cause_type:diag.rct
            }
        });
    });

    // -- Load profile absolute flags -------------------------------------------
    const lpFlags = [];
    const _lpAbsChecks = [
        {key:'physical_reads',  label:'Physical Reads/s',  threshold:5000, severity:'WARNING'},
        {key:'hard_parses',     label:'Hard Parses/s',     threshold:5,    severity:'CRITICAL'},
        {key:'redo_size',       label:'Redo Size/s',       threshold:500000, severity:'WARNING'},
    ];
    _lpAbsChecks.forEach(chk => {
        const val = lp2[chk.key] || 0;
        if (val > chk.threshold)
            lpFlags.push({label:chk.label, val:val, threshold:chk.threshold, severity:chk.severity});
    });
    if (lpFlags.length > 0) {
        const worst = lpFlags.sort((a,b)=>b.val-a.val)[0];
        findings.push({
            id:'lp_flag', severity:worst.severity,
            category:'workload_analysis', trend:'ELEVATED',
            title:'Load Profile \u2014 ' + worst.label + ' at ' + comma(Math.round(worst.val)) + '/s',
            headline:lpFlags.map(f=>f.label+': '+comma(Math.round(f.val))+'/s (threshold: '+comma(f.threshold)+')').join(' \u00B7 '),
            evidence:lpFlags.map(f=>f.label+': '+comma(Math.round(f.val))+'/s exceeds threshold '+comma(f.threshold)),
            root_cause:'Elevated load profile metrics confirm high workload pressure',
            fix:'Cross-reference with top SQL \u2014 the SQL driving these metrics is the primary candidate',
            impact_score:50, confidence:'HIGH', sql_ids:[], causal_chain:[],
            fix_detail:{ title:'Load Profile Pressure', fix_statement:'Address top SQL driving elevated metrics',
                fix_reasoning:'Absolute load profile metrics exceed operational thresholds',
                action_1:'Identify top SQL by physical reads in DBA_HIST_SQLSTAT',
                action_2:'Check if batch jobs are running during this window',
                action_3:'Monitor in next AWR period',
                validate_by:'Confirm metrics return to normal in next AWR',
                confidence:'HIGH', root_cause_type:'workload_analysis' }
        });
    }

    // -- Correlation notes (absolute pattern matching) --------------------------
    const corrNotes = [];
    if ((lp2.physical_reads||0) > 5000 && ev2.find(e=>/db file sequential/i.test(e.event_name||'')))
        corrNotes.push('High physical reads corroborate db file sequential read wait \u2014 I/O bottleneck confirmed');
    if ((lp2.redo_size||0) > 500000 && ev2.find(e=>/log file sync/i.test(e.event_name||'')))
        corrNotes.push('High redo rate corroborates log file sync wait \u2014 commit frequency bottleneck confirmed');
    if ((lp2.hard_parses||0) > 5 && ev2.find(e=>/library cache|latch.*shared/i.test(e.event_name||'')))
        corrNotes.push('Hard parse rate corroborates library cache / shared pool latch contention \u2014 parse storm confirmed');
    if (ev2.find(e=>/free buffer/i.test(e.event_name||'')) && ev2.find(e=>/buffer busy/i.test(e.event_name||'')))
        corrNotes.push('Free buffer waits + buffer busy waits \u2014 DBWR cannot keep up with block demand. I/O subsystem under pressure.');

    findings.sort((a,b)=>(b.impact_score||0)-(a.impact_score||0));
    const ranked = findings.slice(0,10);

    const topWait = ev2[0] || {};
    const verdictText = topSql && (topSql.pct_db_time||0)>=20
        ? 'SQL ' + topSql.sql_id + ' dominates at ' + f1(topSql.pct_db_time||0) + '% DB Time \u2014 ' + primaryBottleneck.toUpperCase() + ' bottleneck. AAS ' + f1(aas2) + ' / ' + cpus + ' CPUs.'
        : primaryBottleneck.toUpperCase() + ' bottleneck \u2014 "' + (topWait.event_name||'') + '" at ' + f1(topWait.pct_db_time||0) + '% DB Time. AAS ' + f1(aas2) + ' / ' + cpus + ' CPUs.';

    return {
        upload_id: 'single_fallback',
        db_name: ctx.meta?.db_name || '',
        snap_range: 'Single AWR Analysis',
        overall_health: overallHealth,
        primary_bottleneck: primaryBottleneck,
        verdict: verdictText,
        findings: ranked,
        correlation_notes: corrNotes,
        trend_notes: [],
        pipeline_ms: 0,
        _isFallback: true,
        _isSingle: true,
    };
}


function _buildFallbackReport(ctx) {
    const ev2  = ctx.waitEvents.bad  || [];
    const ev1  = ctx.waitEvents.good || [];
    const sql2 = (ctx._raw.bad  || {}).sql_stats || [];
    const sql1 = (ctx._raw.good || {}).sql_stats || [];
    const lp1  = ctx.loadProfile.good || {};
    const lp2  = ctx.loadProfile.bad  || {};
    const s1   = ctx._raw.s1 || ctx._raw.good || {};
    const s2   = ctx._raw.s2 || ctx._raw.bad  || {};
    const cpus = ctx.meta.cpu_count || 1;
    const lbl1 = ctx.meta.lbl1, lbl2 = ctx.meta.lbl2;
    const aas2 = s2.aas || 0;
    const f1   = v => (+v||0).toFixed(1);
    const comma = n => (+n||0).toLocaleString();

    // -- Bottleneck classification ---------------------------------------------
    const dbCpuPct  = (ev2.find(e=>/DB CPU/i.test(e.event_name||''))||{}).pct_db_time || 0;
    const ioPct     = ev2.filter(e=>/db file|direct path/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const concPct   = ev2.filter(e=>/latch|lock|buffer busy|enq/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const commitPct = ev2.filter(e=>/log file sync/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const primaryBottleneck = dbCpuPct>=35?'cpu':ioPct>=30?'io':concPct>=10?'concurrency':commitPct>=10?'commit':'mixed';
    const overallHealth = aas2>cpus?'CRITICAL':aas2>cpus*0.7?'WARNING':'OK';

    const sql1Map = {}; (sql1||[]).forEach(s=>{ sql1Map[s.sql_id]=s; });
    const findings = [];

    // -- SQL dominant finding --------------------------------------------------
    const sqlSorted = (sql2||[]).slice().sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));
    const topSql = sqlSorted[0];
    if (topSql && (topSql.pct_db_time||0) > 5) {
        const isNew  = !sql1Map[topSql.sql_id];
        const s1x    = sql1Map[topSql.sql_id];
        const epe2   = topSql.avg_elapsed_secs || ((topSql.elapsed_time_secs||0)/Math.max(topSql.executions||1,1));
        const epe1   = s1x ? (s1x.avg_elapsed_secs||((s1x.elapsed_time_secs||0)/Math.max(s1x.executions||1,1))) : null;
        const gets   = topSql.buffer_gets_per_exec || topSql.buffer_gets || 0;
        const pdb    = topSql.pct_db_time || 0;
        const isPlan = !isNew && s1x && topSql.plan_hash_value && s1x.plan_hash_value && topSql.plan_hash_value !== s1x.plan_hash_value;
        const label  = isNew?'[NEW]':isPlan?'[PLAN CHG]':'[WORSE]';
        const rct    = isNew?'new_sql':isPlan?'sql_regression':'sql_regression';
        const action1fix = `SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('${topSql.sql_id}'))`;
        const action2fix = gets>50000
            ? `Check for missing index — ${comma(Math.round(gets))} buffer gets/exec is excessive. Query DBA_HIST_SEG_STAT for top segments.`
            : isPlan
            ? `Pin good execution plan: EXEC DBMS_SPM.LOAD_PLANS_FROM_AWR(begin_snap_id=>?, end_snap_id=>?, sql_id=>'${topSql.sql_id}')`
            : `Run SQL Tuning Advisor: EXEC DBMS_SQLTUNE.CREATE_TUNING_TASK(sql_id=>'${topSql.sql_id}', task_name=>'tune_${topSql.sql_id}')`;
        const evidence = [
            `${f1(pdb)}% of DB Time in problem period`,
            isNew?`Not present in baseline — new workload`:`Baseline ${epe1!=null?f1(epe1)+'s':'?'}s ? Problem ${f1(epe2)}s per execution`,
            gets>0?`${comma(Math.round(gets))} buffer gets/exec`:'',
            `${comma(topSql.executions||0)} executions in problem window`,
        ].filter(Boolean);
        findings.push({
            id:'sql_dominant', severity:pdb>=25?'CRITICAL':'WARNING',
            category:rct, trend:'WORSENING',
            title:`${label} SQL ${topSql.sql_id} — dominant ${primaryBottleneck.toUpperCase()} consumer`,
            headline:`SQL ${topSql.sql_id}: ${f1(pdb)}% DB Time · ${comma(topSql.executions||0)} execs · ${f1(epe2)}s/exec`,
            evidence,
            root_cause: isNew?`SQL ${topSql.sql_id} absent from baseline — new workload introduced without production-volume validation`
                :isPlan?`Execution plan changed on SQL ${topSql.sql_id} — new plan is significantly more expensive`
                :`SQL ${topSql.sql_id} execution cost increased — higher frequency or regression in access path`,
            fix:`Run SQL Tuning Advisor on SQL ID ${topSql.sql_id}`,
            impact_score:Math.min(100,pdb*2), confidence:'HIGH', sql_ids:[topSql.sql_id],
            causal_chain:[], oracle_ref:'Oracle Performance Tuning Guide — SQL Tuning',
            fix_detail:{
                title:`${label} SQL ${topSql.sql_id}`,
                fix_statement:`Run SQL Tuning Advisor on SQL ID ${topSql.sql_id} to identify access path improvements and reduce per-execution resource cost`,
                fix_reasoning: isNew?`SQL was absent from baseline — not validated at production execution scale before deployment`
                    :isPlan?`Plan change introduced a more expensive access path — pin the known-good plan via SQL Plan Baseline`
                    :`Execution resource cost increased — likely stale statistics or missing index`,
                action_1:action1fix, action_2:action2fix,
                action_3:`Re-run AWR comparison after tuning — confirm ${topSql.sql_id} DB Time% drops`,
                validate_by:`Confirm SQL ${topSql.sql_id} DB Time% below ${Math.max(5,Math.round(pdb/3))}% in next AWR window`,
                confidence:'HIGH', root_cause_type:rct,
                notes:isPlan?`Plan hash changed: baseline ${s1x?.plan_hash_value||'?'} ? problem ${topSql.plan_hash_value||'?'}`:''
            }
        });

        // Minor contributing SQLs as secondary finding
        const minorSqls = sqlSorted.slice(1,4).filter(s=>(s.pct_db_time||0)>2);
        if (minorSqls.length > 0) {
            findings.push({
                id:'sql_secondary', severity:'WARNING', category:'sql_regression', trend:'WORSENING',
                title:`[WORSE] ${minorSqls.length} contributing SQL statement(s)`,
                headline:minorSqls.map(s=>`${s.sql_id}: ${f1(s.pct_db_time||0)}%`).join(' · '),
                evidence:minorSqls.map(s=>`SQL ${s.sql_id}: ${f1(s.pct_db_time||0)}% DB Time · ${comma(s.executions||0)} execs`),
                root_cause:`Secondary SQL workload contributing to total DB Time consumption`,
                fix:`Review SQL ${minorSqls[0].sql_id} access path after addressing dominant SQL`,
                impact_score:Math.min(60, minorSqls.reduce((s,sq)=>s+(sq.pct_db_time||0),0)),
                confidence:'MEDIUM', sql_ids:minorSqls.map(s=>s.sql_id), causal_chain:[],
                fix_detail:{
                    title:'Secondary SQL contributors',
                    fix_statement:`Review access paths for ${minorSqls.map(s=>s.sql_id).join(', ')}`,
                    fix_reasoning:'Secondary SQLs add to total DB Time — address after dominant SQL is tuned',
                    action_1:minorSqls.map(s=>`DBMS_XPLAN.DISPLAY_AWR('${s.sql_id}')`).join(', '),
                    action_2:'Compare execution plans vs baseline',
                    action_3:'Monitor in next AWR period',
                    validate_by:'Confirm total SQL DB Time normalises',
                    confidence:'MEDIUM', root_cause_type:'sql_regression'
                }
            });
        }
    }

    // -- Wait event findings ---------------------------------------------------
    const ev1Map = {}; ev1.forEach(e=>{ ev1Map[e.event_name]=e; });
    const waitDiagMap = {
        'log file sync':     { rct:'commit_bottleneck', fix:'Reduce commit frequency — batch commits; move redo logs to faster storage' },
        'db file sequential':{ rct:'io_bottleneck',     fix:'Check for unselective index scans — db file sequential read is single-block I/O. Review DBA_HIST_SEG_STAT.' },
        'db file scattered': { rct:'io_bottleneck',     fix:'Check for full table/index scans — db file scattered read is multi-block I/O. Verify index coverage.' },
        'buffer busy':       { rct:'latch_contention',  fix:'Identify hot blocks via DBA_HIST_SEG_STAT — consider reverse-key index or partitioning to distribute access' },
        'read by other session':{ rct:'latch_contention', fix:'Hot block contention — same as buffer busy waits. Identify segment and evaluate partitioning.' },
        'latch:':            { rct:'latch_contention',  fix:'Check V$LATCH for top miss category — often shared pool (parse storm) or CBC (hot block)' },
        'cursor pin s':      { rct:'latch_contention',  fix:'Hard parse storm driving cursor serialisation — enable bind variables, increase SESSION_CACHED_CURSORS' },
        'library cache':     { rct:'latch_contention',  fix:'Parse storm — set CURSOR_SHARING=FORCE or add bind variables; check DDL invalidation' },
        'enq: hw':           { rct:'concurrency_lock',  fix:'HWM contention — pre-allocate extents via DBMS_SPACE.EXTEND; set PCTINCREASE=0; use locally managed tablespaces' },
        'enq: tx':           { rct:'concurrency_lock',  fix:'Row-level lock conflict — check V$LOCK for blocking session; investigate ITL exhaustion (increase INITRANS)' },
        'enq: tm':           { rct:'concurrency_lock',  fix:'Table-level DML lock — check foreign key indexes; missing FK index causes TM lock escalation' },
        'direct path read temp':{ rct:'temp_spill',     fix:'Sort/hash join spill to temp — increase PGA_AGGREGATE_TARGET; reduce WORK_AREA_SIZE_POLICY if manual' },
        'direct path write temp':{ rct:'temp_spill',    fix:'Temp write pressure — same as temp read. Increase PGA or reduce sort/hash join demand.' },
        'gc buffer busy':    { rct:'rac_contention',    fix:'RAC inter-node block transfer — identify hot objects via GV$SEGMENT_STATISTICS; consider object affinity' },
        'gc cr request':     { rct:'rac_contention',    fix:'RAC consistent-read block transfer — reduce cross-node DML; consider sequence cache sizing' },
        'db cpu':            { rct:'cpu_saturation',    fix:'CPU saturated — reduce logical reads per exec; verify bind variables; profile via V$SQL ordered by CPU' },
    };

    ev2.filter(e=>(e.pct_db_time||0)>3).slice(0,5).forEach(ev => {
        const prev  = ev1Map[ev.event_name];
        const isNew = !prev;
        const delta = prev ? (ev.pct_db_time||0)-(prev.pct_db_time||0) : (ev.pct_db_time||0);
        if (!isNew && delta < 2) return; // skip stable events
        const pct = ev.pct_db_time||0;
        const sev = pct>20?'CRITICAL':pct>8?'WARNING':'INFO';
        const diagKey = Object.keys(waitDiagMap).find(k=>(ev.event_name||'').toLowerCase().includes(k.toLowerCase()));
        const diag = diagKey ? waitDiagMap[diagKey] : { rct:'inconclusive', fix:`Investigate ${ev.event_name} — query Oracle Support for specific remediation` };
        const label = isNew?'[NEW]':'[WORSE]';

        // Skip if already covered by dominant SQL finding (to avoid duplication)
        if (!isNew && delta < 5 && findings.some(f=>f.id==='sql_dominant')) return;

        findings.push({
            id:`wait_${(ev.event_name||'').replace(/[^a-z0-9]/gi,'_').slice(0,20)}`,
            severity:sev, category:diag.rct, trend:'WORSENING',
            title:`${label} ${ev.event_name}${isNew?'':` (+${f1(delta)}pp)`}`,
            headline:`${ev.event_name}: ${f1(pct)}% DB Time${isNew?' (new in problem period)':` (+${f1(delta)}pp from baseline)`}`,
            evidence:[
                `${f1(pct)}% of DB Time in problem period`,
                prev?`Baseline: ${f1(prev.pct_db_time||0)}% ? Problem: ${f1(pct)}%`:'Not present in baseline',
                (ev.avg_wait_ms||0)>0?`Avg wait: ${f1(ev.avg_wait_ms)}ms (${(ev.avg_wait_ms||0)>20?'EXCEEDS 20ms threshold':'within threshold'})`: '',
                (ev.total_waits||0)>0?`${comma(ev.total_waits)} total waits`:''
            ].filter(Boolean),
            root_cause:isNew?`${ev.event_name} absent from baseline — structural change introduced this wait category`
                :`${ev.event_name} increased ${f1(delta)}pp — workload change or resource pressure increase`,
            fix:diag.fix,
            impact_score:Math.min(100,pct*1.5), confidence:'MEDIUM',
            sql_ids:[], causal_chain:[],
            fix_detail:{
                title:`${label} ${ev.event_name}`,
                fix_statement:diag.fix,
                fix_reasoning:isNew?`Wait event absent from baseline — new bottleneck introduced with problem period workload`
                    :`Wait share of DB Time increased — correlated with ${primaryBottleneck.toUpperCase()} bottleneck type`,
                action_1:diag.fix,
                action_2:`Cross-reference with top SQL statements — check if dominant SQL drives this wait category`,
                action_3:`Monitor in next AWR period — confirm wait normalises after fix`,
                validate_by:`Confirm ${ev.event_name} below 5% DB Time in next comparison`,
                confidence:'MEDIUM', root_cause_type:diag.rct
            }
        });
    });

    // -- Load profile delta finding --------------------------------------------
    const lpShifts = [];
    const _lpD=(a,b)=>a>0?(b-a)/a*100:0;
    const lpChecks = [
        {key:'physical_reads',  label:'Physical Reads/s',  threshold:30},
        {key:'logical_reads',   label:'Logical Reads/s',   threshold:50},
        {key:'hard_parses',     label:'Hard Parses/s',     threshold:50},
        {key:'redo_size',       label:'Redo Size/s',       threshold:50},
        {key:'executes',        label:'Executions/s',      threshold:30},
        {key:'block_changes',   label:'Block Changes/s',   threshold:50},
    ];
    lpChecks.forEach(c=>{
        const d=_lpD(lp1[c.key]||0,lp2[c.key]||0);
        if(Math.abs(d)>=c.threshold) lpShifts.push({...c, d, g:lp1[c.key]||0, b:lp2[c.key]||0});
    });
    if (lpShifts.length > 0) {
        const worst = lpShifts.sort((a,b)=>Math.abs(b.d)-Math.abs(a.d))[0];
        findings.push({
            id:'lp_shift', severity:Math.abs(worst.d)>100?'CRITICAL':'WARNING',
            category:'workload_growth', trend:'WORSENING',
            title:`[WORSE] Load Profile shift — ${worst.label} ${worst.d>0?'+':''}${worst.d.toFixed(0)}%`,
            headline:lpShifts.map(s=>`${s.label}: ${s.d>0?'+':''}${s.d.toFixed(0)}%`).join(' · '),
            evidence:lpShifts.map(s=>`${s.label}: ${(+s.g||0).toFixed(1)} → ${(+s.b||0).toFixed(1)}/s (${s.d>0?'+':''}${s.d.toFixed(0)}%)`),
            root_cause:`Significant load profile shift confirms workload change between baseline and problem period`,
            fix:`Cross-reference load profile shifts with top SQL — the SQL driving physical reads or logical reads is the primary candidate`,
            impact_score:Math.min(80, Math.abs(worst.d)/2), confidence:'HIGH',
            sql_ids:[], causal_chain:[],
            fix_detail:{
                title:'Load Profile Regression',
                fix_statement:`Address top SQL contributing to ${worst.label} increase`,
                fix_reasoning:`Load profile metrics confirm workload change — not just elapsed time difference`,
                action_1:`Identify top SQL by ${worst.key.includes('physical')?'physical reads':'logical reads'} in DBA_HIST_SQLSTAT`,
                action_2:`Verify elapsed time window difference: baseline ${f1((s1.elapsed_secs||0)/60)}min vs problem ${f1((s2.elapsed_secs||0)/60)}min`,
                action_3:'Monitor in next AWR period after SQL tuning',
                validate_by:`Confirm ${worst.label} normalises in next AWR comparison`,
                confidence:'HIGH', root_cause_type:'workload_growth'
            }
        });
    }

    // -- Sort by impact, cap at 10 ---------------------------------------------
    findings.sort((a,b)=>(b.impact_score||0)-(a.impact_score||0));
    const ranked = findings.slice(0,10);

    // -- Verdict text ----------------------------------------------------------
    const topWait = ev2[0] || {};
    const dtGood = (s1.db_time_secs||0)/60;
    const dtBad  = (s2.db_time_secs||0)/60;
    const dtPct  = dtGood>0?((dtBad-dtGood)/dtGood*100):0;
    const verdictText = topSql && (topSql.pct_db_time||0)>=20
        ? `SQL ${topSql.sql_id} dominates at ${f1(topSql.pct_db_time||0)}% DB Time — ${primaryBottleneck.toUpperCase()} bottleneck. DB Time ${dtPct>0?'+':''}${dtPct.toFixed(0)}% vs baseline.`
        : `${primaryBottleneck.toUpperCase()} bottleneck — "${topWait.event_name||''}" at ${f1(topWait.pct_db_time||0)}% DB Time. DB Time ${dtPct>0?'+':''}${dtPct.toFixed(0)}% vs baseline.`;

    // -- Correlation notes from LP ? wait causal links -------------------------
    const corrNotes = [];
    if (lpShifts.find(s=>s.key==='physical_reads') && ev2.find(e=>/db file sequential/i.test(e.event_name||''))) {
        corrNotes.push('Physical reads spike corroborates db file sequential read wait — index scan I/O bottleneck confirmed');
    }
    if (lpShifts.find(s=>s.key==='redo_size') && ev2.find(e=>/log file sync/i.test(e.event_name||''))) {
        corrNotes.push('Redo size surge corroborates log file sync wait — commit frequency bottleneck confirmed');
    }
    if (lpShifts.find(s=>s.key==='hard_parses') && ev2.find(e=>/library cache|latch.*shared/i.test(e.event_name||''))) {
        corrNotes.push('Hard parse spike corroborates library cache / shared pool latch contention — parse storm confirmed');
    }

    return {
        upload_id: 'context_fallback',
        db_name: ctx.meta.db_name || '',
        snap_range: `${lbl1} vs ${lbl2}`,
        overall_health: overallHealth,
        primary_bottleneck: primaryBottleneck,
        verdict: verdictText,
        findings: ranked,
        correlation_notes: corrNotes,
        trend_notes: [],
        pipeline_ms: 0,
        _isFallback: true,
    };
}


// === COMPARISON DASHBOARD ===

function renderComparisonDashboard(ctx) {

    // === ALL DATA FROM AWRContext — no independent parsing ===
    const {meta, loadProfile, instanceEfficiency, waitEvents, timeModel, aas, scores, delta, spikes, connWaitPct, verdicts, sqlAttribution, _raw} = ctx;
    const {s1, s2, crca, rca1, rca2} = _raw;
    const d1 = _raw.good, d2 = _raw.bad;
    const h1 = _raw.health_good, h2 = _raw.health_bad;
    const lbl1 = meta.lbl1, lbl2 = meta.lbl2;
    const sc1 = scores.good, sc2 = scores.bad;
    const ev1 = waitEvents.good.slice(0, 10), ev2 = waitEvents.bad.slice(0, 10);
    const sql1 = d1.sql_stats || [], sql2 = d2.sql_stats || [];
    const eff1 = instanceEfficiency.good, eff2 = instanceEfficiency.bad;
    const aas1 = aas.good, aas2 = aas.bad, cpus = meta.cpu_count;
    const v1 = verdicts.good, v2 = verdicts.bad;

    // LP values from context — no re-parsing
    const exec1 = loadProfile.good.executes, exec2 = loadProfile.bad.executes;
    const parse1 = loadProfile.good.parses, parse2 = loadProfile.bad.parses;
    const hparse1 = loadProfile.good.hard_parses, hparse2 = loadProfile.bad.hard_parses;
    const execSpike = spikes.exec, parseSpike = spikes.parse;
    const logon1 = loadProfile.good.logons, logon2 = loadProfile.bad.logons;
    const logonSpike = spikes.logon;
    const uc1 = loadProfile.good.user_calls, uc2 = loadProfile.bad.user_calls;
    const redo1 = loadProfile.good.redo_size, redo2 = loadProfile.bad.redo_size;
    const connWait1 = connWaitPct.good, connWait2 = connWaitPct.bad;
    const connMgmt1 = timeModel.good.connection_mgmt, connMgmt2 = timeModel.bad.connection_mgmt;
    const sreConn = analyzeSessionConnections(logon1, logon2, connWait1, connWait2, ev2, delta, connMgmt1, connMgmt2);
    const lps = sreConn.lps;
    const lpsRisk = sreConn.lpsRisk;

    const aiText = generateComparisonAISummary(ctx);

    // Run environment mismatch check after render
    setTimeout(() => checkEnvironmentMismatch(d1, d2, lbl1, lbl2), 150);

    // Populate Session Performance Intelligence panel after DOM render
    setTimeout(() => renderSessionIntelligencePanel(ctx), 200);



    document.getElementById('dashboard-content').innerHTML = `

        <!-- DB Info Banner for both databases -->

        ${renderComparisonDBInfoBanner(s1, s2, lbl1, lbl2)}



        <!-- Compact Comparison Banner -->
        <div class="verdict-hero mb-4 fade-in" style="padding:14px 20px">
            <div class="flex items-center justify-between relative z-10">
                <div class="flex items-center gap-4 flex-1">
                    <div class="text-2xl font-black ${((s2.db_time_secs||0)/(Math.max(s1.db_time_secs||1,0.01))-1)*100 > 50 ? 'text-Cred' : ((s2.db_time_secs||0)/(Math.max(s1.db_time_secs||1,0.01))-1)*100 < -10 ? 'text-Cgreen' : 'text-Camber'}">${deltaArrow(s1.db_time_secs||0, s2.db_time_secs||0, true)}</div>
                    <div>
                        <div class="text-sm text-white font-bold">${(()=>{
                            const _dbRatio = (s2.db_time_secs||0) / Math.max(s1.db_time_secs||1, 0.01);
                            const _dbInc   = _dbRatio > 1;
                            const _gl      = ctx.bottleneck.goodLabel || '';
                            const _bl      = ctx.bottleneck.badLabel  || '';
                            const _sameBtl = _gl && _gl === _bl;
                            const _aasOver = aas2 > cpus;
                            const _isPar   = ctx.verdict && ctx.verdict.isParallel;
                            if (!_dbInc) {
                                return `DB Time improved ${num(1/_dbRatio,1)}× — ${_bl} pressure reduced`;
                            } else if (_isPar && _aasOver) {
                                return `<span class="text-Cred font-black">PARALLEL CPU STORM</span> — parallel SQL consumed all ${cpus} cores · AAS <span class="text-Cred">${num(aas2,1)}</span>/${cpus}`;
                            } else if (_aasOver && _sameBtl) {
                                return `<span class="text-Cred font-black">CPU SATURATED</span> — ${num(_dbRatio,1)}× more work than <span class="text-Ccyan">${cpus} cores</span> can service · AAS <span class="text-Cred">${num(aas2,1)}</span>`;
                            } else if (_sameBtl) {
                                return `DB Time intensified ${num(_dbRatio,1)}× — <span class="text-Ccyan">${_bl}</span> pressure sustained`;
                            } else {
                                return `DB Time ${num(_dbRatio,1)}× — bottleneck shifted from <span class="text-Ccyan">${_gl}</span> to <span class="text-Ccyan">${_bl}</span>`;
                            }
                        })()}</div>
                        <div class="text-xs text-Cmuted mt-1">${num((s1.db_time_secs||0)/60,1)} → ${num((s2.db_time_secs||0)/60,1)} min · AAS ${num(aas1,1)} → ${num(aas2,1)}${aas2>cpus?' <span class="sev-critical font-bold">⚠ OVER '+cpus+' CPUs</span>':''}</div>
                    </div>
                </div>
                <button onclick="const d=document.getElementById('hero-detail');d.style.display=d.style.display==='none'?'block':'none';this.textContent=d.style.display==='none'?'Details \u25bc':'Details \u25b2'" style="font-size:9px;color:#818cf8;background:rgba(129,140,248,0.1);border:1px solid rgba(129,140,248,0.2);border-radius:4px;padding:3px 10px;cursor:pointer">Details &#x25BC;</button>
            </div>
            <div id="hero-detail" style="display:none;margin-top:12px;border-top:1px solid #1e293b;padding-top:12px">
                <div class="grid grid-cols-2 gap-4">
                    <div>
                        <div class="text-[10px] text-Cgreen uppercase tracking-widest font-semibold mb-1">${esc(lbl1)}</div>
                        <div class="text-xs text-white font-bold">${esc(v1.primary_finding||'Baseline Period')}</div>
                        <div class="text-[10px] text-Cmuted">${ctx.bottleneck.goodDescriptor||''}</div>
                    </div>
                    <div class="text-right">
                        <div class="text-[10px] text-Cred uppercase tracking-widest font-semibold mb-1">${esc(lbl2)}</div>
                        <div class="text-xs text-white font-bold">${esc(v2.primary_finding||'Problem Period')}</div>
                        <div class="text-[10px] text-Cmuted">${ctx.bottleneck.badDescriptor||''}</div>
                    </div>
                </div>
            </div>
        </div>

        ${(() => {
            const hp1 = hparse1 || 0, hp2 = hparse2 || 0;
            const hpDelta = hp1 > 0 ? (hp2 - hp1) / hp1 * 100 : (hp2 > 0 ? 100 : 0);
            const parseCpu1 = (eff1 && eff1.parse_cpu_pct) || 0, parseCpu2 = (eff2 && eff2.parse_cpu_pct) || 0;
            const softParse2 = (eff2 && eff2.soft_parse_pct) || 100;
            const showParse = hpDelta > 50 || parseCpu2 > 50 || softParse2 < 70;
            if (!showParse) return '';
            const flags = [];
            if (hpDelta > 50) flags.push('Hard Parses/sec: ' + num(hp1,1) + ' → ' + num(hp2,1) + ' (+' + num(hpDelta,0) + '%)');
            if (parseCpu2 > 50) flags.push('Parse CPU: ' + num(parseCpu2,0) + '% of total CPU (was ' + num(parseCpu1,0) + '%)');
            if (softParse2 < 70) flags.push('Soft Parse %: ' + num(softParse2,0) + '% — cursor sharing may be ineffective');
            return '<div style="background:rgba(245,158,11,0.06);border:1px solid rgba(245,158,11,0.25);border-radius:6px;padding:8px 14px;margin-bottom:12px;display:flex;align-items:center;gap:10px">' +
                '<span style="font-size:14px">⚡</span>' +
                '<div><div style="color:#fbbf24;font-size:10px;font-weight:800">PARSE PRESSURE</div>' +
                '<div style="color:#94a3b8;font-size:9px;line-height:1.5">' + flags.join(' · ') + '</div></div></div>';
        })()}

        ${aiNarrative('Comparison Summary', aiText)}



        <!-- KPI Comparison Row -->

        <div class="grid grid-cols-2 md:grid-cols-6 gap-2 mb-4 fade-in fade-in-d1">

            <div class="kpi-card" title="Average Active Sessions = DB Time / Elapsed Time. Represents how many sessions were actively working on average. Exceeding CPU count means saturation.">

                <div class="kpi-label">Avg Active Sessions <span style="color:#374151;font-weight:400">(AAS)</span></div>

                <div class="flex justify-center gap-1 items-baseline"><span class="text-lg text-Cgreen font-bold">${num(aas1,1)}</span><span class="text-[10px] text-gray-600">&rarr;</span><span class="text-lg ${aas2>cpus?'sev-critical':aas2>aas1?'text-Cred':'text-Cgreen'} font-bold">${num(aas2,1)}</span></div>

                <div class="kpi-sub">${cpus} CPUs ${aas2>cpus?'<span style="color:#f87171;font-weight:700">⚠ SATURATED</span>':''} | ${deltaArrow(aas1, aas2, true)}</div>

            </div>

            <div class="kpi-card" title="DB Time (min): total database work time for each period in minutes. Compare the two bars — a large increase means the bad period had significantly more concurrent session activity or longer waits per operation." title="DB Time (min): total database work time for each period in minutes. Compare the two bars — a large increase means the bad period had significantly more concurrent session activity or longer waits per operation."><div class="kpi-label">DB Time (min)</div>

                <div class="flex justify-center gap-1 items-baseline"><span class="text-sm text-Cgreen">${num((s1.db_time_secs||0)/60)}</span><span class="text-[10px] text-gray-600">&rarr;</span><span class="text-sm text-Cred">${num((s2.db_time_secs||0)/60)}</span></div>

                <div class="kpi-sub">${deltaArrow(s1.db_time_secs||0, s2.db_time_secs||0, true)}</div>

            </div>

            <div class="kpi-card" title="Buffer Cache Hit %: percentage of data block reads satisfied from RAM (the buffer cache) without going to disk. Target is above 95%. A drop signals increased physical I/O — check physical reads in Load Profile and SQL ordered by Physical Reads." title="Buffer Cache Hit %: percentage of data block reads satisfied from RAM (the buffer cache) without going to disk. Target is above 95%. A drop signals increased physical I/O — check physical reads in Load Profile and SQL ordered by Physical Reads."><div class="kpi-label">Buffer Hit %</div>

                <div class="flex justify-center gap-1 items-baseline"><span class="text-sm text-Cgreen">${num(eff1.buffer_cache_hit_pct||0)}</span><span class="text-[10px] text-gray-600">&rarr;</span><span class="text-sm ${(eff2.buffer_cache_hit_pct||0)<95?'text-Cred':'text-Cgreen'}">${num(eff2.buffer_cache_hit_pct||0)}</span></div>

                <div class="kpi-sub">${deltaArrow(eff1.buffer_cache_hit_pct||0, eff2.buffer_cache_hit_pct||0, false)}</div>

            </div>

            <div class="kpi-card" onclick="switchTab('rca')" style="cursor:pointer;border:1px solid rgba(245,158,11,0.25)" title="Click to view Delta Findings in RCA tab">

                <div class="kpi-label">Delta Issues <span style="color:#374151;font-size:9px">RCA</span></div>

                <div class="kpi-val sev-warning">${delta.length}</div>

                <div class="kpi-sub">${delta.filter(f=>f.severity==='critical').length} critical · click to view</div>

            </div>

            ${exec1>0?`<div class="kpi-card" style="${execSpike>100?'border-top:3px solid #f59e0b':execSpike>300?'border-top:3px solid #ef4444':''}" title="Executes/sec: SQL statement executions per second. A spike means more workload was submitted — determine if this is expected application load or a runaway loop. Cross-reference with Parses/sec to check cursor reuse."><div class="kpi-label">Executes/sec</div><div class="flex justify-center gap-1 items-baseline"><span class="text-xs text-Cgreen">${num(exec1,0)}</span><span class="text-[10px] text-gray-600">→</span><span class="text-xs ${execSpike>100?'sev-warning':''} font-bold">${num(exec2,0)}</span></div><div class="kpi-sub ${execSpike>100?'text-Camber font-bold':''}">${execSpike>0?'+':''}${num(execSpike,0)}%${execSpike>200?' ⚠ SPIKE':''}</div></div>`:``}

            ${parse1>0?`<div class="kpi-card" style="${parseSpike>200?'border-top:3px solid #f59e0b':parseSpike>500?'border-top:3px solid #ef4444':''}" title="Parses/sec: SQL parse operations per second. Hard parses (building a new execution plan from scratch) are expensive. A spike here — especially with rising DB CPU — indicates literal SQL without bind variables or cursor cache pressure."><div class="kpi-label">Parses/sec</div><div class="flex justify-center gap-1 items-baseline"><span class="text-xs text-Cgreen">${num(parse1,0)}</span><span class="text-[10px] text-gray-600">→</span><span class="text-xs ${parseSpike>200?'sev-warning':''} font-bold">${num(parse2,0)}</span></div><div class="kpi-sub ${parseSpike>200?'text-Camber font-bold':''}">${parseSpike>0?'+':''}${num(parseSpike,0)}%${parseSpike>400?' ⚠ SPIKE':''}</div></div>`:``}

            ${(()=>{

                const b1 = ctx.bottleneck.good.type, b2 = ctx.bottleneck.bad.type;

                const shifted = ctx.bottleneck.shifted;

                const b1c = b1==='io'?'#3b82f6':b1==='cpu'?'#10b981':b1==='concurrency'?'#f59e0b':b1==='configuration'?'#e879f9':'#94a3b8';

                const b2c = b2==='io'?'#3b82f6':b2==='cpu'?'#10b981':b2==='concurrency'?'#f59e0b':b2==='configuration'?'#e879f9':'#94a3b8';

                return `<div class="kpi-card" style="${shifted?'border:1px solid rgba(239,68,68,0.4)':''}" title="Baseline Bottleneck: the primary resource constraint in the good/baseline period — CPU, I/O, or Concurrency. Compare with the bad period bottleneck to see if the problem type changed." title="Baseline Bottleneck: the primary resource constraint in the good/baseline period — CPU, I/O, or Concurrency. Compare with the bad period bottleneck to see if the problem type changed."><div class="kpi-label">${esc(lbl1)} Bottleneck</div><div class="kpi-val text-sm font-bold" style="color:${b1c}">${ctx.bottleneck.goodLabel}</div>${shifted?'<div class="text-[9px] text-Cred font-bold mt-0.5">SHIFTED ?</div>':''}</div>

                <div class="kpi-card" style="${shifted?'border:1px solid rgba(239,68,68,0.4)':''}" title="Problem Period Bottleneck: the primary resource constraint in the bad/problem period. If this differs from the baseline, a new bottleneck category emerged — a strong signal that something structural changed (new workload, missing index, lock contention)." title="Problem Period Bottleneck: the primary resource constraint in the bad/problem period. If this differs from the baseline, a new bottleneck category emerged — a strong signal that something structural changed (new workload, missing index, lock contention)."><div class="kpi-label">${esc(lbl2)} Bottleneck</div><div class="kpi-val text-sm font-bold" style="color:${b2c}">${ctx.bottleneck.badLabel}</div>${shifted?'<div class="text-[9px] text-Cred font-bold mt-0.5">▲ CHANGED</div>':''}</div>`;

            })()}

        </div>

        ${(()=>{
            const _blAas = aas1, _blCpus = cpus;
            const _blCpuBusy = d1.os_stats?.cpu_busy_pct || 0;
            const _blLatchHit = eff1.latch_hit_pct || 0;
            const _blStressed = _blAas >= _blCpus * 0.9 || _blCpuBusy >= 90;
            if (!_blStressed) return '';
            const _pctUtil = (_blAas / _blCpus * 100).toFixed(0);
            const _addmGood = d1.addm_findings || [];
            const _preExisting = _addmGood.filter(f => {
                const n = (f.finding_name||'').toLowerCase();
                return n.includes('undersized sga') || n.includes('buffer busy') || n.includes('hot object');
            }).map(f => f.finding_name);
            return '<div class="mb-4" style="padding:12px 16px;background:linear-gradient(135deg,rgba(120,53,15,0.3),rgba(69,26,3,0.4));border:1px solid rgba(245,158,11,0.3);border-radius:8px;border-left:4px solid #f59e0b">' +
                '<div style="display:flex;align-items:center;gap:10px;margin-bottom:6px">' +
                '<span style="display:inline-flex;align-items:center"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="1.5" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065zM15 12a3 3 0 11-6 0 3 3 0 016 0z"/></svg></span>' +
                '<span style="color:#fbbf24;font-size:13px;font-weight:800;text-transform:uppercase;letter-spacing:0.5px">Baseline Already Stressed</span>' +
                '</div>' +
                '<div style="color:#e2e8f0;font-size:12px;line-height:1.7">' +
                'The <b style="color:#4ade80">' + esc(lbl1) + '</b> period itself was <b style="color:#fbbf24">near-saturated</b> ' +
                '(AAS=' + num(_blAas,1) + ' vs ' + _blCpus + ' CPUs = <b style="color:#fbbf24">' + _pctUtil + '% utilization</b>' +
                (_blCpuBusy >= 90 ? ', Host CPU <b style="color:#f87171">' + num(_blCpuBusy,0) + '% busy</b>' : '') +
                '). The problem period degradation is <b>on top of an already overloaded system</b>.' +
                (_blLatchHit > 0 && _blLatchHit < 99 ? ' Latch hit ' + num(_blLatchHit,1) + '% in baseline — not newly introduced.' : '') +
                (_preExisting.length > 0 ? ' Pre-existing ADDM findings: <b style="color:#fb923c">' + _preExisting.join(', ') + '</b>.' : '') +
                ' Performance deltas may understate the true severity.' +
                '</div></div>';
        })()}

        <!-- Charts Row 1: Wait Events + Significant Load Profile Signal Cards -->

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4 fade-in fade-in-d2">

            <div class="card p-4">

                <div class="text-xs font-semibold text-Cmuted mb-2 uppercase">Wait Events: ${esc(lbl1)} vs ${esc(lbl2)}</div>

                <div class="chart-wrapper" style="height:270px"><canvas id="dash-wait-cmp"></canvas></div>

            </div>

            <div class="card p-4">

                <div class="flex items-center justify-between mb-3">

                    <div class="text-xs font-semibold text-Cmuted uppercase">Key Metric Changes</div>

                    <div class="text-[10px] text-gray-600">Only significant deltas shown &nbsp;·&nbsp; green bar = ${esc(lbl1)}, solid = ${esc(lbl2)}</div>

                </div>

                ${(()=>{

                    // Efficiency ratios (always show if value is not "all-good")
                    const effMetrics = [

                        { label:'Buffer Cache Hit %',  tip:'How often data is found in RAM vs reading from disk. <95% = excessive disk I/O.',  g:eff1.buffer_cache_hit_pct||0,  b:eff2.buffer_cache_hit_pct||0,  thresh:[99,95,90] },

                        { label:'Soft Parse %',        tip:'% of SQL executions that reuse a cached plan. <95% = hard parse overhead.',         g:eff1.soft_parse_pct||0,        b:eff2.soft_parse_pct||0,        thresh:[99,95,85] },

                        { label:'Library Cache Hit %', tip:'% of SQL look-ups that find cursor in memory. Low = shared pool too small.',         g:eff1.library_cache_hit_pct||0, b:eff2.library_cache_hit_pct||0, thresh:[99,97,95] },

                        { label:'Execute to Parse %',  tip:'% of executes reusing an open cursor. Low = cursor caching not enabled.',           g:eff1.execute_to_parse_pct||0,  b:eff2.execute_to_parse_pct||0,  thresh:[90,70,50] },

                        { label:'Latch Hit %',         tip:'Internal Oracle lock efficiency. <99% = contention in shared memory.',              g:eff1.latch_hit_pct||0,        b:eff2.latch_hit_pct||0,         thresh:[99.9,99,98] },

                    ].filter(m => {
                        // Show if: degraded in bad period, OR below warning threshold in either period
                        const degraded = m.b < m.g - 3;
                        const atRisk = m.b < m.thresh[1] || m.g < m.thresh[1];
                        return degraded || atRisk;
                    });

                    const barColor = (v, t) => v>=t[0]?'#10b981':v>=t[1]?'#f59e0b':'#ef4444';

                    const statusLabel = (v, t) => v>=t[0]?'<span class="text-Cgreen font-bold text-[9px]">OK</span>':v>=t[1]?'<span class="text-Camber font-bold text-[9px]">WARN</span>':'<span class="text-Cred font-bold text-[9px]">BAD</span>';

                    const effHtml = effMetrics.length > 0
                        ? effMetrics.map(m => {

                            const gV = Math.min(m.g, 100), bV = Math.min(m.b, 100);

                            const gColor = barColor(gV, m.thresh), bColor = barColor(bV, m.thresh);

                            const degraded = bV < gV - 3;

                            return `<div class="mb-2" title="${m.tip}">

                                <div class="flex items-center justify-between mb-0.5">

                                    <span class="text-xs text-gray-300">${m.label}</span>

                                    <span class="flex items-center gap-2 text-xs">

                                        <span class="text-Cgreen">${gV.toFixed(1)}%</span>

                                        <svg class="w-2.5 h-2.5 ${degraded?'text-Cred':'text-gray-600'}" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M17 8l4 4m0 0l-4 4m4-4H3"/></svg>

                                        <span class="${degraded?'text-Cred font-bold':'text-gray-300'}">${bV.toFixed(1)}%</span>

                                        ${statusLabel(bV, m.thresh)}

                                    </span>

                                </div>

                                <div class="relative h-1.5 rounded-full overflow-hidden" style="background:#1e293b">

                                    <div class="absolute left-0 top-0 h-full rounded-full opacity-40" style="width:${gV}%;background:${gColor}"></div>

                                    <div class="absolute left-0 top-0 h-full rounded-full" style="width:${bV}%;background:${bColor}"></div>

                                </div>

                            </div>`;

                        }).join('')
                        : '<div class="text-[10px] text-Cgreen py-2">&#10003; All efficiency ratios within normal range</div>';

                    // Significant LP metrics from normalized comparison (top 4 by |delta|)
                    const sigLP = ctx._norm && ctx._norm.significantLP ? ctx._norm.significantLP.slice(0, 4) : [];

                    const lpHtml = sigLP.length > 0 ? `

                        <div class="mt-3 pt-3" style="border-top:1px solid #1e293b">

                            <div class="text-[9px] text-Cindigo font-bold uppercase mb-2">Significant Load Profile Changes</div>

                            <div style="display:grid;grid-template-columns:repeat(2,1fr);gap:6px">

                                ${sigLP.map(m => {

                                    const col = m.direction==='regression'?'#f87171':m.direction==='improvement'?'#4ade80':'#94a3b8';

                                    const fmtV = v => Math.abs(v)>=1e6?(v/1e6).toFixed(1)+'M':Math.abs(v)>=1e3?(v/1e3).toFixed(1)+'K':v.toFixed(v<10?2:0);

                                    return `<div style="background:rgba(15,23,42,0.8);border:1px solid ${col}30;border-radius:6px;padding:6px 8px">

                                        <div style="font-size:8px;color:#64748b;font-weight:700;text-transform:uppercase;margin-bottom:2px">${esc(m.label)}</div>

                                        <div style="font-size:13px;font-weight:900;color:${col}">${m.delta_pct>0?'+':''}${m.delta_pct.toFixed(0)}%</div>

                                        <div style="font-size:8px;color:#475569">${fmtV(m.good_val)} &rarr; ${fmtV(m.bad_val)}${esc(m.unit)}</div>

                                    </div>`;

                                }).join('')}

                            </div>

                        </div>` : '';

                    return effHtml + lpHtml +

                        (effMetrics.length === 0 && sigLP.length === 0 ? '' :

                            '<div class="text-[9px] text-gray-600 mt-2 pt-2 border-t border-Cborder">Full detail in the Efficiency &amp; Load Profile table below.</div>');

                })()}

            </div>

        </div>



        <!-- Charts Row 2: SQL 3-Zone Comparison — collapses when outer zones empty -->

        <div class="card p-4 mb-4 fade-in fade-in-d3" id="sql-3zone-card">

            <div class="flex items-center justify-between mb-3">

                <div class="text-xs font-semibold text-Cmuted uppercase">SQL Elapsed/Exec — 3-Zone Comparative Analysis</div>

                <div class="flex items-center gap-4 text-[10px] text-Cmuted">

                    <span><span style="color:#10b981;font-size:13px">¦</span> Good-only (${esc(lbl1)})</span>

                    <span><span style="color:#06b6d4;font-size:13px">¦</span> Common</span>

                    <span><span style="color:#ef4444;font-size:13px">¦</span> Bad-only (${esc(lbl2)})</span>

                    <span title="Common zone severity colors"><span style="color:#ef4444;font-size:9px">■</span><span style="color:#f97316;font-size:9px">■</span><span style="color:#f59e0b;font-size:9px">■</span><span style="color:#3b82f6;font-size:9px">■</span><span style="color:#818cf8;font-size:9px">■</span> <span style="font-size:9px">Critical/Severe/Significant/Stable/Contention</span></span>

                </div>

            </div>

            <!-- Zone summary line (shown when outer zones empty) -->

            <div id="sql-3zone-empty" style="display:none;padding:8px 12px;background:rgba(15,23,42,0.6);border-radius:6px;margin-bottom:8px">

                <span style="font-size:10px;color:#64748b">No unique-baseline or new-problem SQLs — all top SQLs are common to both periods. </span>

                <span style="font-size:10px;color:#475569;cursor:pointer;text-decoration:underline" onclick="document.getElementById('sql-3zone-charts').style.display='grid';this.parentElement.style.display='none'">Show charts anyway</span>

            </div>

            <div id="sql-3zone-charts" class="grid gap-2" style="grid-template-columns:1fr 1.6fr 1fr">

                <div class="sql-zone sql-zone-good">

                    <div class="sql-zone-label" style="color:#34d399">Good Only &mdash; ${esc(lbl1)}</div>

                    <div class="text-[9px] text-Cmuted mb-2">Queries only in baseline (disappeared in problem)</div>

                    <div style="height:200px"><canvas id="dash-sql-good-only"></canvas></div>

                </div>

                <div class="sql-zone sql-zone-common">

                    <div class="sql-zone-label" style="color:#22d3ee">Common &mdash; Both Periods</div>

                    <div class="text-[9px] text-Cmuted mb-2">Top 5 worst common SQLs — green=baseline, colored=problem (by regression severity)</div>

                    <div style="height:200px"><canvas id="dash-sql-common-cmp"></canvas></div>

                    <div id="sql-common-anno" style="display:none;margin-top:4px;display:flex;flex-wrap:wrap;gap:4px"></div>

                </div>

                <div class="sql-zone sql-zone-bad">

                    <div class="sql-zone-label" style="color:#f87171">Bad Only &mdash; ${esc(lbl2)} ?</div>

                    <div class="text-[9px] text-Cmuted mb-2">New offenders — not in baseline period</div>

                    <div style="height:200px"><canvas id="dash-sql-bad-only"></canvas></div>

                </div>

            </div>

            <!-- Top 3 culprit highlight strip -->

            <div id="dash-sql-top3" class="mt-3" style="display:grid;grid-template-columns:repeat(3,1fr);gap:8px"></div>

        </div>



        <!-- Efficiency + Load Profile Comparison Table (SSoT from normalized_comparison) -->

        ${renderEfficiencyComparisonTable(eff1, eff2, s1, s2, lbl1, lbl2, ctx._norm)}



        <!-- SRE Operations Panel -->

        <div class="sre-card mb-4 fade-in">

            <div class="flex items-center gap-2 mb-4">

                <div style="width:24px;height:24px;background:linear-gradient(135deg,#7c3aed,#06b6d4);border-radius:6px;display:flex;align-items:center;justify-content:center;flex-shrink:0">

                    <svg class="w-3.5 h-3.5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>

                </div>

                <div>

                    <div class="text-xs font-bold text-Ccyan uppercase tracking-wide">Session Performance Intelligence</div>

                    <div class="text-[10px] text-Cmuted" title="Cross-correlates Commit &amp; Execution Health, Session/Logon Pressure, Load Profile, SQL Attribution, and Wait Events into a single diagnostic chain. Each node is evidence-linked.">Commit &amp; Execution Health &nbsp;·&nbsp; Session &amp; Logon Pressure &nbsp;·&nbsp; Connecting Dots Analysis</div>

                </div>

            </div>

            ${(()=>{

                // -- Shared calculations ----------------------------------------------

                const fmtLat = v => v >= 1000 ? num(v/1000,2)+'s' : num(v,1)+'ms';

                const fmtK   = v => v>=1000000?num(v/1000000,1)+'M':v>=1000?num(v/1000,1)+'K':num(v,1);



                // COMMIT & EXECUTION HEALTH — 3 metrics:
                //   1. db_time_per_exec_ms = (AAS / exec_per_sec) * 1000
                //   2. commit_latency_ms   = log_file_sync avg wait ms (from wait events)
                //   3. cpu_efficiency_pct  = (db_cpu_per_sec / db_time_per_sec) * 100

                const dbTimeSecs1 = (s1.db_time_secs||0) || ((d1.db_time_min||0)*60);
                const dbTimeSecs2 = (s2.db_time_secs||0) || ((d2.db_time_min||0)*60);

                // db_time_per_exec = (AAS / exec_per_sec) * 1000  [ms]
                const lat1 = exec1 > 0 ? (aas1 / exec1) * 1000
                           : uc1   > 0 ? (aas1 / uc1) * 1000
                           : 0;
                const lat2 = exec2 > 0 ? (aas2 / exec2) * 1000
                           : uc2   > 0 ? (aas2 / uc2) * 1000
                           : 0;
                const latSrc = exec2 > 0 ? 'AAS \u00f7 Executes/sec \u00d7 1000' : uc2 > 0 ? 'AAS \u00f7 User Calls/sec \u00d7 1000' : 'N/A';

                const latDelta = lat1 > 0 ? (lat2 - lat1) / lat1 * 100 : 0;
                const latBad   = latDelta > 50;
                const latWarn  = latDelta > 15;
                const latRating = latBad ? 'CRITICAL' : latWarn ? 'DEGRADED' : 'STABLE';
                const latCol    = latBad ? '#ef4444' : latWarn ? '#f59e0b' : '#10b981';
                const latBg     = latBad ? 'rgba(239,68,68,0.06)' : latWarn ? 'rgba(245,158,11,0.06)' : 'rgba(16,185,129,0.06)';

                // Commit latency from log file sync wait event
                const _findWaitAvg = (evts, pattern) => {
                    const e = (evts||[]).find(w => pattern.test(w.event_name||''));
                    return e ? (e.avg_wait_ms || (e.total_wait_s && e.total_waits ? e.total_wait_s / e.total_waits * 1000 : 0)) : 0;
                };
                const commitLat1 = _findWaitAvg(ev1, /log file sync/i);
                const commitLat2 = _findWaitAvg(ev2, /log file sync/i);
                const commitDelta = commitLat1 > 0 ? (commitLat2 - commitLat1) / commitLat1 * 100 : 0;
                const commitCol = commitLat2 > 20 ? '#ef4444' : commitLat2 > 10 ? '#f59e0b' : '#10b981';

                // CPU efficiency = (DB CPU per sec / DB Time per sec) * 100
                const dbCpuPerSec1 = loadProfile.good.db_cpu_s || 0;
                const dbCpuPerSec2 = loadProfile.bad.db_cpu_s || 0;
                const dbTimePerSec1 = loadProfile.good.db_time_s || aas1 || 0;
                const dbTimePerSec2 = loadProfile.bad.db_time_s || aas2 || 0;
                const cpuEff1 = dbTimePerSec1 > 0 ? (dbCpuPerSec1 / dbTimePerSec1) * 100 : 0;
                const cpuEff2 = dbTimePerSec2 > 0 ? (dbCpuPerSec2 / dbTimePerSec2) * 100 : 0;
                const cpuEffDelta = cpuEff1 > 0 ? cpuEff2 - cpuEff1 : 0;
                const cpuEffCol = cpuEff2 > 80 ? '#10b981' : cpuEff2 > 50 ? '#f59e0b' : '#ef4444';



                // Soft-parse & buffer-cache

                const sp2 = eff2.soft_parse_pct||100, sp1 = eff1.soft_parse_pct||100;

                const bch2 = eff2.buffer_cache_hit_pct||0, bch1 = eff1.buffer_cache_hit_pct||0;



                // LOGON / SESSION PRESSURE

                const hasLogonData = logon1>0 || logon2>0;

                const logonCol    = lps>100?'#ef4444':lps>50?'#f59e0b':'#10b981';

                const logonBg     = lps>100?'rgba(239,68,68,0.06)':lps>50?'rgba(245,158,11,0.06)':'rgba(16,185,129,0.06)';

                // Use lpsRisk (from analyzeSessionConnections) to avoid "LOGON STORM" misfiring
                // when logon spike is actually caused by parallel slave processes registering as sessions.
                const logonRating = lpsRisk==='storm'  ? 'LOGON STORM'
                                  : (lpsRisk==='high'||lpsRisk==='medium') ? 'HIGH PRESSURE'
                                  : (lpsRisk==='low' && lps > 100) ? 'PARALLEL SESSIONS'
                                  : lps > 20 ? 'MODERATE' : 'STABLE';

                const netPct2 = ev2.filter(e=>/SQL\*Net|Net message/i.test(e.event_name)).reduce((s,e)=>s+(e.pct_db_time||0),0);

                const netPct1 = ev1.filter(e=>/SQL\*Net|Net message/i.test(e.event_name)).reduce((s,e)=>s+(e.pct_db_time||0),0);



                // -- LOAD PROFILE CROSS-CORRELATION -----------------------------------

                const pD = (a,b) => a>0 ? (b-a)/a*100 : 0;
                // loadProfile accessed directly from ctx destructured above

                const physRead1 = loadProfile.good.physical_reads;
                const physRead2 = loadProfile.bad.physical_reads;

                const logRead1  = loadProfile.good.logical_reads;
                const logRead2  = loadProfile.bad.logical_reads;

                const blkChg1   = loadProfile.good.block_changes;
                const blkChg2   = loadProfile.bad.block_changes;

                const physDelta   = loadProfile.deltas.physical_reads||0;

                const logDelta    = loadProfile.deltas.logical_reads||0;

                const redoDelta   = loadProfile.deltas.redo_size||0;

                const hparseDelta = loadProfile.deltas.hard_parses||0;

                const execDeltaLP = loadProfile.deltas.executes||0;

                const blkChgDelta = loadProfile.deltas.block_changes||0;

                // Transactions/sec — critical business throughput signal (FIX 3)
                const txn1 = loadProfile.good.transactions;
                const txn2 = loadProfile.bad.transactions;
                const txnDelta = pD(txn1, txn2);
                const dbTimePctChg = (s1.db_time_secs||0) > 0 ? ((s2.db_time_secs||0)-(s1.db_time_secs||0))/(s1.db_time_secs||1)*100 : 0;
                const isCongestion = dbTimePctChg > 10 && txnDelta < -5; // DB Time up AND txn/s down

                const lpRows = [

                    { label:'Physical Reads/s', v1:physRead1, v2:physRead2, d:physDelta,   sig:Math.abs(physDelta)>50?'crit':Math.abs(physDelta)>20?'warn':'ok' },

                    { label:'Logical Reads/s',  v1:logRead1,  v2:logRead2,  d:logDelta,    sig:Math.abs(logDelta)>100?'crit':Math.abs(logDelta)>40?'warn':'ok' },

                    { label:'Redo Size/s',       v1:redo1,     v2:redo2,     d:redoDelta,   sig:Math.abs(redoDelta)>80?'crit':Math.abs(redoDelta)>30?'warn':'ok' },

                    { label:'Hard Parses/s',     v1:hparse1,   v2:hparse2,   d:hparseDelta, sig:Math.abs(hparseDelta)>100?'crit':Math.abs(hparseDelta)>50?'warn':'ok' },

                    { label:'Executes/s',        v1:exec1,     v2:exec2,     d:execDeltaLP, sig:Math.abs(execDeltaLP)>50?'warn':'ok' },

                    { label:'Block Changes/s',   v1:blkChg1,   v2:blkChg2,   d:blkChgDelta, sig:Math.abs(blkChgDelta)>80?'crit':Math.abs(blkChgDelta)>30?'warn':'ok' },

                ].filter(r => (r.v1>0||r.v2>0) && Math.abs(r.d)>10);

                const sigCol = s => s==='crit'?'#ef4444':s==='warn'?'#f59e0b':'#64748b';

                const sigBg  = s => s==='crit'?'rgba(239,68,68,0.10)':s==='warn'?'rgba(245,158,11,0.08)':'rgba(100,116,139,0.05)';



                const lpEvidence = [];

                if (physDelta>30)   lpEvidence.push('Physical reads +'+num(physDelta,0)+'% ? I/O amplification');

                if (hparseDelta>50) lpEvidence.push('Hard parse +'+num(hparseDelta,0)+'% ? parse overhead');

                if (logDelta>50)    lpEvidence.push('Logical reads +'+num(logDelta,0)+'% ? buffer gets surge');

                if (redoDelta>50)   lpEvidence.push('Redo +'+num(redoDelta,0)+'% ? write amplification');

                if (blkChgDelta>50) lpEvidence.push('Block changes +'+num(blkChgDelta,0)+'% ? DML hotspot');

                if (execDeltaLP>50) lpEvidence.push('Executes/s +'+num(execDeltaLP,0)+'% ? workload volume spike');



                // -- SQL ATTRIBUTION ANALYSIS -----------------------------------------

                // additionalSecs = (epe_bad - epe_good) × execs_bad  [common regressed]

                // additionalSecs = epe_bad × execs_bad                [new bad-only SQL]

                const sql2idSet = new Set((sql2||[]).map(s=>s.sql_id));

                const sql1idSet = new Set((sql1||[]).map(s=>s.sql_id));

                const map1sq = {};

                (sql1||[]).forEach(s=>{ map1sq[s.sql_id]=s; });



                const sqlAttrib = [];

                (sql2||[]).filter(s=>sql1idSet.has(s.sql_id)).forEach(s2x=>{

                    const s1x = map1sq[s2x.sql_id];

                    const epe2x = (s2x.elapsed_time_secs||0)/Math.max(s2x.executions||1,1);

                    const epe1x = (s1x.elapsed_time_secs||0)/Math.max(s1x.executions||1,1);

                    if (epe2x > epe1x) {

                        const planChg = !!(s1x.plan_hash_value && s2x.plan_hash_value && s1x.plan_hash_value!==s2x.plan_hash_value);

                        sqlAttrib.push({ id:s2x.sql_id, epe1:epe1x, epe2:epe2x,

                            addlSecs:(epe2x-epe1x)*(s2x.executions||0),

                            type:'regression', planChg, pctDb:s2x.pct_db_time||0, execs:s2x.executions||0 });

                    }

                });

                (sql2||[]).filter(s=>!sql1idSet.has(s.sql_id)).forEach(s2x=>{

                    const epe2x = (s2x.elapsed_time_secs||0)/Math.max(s2x.executions||1,1);

                    sqlAttrib.push({ id:s2x.sql_id, epe1:0, epe2:epe2x,

                        addlSecs:epe2x*(s2x.executions||0), type:'new', planChg:false,

                        pctDb:s2x.pct_db_time||0, execs:s2x.executions||0 });

                });

                sqlAttrib.sort((a,b)=>b.addlSecs-a.addlSecs);

                const top3A    = sqlAttrib.slice(0,3);

                const totAttrib = top3A.reduce((s,x)=>s+x.addlSecs, 0);



                // -- WAIT EVENT INTELLIGENCE ------------------------------------------

                // Extract named wait signals from both periods for chain node cross-reference

                const topWait2     = ev2[0];

                const topWait1     = ev1.find(e=>e.event_name===topWait2?.event_name);

                const topWaitName  = topWait2?.event_name || 'DB CPU';

                const topWaitPct2  = topWait2?.pct_db_time || 0;

                const topWaitPct1  = topWait1?.pct_db_time || 0;

                const topWaitDelta = topWaitPct2 - topWaitPct1;

                const topWaitShort = topWaitName.length>28 ? topWaitName.substring(0,28)+'…' : topWaitName;



                // Categorise wait events by type

                const ioWaitPct2   = ev2.filter(e=>/read|write|direct path/i.test(e.event_name)).reduce((s,e)=>s+(e.pct_db_time||0),0);

                const conWaitPct2  = ev2.filter(e=>(e.wait_class||'').toLowerCase()==='concurrency' || /buffer busy waits|enq:/i.test(e.event_name)).reduce((s,e)=>s+(e.pct_db_time||0),0);

                const ioWaitPct1   = ev1.filter(e=>/read|write|direct path/i.test(e.event_name)).reduce((s,e)=>s+(e.pct_db_time||0),0);

                const topIoWait    = ev2.find(e=>/read|write|direct path/i.test(e.event_name));

                const topConWait   = ev2.find(e=>/latch|lock|buffer busy|enq/i.test(e.event_name));

                const topIoName    = topIoWait ? (topIoWait.event_name.length>25?topIoWait.event_name.substring(0,25)+'…':topIoWait.event_name) : null;

                const topConName   = topConWait ? (topConWait.event_name.length>25?topConWait.event_name.substring(0,25)+'…':topConWait.event_name) : null;



                // NOTE: Connecting Dots chain is now centralized in classifyAndAnnotate() -> ctx.connectingDots
                // Evidence scoring, scenario selection, and chain rendering removed from SRE card (was dead code).



                // LPS semi-arc gauge (0=empty, 100=full)

                const gaugeR=36, gCx=44, gCy=44, gStroke=8;

                const gCirc = 2*Math.PI*gaugeR;

                const gOffset = (gCirc/2)*(1 - Math.min(lps,100)/100);



                return `

                <!-- -- Three metric panels (re-balanced: 4/3/5 of 12 cols so Session panel has room) -- -->

                <div class="grid grid-cols-1 md:grid-cols-12 gap-3 mb-3">



                    <!-- PANEL 1: Commit & Execution Health -->

                    <div class="md:col-span-4" style="background:${latBg};border:1px solid ${latCol}30;border-radius:10px;padding:16px" title="Commit &amp; Execution Health — 3 metrics: DB Time per Execute (how much DB time each SQL costs), Commit Latency (log file sync avg wait), CPU Efficiency (% of DB Time spent on CPU vs waiting).">

                        <div class="flex items-center justify-between mb-3">

                            <div>

                                <div class="text-[10px] font-bold text-Cmuted uppercase tracking-wider mb-0.5">\u2694 Commit &amp; Execution Health</div>

                                <div class="text-[9px] text-gray-600 font-mono">${latSrc}</div>

                            </div>

                            <div style="background:${latCol}20;border:1px solid ${latCol}50;border-radius:6px;padding:3px 10px">

                                <span style="color:${latCol};font-size:9px;font-weight:900;letter-spacing:0.5px">${latRating}</span>

                            </div>

                        </div>

                        <!-- Metric 1: DB Time per Execute -->
                        <div class="mb-3">
                            <div class="text-[9px] text-Cmuted uppercase font-bold mb-1">DB Time / Execute</div>
                            <div class="flex items-end gap-4">
                                <div>
                                    <div class="text-[9px] text-gray-600">${esc(lbl1)}</div>
                                    <div class="text-lg font-black text-Cgreen">${fmtLat(lat1)}</div>
                                </div>
                                <div class="text-gray-600 mb-1">\u2192</div>
                                <div>
                                    <div class="text-[9px] text-gray-600">${esc(lbl2)}</div>
                                    <div class="text-lg font-black" style="color:${latCol}">${fmtLat(lat2)}</div>
                                </div>
                                <div style="margin-left:auto;text-align:right">
                                    <div class="text-[9px] text-Cmuted">\u0394</div>
                                    <div class="text-sm font-bold" style="color:${latCol}">${latDelta>0?'+':''}${num(latDelta,0)}%</div>
                                </div>
                            </div>
                        </div>

                        <div class="grid grid-cols-2 gap-2">
                            <!-- Metric 2: Commit Latency -->
                            <div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px">
                                <div class="text-[9px] text-Cmuted uppercase font-bold mb-1">Commit Latency</div>
                                <div class="text-[9px] text-gray-600 mb-0.5">log file sync avg wait</div>
                                <div class="flex items-baseline gap-2">
                                    <div>
                                        <div style="font-size:9px;color:#64748b">Good</div>
                                        <div class="font-bold text-sm" style="color:#4ade80">${commitLat1 > 0 ? num(commitLat1,1)+'ms' : 'N/A'}</div>
                                    </div>
                                    <span style="color:#475569;font-size:10px">→</span>
                                    <div>
                                        <div style="font-size:9px;color:#64748b">Bad</div>
                                        <div class="font-bold text-sm" style="color:${commitCol}">${commitLat2 > 0 ? num(commitLat2,1)+'ms' : 'N/A'}</div>
                                    </div>
                                </div>
                                <div class="text-[9px] text-gray-600">${commitDelta !== 0 ? (commitDelta>0?'+':'')+num(commitDelta,0)+'%' : ''}</div>
                            </div>

                            <!-- Metric 3: CPU Efficiency -->
                            <div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px">
                                <div class="text-[9px] text-Cmuted uppercase font-bold mb-1">CPU Efficiency</div>
                                <div class="text-[9px] text-gray-600 mb-0.5">DB CPU / DB Time</div>
                                <div class="flex items-baseline gap-2">
                                    <div>
                                        <div style="font-size:9px;color:#64748b">Good</div>
                                        <div class="font-bold text-sm" style="color:#4ade80">${num(cpuEff1,1)}%</div>
                                    </div>
                                    <span style="color:#475569;font-size:10px">→</span>
                                    <div>
                                        <div style="font-size:9px;color:#64748b">Bad</div>
                                        <div class="font-bold text-sm" style="color:${cpuEffCol}">${num(cpuEff2,1)}%</div>
                                    </div>
                                </div>
                                <div class="text-[9px] text-gray-600">${cpuEffDelta !== 0 ? (cpuEffDelta>0?'+':'')+num(cpuEffDelta,1)+'pp' : ''}</div>
                            </div>
                        </div>

                        <!-- -- Cross-correlations: where this latency comes from -- -->
                        ${(() => {
                            const _ioPct = ioWaitPct2 || 0;
                            const _conPct = conWaitPct2 || 0;
                            const _cpuPct = cpuEff2 || 0;
                            const drivers = [];
                            if (_cpuPct > 60) drivers.push({label:'CPU-bound', val:num(_cpuPct,0)+'%', col:'#fbbf24', hint:'sessions on CPU vs waiting'});
                            if (_ioPct > 15) drivers.push({label:'I/O wait', val:num(_ioPct,0)+'%', col:'#f87171', hint:topIoName||'read/write waits'});
                            if (_conPct > 10) drivers.push({label:'Concurrency', val:num(_conPct,0)+'%', col:'#fb923c', hint:topConName||'latch/lock contention'});
                            if (commitLat2 > 10) drivers.push({label:'Commit', val:num(commitLat2,0)+'ms', col:'#f87171', hint:'log file sync slow'});
                            if (drivers.length === 0) return '';
                            return '<div class="mt-3 pt-2" style="border-top:1px solid #1e293b">' +
                                '<div class="text-[9px] text-Cmuted uppercase font-bold mb-1.5">Latency Drivers · Where DB Time Goes</div>' +
                                '<div class="flex flex-wrap gap-1.5">' +
                                  drivers.map(d => '<div title="' + esc(d.hint) + '" style="background:' + d.col + '15;border:1px solid ' + d.col + '40;border-radius:5px;padding:3px 7px;font-size:10px"><span style="color:' + d.col + ';font-weight:700">' + d.label + '</span> <span style="color:#cbd5e1;font-family:ui-monospace,monospace">' + d.val + '</span></div>').join('') +
                                '</div>' +
                                '<div class="text-[9px] text-gray-600 mt-1.5" style="line-height:1.4">See <b style="color:#94a3b8">Wait Events</b> &amp; <b style="color:#94a3b8">SQL Analysis</b> tabs to drill in.</div>' +
                            '</div>';
                        })()}

                    </div>



                    <!-- PANEL 1b: Transactions/sec — Business Throughput -->
                    <div class="md:col-span-3" style="background:rgba(10,16,32,0.7);border:1px solid #1e293b;border-radius:10px;padding:16px" title="Transactions per second from AWR Load Profile (Per Second column). This is the most important business throughput signal.&#10;&#10;When DB Time rises but Transactions/sec falls, the database is spending MORE time producing LESS business output — a congestion pattern indicating queries are blocked or degraded.">
                        <div class="flex items-center justify-between mb-3">
                            <div>
                                <div class="text-[10px] font-bold text-Cmuted uppercase tracking-wider mb-0.5">Transactions/sec</div>
                                <div class="text-[9px] text-gray-600 font-mono">AWR Load Profile · Per Second</div>
                            </div>
                            ${isCongestion
                                ? '<div style="background:rgba(239,68,68,0.2);border:1px solid rgba(239,68,68,0.5);border-radius:6px;padding:3px 10px"><span style="color:#ef4444;font-size:9px;font-weight:900;letter-spacing:0.5px">CONGESTION</span></div>'
                                : Math.abs(txnDelta)>15
                                    ? '<div style="background:rgba(245,158,11,0.2);border:1px solid rgba(245,158,11,0.5);border-radius:6px;padding:3px 10px"><span style="color:#f59e0b;font-size:9px;font-weight:900;letter-spacing:0.5px">CHANGED</span></div>'
                                    : '<div style="background:rgba(16,185,129,0.2);border:1px solid rgba(16,185,129,0.5);border-radius:6px;padding:3px 10px"><span style="color:#10b981;font-size:9px;font-weight:900;letter-spacing:0.5px">STABLE</span></div>'
                            }
                        </div>
                        <div class="flex items-end gap-3 mb-3 flex-wrap">
                            <div style="min-width:0">
                                <div class="text-[9px] text-Cmuted uppercase font-bold mb-0.5 truncate">${esc(lbl1)}</div>
                                <div class="text-lg font-black text-Cgreen">${num(txn1,1)}</div>
                            </div>
                            <div class="text-gray-600 text-base mb-1">→</div>
                            <div style="min-width:0">
                                <div class="text-[9px] text-Cmuted uppercase font-bold mb-0.5 truncate">${esc(lbl2)}</div>
                                <div class="text-lg font-black" style="color:${txnDelta<-15?'#ef4444':txnDelta<-5?'#f59e0b':'#10b981'}">${num(txn2,1)}</div>
                            </div>
                            <div style="margin-left:auto;text-align:right;min-width:0">
                                <div class="text-[9px] text-Cmuted uppercase">CHANGE</div>
                                <div class="text-base font-black" style="color:${txnDelta<-15?'#ef4444':txnDelta<-5?'#f59e0b':txnDelta>15?'#10b981':'#94a3b8'}">${txnDelta>0?'+':''}${num(txnDelta,0)}%</div>
                            </div>
                        </div>
                        ${isCongestion
                            ? '<div style="background:rgba(239,68,68,0.08);border:1px solid rgba(239,68,68,0.3);border-radius:5px;padding:8px 12px"><div style="color:#f87171;font-size:11px;font-weight:800;margin-bottom:3px">⚠ CONGESTION — more DB time, less business output</div><div style="color:#94a3b8;font-size:10px;line-height:1.5">DB Time rose +'+num(dbTimePctChg,0)+'% while Transactions/sec fell '+num(txnDelta,0)+'%. The database is doing more work but delivering fewer completed transactions — queries are blocked or degraded.</div></div>'
                            : '<div style="background:rgba(15,23,42,0.6);border-radius:6px;padding:8px"><div class="text-[9px] text-Cmuted uppercase font-bold mb-1">DB Time Δ</div><div class="font-bold text-sm" style="color:'+(dbTimePctChg>20?'#ef4444':dbTimePctChg>0?'#f59e0b':'#10b981')+'">'+(dbTimePctChg>0?'+':'')+num(dbTimePctChg,0)+'%</div><div class="text-[9px] text-gray-600">'+(Math.abs(txnDelta)<10?'Throughput steady':'Throughput shifted')+'</div></div>'
                        }

                        <!-- -- Connected Workload Signals (cross-correlated with Session panel) -- -->
                        ${(() => {
                            const _sigRow = (label, v1, v2, fmt, hint, threshWarn, threshCrit) => {
                                if (v1 == null && v2 == null) return '';
                                // Delta = (BAD - GOOD) / GOOD × 100  (positive = increase in bad period)
                                const dPct = v1 > 0 ? ((v2 - v1) / v1) * 100 : (v2 > 0 ? 100 : 0);
                                const sev = Math.abs(dPct) > (threshCrit||100) ? '#ef4444'
                                          : Math.abs(dPct) > (threshWarn||40) ? '#f59e0b'
                                          : '#64748b';
                                const arrow = dPct > 5 ? '▲' : dPct < -5 ? '▼' : '·';
                                return '<div style="display:flex;align-items:center;justify-content:space-between;padding:3px 0;border-bottom:1px dotted rgba(71,85,105,0.2)">' +
                                  '<span style="color:#94a3b8;font-size:10px">' + label + '</span>' +
                                  '<span style="font-family:ui-monospace,monospace;font-size:10px;color:#cbd5e1">' + fmt(v1) + ' <span style="color:#475569">→</span> <b style="color:' + sev + '">' + fmt(v2) + '</b> ' +
                                  '<span style="color:' + sev + ';font-size:9px">' + (dPct >= 0 ? '+' : '') + (Math.abs(dPct) > 1 ? num(dPct,0) + '%' : '') + '</span></span>' +
                                '</div>';
                            };
                            const _topWaitRow = topWaitName ? (
                                '<div style="display:flex;align-items:center;justify-content:space-between;padding:3px 0;border-bottom:1px dotted rgba(71,85,105,0.2)">' +
                                  '<span style="color:#94a3b8;font-size:10px" title="' + esc(topWaitName) + '">Top Wait</span>' +
                                  '<span style="font-family:ui-monospace,monospace;font-size:10px"><span style="color:#cbd5e1">' + esc(topWaitShort) + '</span> <b style="color:' + (topWaitPct2 > 30 ? '#ef4444' : topWaitPct2 > 10 ? '#f59e0b' : '#94a3b8') + '">' + num(topWaitPct2,0) + '%</b></span>' +
                                '</div>'
                            ) : '';
                            const rows = [
                                _topWaitRow,
                                _sigRow('Hard Parses/s', hparse1, hparse2, v => num(v||0,1), 'parse', 50, 200),
                                _sigRow('Logical Reads/s', logRead1, logRead2, v => fmtK(v||0), 'buffer', 40, 100),
                                _sigRow('Physical Reads/s', physRead1, physRead2, v => fmtK(v||0), 'I/O', 50, 150),
                                _sigRow('Redo Size/s', redo1, redo2, v => fmtK(v||0)+'B', 'DML', 50, 150),
                                _sigRow('Soft Parse %', sp1, sp2, v => num(v||0,1)+'%', 'parse', 5, 15)
                            ].filter(Boolean).join('');
                            return rows ? (
                                '<div class="mt-3 pt-2" style="border-top:1px solid #1e293b">' +
                                  '<div class="text-[9px] text-Cmuted uppercase font-bold mb-1.5 flex items-center gap-1.5">' +
                                    '<svg class="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>' +
                                    'Connected Workload Signals' +
                                  '</div>' +
                                  '<div class="text-[9px] text-gray-600 mb-1.5" style="line-height:1.3">Cross-correlated with Session panel — every signal here either causes or amplifies the session symptoms.</div>' +
                                  rows +
                                '</div>'
                            ) : '';
                        })()}
                    </div>

                    <!-- PANEL 2: Session Performance Intelligence (populated by renderSessionIntelligencePanel) -->
                    <div id="session-intelligence-panel" class="md:col-span-5" style="background:rgba(15,23,42,0.5);border:1px solid rgba(100,116,139,0.2);border-radius:10px;padding:16px">

                        <div class="flex items-center justify-between gap-2">
                            <div>
                                <div class="flex items-center gap-2">
                                    <svg class="w-4 h-4 text-Camber" fill="currentColor" viewBox="0 0 20 20">
                                        <path d="M11.3 1.046A1 1 0 0112 2v5h4a1 1 0 01.82 1.573l-7 10A1 1 0 018 18v-5H4a1 1 0 01-.82-1.573l7-10a1 1 0 011.12-.38z"/>
                                    </svg>
                                    <span class="text-[11px] font-bold tracking-widest text-gray-300 uppercase">Session &amp; Logon Pressure</span>
                                </div>
                            </div>
                            <span id="si-stability-badge" class="text-[9px] font-bold px-3 py-1 rounded-full bg-gray-700 text-Cmuted border border-gray-600">—</span>
                        </div>

                        <!-- 3 metric cards (vertical stack inside each to prevent overflow) -->
                        <div class="grid grid-cols-3 gap-2 mt-3">
                            <div class="rounded-lg p-2.5" style="background:rgba(30,41,59,0.5);border:1px solid rgba(100,116,139,0.2);min-width:0">
                                <div class="text-[9px] text-Cmuted mb-1 uppercase font-bold">Logons/sec</div>
                                <div class="flex items-baseline gap-1.5 flex-wrap">
                                    <span class="text-[10px] text-Cgreen font-mono" id="si-logons-base">—</span>
                                    <span class="text-gray-600 text-[10px]">→</span>
                                    <span class="text-sm font-bold font-mono" id="si-logons-comp">—</span>
                                </div>
                                <div class="text-[9px] font-mono mt-0.5" id="si-logons-delta">—</div>
                                <div class="text-[9px] text-gray-600" id="si-logons-total-note">— total in window</div>
                            </div>
                            <div class="rounded-lg p-2.5" style="background:rgba(30,58,138,0.15);border:1px solid rgba(59,130,246,0.25);min-width:0">
                                <div class="text-[9px] text-Cblue mb-1 font-bold uppercase">Net Sessions/sec Δ</div>
                                <div class="flex items-baseline gap-1.5 flex-wrap">
                                    <span class="text-[10px] text-Cgreen font-mono" id="si-net-base">—</span>
                                    <span class="text-gray-600 text-[10px]">→</span>
                                    <span class="text-sm font-bold font-mono" id="si-net-comp">—</span>
                                </div>
                                <div class="text-[9px] text-blue-700 mt-0.5" id="si-sessions-hr">—/hr projected</div>
                            </div>
                            <div class="rounded-lg p-2.5" style="background:rgba(30,41,59,0.5);border:1px solid rgba(100,116,139,0.2);min-width:0">
                                <div class="text-[9px] text-Cmuted mb-1 uppercase font-bold">Churn Rate</div>
                                <div class="flex items-baseline gap-1.5">
                                    <span class="text-sm font-bold font-mono" id="si-churn-val">—</span>
                                </div>
                                <div class="text-[9px] text-Cmuted" id="si-churn-desc">session turnover</div>
                                <div class="text-[9px] font-medium mt-0.5 break-words" id="si-churn-pattern" style="line-height:1.2">—</div>
                            </div>
                        </div>

                        <!-- Metrics table -->
                        <table class="w-full mt-2" style="font-size:11px;border-collapse:collapse">
                            <thead>
                                <tr style="border-bottom:1px solid #1e293b">
                                    <td class="text-left pb-1" style="color:#475569;font-size:10px;font-weight:700">METRIC</td>
                                    <td class="pb-1 text-right" style="color:#34d399;font-size:10px;font-weight:700">GOOD</td>
                                    <td class="pb-1 text-right" style="color:#f87171;font-size:10px;font-weight:700">BAD</td>
                                    <td class="pb-1 text-right" style="color:#94a3b8;font-size:10px;font-weight:700">Δ</td>
                                </tr>
                            </thead>
                            <tbody>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Logons/sec <span style="color:#475569">· rate</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-logons-b">—</td>
                                    <td class="font-mono text-right" id="mt-logons-c">—</td>
                                    <td class="font-mono text-right" id="mt-logons-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Cumul. Logons <span style="color:#475569">· total</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-cumlogon-b">—</td>
                                    <td class="font-mono text-right" id="mt-cumlogon-c">—</td>
                                    <td class="font-mono text-right" id="mt-cumlogon-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">ConnMgmt/min <span style="color:#475569">· normalized</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-connmgmt-b">—</td>
                                    <td class="font-mono text-right" id="mt-connmgmt-c">—</td>
                                    <td class="font-mono text-right" id="mt-connmgmt-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Per-Conn Cost <span style="color:#475569">· ms/logon</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-conncost-b">—</td>
                                    <td class="font-mono text-right" id="mt-conncost-c">—</td>
                                    <td class="font-mono text-right" id="mt-conncost-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Exec/Logon <span style="color:#475569">· session efficiency</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-execlogon-b">—</td>
                                    <td class="font-mono text-right" id="mt-execlogon-c">—</td>
                                    <td class="font-mono text-right" id="mt-execlogon-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">AAS <span style="color:#475569" id="mt-cpu-label">· CPUs</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-aas-b">—</td>
                                    <td class="font-mono text-right" id="mt-aas-c">—</td>
                                    <td class="font-mono text-right" id="mt-aas-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">AAS / Sessions <span style="color:#475569">· active %</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-aassess-b">—</td>
                                    <td class="font-mono text-right" id="mt-aassess-c">—</td>
                                    <td class="font-mono text-right" id="mt-aassess-d">—</td></tr>
                                <tr style="border-top:1px solid rgba(30,41,59,0.5)"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Queuing Sessions <span style="color:#475569">· AAS-CPUs</span></td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-queuing-b">—</td>
                                    <td class="font-mono text-right" id="mt-queuing-c">—</td>
                                    <td class="font-mono text-right" id="mt-queuing-d">—</td></tr>
                                <tr id="mt-seslim-row" style="border-top:1px solid rgba(30,41,59,0.5);display:none"><td class="py-1 text-left" style="color:#94a3b8;font-size:10px">Session Limit %</td>
                                    <td class="font-mono text-right text-Cgreen" id="mt-seslim-b">—</td>
                                    <td class="font-mono text-right" id="mt-seslim-c">—</td>
                                    <td class="font-mono text-right" id="mt-seslim-d">—</td></tr>
                            </tbody>
                        </table>

                        <!-- Bottom: pattern + fix -->
                        <div class="flex items-start justify-between pt-2 mt-2 gap-2" style="border-top:1px solid #1e293b">
                            <div class="min-w-0">
                                <div class="text-[9px] text-Cmuted mb-0.5 uppercase font-bold">Pattern</div>
                                <div class="text-[10px] font-bold" id="si-pattern-label">—</div>
                                <div class="text-[9px] text-Cmuted mt-0.5" id="si-pattern-detail">—</div>
                            </div>
                            <div class="text-right" style="max-width:45%">
                                <div class="text-[9px] text-Cmuted mb-0.5 uppercase font-bold">Fix</div>
                                <div class="text-[9px] text-Corange leading-snug" id="si-fix-text">—</div>
                            </div>
                        </div>

                        <!-- Executes (SQL)/s — full width -->
                        <div class="mt-2 pt-2" style="border-top:1px solid #1e293b">
                            <div style="background:rgba(15,23,42,0.5);border-radius:6px;padding:7px 10px">
                                <div class="text-[9px] text-Cmuted uppercase font-bold mb-1">Executes (SQL)/s</div>
                                <div class="font-bold text-sm" id="ei-exec-values">–</div>
                                <div class="text-[9px]" id="ei-exec-label">—</div>
                            </div>
                            <!-- Situational suggestion based on AWR comparison -->
                            <div id="si-suggestion" class="mt-2 rounded-lg px-3 py-2.5" style="display:none;background:rgba(59,130,246,0.06);border:1px solid rgba(59,130,246,0.18)">
                                <div class="text-[10px] text-Cblue uppercase font-bold mb-1 flex items-center gap-1"><svg class="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fill-rule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7-4a1 1 0 11-2 0 1 1 0 012 0zM9 9a1 1 0 000 2v3a1 1 0 001 1h1a1 1 0 100-2v-3a1 1 0 00-1-1H9z" clip-rule="evenodd"/></svg>Oracle Performance Insight</div>
                                <div class="text-[10px] text-gray-300 leading-relaxed" id="si-suggestion-text">—</div>
                            </div>
                        </div>



                    </div>

                </div>



                <!-- -- Load Profile shifts shown in RCA Verdict tab -- -->



                <!-- -- SQL Attribution Analysis -- -->

                `;

            })()}

        </div>

    `;

    setTimeout(() => renderComparisonCharts(ev1, ev2, sql1, sql2, eff1, eff2, lbl1, lbl2), 80);



    // Detect workload patterns and inject notes above the hero banner

    setTimeout(() => {

        const patterns = detectWorkloadPatterns(ev1, ev2, d1.load_profile||[], d2.load_profile||[], sql1, sql2); // detectWorkloadPatterns uses raw arrays internally

        if (patterns.length > 0) renderPatternNotes(patterns, 'dashboard-content');

    }, 120);



    // Show download button in sidebar once comparison is loaded

    const dlBtn = document.getElementById('btn-download-report');

    if (dlBtn) dlBtn.style.display = '';

}



// Derive actual bottleneck from wait event data (more accurate than RCA engine verdict alone)

function _deriveBottleneck(events, dbTimeSecs) {

    if (!events || !events.length || !dbTimeSecs) return 'unknown';

    const cpuEv = events.find(e => /DB CPU/i.test(e.event_name));

    const cpuPct = cpuEv ? (cpuEv.pct_db_time || 0) : 0;

    const ioEvents = events.filter(e => /read|write|direct path/i.test(e.event_name) && !/DB CPU/i.test(e.event_name));

    const ioPct = ioEvents.reduce((s, e) => s + (e.pct_db_time || 0), 0);

    const ccEvents = events.filter(e => /latch|lock|enq.*tx|enq.*tm|mutex|buffer busy|gc /i.test(e.event_name));

    const ccPct = ccEvents.reduce((s, e) => s + (e.pct_db_time || 0), 0);

    const commitEv = events.filter(e => /log file sync/i.test(e.event_name));

    const commitPct = commitEv.reduce((s, e) => s + (e.pct_db_time || 0), 0);

    const configEv = events.filter(e => (e.wait_class||'').toLowerCase() === 'configuration' || /enq.*hw|enq.*cf|log buffer space|latch.*redo copy/i.test(e.event_name));

    const configPct = configEv.reduce((s, e) => s + (e.pct_db_time || 0), 0);

    // Primary bottleneck = largest contributor excluding CPU itself when CPU > 50%

    if (cpuPct >= 70) return 'cpu';          // CPU dominant, system doing real work

    if (configPct >= 20) return 'configuration'; // Configuration/resource sizing before I/O check

    if (ioPct >= 15 && ioPct > cpuPct * 0.3) return 'io';  // I/O significant

    if (ccPct >= 10) return 'concurrency';

    if (commitPct >= 8) return 'commit';

    if (configPct >= 5) return 'configuration'; // lower threshold also catches it

    if (cpuPct >= 50) return 'cpu';

    return 'io';  // fallback

}



function _bottleneckLabel(btn) {

    return {cpu:'CPU',io:'I/O',concurrency:'Concurrency',commit:'Commit/Redo',configuration:'Configuration/Resource Sizing',unknown:'Unknown'}[btn] || btn.toUpperCase();

}



function generateComparisonAISummary(ctx) {
    const v = ctx.verdict;
    if (!v || v.severity === 'UNKNOWN') {
        return '<b>Analysis unavailable</b> — insufficient data to generate comparison summary.';
    }

    const {meta, loadProfile, waitEvents, delta, spikes, sqlAttribution, _raw} = ctx;
    const {s1, s2} = _raw;
    const lbl1 = meta.lbl1, lbl2 = meta.lbl2;
    const cpus = meta.cpu_count;

    // -------------------------------------------------------------
    // BLOCK A — VERDICT (one sentence)
    // -------------------------------------------------------------
    const sevStyles = {
        CRITICAL:       { cls: 'sev-critical',  bg: 'rgba(239,68,68,0.12)',  border: '#ef4444', label: 'CRITICAL' },
        DEGRADED:       { cls: 'sev-warning',   bg: 'rgba(245,158,11,0.1)', border: '#f59e0b', label: 'DEGRADED' },
        WORKLOAD_SHIFT: { cls: 'sev-warning',   bg: 'rgba(245,158,11,0.1)', border: '#f59e0b', label: 'WORKLOAD SHIFT' },
        IMPROVED:       { cls: 'sev-good',      bg: 'rgba(52,211,153,0.1)', border: '#34d399', label: 'IMPROVED' },
        STABLE:         { cls: '',              bg: 'rgba(100,116,139,0.08)',border: '#64748b', label: 'STABLE' },
        UNKNOWN:        { cls: '',              bg: 'rgba(100,116,139,0.08)',border: '#64748b', label: 'UNKNOWN' },
    };
    const sev = sevStyles[v.severity] || sevStyles.UNKNOWN;
    const confBadge = v.confidence === 'CONFIRMED'
        ? '<span style="background:rgba(52,211,153,0.15);color:#34d399;font-size:9px;font-weight:800;padding:2px 8px;border-radius:9999px;margin-left:8px">ADDM CONFIRMED</span>'
        : v.confidence === 'PROBABLE'
        ? '<span style="background:rgba(96,165,250,0.15);color:#60a5fa;font-size:9px;font-weight:800;padding:2px 8px;border-radius:9999px;margin-left:8px">PROBABLE</span>'
        : v.confidence === 'POSSIBLE'
        ? '<span style="background:rgba(251,191,36,0.15);color:#fbbf24;font-size:9px;font-weight:800;padding:2px 8px;border-radius:9999px;margin-left:8px">POSSIBLE</span>'
        : '';

    const blockA = `<div style="padding:12px 16px;background:${sev.bg};border-left:3px solid ${sev.border};border-radius:0 8px 8px 0;margin-bottom:8px">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px">
            <span style="background:${sev.border};color:#fff;font-size:10px;font-weight:800;padding:2px 10px;border-radius:9999px;letter-spacing:0.5px">${sev.label}</span>
            ${confBadge}
        </div>
        <div style="font-size:13px;color:#e2e8f0;line-height:1.5">${esc(v.rootCause)}</div>
    </div>`;

    // -------------------------------------------------------------
    // BLOCK B — CRITICAL SQL FOCUS (multi-signal priority scoring)
    // Signals: exec/sec delta · exec volume · epe regression · %DB · wait events · CPU · plan · type
    // Extra weight: high-frequency AND materially regressed = broadest workload impact
    // Platform/scheduler SQLs always suppressed unless no app SQL available
    // -------------------------------------------------------------
    const tc = v.topCulprit;

    // Snapshot durations for exec/sec calculation
    const _elGoodMin = (meta.good && meta.good.elapsed_min) || 1;
    const _elBadMin  = (meta.bad  && meta.bad.elapsed_min)  || 1;

    // Platform/scheduler detection for culprit candidates
    const _isPlatformCandidate = (c) => {
        if (!c) return false;
        const mod = (c.module || '').trim();
        if (/^DBMS_(SCHEDULER|JOB|PIPE|AQ|STREAMS|APPLY|CAPTURE)/i.test(mod)) return true;
        // Ad-hoc tool sessions (TOAD, SQL*Plus, SQL Developer, PL/SQL Dev) are not application SQL
        if (/TOAD|SQL\*PLUS|SQLPLUS|SQL DEVELOPER|PLSQLDEV|PL\/SQL DEVELOPER/i.test(mod)) return true;
        if (typeof _isPlatformSQL === 'function') return _isPlatformSQL({ module: mod, sqlText: c.sqlText || '' });
        return false;
    };

    // SQL type weight for priority boosting (SELECT/DML = 4-5, PLSQL = 2, other = 1)
    // Returns 'SELECT'|'INSERT'|'UPDATE'|'DELETE'|'MERGE'|'PLSQL'|'OTHER'
    const _getSqlTypeFull = (c) => {
        if (typeof _getSQLTypeFor === 'function')
            return _getSQLTypeFor(c.sqlId, c.module||'', c.sqlText||'');
        if (typeof _getSQLType === 'function')
            return _getSQLType(c.sqlText || '');
        return 'OTHER';
    };

    // ── Priority scoring function ────────────────────────────────
    // Primary signals (in weight order):
    //  A. %DB time × elapsed regression (combined confirmed-bottleneck signal)
    //  B. Per-exec elapsed regression alone
    //  C. %DB time alone
    //  D. Exec/sec delta (frequency shift)
    //  E. Exec volume
    //  F. SQL type anchored to %DB (SELECT/DML get credit only when they're actually consuming DB time)
    const _priorityScore = (c) => {
        const isPlatform = _isPlatformCandidate(c);
        if (isPlatform) return { score: -1, rank: 'SUPPRESSED', signals: ['Platform/scheduler SQL'] };
        if (c.classification === 'ORACLE_MAINTENANCE') return { score: -1, rank: 'SUPPRESSED', signals: ['Oracle maintenance'] };

        let score = 0;
        const signals = [];

        const epeRatio  = c.epeGood > 0 ? (c.epeBad / c.epeGood - 1) * 100 : 0;
        const execsBad  = c.execsBad  || 0;
        const execsGood = c.execsGood || 0;
        const epsGood   = execsGood / _elGoodMin;
        const epsBad    = execsBad  / _elBadMin;
        const epsDelta  = epsGood > 0 ? (epsBad - epsGood) / epsGood * 100 : (execsBad > 0 ? 999 : 0);
        const pctDb     = c.pctDb || 0;
        const cpuPct    = c.cpuPctBad || 0;
        const hasWait   = !!(c.waitCorrelation && c.waitCorrelation.corrDetail);
        const isNew     = c.isNew || c.classification === 'NEW_HIGH_IMPACT' || c.classification === 'NEW_SQL';

        // Resolve SQL type using full resolver (id + module + text)
        const sqlType   = _getSqlTypeFull(c);
        const isAppDML  = ['INSERT','UPDATE','DELETE','MERGE'].includes(sqlType);
        const isSelect  = sqlType === 'SELECT';
        const isAppSQL  = isSelect || isAppDML;   // user-facing application SQL
        const isPLSQL   = sqlType === 'PLSQL';

        // ── Signal 1: Per-exec elapsed regression (PRIMARY — individual query got slower)
        if (!isNew) {
            if      (epeRatio > 200) { score += 35; signals.push(`+${num(epeRatio,0)}%/exec (critical)`); }
            else if (epeRatio > 100) { score += 25; signals.push(`+${num(epeRatio,0)}%/exec`); }
            else if (epeRatio >  50) { score += 15; signals.push(`+${num(epeRatio,0)}%/exec`); }
            else if (epeRatio >  20) { score +=  8; signals.push(`+${num(epeRatio,0)}%/exec`); }
            else if (epeRatio > 0 && epeRatio <= 5 && execsBad < 100) { score -= 8; }
        }

        // ── Signal 2: %DB Time (PRIMARY — actual share of database resource consumed)
        if      (pctDb > 25) { score += 35; signals.push(`${num(pctDb,1)}% DB time (dominant)`); }
        else if (pctDb > 15) { score += 28; signals.push(`${num(pctDb,1)}% DB time`); }
        else if (pctDb > 10) { score += 20; signals.push(`${num(pctDb,1)}% DB time`); }
        else if (pctDb >  5) { score += 12; }
        else if (pctDb >  2) { score +=  5; }
        else if (pctDb < 0.5 && !isNew) { score -= 8; signals.push('<0.5% DB time'); }

        // ── Signal 3: Combined %DB × elapsed regression (confirmed bottleneck — BOTH signals firing)
        // A SQL that is regressing per-exec AND consuming high %DB time is a verified bottleneck.
        // Threshold lowered to 15% epeRatio — moderate regression at high DB time is still impactful.
        if (!isNew && pctDb >= 5 && epeRatio >= 15) {
            const comboBonus = pctDb >= 15 && epeRatio >= 100 ? 25
                             : pctDb >= 10 && epeRatio >=  50 ? 18
                             : pctDb >= 10 && epeRatio >=  15 ? 12
                             : pctDb >=  5 && epeRatio >=  30 ? 10
                             : pctDb >=  5 && epeRatio >=  15 ?  6 : 0;
            if (comboBonus > 0) { score += comboBonus; signals.push(`${num(pctDb,1)}% DB + ${num(epeRatio,0)}% slower (confirmed)`); }
        }

        // ── Signal 4: Exec/sec delta (frequency shift — more sessions hitting this SQL)
        // Sub-condition: extreme volume shift WITHOUT per-exec regression (epsDelta >200% but epeRatio <20%)
        // → application-layer issue: loop bug, missing cache, N+1. Signal 1 fires low because each exec
        //   is not slower, but the aggregate workload impact is severe — needs its own elevated path.
        // GUARD: epsDelta=999 is a sentinel for new SQL (execsGood=0), NOT a real frequency shift.
        //        isVolumeShiftOnly must only fire for existing SQLs that genuinely appear at new frequency.
        const isVolumeShiftOnly = !isNew && epsDelta > 200 && Math.abs(epeRatio) < 20;
        if (isVolumeShiftOnly)    { score += 30; signals.push(`Exec/sec +${num(epsDelta,0)}% no per-exec change (app loop/cache)`); }
        else if (epsDelta > 100)  { score += 25; signals.push(`Exec/sec +${num(epsDelta,0)}% (major freq shift)`); }
        else if (epsDelta >  50)  { score += 18; signals.push(`Exec/sec +${num(epsDelta,0)}%`); }
        else if (epsDelta >  20)  { score += 10; signals.push(`Exec/sec +${num(epsDelta,0)}%`); }
        else if (epsDelta < -50)  { score -=  5; }

        // ── Signal 5: Exec volume in Bad period
        if      (execsBad >= 100000) { score += 20; signals.push(`${comma(execsBad)} execs (very high)`); }
        else if (execsBad >=  10000) { score += 14; signals.push(`${comma(execsBad)} execs (high)`); }
        else if (execsBad >=   1000) { score +=  8; }
        else if (execsBad >=    100) { score +=  4; }
        else if (execsBad === 1 && !isNew) { score -= 10; signals.push('Single execution'); }

        // AMPLIFIER — High-frequency AND regressed = broadest combined impact
        if      (execsBad >= 1000 && epeRatio > 30) { score += 20; signals.push('High-vol + regressed'); }
        else if (execsBad >=  100 && epeRatio > 50) { score += 10; }

        // ── Signal 6: New SQL with meaningful %DB time
        if (isNew) {
            if      (pctDb > 10) { score += 30; signals.push(`New SQL, ${num(pctDb,1)}% DB time`); }
            else if (pctDb >  5) { score += 20; signals.push(`New SQL, ${num(pctDb,1)}% DB time`); }
            else if (pctDb >  2) { score += 10; }
            else if (pctDb < 1 && execsBad < 10) { score -= 10; }
        }

        // ── Signal 7: Wait event correlation — type multiplier applied.
        // Not all waits explain elapsed regression equally:
        //   +25 — db file sequential/scattered: directly explains I/O-bound elapsed time
        //   +23 — log file sync: directly explains commit-heavy DML latency  
        //   +22 — enq: TX row lock / index contention: direct concurrency serialisation
        //   +20 — enq: HW, free buffer waits, buffer busy: segment/cache pressure
        //   +15 — any other correlated wait (general supporting evidence)
        if (hasWait) {
            const _wname = (c.waitCorrelation.name || '').toLowerCase();
            const waitPts =
                /db file (sequential|scattered) read/.test(_wname)      ? 25 :
                /log file sync/.test(_wname)                            ? 23 :
                /enq.*tx.*(row lock|index contention)/.test(_wname)    ? 22 :
                /enq.*hw|free buffer waits|buffer busy/.test(_wname)   ? 20 :
                15;
            score += waitPts;
            signals.push(`Wait: ${c.waitCorrelation.name || 'correlated'} (+${waitPts})`);
        }

        // ── Signal 8: Plan changed
        if (c.planChanged) { score += 12; signals.push('Plan changed'); }

        // ── Signal 9: SQL type — SELECT/DML earn credit proportional to %DB time they consume.
        // Only meaningful when these application queries actually account for real DB time.
        // PL/SQL gets a small flat bonus; OTHER (maintenance/DDL) gets nothing.
        if (isAppSQL) {
            if      (pctDb > 15) { score += 15; signals.push(`${sqlType} @ ${num(pctDb,1)}% DB`); }
            else if (pctDb > 5)  { score += 10; signals.push(`${sqlType} @ ${num(pctDb,1)}% DB`); }
            else if (pctDb > 1)  { score +=  5; }
            else                 { score +=  2; } // tiny share — minimal credit
        } else if (isPLSQL) {
            score += 4;
        }
        // OTHER/DDL: 0 pts

        // ── Signal 10: Physical reads (I/O evidence)
        if      (c.diskReads > 1000000) { score += 10; signals.push(`${comma(c.diskReads)} phys reads`); }
        else if (c.diskReads >  100000) { score +=  6; }

        // ── Signal 11: CPU % — context only, secondary to %DB time.
        // High CPU is relevant only when the SQL is also consuming significant DB time.
        // Do NOT let CPU alone inflate the rank of a low-%DB SQL.
        if (cpuPct > 70 && pctDb > 5)  { score += 8; signals.push(`${num(cpuPct,0)}% CPU bound`); }
        else if (cpuPct > 50 && pctDb > 3) { score += 4; }
        // cpuPct alone without %DB support: no points

        // Rank from score
        const rank = score >= 60 ? 1 : score >= 35 ? 2 : score >= 15 ? 3 : 'SUPPRESSED';
        return { score, rank, signals };
    };

    // ── Rebuild full candidate pool from ctx.sqlRegistry ────────────────────────
    // Critical design principle: v.culpritCandidates is pre-sorted by addlSecs and
    // sliced to 5 before we ever run the scorer. Any SQL outside that top-5-by-addlSecs
    // is invisible — this is the root cause of high-%DB/regressed SQLs being excluded.
    //
    // Fix: rebuild here from the full registry (same shape as buildVerdict), with NO
    // pre-slice. The scorer is the only gate — classification labels are not gates.
    // This mirrors the user-facing SQL Analysis tab which shows all common/new SQLs.
    const _allCandidates = [];
    if (ctx.sqlRegistry) {
        for (const _sqlId in ctx.sqlRegistry) {
            const _entry = ctx.sqlRegistry[_sqlId];
            if (!_entry.badEntry) continue;
            if (_entry.classification === 'ORACLE_MAINTENANCE') continue;
            if (_entry.classification === 'DISAPPEARED') continue;
            const _bad  = _entry.badEntry;
            const _good = _entry.goodEntry;
            const _isNew = !_good;
            _allCandidates.push({
                sqlId: _sqlId,
                entry: _entry,
                isNew: _isNew,
                classification: _entry.classification,
                epeGood:  _good ? (_good.perExec || 0) : 0,
                epeBad:   _bad.perExec || 0,
                execsBad: _bad.executions  || 0,
                execsGood: _good ? (_good.executions || 0) : 0,
                pctDb:    _bad.pctDbTime   || 0,
                cpuPctBad:  _bad.cpuPct    || 0,
                cpuPctGood: _good ? (_good.cpuPct || 0) : null,
                planChanged: !!(_good && _bad.planHash && _good.planHash && _bad.planHash !== _good.planHash),
                sqlText:  _bad.sqlText || _good?.sqlText || '',
                module:   _bad.module  || _good?.module  || '',
                tables:   (typeof extractTablesFromSQL === 'function')
                              ? extractTablesFromSQL(_bad.sqlText || _good?.sqlText || '')
                              : [],
                diskReads:    _bad.diskReads    || 0,
                bufferGets:   _bad.bufferGets   || 0,
                diskReadsGood:  _good?.diskReads  || 0,
                bufferGetsGood: _good?.bufferGets || 0,
                waitCorrelation: _entry.waitCorrelation || null,
                addlSecs: _isNew
                    ? (_bad.perExec || 0) * (_bad.executions || 0)
                    : ((_bad.perExec || 0) - (_good?.perExec || 0)) * (_bad.executions || 0),
            });
        }
    } else {
        // Fallback: verdict pre-built pool (no slice guard here — already sliced upstream)
        _allCandidates.push(...(v.culpritCandidates || []));
    }

    // Score every candidate; the scorer decides what to suppress — no label-based gates.
    const _scoredCandidates = _allCandidates
        .map(c => ({ ...c, _priority: _priorityScore(c) }))
        .filter(c => c._priority.rank !== 'SUPPRESSED')
        .sort((a, b) => b._priority.score - a._priority.score);

    const _appRanked  = _scoredCandidates.filter(c => !_isPlatformCandidate(c));
    const _platRanked = _scoredCandidates.filter(c =>  _isPlatformCandidate(c));
    const _rankedCandidates = [..._appRanked, ..._platRanked].slice(0, 3);

    // True when no app SQL has strong enough evidence
    const _noStrongSQLFound = _appRanked.length === 0 ||
        (_appRanked[0]._priority.score < 15);

    if (_rankedCandidates.length > 0) {
        const classLabels = {
            CONTENTION_VICTIM:       { label: 'CONTENTION VICTIM', color: '#f87171', bg: 'rgba(248,113,113,0.15)' },
            NEW_HIGH_IMPACT:         { label: 'NEW HIGH IMPACT',   color: '#fb923c', bg: 'rgba(251,146,60,0.15)' },
            PLAN_REGRESSION:         { label: 'PLAN REGRESSION',   color: '#f59e0b', bg: 'rgba(245,158,11,0.15)' },
            REGRESSION:              { label: 'REGRESSION',         color: '#f59e0b', bg: 'rgba(245,158,11,0.15)' },
            PLAN_IMPROVED:           { label: 'PLAN IMPROVED',     color: '#34d399', bg: 'rgba(52,211,153,0.15)' },
            EXEC_REGRESSION:         { label: 'EXEC REGRESSION',   color: '#f59e0b', bg: 'rgba(245,158,11,0.15)' },
            HIGH_FREQUENCY_INCREASE: { label: 'FREQ INCREASE',     color: '#60a5fa', bg: 'rgba(96,165,250,0.15)' },
            IO_SHIFT:                { label: 'I/O SHIFT',         color: '#c084fc', bg: 'rgba(192,132,252,0.15)' },
            NEW_SQL:                 { label: 'NEW SQL',           color: '#fb923c', bg: 'rgba(251,146,60,0.15)' },
            STABLE:                  { label: 'STABLE',            color: '#64748b', bg: 'rgba(100,116,139,0.1)' },
        };
        const rankStyleMap = {
            1: { label: 'Highest Focus',   color: '#ef4444', border: 'rgba(239,68,68,0.4)',  bg: 'rgba(239,68,68,0.07)' },
            2: { label: 'Priority Review', color: '#f59e0b', border: 'rgba(245,158,11,0.3)', bg: 'rgba(245,158,11,0.05)' },
            3: { label: 'Additional Review',color:'#60a5fa', border: 'rgba(96,165,250,0.2)', bg: 'rgba(96,165,250,0.04)' },
        };

        const rankCards = _rankedCandidates.map((c, idx) => {
            const cl   = classLabels[c.classification] || classLabels.STABLE;
            const computedRank = (typeof c._priority?.rank === 'number') ? c._priority.rank : (idx + 1);
            const rank = rankStyleMap[computedRank] || rankStyleMap[3];
            const isPlatformCard = _isPlatformCandidate(c);
            const badge = isPlatformCard
                ? `<span style="background:rgba(100,116,139,0.2);color:#94a3b8;font-size:9px;font-weight:900;padding:3px 9px;border-radius:9999px;letter-spacing:0.4px;border:1px solid rgba(100,116,139,0.4)">⚙ PLATFORM / SCHEDULER</span>`
                : `<span style="background:${cl.bg};color:${cl.color};font-size:9px;font-weight:900;padding:3px 9px;border-radius:9999px;letter-spacing:0.4px;border:1px solid ${cl.color}40">${cl.label}</span>`;

            const isVictim = c.classification === 'CONTENTION_VICTIM';
            const epeRatio = c.epeGood > 0 ? ((c.epeBad/c.epeGood - 1)*100) : 999;
            const wc = c.waitCorrelation;
            const waitEventName = wc?.name || ctx.sqlCorrelation?.topWaitName || v.primarySignals?.[0]?.metric || '';

            // Evidence signals row (from priority scorer)
            const _pSig = (c._priority && c._priority.signals) || [];
            const signalsRow = _pSig.length > 0
                ? `<div style="display:flex;flex-wrap:wrap;gap:4px;margin-bottom:8px">${_pSig.slice(0,4).map(s =>
                    `<span style="font-size:9px;font-weight:700;color:#64748b;background:rgba(100,116,139,0.12);padding:1px 7px;border-radius:4px;border:1px solid rgba(100,116,139,0.2)">${esc(s)}</span>`
                  ).join('')}</div>`
                : '';

            // Exec/sec row (show when meaningful)
            const epsGood_ = (c.execsGood||0) / _elGoodMin;
            const epsBad_  = (c.execsBad||0)  / _elBadMin;
            const epsDelta_ = epsGood_ > 0 ? (epsBad_ - epsGood_) / epsGood_ * 100 : 0;
            const execSecRow = (c.execsBad || 0) > 0
                ? `<div style="margin-top:6px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
                      <span style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase">Exec/min:</span>
                      ${c.execsGood > 0 ? `<span style="font-size:10px;color:#34d399;font-family:monospace">${num(epsGood_,1)}</span><span style="color:#475569;font-size:9px"> → </span>` : ''}
                      <span style="font-size:10px;font-weight:800;font-family:monospace;color:${epsDelta_ > 30 ? '#fbbf24' : '#e2e8f0'}">${num(epsBad_,1)}</span>
                      ${epsDelta_ !== 0 && c.execsGood > 0 ? `<span style="font-size:9px;font-weight:800;color:${epsDelta_>30?'#fbbf24':'#64748b'}">(${epsDelta_>0?'+':''}${num(epsDelta_,0)}%)</span>` : ''}
                   </div>`
                : '';

            // ── METRIC TILES ─────────────────────────────────────
            let metricTiles = '';
            if (c.isNew) {
                metricTiles = `
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(251,146,60,0.2);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">E/Exec (Bad)</div>
                        <div style="color:#fb923c;font-size:18px;font-weight:900;font-family:monospace;line-height:1.2">${num(c.epeBad,3)}s</div>
                    </div>
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(251,146,60,0.2);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">Executions</div>
                        <div style="color:#e2e8f0;font-size:18px;font-weight:900;font-family:monospace;line-height:1.2">${comma(c.execsBad)}</div>
                    </div>
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(251,146,60,0.2);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">% DB Time</div>
                        <div style="color:#f87171;font-size:18px;font-weight:900;font-family:monospace;line-height:1.2">${num(c.pctDb,1)}%</div>
                    </div>`;
            } else {
                const epeColor = epeRatio > 200 ? '#f87171' : epeRatio > 50 ? '#fb923c' : '#f59e0b';
                metricTiles = `
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(255,255,255,0.06);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">E/Exec Good→Bad</div>
                        <div style="font-family:monospace;font-size:13px;font-weight:900;line-height:1.3;margin-top:2px">
                            <span style="color:#34d399">${num(c.epeGood,3)}s</span>
                            <span style="color:#475569;font-size:11px"> → </span>
                            <span style="color:${epeColor}">${num(c.epeBad,3)}s</span>
                        </div>
                        <div style="color:${epeColor};font-size:10px;font-weight:800">${epeRatio>0?'+':''}${num(epeRatio,0)}%</div>
                    </div>
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(255,255,255,0.06);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">% DB Time (Bad)</div>
                        <div style="color:#f87171;font-size:18px;font-weight:900;font-family:monospace;line-height:1.2">${num(c.pctDb,1)}%</div>
                    </div>
                    <div style="background:rgba(0,0,0,0.25);border:1px solid rgba(255,255,255,0.06);border-radius:6px;padding:7px 12px;text-align:center">
                        <div style="color:#64748b;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:0.4px">CPU% (Bad)</div>
                        <div style="color:${(c.cpuPctBad||0)<15?'#fca5a5':'#4ade80'};font-size:18px;font-weight:900;font-family:monospace;line-height:1.2">${num(c.cpuPctBad||0,0)}%</div>
                        ${(c.cpuPctBad||0)<15 ? '<div style="color:#f87171;font-size:9px;font-weight:700">WAITING</div>' : ''}
                    </div>`;
            }

            // ── CONTENTION VICTIM CALLOUT ────────────────────────
            const victimCallout = isVictim ? `
                <div style="margin-top:8px;padding:8px 12px;background:rgba(248,113,113,0.08);border:1px solid rgba(248,113,113,0.25);border-radius:6px">
                    <div style="display:flex;align-items:center;gap:6px;margin-bottom:4px">
                        <span style="color:#f87171;font-size:10px;font-weight:900;text-transform:uppercase;letter-spacing:0.5px">⚠ Root Cause: Wait Event</span>
                        ${waitEventName ? `<code style="color:#fca5a5;font-size:11px;font-weight:800;background:rgba(248,113,113,0.12);padding:1px 7px;border-radius:4px">${esc(waitEventName)}</code>` : ''}
                    </div>
                    <div style="color:#cbd5e1;font-size:11px;font-weight:500;line-height:1.6">
                        This SQL is a <strong style="color:#f87171">contention victim</strong> — it is not the cause of degradation.
                        The session is blocked waiting on <strong style="color:#fca5a5">${esc(waitEventName||'a wait event')}</strong>.
                        <strong style="color:#e2e8f0">Investigate the lock/resource holder</strong>, not this SQL's execution plan.
                    </div>
                    ${wc?.corrDetail ? `<div style="margin-top:5px;color:#a78bfa;font-size:10px;font-weight:600">↔ ${esc(wc.corrDetail)}</div>` : ''}
                </div>` : '';

            // ── PLATFORM / SCHEDULER CALLOUT ────────────────────────
            const platformCallout = isPlatformCard ? `
                <div style="margin-top:8px;padding:8px 12px;background:rgba(100,116,139,0.08);border:1px solid rgba(100,116,139,0.25);border-radius:6px">
                    <div style="color:#94a3b8;font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:0.4px;margin-bottom:4px">⚙ Platform / Scheduler SQL</div>
                    <div style="color:#64748b;font-size:11px;line-height:1.6">This SQL runs under a <strong style="color:#94a3b8">platform or scheduler module</strong> (${esc(c.module||'unknown')}). It is not an application query. A single long-running execution is normal for batch/scheduler jobs. <strong style="color:#e2e8f0">Do not tune this as an application bottleneck</strong> — investigate via Oracle Scheduler or the owning platform team. Application SQLs are shown above.</div>
                </div>` : '';

            // ── PLAN/FLAGS ───────────────────────────────────────
            const flags = [];
            if (c.planChanged) flags.push(`<span style="background:rgba(245,158,11,0.12);color:#fbbf24;font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;border:1px solid rgba(245,158,11,0.3)">⚠ Plan Hash Changed</span>`);
            if (c.isNew) flags.push(`<span style="background:rgba(251,146,60,0.12);color:#fb923c;font-size:10px;font-weight:700;padding:2px 8px;border-radius:4px;border:1px solid rgba(251,146,60,0.3)">NEW — Not in Good period</span>`);
            if (!isVictim && wc?.corrDetail) flags.push(`<span style="color:#a78bfa;font-size:10px;font-weight:600">↔ ${esc(wc.corrDetail)}</span>`);
            if (c.diskReads > 0) flags.push(`<span style="color:#94a3b8;font-size:10px">Physical reads: <strong style="color:#e2e8f0">${comma(c.diskReads)}</strong></span>`);

            const modLine = c.module ? `<span style="color:#94a3b8;font-size:10px;font-weight:500">Module: <strong style="color:#60a5fa;font-weight:700">${esc(c.module)}</strong></span>` : '';
            const tblLine = c.tables && c.tables.length ? `<span style="color:#94a3b8;font-size:10px;font-weight:500">Tables: <strong style="color:#c084fc;font-weight:700">${c.tables.slice(0,3).map(t=>esc(t)).join(', ')}</strong></span>` : '';
            const metaLine = [modLine, tblLine].filter(Boolean).join(' <span style="color:#1e293b;padding:0 4px">|</span> ');

            const _scoreNum = c._priority ? c._priority.score : 0;

            return `<div style="padding:12px 16px;background:${rank.bg};border:1px solid ${rank.border};border-left:4px solid ${rank.color};border-radius:0 8px 8px 0;margin-bottom:8px">
                <!-- Header row -->
                <div style="display:flex;align-items:center;gap:8px;margin-bottom:8px;flex-wrap:wrap">
                    <span style="display:inline-flex;align-items:center;gap:5px;font-size:11px;font-weight:900;color:${rank.color}">
                        <span style="display:inline-flex;align-items:center;justify-content:center;width:20px;height:20px;background:${rank.color};color:#fff;border-radius:50%;font-size:10px;font-weight:900;flex-shrink:0">${computedRank}</span>
                        ${rank.label}
                    </span>
                    <code style="font-size:13px;color:#fbbf24;background:rgba(251,191,36,0.12);padding:3px 9px;border-radius:5px;font-weight:800;letter-spacing:0.3px">${esc(c.sqlId)}</code>
                    ${badge}
                    <span style="margin-left:auto;font-size:9px;color:#334155;font-weight:700" title="Priority score from exec/sec + volume + regression + %DB + wait signals">score: ${_scoreNum}</span>
                </div>
                <!-- Meta: module / tables -->
                ${metaLine ? `<div style="margin-bottom:8px;display:flex;flex-wrap:wrap;gap:8px">${metaLine}</div>` : ''}
                <!-- Evidence signals -->
                ${signalsRow}
                <!-- Exec/sec row -->
                ${execSecRow}
                <!-- Metric tiles -->
                <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:6px;margin-top:8px;margin-bottom:${flags.length||isVictim?'8px':'0'}">
                    ${metricTiles}
                </div>
                <!-- Flags row -->
                ${flags.length ? `<div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:${isVictim||isPlatformCard?'8px':'0'}">${flags.join('')}</div>` : ''}
                <!-- Contention victim callout -->
                ${victimCallout}
                <!-- Platform/scheduler callout -->
                ${platformCallout}
            </div>`;
        }).join('');

        // "No strong SQL" advisory when all app SQLs scored weakly
        const _noStrongNote = _noStrongSQLFound
            ? `<div style="margin-bottom:8px;padding:10px 14px;background:rgba(100,116,139,0.08);border:1px solid rgba(100,116,139,0.2);border-left:3px solid #64748b;border-radius:0 6px 6px 0">
                <div style="font-size:11px;font-weight:800;color:#94a3b8;margin-bottom:3px">No strongly-evidenced application SQL bottleneck found</div>
                <div style="font-size:10px;color:#64748b;line-height:1.6">No application SQL shows a convincing combination of high execution volume, exec/sec shift, and per-exec regression. The bottleneck may be infrastructure, session management, or a resource not captured in the top-N AWR SQL list. Check Wait Events and Load Profile sections.</div>
              </div>`
            : '';

        const _tabLink = `<div style="margin-top:10px;padding:10px 16px;background:rgba(99,102,241,0.15);border:1.5px solid rgba(99,102,241,0.5);border-radius:8px;display:flex;align-items:center;justify-content:space-between;gap:10px;cursor:pointer" onclick="document.querySelectorAll('.main-tab-btn').forEach(b=>b.classList.remove('active'));const st=document.getElementById('tab-sql');if(st){document.querySelectorAll('.tab-pane').forEach(p=>p.style.display='none');st.style.display='';const btn=document.querySelector('[data-tab=sql]');if(btn)btn.classList.add('active')}">
            <div style="display:flex;align-items:center;gap:10px">
                <div style="display:flex;align-items:center;justify-content:center;width:32px;height:32px;background:rgba(99,102,241,0.25);border-radius:6px;flex-shrink:0">
                    <svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="#818cf8" stroke-width="2.5"><path stroke-linecap="round" stroke-linejoin="round" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"/></svg>
                </div>
                <div>
                    <div style="font-size:12px;font-weight:800;color:#c7d2fe;letter-spacing:0.3px">Open Full SQL Analysis Tab</div>
                    <div style="font-size:10px;color:#64748b;margin-top:1px">All <strong style="color:#a5b4fc">${(v.culpritCandidates||[]).length} ranked SQL${(v.culpritCandidates||[]).length===1?'':'s'}</strong> · sortable metrics · execution plans · PE recommendations</div>
                </div>
            </div>
            <span style="color:#6366f1;font-size:16px;font-weight:900;flex-shrink:0">→</span>
        </div>`;

        blockB = `<div style="margin-bottom:8px">
            <div style="display:flex;align-items:baseline;gap:8px;margin-bottom:6px">
                <span style="font-size:10px;font-weight:800;color:#e2e8f0;text-transform:uppercase;letter-spacing:1px">Critical SQL Focus</span>
                <span style="font-size:9px;color:#475569">— ranked by exec/sec shift · volume · per-exec regression · %DB time · wait evidence</span>
            </div>
            ${_noStrongNote}
            ${rankCards}
            ${_tabLink}
        </div>`;
    }

    // -------------------------------------------------------------
    // BLOCK C — THREE CORROBORATING METRICS
    // -------------------------------------------------------------
    const metrics = v.keyMetrics || [];
    const metricCards = metrics.slice(0, 3).map(km => {
        const e = km.entry || {};
        const isEff = e.section === 'efficiency';
        const gVal = isEff ? num(e.good, 1) + '%' : num(e.good, 1) + (e.unit ? ' ' + e.unit : '');
        const bVal = isEff ? num(e.bad, 1) + '%' : num(e.bad, 1) + (e.unit ? ' ' + e.unit : '');
        const arrow = e.direction === 'up' ? '\u2191' : e.direction === 'down' ? '\u2193' : '\u2192';
        const deltaPct = e.delta_pct || 0;
        const deltaCol = Math.abs(deltaPct) > 30 ? '#f59e0b' : Math.abs(deltaPct) > 10 ? '#94a3b8' : '#64748b';
        const srcBadge = `<span style="color:#475569;font-size:8px;text-transform:uppercase">${esc((e.section || 'metric').replace(/_/g, ' '))}</span>`;

        // Build explanation connecting to culprit — use wait correlation detail when available
        let explanation = '';
        if (tc && tc.waitCorrelation && tc.waitCorrelation.corrDetail) {
            explanation = `↔ ${esc(tc.waitCorrelation.corrDetail)}`;
        } else if (tc && tc.sqlId) {
            explanation = `Corroborates ${esc(tc.sqlId)} impact.`;
        }

        return `<div style="flex:1;min-width:140px;padding:8px 12px;background:rgba(15,23,42,0.4);border:1px solid rgba(148,163,184,0.08);border-radius:6px">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:4px">
                <span style="font-size:11px;font-weight:700;color:#e2e8f0">${esc(km.metric.replace(/_/g, ' '))}</span>
                ${srcBadge}
            </div>
            <div style="font-size:11px;color:#94a3b8">Good: <b style="color:#34d399">${gVal}</b> &nbsp; Bad: <b style="color:#f87171">${bVal}</b></div>
            <div style="font-size:12px;font-weight:700;color:${deltaCol}">${arrow} ${deltaPct > 0 ? '+' : ''}${num(deltaPct,0)}%</div>
            ${explanation ? `<div style="font-size:9px;color:#64748b;margin-top:4px">${explanation}</div>` : ''}
        </div>`;
    }).join('');

    const blockC = metrics.length > 0
        ? `<div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:8px">${metricCards}</div>`
        : '';

    // -------------------------------------------------------------
    // BLOCK D — IMMEDIATE ACTION
    // -------------------------------------------------------------
    const steps = v.actionSteps || [];
    let blockD = '';
    if (steps.length > 0) {
        const stepsHtml = steps.map((step, i) => {
            return `<div style="margin-bottom:${i < steps.length - 1 ? '10px' : '0'}">
                <div style="font-size:11px;color:#60a5fa;font-weight:700;margin-bottom:4px">Step ${i + 1} \u2014 ${esc(step.what)}</div>
                <pre style="background:rgba(0,0,0,0.3);color:#a5f3fc;padding:8px 12px;border-radius:6px;font-size:10px;line-height:1.5;overflow-x:auto;margin:0;white-space:pre-wrap;border:1px solid rgba(96,165,250,0.15)">${esc(step.query)}</pre>
            </div>`;
        }).join('');
        blockD = `<div style="padding:10px 16px;background:rgba(30,58,138,0.12);border:1px solid rgba(96,165,250,0.15);border-radius:8px;margin-bottom:8px">
            <div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:1px;font-weight:700;margin-bottom:8px">Immediate Action</div>
            ${stepsHtml}
        </div>`;
    } else if (v.action) {
        blockD = `<div style="padding:10px 16px;background:rgba(30,58,138,0.12);border:1px solid rgba(96,165,250,0.15);border-radius:8px;margin-bottom:8px">
            <div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:1px;font-weight:700;margin-bottom:6px">Immediate Action</div>
            <div style="font-size:11px;color:#93c5fd">${esc(v.action)}</div>
        </div>`;
    }

    // -------------------------------------------------------------
    // BLOCK E — CONTEXT NOTE (only when needed)
    // -------------------------------------------------------------
    const notes = v.contextNotes || [];
    const blockE = notes.length > 0
        ? `<div style="padding:8px 14px;background:rgba(100,116,139,0.06);border-left:2px solid #475569;border-radius:0 6px 6px 0;font-size:10px;color:#94a3b8;line-height:1.6">
            ${notes.map(n => `<div style="margin-bottom:4px">\u26A0 ${esc(n)}</div>`).join('')}
        </div>`
        : '';

    // -------------------------------------------------------------
    // BLOCK F — MEMORY ADVISORIES (Oracle 19c thresholds, when any)
    // -------------------------------------------------------------
    const memAdv = (v.memoryAdvisories || []).filter(a => a.severity === 'critical' || a.severity === 'warning');
    let blockF = '';
    if (memAdv.length > 0) {
        const advCards = memAdv.map(a => {
            const isCrit = a.severity === 'critical';
            const borderCol = isCrit ? '#ef4444' : '#f59e0b';
            const bg = isCrit ? 'rgba(239,68,68,0.07)' : 'rgba(245,158,11,0.07)';
            const labelCol = isCrit ? '#f87171' : '#fbbf24';
            return `<div style="padding:8px 12px;background:${bg};border-left:2px solid ${borderCol};border-radius:0 6px 6px 0;margin-bottom:6px">
                <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:2px">
                    <span style="font-size:11px;font-weight:700;color:#e2e8f0">${esc(a.metric)}</span>
                    <span style="font-size:9px;font-weight:800;color:${labelCol};text-transform:uppercase">${isCrit ? 'CRITICAL' : 'WARNING'}</span>
                </div>
                <div style="font-size:10px;color:#94a3b8">
                    Value: <b style="color:${labelCol}">${num(a.value, 1)}%</b>
                    &nbsp;\u00B7&nbsp; Oracle 19c threshold: <b style="color:#64748b">${a.threshold}%</b>
                </div>
                <div style="font-size:10px;color:#7dd3fc;margin-top:4px">\u2192 ${esc(a.fix)}</div>
            </div>`;
        }).join('');
        blockF = `<div style="padding:10px 16px;background:rgba(15,23,42,0.4);border:1px solid rgba(148,163,184,0.1);border-radius:8px;margin-bottom:8px">
            <div style="font-size:10px;color:#64748b;text-transform:uppercase;letter-spacing:1px;font-weight:700;margin-bottom:8px">
                \u26A0 Oracle 19c Memory Efficiency Advisories
            </div>
            ${advCards}
        </div>`;
    }

    return blockA + blockB + blockC + blockF + blockE;
}


// === CHART RENDERING ===

function renderSingleDashboardCharts(events, sqls, lp, waitClassMap) {

    destroyChart('dash-wait-donut');

    const wCtx = document.getElementById('dash-wait-donut');

    if (wCtx && events.length) {

        const colors = ['#ef4444','#f97316','#f59e0b','#eab308','#84cc16','#22c55e','#14b8a6','#06b6d4','#3b82f6','#8b5cf6'];

        storeChart('dash-wait-donut', new Chart(wCtx, {

            type: 'doughnut',

            data: { labels: events.map(e=>e.event_name), datasets: [{ data: events.map(e=>e.pct_db_time||0), backgroundColor: colors.slice(0,events.length), borderWidth: 0 }] },

            options: { responsive: true, maintainAspectRatio: false, cutout: '55%', plugins: { legend: { position: 'right', labels: { color: '#94a3b8', font: {size:10}, boxWidth: 10, padding: 6 } } } }

        }));

    }

    destroyChart('dash-wclass-bar');

    const wcCtx = document.getElementById('dash-wclass-bar');

    if (wcCtx && Object.keys(waitClassMap).length) {

        const wcColors = { 'User I/O': '#3b82f6', 'System I/O': '#6366f1', 'Concurrency': '#f59e0b', 'Application': '#ef4444', 'Configuration': '#ec4899', 'Network': '#8b5cf6', 'Commit': '#14b8a6', 'Idle': '#475569', 'Other': '#64748b', 'CPU': '#22c55e' };

        const entries = Object.entries(waitClassMap).sort((a,b) => b[1]-a[1]);

        storeChart('dash-wclass-bar', new Chart(wcCtx, {

            type: 'bar',

            data: { labels: entries.map(e=>e[0]), datasets: [{ data: entries.map(e=>e[1]), backgroundColor: entries.map(e=>wcColors[e[0]]||'#64748b'), borderRadius: 4 }] },

            options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { display: false } }, scales: { x: { grid:{display:false}, ticks:{color:'#94a3b8',font:{size:9}} }, y: { grid:{color:'#1e293b'}, ticks:{color:'#94a3b8',font:{size:9}}, title:{display:true,text:'% DB Time',color:'#64748b',font:{size:9}} } } }

        }));

    }

    destroyChart('dash-sql-bar');

    const sCtx = document.getElementById('dash-sql-bar');

    if (sCtx && sqls.length) {

        const sorted = [...sqls].sort((a,b) => {

            return ((b.elapsed_time_secs||0)/(b.executions||1)) - ((a.elapsed_time_secs||0)/(a.executions||1));

        }).slice(0,10);

        storeChart('dash-sql-bar', new Chart(sCtx, {

            type: 'bar',

            data: { labels: sorted.map(s=>s.sql_id), datasets: [{ label: 'Elapsed/Exec (s)', data: sorted.map(s=>(s.elapsed_time_secs||0)/(s.executions||1)), backgroundColor: sorted.map(s => { const v=(s.elapsed_time_secs||0)/(s.executions||1); return v>10?'#ef4444':v>2?'#f59e0b':'#3b82f6'; }), borderRadius: 3 }] },

            options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { grid:{color:'#1e293b'}, ticks:{color:'#94a3b8',font:{size:10}}, title:{display:true,text:'seconds/exec',color:'#64748b',font:{size:9}} }, y: { grid:{display:false}, ticks:{color:'#d1d5db',font:{size:10,family:'monospace'}} } } }

        }));

    }

    destroyChart('dash-load-bar');

    const lCtx = document.getElementById('dash-load-bar');

    if (lCtx && lp.length) {

        const important = ['Redo size', 'Logical read', 'Physical read', 'Block changes', 'User calls', 'Parses', 'Hard parses', 'Executes', 'Transactions', 'User commits'];

        const filtered = lp.filter(l => important.some(k => (l.stat_name||'').toLowerCase().includes(k.toLowerCase()))).slice(0,10);

        if (filtered.length) {

            storeChart('dash-load-bar', new Chart(lCtx, {

                type: 'bar',

                data: { labels: filtered.map(l=>l.stat_name), datasets: [{ label: 'Per Second', data: filtered.map(l=>l.per_sec||0), backgroundColor: '#06b6d4', borderRadius: 3 }] },

                options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { display: false } }, scales: { x: { grid:{color:'#1e293b'}, ticks:{color:'#94a3b8',font:{size:10}} }, y: { grid:{display:false}, ticks:{color:'#d1d5db',font:{size:9}} } } }

            }));

        }

    }

}



function renderComparisonCharts(ev1, ev2, sql1, sql2, eff1, eff2, lbl1, lbl2) {

    destroyChart('dash-wait-cmp');

    const wCtx = document.getElementById('dash-wait-cmp');

    if (wCtx) {

        const allNames = [...new Set([...ev1.map(e=>e.event_name),...ev2.map(e=>e.event_name)])];

        const map1={}, map2={}; ev1.forEach(e=>{map1[e.event_name]=e.pct_db_time||0;}); ev2.forEach(e=>{map2[e.event_name]=e.pct_db_time||0;});

        const sorted = allNames.sort((a,b) => Math.max(map1[b]||0,map2[b]||0) - Math.max(map1[a]||0,map2[a]||0)).slice(0,10);

        storeChart('dash-wait-cmp', new Chart(wCtx, {

            type: 'bar', data: { labels: sorted.map(n=>n.length>25?n.substring(0,23)+'..':n), datasets: [

                { label: lbl1, data: sorted.map(n=>map1[n]||0), backgroundColor: '#10b981', borderRadius: 3 },

                { label: lbl2, data: sorted.map(n=>map2[n]||0), backgroundColor: '#ef4444', borderRadius: 3 },

            ]}, options: { responsive: true, maintainAspectRatio: false, indexAxis: 'y', plugins: { legend: { labels:{color:'#d1d5db',font:{size:10}} } }, scales: { x:{grid:{color:'#1e293b'},ticks:{color:'#94a3b8'},title:{display:true,text:'% DB Time',color:'#64748b',font:{size:9}}}, y:{grid:{display:false},ticks:{color:'#d1d5db',font:{size:9}}} } }

        }));

    }

    destroyChart('dash-eff-cmp');

    const eCtx = document.getElementById('dash-eff-cmp');

    if (eCtx) {

        const labels = ['Buffer Hit%','Library Hit%','Soft Parse%','Latch Hit%'];

        storeChart('dash-eff-cmp', new Chart(eCtx, {

            type: 'radar', data: { labels, datasets: [

                { label: lbl1, data: [eff1.buffer_cache_hit_pct||0, eff1.library_cache_hit_pct||0, eff1.soft_parse_pct||0, eff1.latch_hit_pct||0], borderColor: '#10b981', backgroundColor: 'rgba(16,185,129,0.1)', pointBackgroundColor: '#10b981' },

                { label: lbl2, data: [eff2.buffer_cache_hit_pct||0, eff2.library_cache_hit_pct||0, eff2.soft_parse_pct||0, eff2.latch_hit_pct||0], borderColor: '#ef4444', backgroundColor: 'rgba(239,68,68,0.1)', pointBackgroundColor: '#ef4444' },

            ]}, options: { responsive: true, maintainAspectRatio: false, scales: { r: { min: 80, max: 100, ticks:{stepSize:5,color:'#64748b',font:{size:9},backdropColor:'transparent'}, grid:{color:'#1e293b'}, pointLabels:{color:'#d1d5db',font:{size:10}} } }, plugins: { legend: { labels:{color:'#d1d5db',font:{size:10}} } } }

        }));

    }

    // === 3-Zone SQL Chart ===

    const map1sql = {}; sql1.forEach(s => { map1sql[s.sql_id] = s; });

    const map2sql = {}; sql2.forEach(s => { map2sql[s.sql_id] = s; });

    const sql1ids = new Set(sql1.map(s=>s.sql_id));

    const sql2ids = new Set(sql2.map(s=>s.sql_id));

    // Helper: pull module + sql text from the registry for any SQL ID
    const _getRegEntry = (id) => (AWRContext && AWRContext.sqlRegistry && AWRContext.sqlRegistry[id]) || null;
    const _getSQLTypeFor = (id, fallbackMod, fallbackSqlText) => {
        const reg = _getRegEntry(id);
        // Prefer raw sql_text from the data row, then registry, then nothing
        const txt = fallbackSqlText || (reg && (reg.sqlTextFull || reg.displayText || '')) || '';
        const type = _getSQLType(txt);
        if (type !== 'OTHER') return type;
        // fallback: try to infer from module
        const mod = (fallbackMod || (reg && reg.module) || '').toUpperCase();
        if (/INSERT/i.test(mod)) return 'INSERT';
        if (/UPDATE/i.test(mod)) return 'UPDATE';
        if (/DELETE/i.test(mod)) return 'DELETE';
        return 'OTHER';
    };
    const _isPlatformId = (id, fallbackMod, fallbackSqlText) => {
        const reg = _getRegEntry(id);
        const mod = fallbackMod || (reg && reg.module) || '';
        const sqlText = fallbackSqlText || (reg && (reg.sqlTextFull || reg.displayText)) || '';
        return _isPlatformSQL({ module: mod, sqlText }) || _isSysSQL({ module: mod, sqlTextFull: sqlText });
    };
    // Priority weight: app DML/SELECT > PLSQL > platform/sys
    const _appPriorityWeight = (type, isPlatform) => {
        if (isPlatform) return 0;
        const w = {INSERT:6,UPDATE:5,DELETE:5,MERGE:5,SELECT:4,PLSQL:2,OTHER:1};
        return w[type] || 1;
    };

    // Good-only: in baseline, NOT in problem (disappeared)

    const goodOnly = sql1.filter(s => !sql2ids.has(s.sql_id))

        .map(s => ({

            id: s.sql_id,

            epe:    (s.elapsed_time_secs||0) / Math.max(s.executions||1, 1),

            execs:  s.executions||0,

            pctDb:  s.pct_db_time||0,

            elapsed:s.elapsed_time_secs||0,

            cpu:    Math.round((s.cpu_time_secs||0)/(s.elapsed_time_secs||1)*100),

            sqlType: _getSQLTypeFor(s.sql_id, s.module||'', s.sql_text||''),
            isPlatform: _isPlatformId(s.sql_id, s.module||'', s.sql_text||''),

        }))

        .sort((a,b) => b.epe - a.epe).slice(0,3);



    // Bad-only: in problem, NOT in baseline (new offenders)

    const badOnly = sql2.filter(s => !sql1ids.has(s.sql_id))

        .map(s => ({

            id: s.sql_id,

            epe:    (s.elapsed_time_secs||0) / Math.max(s.executions||1, 1),

            execs:  s.executions||0,

            pctDb:  s.pct_db_time||0,

            elapsed:s.elapsed_time_secs||0,

            cpu:    Math.round((s.cpu_time_secs||0)/(s.elapsed_time_secs||1)*100),

            sqlType: _getSQLTypeFor(s.sql_id, s.module||'', s.sql_text||''),
            isPlatform: _isPlatformId(s.sql_id, s.module||'', s.sql_text||''),

        }))

        .sort((a,b) => b.epe - a.epe).slice(0,3);



    // Common: in both — top 5 by problem epe, with full regression detail + classification
    const _sevColor = { CRITICAL:'#ef4444', SEVERE:'#f97316', SIGNIFICANT:'#f59e0b', MINOR:'#eab308', STABLE:'#3b82f6' };
    const _getSev   = pct => pct >= 1000 ? 'CRITICAL' : pct >= 500 ? 'SEVERE' : pct >= 100 ? 'SIGNIFICANT' : pct >= 20 ? 'MINOR' : 'STABLE';
    const commonSQL = sql2.filter(s => sql1ids.has(s.sql_id))
        .map(s2item => {
            const s1item = map1sql[s2item.sql_id];
            const epe2 = (s2item.elapsed_time_secs||0) / Math.max(s2item.executions||1, 1);
            const epe1 = (s1item.elapsed_time_secs||0) / Math.max(s1item.executions||1, 1);
            const execsDelta = s1item.executions>0 ? ((s2item.executions||0)-(s1item.executions||0))/(s1item.executions)*100 : 0;
            const planChg = s1item.plan_hash_value && s2item.plan_hash_value &&
                            s1item.plan_hash_value !== s2item.plan_hash_value;
            // -- regression_severity ------------------------------------------
            const regPct = epe1 > 0 ? (epe2 - epe1) / epe1 * 100 : (epe2 > 0 ? 9999 : 0);
            const regressionSeverity = _getSev(regPct);
            // -- contention victim detection -----------------------------------
            // cpu_pct_of_elapsed: if SQL spent <10% of elapsed time on CPU, it was mostly waiting
            const cpuPct2 = (s2item.elapsed_time_secs||0) > 0
                ? Math.round((s2item.cpu_time_secs||0) / (s2item.elapsed_time_secs||1) * 100) : 100;
            // Top contention event in bad wait profile (enq:, latch:, buffer busy, read by other)
            const _topContEvent = ev2.find(e => /enq:|latch:|buffer busy|read by other/i.test(e.event_name||''));
            const isContentionVictim = cpuPct2 < 10 && !!_topContEvent;
            const contentionRootCause = isContentionVictim ? (_topContEvent?.event_name || '') : '';
            const recommendationType = isContentionVictim ? 'INVESTIGATE_CONTENTION'
                : (regressionSeverity === 'CRITICAL' || regressionSeverity === 'SEVERE') ? 'SQL_TUNING_URGENT'
                : 'SQL_TUNING_STANDARD';
            return {
                id: s2item.sql_id, epe1, epe2,
                execs1: s1item.executions||0,
                execs2: s2item.executions||0,
                execsDelta,
                pctDb1: s1item.pct_db_time||0,
                pctDb2: s2item.pct_db_time||0,
                planChg,
                plan1: s1item.plan_hash_value||'',
                plan2: s2item.plan_hash_value||'',
                regPct, regressionSeverity, cpuPct2,
                isContentionVictim, contentionRootCause, recommendationType,
                sqlType: _getSQLTypeFor(s2item.sql_id, s2item.module||s1item.module||''),
                isPlatform: _isPlatformId(s2item.sql_id, s2item.module||s1item.module||'', s2item.sql_text||s1item.sql_text||''),
            };
        }).sort((a,b) => b.epe2 - a.epe2).slice(0,5);

    // Auto-collapse 3-zone chart when outer zones are empty
    if (goodOnly.length === 0 && badOnly.length === 0) {
        const emptyEl = document.getElementById('sql-3zone-empty');
        const chartsEl = document.getElementById('sql-3zone-charts');
        if (emptyEl) emptyEl.style.display = '';
        if (chartsEl) chartsEl.style.display = 'none';
    }


    // Render good-only zone

    destroyChart('dash-sql-good-only');

    const goCtx = document.getElementById('dash-sql-good-only');

    if (goCtx) {

        if (goodOnly.length) {

            storeChart('dash-sql-good-only', new Chart(goCtx, {

                type: 'bar',

                data: { labels: goodOnly.map(s=>s.id), datasets: [{ label: lbl1+' only (s/exec)', data: goodOnly.map(s=>s.epe), backgroundColor: '#10b981', borderRadius: 4 }] },

                options: { responsive:true, maintainAspectRatio:false, plugins:{ legend:{labels:{color:'#94a3b8',font:{size:9}}} }, scales:{ x:{grid:{display:false},ticks:{color:'#34d399',font:{size:8,family:'monospace'}}}, y:{grid:{color:'#1e293b'},ticks:{color:'#94a3b8',font:{size:8}},title:{display:true,text:'s/exec',color:'#64748b',font:{size:8}}} } }

            }));

        } else {

            goCtx.parentElement.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:200px;color:#374151;font-size:11px;text-align:center">No unique-baseline SQLs<br><span style="color:#1e293b;font-size:9px">all baseline SQLs present in problem too</span></div>';

        }

    }



    // Render common zone — severity-colored problem bars + regression % badges
    destroyChart('dash-sql-common-cmp');
    const cmCtx = document.getElementById('dash-sql-common-cmp');
    if (cmCtx && commonSQL.length) {
        const _problemColors = commonSQL.map(s =>
            s.isContentionVictim ? '#818cf8'       // purple = contention victim
            : _sevColor[s.regressionSeverity] || '#ef4444'
        );
        // Custom plugin: draw regression % badge above problem bars
        const _regressionBadgePlugin = {
            id: 'regressionBadge',
            afterDatasetsDraw(chart) {
                const { ctx: c, scales: { x, y }, data } = chart;
                // dataset index 1 = problem bars
                const ds = chart.getDatasetMeta(1);
                if (!ds || ds.hidden) return;
                ds.data.forEach((bar, i) => {
                    const s = commonSQL[i];
                    if (!s) return;
                    const regAbs = s.regPct;
                    if (Math.abs(regAbs) < 5) return; // skip near-stable
                    const sign   = regAbs >= 0 ? '+' : '';
                    let label    = s.isContentionVictim ? '⚠ CONTENTION' : `${sign}${Math.round(regAbs)}%`;
                    const fgCol  = s.isContentionVictim ? '#c4b5fd'
                                 : s.regressionSeverity === 'CRITICAL'    ? '#fca5a5'
                                 : s.regressionSeverity === 'SEVERE'      ? '#fdba74'
                                 : s.regressionSeverity === 'SIGNIFICANT' ? '#fcd34d'
                                 : s.regressionSeverity === 'MINOR'       ? '#fef08a'
                                 : '#6ee7b7';
                    c.save();
                    c.font = 'bold 7px sans-serif';
                    c.fillStyle = fgCol;
                    c.textAlign = 'center';
                    c.textBaseline = 'bottom';
                    const barTop = bar.y - 2;
                    c.fillText(label, bar.x, barTop);
                    c.restore();
                });
            }
        };
        storeChart('dash-sql-common-cmp', new Chart(cmCtx, {
            type: 'bar',
            data: {
                labels: commonSQL.map(s=>s.id),
                datasets: [
                    { label: lbl1+' (s/exec)', data: commonSQL.map(s=>s.epe1), backgroundColor: '#10b981', borderRadius: 3 },
                    { label: lbl2+' (s/exec)', data: commonSQL.map(s=>s.epe2), backgroundColor: _problemColors, borderRadius: 3 },
                ]
            },
            plugins: [_regressionBadgePlugin],
            options: {
                responsive:true, maintainAspectRatio:false,
                plugins: { legend: { labels: { color:'#d1d5db', font:{size:9} }, position:'top' } },
                scales: {
                    x: { grid:{display:false}, ticks:{color:'#22d3ee', font:{size:8,family:'monospace'}} },
                    y: { grid:{color:'#1e293b'}, ticks:{color:'#94a3b8',font:{size:8}}, title:{display:true,text:'s/exec',color:'#64748b',font:{size:8}} }
                },
                layout: { padding: { top: 18 } }
            }
        }));
        // Render contention victim annotation strip below chart
        const _cmAnnoEl = document.getElementById('sql-common-anno');
        if (_cmAnnoEl) {
            const _victims = commonSQL.filter(s => s.isContentionVictim);
            _cmAnnoEl.innerHTML = _victims.length
                ? _victims.map(s => `<span style="display:inline-flex;align-items:center;gap:4px;padding:2px 8px;background:rgba(129,140,248,0.12);border:1px solid rgba(129,140,248,0.3);border-radius:4px;font-size:9px;color:#c4b5fd">
                    ${_iconSvg('lock','#a78bfa')} <b style="color:#a78bfa">${esc(s.id)}</b> — CONTENTION VICTIM
                    ${s.contentionRootCause ? `<span style="color:#818cf8">${esc(s.contentionRootCause)}</span>` : ''}
                    <span style="color:#64748b;margin-left:2px">CPU ${s.cpuPct2}% of elapsed — not a SQL tuning issue</span>
                  </span>`).join('')
                : '';
            _cmAnnoEl.style.display = _victims.length ? '' : 'none';
        }
    }



    // Render bad-only zone

    destroyChart('dash-sql-bad-only');

    const boCtx = document.getElementById('dash-sql-bad-only');

    if (boCtx) {

        if (badOnly.length) {

            storeChart('dash-sql-bad-only', new Chart(boCtx, {

                type: 'bar',

                data: { labels: badOnly.map(s=>s.id), datasets: [{ label: lbl2+' only (s/exec)', data: badOnly.map(s=>s.epe), backgroundColor: '#ef4444', borderRadius: 4 }] },

                options: { responsive:true, maintainAspectRatio:false, plugins:{ legend:{labels:{color:'#94a3b8',font:{size:9}}} }, scales:{ x:{grid:{display:false},ticks:{color:'#f87171',font:{size:8,family:'monospace'}}}, y:{grid:{color:'#1e293b'},ticks:{color:'#94a3b8',font:{size:8}},title:{display:true,text:'s/exec',color:'#64748b',font:{size:8}}} } }

            }));

        } else {

            boCtx.parentElement.innerHTML = '<div style="display:flex;align-items:center;justify-content:center;height:200px;color:#374151;font-size:11px;text-align:center">No new-problem SQLs<br><span style="color:#1e293b;font-size:9px">all problem SQLs existed in baseline too</span></div>';

        }

    }



    // Top-3 highlight strip below the 3-zone chart

    const top3el = document.getElementById('dash-sql-top3');

    if (top3el) {

        const crownIcons = ['#1','#2','#3'];

        const crownCls   = ['crown-1','crown-2','crown-3'];

        // ── 3-Zone card scorer ──────────────────────────────────────────────
        // Design rules:
        //   COMMON regressions > BAD ONLY new > GONE (never a priority card)
        //   %DB × elapsed delta is the primary signal. epe alone is misleading for
        //   single-execution ad-hoc queries (60s × 1 exec ≠ DBA tuning target).
        //   Contention victims: scored lower (DBA should investigate wait, not SQL).
        //   Platform/ad-hoc tool sessions: suppressed.
        const _3zScore = (s) => {
            let sc = 0;
            const pctDb    = s.pctDb2 != null ? s.pctDb2 : (s.pctDb || 0);
            const execsBad = s.execs2 != null ? s.execs2 : (s.execs || 0);
            const epeRat   = (s.epe1 > 0 && s.epe != null) ? (s.epe - s.epe1) / s.epe1 * 100 : 0;
            const isNew    = s.zone === 'bad';
            const isGone   = s.zone === 'good';
            if (isGone)   return -100 + pctDb;  // always below active SQLs
            if (s.isPlatform) return -200;       // platform: suppressed
            // Signal 1 — per-exec elapsed regression
            if (!isNew) {
                if      (epeRat > 200) sc += 35;
                else if (epeRat > 100) sc += 25;
                else if (epeRat >  50) sc += 15;
                else if (epeRat >  20) sc += 10;
                else if (epeRat >   9) sc +=  6;
            }
            // Signal 2 — % DB Time
            if      (pctDb > 25) sc += 35;
            else if (pctDb > 15) sc += 28;
            else if (pctDb > 10) sc += 20;
            else if (pctDb >  5) sc += 12;
            else if (pctDb >  2) sc +=  5;
            // Signal 3 — combined %DB × regression (confirmed bottleneck)
            if (!isNew && pctDb >= 5 && epeRat >= 15) {
                sc += pctDb >= 15 && epeRat >= 100 ? 25
                    : pctDb >= 10 && epeRat >=  50 ? 18
                    : pctDb >= 10 && epeRat >=  15 ? 12
                    : pctDb >=  5 && epeRat >=  30 ? 10
                    : 6;
            }
            // Signal 4 — exec volume
            if      (execsBad >= 10000) sc += 14;
            else if (execsBad >=  1000) sc +=  8;
            else if (execsBad >=   100) sc +=  4;
            else if (execsBad === 1 && !isNew) sc -= 10;
            // Signal 5 — new SQL with meaningful %DB
            if (isNew) {
                if      (pctDb > 10) sc += 30;
                else if (pctDb >  5) sc += 20;
                else if (pctDb >  2) sc += 10;
            }
            // Signal 6 — plan changed
            if (s.planChg) sc += 12;
            // Contention victims: penalise so tunable regressions rank higher
            if (s.isContentionVictim) sc -= 15;
            return sc;
        };

        // Build unified pool: COMMON + BAD-ONLY + GOOD-ONLY
        const _allCandidates = [
            ...commonSQL.map(s => ({
                id:s.id, epe:s.epe2, epe1:s.epe1, zone:'common',
                delta: s.epe1>0 ? (s.epe2-s.epe1)/s.epe1*100 : null,
                execs1:s.execs1, execs2:s.execs2, execsDelta:s.execsDelta,
                pctDb1:s.pctDb1, pctDb2:s.pctDb2, planChg:s.planChg,
                plan1:s.plan1, plan2:s.plan2,
                regressionSeverity:s.regressionSeverity, cpuPct2:s.cpuPct2,
                isContentionVictim:s.isContentionVictim, contentionRootCause:s.contentionRootCause,
                recommendationType:s.recommendationType,
                sqlType:s.sqlType, isPlatform:s.isPlatform,
            })),
            ...badOnly.map(s => ({
                ...s, zone:'bad',
                delta:null, epe1:null, execs1:null, execs2:s.execs, pctDb2:s.pctDb, planChg:false,
            })),
            ...goodOnly.map(s => ({
                ...s, zone:'good',
                delta:null, epe1:s.epe, execs1:s.execs, execs2:null, pctDb2:null, planChg:false,
            })),
        ];

        // Score all; active-only priority cards (score > -50), GONE section separate
        const _scoredAll = _allCandidates.map(s => ({ ...s, _sc: _3zScore(s) })).sort((a,b) => b._sc - a._sc);
        const candidates = _scoredAll.filter(s => s._sc > -50).slice(0, 3);
        const _goneSQLs  = _allCandidates.filter(s => s.zone === 'good').sort((a,b) => (b.pctDb||0) - (a.pctDb||0));

        // Detect if platform/SRE SQLs are dominating (would have been top without filtering)
        const _rawTop3 = _allCandidates.sort((a,b) => (b.epe||0)-(a.epe||0)).slice(0,3);
        const _platformDominates = _rawTop3.filter(s => s.isPlatform).length >= 2;
        const _platformInTop3    = _rawTop3.some(s => s.isPlatform);
        const _platformNote = _platformDominates
            ? `<div style="margin-bottom:8px;padding:8px 14px;background:rgba(100,116,139,0.1);border:1px solid rgba(100,116,139,0.3);border-left:3px solid #64748b;border-radius:0 6px 6px 0;display:flex;align-items:flex-start;gap:8px">
                <span style="color:#94a3b8;font-size:13px;flex-shrink:0">⚙</span>
                <div>
                    <div style="font-size:10px;font-weight:800;color:#94a3b8;text-transform:uppercase;letter-spacing:0.4px;margin-bottom:2px">Platform / Infrastructure SQLs dominate by elapsed time</div>
                    <div style="font-size:10px;color:#64748b;line-height:1.6">The highest elapsed/exec SQLs are <strong style="color:#94a3b8">SRE_ / platform infrastructure</strong> queries — not application workload. These are operational by design and typically not the source of user-facing issues. <strong style="color:#e2e8f0">Cards below show the highest-impact application SQLs</strong> (SELECT / DML). Check the <strong style="color:#60a5fa">⚙ Platform tab</strong> in SQL Analysis for the full list.</div>
                </div>
              </div>`
            : _platformInTop3
            ? `<div style="margin-bottom:8px;padding:7px 14px;background:rgba(100,116,139,0.06);border:1px solid rgba(100,116,139,0.2);border-radius:6px;font-size:10px;color:#64748b">
                ⚙ <strong style="color:#94a3b8">Note:</strong> One or more high-elapsed SQLs are platform/infrastructure queries (SRE_ / batch). Application SQLs are shown first. See <strong style="color:#60a5fa">⚙ Platform tab</strong> in SQL Analysis for infrastructure SQL details.
              </div>`
            : '';

        // GONE SQL informational strip (separate section, not priority cards)
        const _goneStrip = _goneSQLs.length > 0
            ? `<div style="margin-top:10px;padding:8px 14px;background:rgba(15,23,42,0.5);border:1px solid rgba(100,116,139,0.2);border-radius:6px">
                <div style="font-size:9px;font-weight:800;color:#475569;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:5px">ℹ Gone in ${esc(lbl2)} — informational only, not tuning targets</div>
                <div style="display:flex;flex-wrap:wrap;gap:6px">${_goneSQLs.map(s =>
                    `<span style="display:inline-flex;align-items:center;gap:5px;padding:3px 9px;background:rgba(16,185,129,0.06);border:1px solid rgba(16,185,129,0.15);border-radius:5px;font-size:10px;font-family:monospace;color:#34d399">
                        ${esc(s.id)}
                        <span style="font-size:9px;color:#374151;font-family:sans-serif">${num(s.epe||0,2)}s/exec</span>
                        ${s.execs>0?`<span style="font-size:9px;color:#1e3a5f">${comma(s.execs)} execs</span>`:''}
                        ${s.pctDb>0?`<span style="font-size:9px;color:#475569">${num(s.pctDb,1)}% DB</span>`:''}
                    </span>`).join('')}</div>
                <div style="margin-top:4px;font-size:9px;color:#334155">Ran in ${esc(lbl1)} but not ${esc(lbl2)} — workload dropped or query retired. No DBA tuning action required.</div>
              </div>`
            : '';

        top3el.innerHTML = (_platformNote + (candidates.length ? candidates.map((s,i) => {

            const zoneCol = { bad:'#ef4444', common:'#06b6d4', good:'#10b981' };

            const col = (s.zone==='common' && s.isContentionVictim) ? '#818cf8' : (zoneCol[s.zone] || '#94a3b8');

            // Wait correlation badge from unified registry
            const regEntry = AWRContext && AWRContext.sqlRegistry && AWRContext.sqlRegistry[s.id];
            const wc = regEntry && regEntry.waitCorrelation;
            const corrBadge = wc && wc.corrStrength > 5
                ? '<div style="margin-top:4px;padding:3px 8px;background:rgba(168,85,247,0.12);border:1px solid rgba(168,85,247,0.25);border-radius:5px;font-size:9px;color:#c4b5fd">&#9889; <b style="color:#a78bfa">'+esc(wc.corrDetail)+'</b></div>'
                : '';

            // Top culprit highlight from Automated Analysis
            const isTopCulprit = AWRContext && AWRContext.analysis && AWRContext.analysis.topCulprit === s.id;
            const culpritHighlight = isTopCulprit
                ? '<div style="margin-top:4px;padding:2px 8px;background:rgba(6,182,212,0.12);border:1px solid rgba(6,182,212,0.25);border-radius:5px;font-size:9px;color:#67e8f9;font-weight:700">\u2605 Highlighted by Automated Analysis</div>'
                : '';

            // -- Zone-specific badge --

            let badge = '';

            if (s.zone==='bad')    badge = `NEW • NEW IN ${esc(lbl2).toUpperCase()}`;

            else if (s.zone==='common') {

                if (s.isContentionVictim) badge = `${_iconSvg('lock','#a78bfa')} CONTENTION VICTIM`;

                else if (s.planChg)       badge = `${_iconSvg('tool','#fbbf24')} PLAN CHANGED`;

                else if (s.regressionSeverity==='CRITICAL')     badge = `${_iconSvg('fire','#ef4444')} CRITICAL +${num(s.delta,0)}%`;

                else if (s.regressionSeverity==='SEVERE')       badge = `${_iconSvg('warning','#f97316')} SEVERE +${num(s.delta,0)}%`;

                else if (s.regressionSeverity==='SIGNIFICANT')  badge = `${_iconSvg('trending','#f87171')} +${num(s.delta,0)}% REGRESSION`;

                else if (s.delta>100)   badge = `${_iconSvg('trending','#f87171')} +${num(s.delta,0)}% REGRESSION`;

                else                    badge = `${_iconSvg('trending','#fbbf24')} SLOWER +${num(s.delta||0,0)}%`;

            }

            else                    badge = `${_iconSvg('info','#94a3b8')} GONE IN ${esc(lbl2).toUpperCase()}`;



            // -- Story headline --

            let headline = '';

            if (s.zone==='bad')

                headline = `Brand-new in <b style="color:#f87171">${esc(lbl2)}</b> — was absent during baseline. ${s.pctDb2>10?`<span style="color:#fbbf24">Consuming ${num(s.pctDb2,1)}% of DB time.</span>`:s.pctDb2>0?`${num(s.pctDb2,1)}% of DB time.`:''}`;

            else if (s.zone==='common') {

                const reason = s.isContentionVictim

                    ? `CPU was only <b style="color:#fbbf24">${s.cpuPct2}% of elapsed time</b> — SQL is a <b style="color:#c4b5fd">contention victim</b>. Root cause: <b style="color:#a78bfa">${esc(s.contentionRootCause||'external wait')}</b>. Investigate the blocking event, not the SQL.`

                    : s.planChg

                    ? `Execution plan changed <span style="color:#94a3b8;font-family:monospace;font-size:9px">${esc(s.plan1)} → ${esc(s.plan2)}</span> — likely index or stat change.`

                    : s.execsDelta > 80

                    ? `Called <b style="color:#fbbf24">${num(s.execsDelta,0)}% more often</b> — higher call frequency is driving the load increase.`

                    : `Slower per execution — same query, degraded performance.`;

                headline = `Ran in both periods. ${reason}`;

            }

            else

                headline = `Present in <b style="color:#34d399">${esc(lbl1)}</b> baseline but <b>no longer running</b> in the problem period. Performance improvement or dropped workload.`;



            // -- Metric row --

            let metrics = '';

            if (s.zone==='bad') {

                metrics = `<div class="flex gap-3 flex-wrap">

                    <span><span style="color:#6b7280;font-size:8px">ELAPSED/EXEC</span><br><span style="color:#f87171;font-weight:800">${num(s.epe,2)}s</span></span>

                    ${s.execs2>0?`<span><span style="color:#6b7280;font-size:8px">EXECUTIONS</span><br><span style="color:#e2e8f0;font-weight:700">${comma(s.execs2)}</span></span>`:''}

                    ${s.pctDb2>0?`<span><span style="color:#6b7280;font-size:8px">% DB TIME</span><br><span style="color:${s.pctDb2>10?'#fbbf24':'#e2e8f0'};font-weight:700">${num(s.pctDb2,1)}%</span></span>`:''}

                </div>`;

            } else if (s.zone==='common') {

                const _recCol = s.recommendationType==='INVESTIGATE_CONTENTION' ? '#818cf8'
                              : s.recommendationType==='SQL_TUNING_URGENT' ? '#ef4444' : '#94a3b8';
                const _recLabel = s.recommendationType==='INVESTIGATE_CONTENTION' ? 'INVESTIGATE CONTENTION'
                                : s.recommendationType==='SQL_TUNING_URGENT'      ? 'SQL TUNING URGENT'
                                : 'SQL TUNING';
                metrics = `<div class="flex gap-3 flex-wrap">

                    <span><span style="color:#6b7280;font-size:8px">${esc(lbl1)}/EXEC</span><br><span style="color:#34d399;font-weight:800">${num(s.epe1,2)}s</span></span>

                    <span style="color:#475569;font-size:10px;align-self:center">→</span>

                    <span><span style="color:#6b7280;font-size:8px">${esc(lbl2)}/EXEC</span><br><span style="color:#f87171;font-weight:800">${num(s.epe,2)}s</span></span>

                    ${s.execs2>0?`<span><span style="color:#6b7280;font-size:8px">EXECS (BAD)</span><br><span style="color:#e2e8f0;font-weight:700">${comma(s.execs2)}</span></span>`:''}

                    ${s.pctDb2>0?`<span><span style="color:#6b7280;font-size:8px">% DB TIME</span><br><span style="color:${s.pctDb2>10?'#fbbf24':'#e2e8f0'};font-weight:700">${num(s.pctDb2,1)}%</span></span>`:''}

                    <span style="align-self:flex-end;padding:1px 6px;background:${_recCol}18;border:1px solid ${_recCol}44;border-radius:3px;font-size:7px;font-weight:700;color:${_recCol}">${_recLabel}</span>

                </div>`;

            } else {

                metrics = `<div class="flex gap-3 flex-wrap">

                    <span><span style="color:#6b7280;font-size:8px">BASELINE/EXEC</span><br><span style="color:#34d399;font-weight:800">${num(s.epe,2)}s</span></span>

                    ${s.execs1>0?`<span><span style="color:#6b7280;font-size:8px">BASELINE EXECS</span><br><span style="color:#e2e8f0;font-weight:700">${comma(s.execs1)}</span></span>`:''}

                    ${s.pctDb>0?`<span><span style="color:#6b7280;font-size:8px">% DB TIME</span><br><span style="color:#e2e8f0;font-weight:700">${num(s.pctDb||0,1)}%</span></span>`:''}

                </div>`;

            }



            return `<div class="sql-top3-card" style="border-top:3px solid ${col}">

                <div class="flex items-center justify-between mb-2">

                    <span class="${crownCls[i]||''}" style="font-size:16px">${crownIcons[i]||'?'}</span>

                    <span style="font-size:8px;color:${col};font-weight:900;text-transform:uppercase;letter-spacing:0.5px;background:${col}18;padding:2px 7px;border-radius:4px">${badge}</span>

                </div>

                <div class="font-mono font-extrabold text-sm mb-1" style="color:${col};overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${esc(s.id)}">${esc(s.id)}</div>

                <div style="margin-bottom:6px;display:flex;align-items:center;gap:6px">
                    ${(()=>{ const _stc={INSERT:'#22c55e',UPDATE:'#f59e0b',DELETE:'#f87171',MERGE:'#c084fc',SELECT:'#60a5fa',PLSQL:'#818cf8',OTHER:'#64748b'}; const _t=s.sqlType||'OTHER'; return s.isPlatform
                        ? `<span style="font-size:9px;font-weight:800;color:#94a3b8;background:rgba(100,116,139,0.15);padding:2px 7px;border-radius:4px;border:1px solid rgba(100,116,139,0.3)">⚙ PLATFORM / INFRA</span>`
                        : `<span style="font-size:9px;font-weight:800;color:${_stc[_t]||'#64748b'};background:${_stc[_t]||'#64748b'}18;padding:2px 7px;border-radius:4px;border:1px solid ${_stc[_t]||'#64748b'}40">${_t}</span>`; })()}
                </div>

                <div class="text-[11px] text-gray-300 leading-snug mb-2">${headline}</div>

                ${culpritHighlight}
                ${corrBadge}
                <div class="border-t pt-2" style="border-color:#1e293b">${metrics}</div>

            </div>`;

        }).join('') : '<div class="text-[10px] text-gray-600 italic">No high-impact SQLs identified — both periods are fully aligned.</div>') + _goneStrip);

    }

}



// === RCA VERDICT ===

function renderSingleRCA(data) {
    // Clear container — add intelligence anchor FIRST, then PE layers below
    const _rcaRoot = document.getElementById('rca-content');
    if (_rcaRoot) _rcaRoot.innerHTML = '<div id="rca-intel-anchor" style="margin-bottom:16px"></div>';

    // ── Build + render RCA Intelligence Pipeline (threshold-based, no baseline) ────
    try {
        const ctx = window.AWRContext || {};
        if (typeof _renderRCAVerdictTabular === 'function' && typeof _buildSingleFallbackReport === 'function') {
            const report = _buildSingleFallbackReport(ctx);
            const intelEl = document.getElementById('rca-intel-anchor');
            if (intelEl) {
                var _rcaHtml = _renderRCAVerdictTabular(report, ctx);
                // Post-process: clean baseline/delta references for single-mode
                _rcaHtml = _rcaHtml.replace(/Baseline\s*\/s/g, '').replace(/>Baseline</g, '><');
                _rcaHtml = _rcaHtml.replace(/vs baseline/gi, '').replace(/baseline period/gi, 'this period');
                _rcaHtml = _rcaHtml.replace(/baseline window/gi, 'this window');
                intelEl.outerHTML = _rcaHtml;
                if (typeof _initRCAClickHandlers === 'function') _initRCAClickHandlers();
            }
        }
    } catch(e) { console.warn('_buildSingleFallbackReport / _renderRCAVerdictTabular failed', e); }

    // ── PE Analysis layers below ────
    try { renderSinglePELayers(data); } catch(e) { console.warn('renderSinglePELayers failed', e); }

    // ── Session Connection Analysis (appended after PE layers) ───────────────
    // Same analysis as compare mode but for single period (logon1=0 triggers absolute-value path)
    if (typeof analyzeSessionConnections === 'function') {
        setTimeout(() => {
            try {
                const ctx = window.AWRContext || {};
                const lp  = ctx.loadProfile?.bad || {};
                const ev  = (data.data?.wait_events || []);
                const tm  = ctx.timeModel?.bad || {};
                const connWait = ctx.connWaitPct?.bad || 0;
                const connMgmt = tm.connection_mgmt || 0;
                const sreConn  = analyzeSessionConnections(0, lp.logons || 0, 0, connWait, ev, [], 0, connMgmt);
                if (sreConn && (sreConn.rcaText || sreConn.lps > 0) && _rcaRoot) {
                    const riskCol = sreConn.lpsRisk === 'high' ? '#ef4444' : sreConn.lpsRisk === 'medium' ? '#f59e0b' : '#10b981';
                    _rcaRoot.innerHTML += `
                        <div class="card p-4 mb-4 fade-in" style="margin-top:16px">
                            <div style="font-size:12px;font-weight:700;color:#94a3b8;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:10px">
                                <span style="display:inline-block;width:3px;height:12px;background:#06b6d4;border-radius:2px;margin-right:8px;vertical-align:middle"></span>
                                Session &amp; Connection Analysis
                            </div>
                            <div style="font-size:12px;color:#e2e8f0;margin-bottom:6px;line-height:1.6">${esc(sreConn.rcaText||'No connection pressure detected.')}</div>
                            ${sreConn.recommendation ? `<div style="font-size:11px;color:#94a3b8;padding:8px 12px;background:rgba(6,182,212,0.07);border-radius:4px;border-left:3px solid #06b6d4">
                                <span style="font-weight:700;color:#22d3ee">Recommendation: </span>${esc(sreConn.recommendation)}
                            </div>` : ''}
                            ${sreConn.lps > 0 ? `<div style="margin-top:8px;font-size:10px;color:#64748b">Connection Pressure Score: <span style="font-weight:700;color:${riskCol}">${sreConn.lps}/200</span> — Risk: <span style="font-weight:700;color:${riskCol}">${(sreConn.lpsRisk||'low').toUpperCase()}</span></div>` : ''}
                        </div>`;
                }
            } catch(e) { console.warn('analyzeSessionConnections failed', e); }
        }, 150);
    }
}

function _renderSingleRCA_LEGACY_DISABLED(data) {
    const rca=data.rca||{}, v=rca.verdict||{}, db=rca.db_summary||{}, h=data.health||{}, score=h.score||0;

    const findings = rca.findings||[];

    const critCount = findings.filter(f=>f.severity==='critical').length;

    const warnCount = findings.filter(f=>f.severity==='warning').length;

    const d = data.data||{};

    // Events from ctx — same path as compare (ctx.waitEvents.bad)
    const events = (ctx.waitEvents?.bad || d.wait_events||[]).slice(0,10);



    // Build breakdown data

    const breakdownRows = [];

    if (v.primary_bottleneck) breakdownRows.push({ type: (v.primary_bottleneck||'').toUpperCase(), area: 'Database Engine', severity: v.severity||'warning', action: v.root_cause||'Investigate top wait events' });

    findings.filter(f=>f.severity==='critical').slice(0,3).forEach(f => {

        breakdownRows.push({ type: esc(f.category||'General'), area: esc(f.title), severity: 'critical', action: esc(f.detail||'Review finding details') });

    });

    findings.filter(f=>f.severity==='warning').slice(0,2).forEach(f => {

        breakdownRows.push({ type: esc(f.category||'General'), area: esc(f.title), severity: 'warning', action: esc(f.detail||'Monitor and assess') });

    });



    document.getElementById('rca-content').innerHTML = `

        <!-- Verdict Hero -->

        <div class="verdict-hero mb-5 fade-in">

            <div class="flex items-start gap-6 relative z-10">

                ${renderBigScoreArc(score, 150)}

                <div class="flex-1">

                    <div class="flex items-center gap-3 mb-2">

                        <span class="text-xs text-Cindigo uppercase tracking-widest font-bold">Root Cause Analysis Verdict</span>

                        ${sevBadge(v.severity)}

                    </div>

                    <div class="text-2xl font-extrabold text-white mb-3">${esc(v.primary_finding)}</div>

                    <div class="text-base text-gray-300 leading-relaxed mb-4">${esc(v.root_cause)}</div>

                    <div class="flex items-center gap-8">

                        <div>

                            <div class="text-[9px] text-Cmuted uppercase">Primary Bottleneck</div>

                            <div class="text-xl font-black text-Ccyan">${(v.primary_bottleneck||'').toUpperCase()}</div>

                        </div>

                        <div>

                            <div class="text-[9px] text-Cmuted uppercase">Confidence</div>

                            <div class="text-xl font-black" style="color:${hColor(v.confidence_score||0)}">${v.confidence_score||0}%</div>

                            <div class="w-36 bg-Ccard rounded-full overflow-hidden h-2.5 mt-1"><div class="confidence-bar h-full" style="width:${v.confidence_score||0}%;background:${hColor(v.confidence_score||0)}"></div></div>

                        </div>

                        <div>

                            <div class="text-[9px] text-Cmuted uppercase">Critical / Warning</div>

                            <div class="flex gap-2 mt-1">

                                <span class="text-xl font-black sev-critical">${critCount}</span>

                                <span class="text-gray-600">/</span>

                                <span class="text-xl font-black sev-warning">${warnCount}</span>

                            </div>

                        </div>

                    </div>

                </div>

            </div>

        </div>



        <!-- Detailed AI Verdict Narrative -->

        ${aiNarrative('Verdict Analysis', generateVerdictNarrative(v, db, rca, events))}



        <!-- Verdict Breakdown Table -->

        <div class="card p-5 mb-4 fade-in fade-in-d1">

            <div class="text-sm font-bold text-gray-300 mb-3 uppercase tracking-wide">Bottleneck Breakdown</div>

            <table class="breakdown-table">

                <thead><tr><th>Bottleneck Type</th><th>Impact Area</th><th>Severity</th><th>What to Do</th></tr></thead>

                <tbody>

                ${breakdownRows.map(r => `<tr>

                    <td class="text-white font-bold">${r.type}</td>

                    <td class="text-gray-300">${r.area}</td>

                    <td>${sevBadge(r.severity)}</td>

                    <td class="text-Ccyan text-sm">${r.action}</td>

                </tr>`).join('')}

                </tbody>

            </table>

        </div>



        <!-- Time Breakdown Pie Chart -->

        <div class="grid grid-cols-1 md:grid-cols-2 gap-4 fade-in fade-in-d2">

            <div class="card p-4">

                <div class="text-sm font-bold text-gray-300 mb-3 uppercase">DB Time Breakdown</div>

                <div style="height:250px"><canvas id="rca-time-pie"></canvas></div>

            </div>

            <div class="card p-4">

                <h4 class="text-sm font-bold text-gray-300 mb-3 uppercase">Top Findings</h4>

                ${findings.slice(0,5).map(f=>`<div class="flex items-start gap-2 mb-2 p-2 rounded bg-sev-${f.severity}">${sevIcon(f.severity)}<div><div class="text-xs font-medium text-white">${esc(f.title)}</div><div class="text-[10px] text-Cmuted">${esc(f.category)} | ${esc(f.evidence_from)}</div></div></div>`).join('')}

            </div>

        </div>

    `;



    // Render time breakdown pie

    setTimeout(() => {

        destroyChart('rca-time-pie');

        const ctx = document.getElementById('rca-time-pie');

        if (ctx && events.length) {

            const colors = ['#ef4444','#f97316','#f59e0b','#eab308','#84cc16','#22c55e','#14b8a6','#06b6d4','#3b82f6','#8b5cf6'];

            storeChart('rca-time-pie', new Chart(ctx, {

                type: 'pie',

                data: { labels: events.map(e=>e.event_name), datasets: [{ data: events.map(e=>e.pct_db_time||0), backgroundColor: colors.slice(0, events.length), borderWidth: 0 }] },

                options: { responsive: true, maintainAspectRatio: false, plugins: { legend: { position:'right', labels:{ color:'#94a3b8', font:{size:9}, boxWidth:10, padding:5 } } } }

            }));

        }
    }, 100);

    // === CATALOG-DRIVEN DIAGNOSTIC SECTION ===
    // Look up top wait events in WAIT_EVENT_CATALOG and render mechanism + fix queries
    const catalogSections = events.slice(0, 5).map(evt => {
        const cat = WAIT_EVENT_CATALOG[evt.event_name];
        if (!cat) return '';
        const pct = num(evt.pct_db_time||0, 1);
        const avgMs = evt.avg_wait_ms ? num(evt.avg_wait_ms, 2)+'ms avg' : '';
        return `<div class="card p-4 mb-3 fade-in" style="border-left:3px solid #38bdf8">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
                <span style="background:#0c2340;color:#38bdf8;font-size:10px;font-weight:800;padding:3px 10px;border-radius:4px;text-transform:uppercase">${esc(cat.waitClass||'Unknown')}</span>
                <span style="color:#e2e8f0;font-size:13px;font-weight:700">${esc(evt.event_name)}</span>
                <span style="color:#f87171;font-size:12px;font-weight:800;margin-left:auto">${pct}% DB Time${avgMs?' · '+avgMs:''}</span>
            </div>
            <div style="color:#94a3b8;font-size:12px;margin-bottom:8px"><span style="color:#64748b;font-size:10px;text-transform:uppercase;font-weight:700;letter-spacing:0.5px">Mechanism: </span>${esc(cat.mechanism)}</div>
            ${cat.specialRule ? `<div style="background:rgba(251,191,36,0.08);border:1px solid rgba(251,191,36,0.2);border-radius:6px;padding:8px 12px;color:#fbbf24;font-size:11px;margin-bottom:8px">? ${esc(cat.specialRule)}</div>` : ''}
            ${cat.fixQuery ? `
            <div style="margin-top:8px">
                <div style="color:#64748b;font-size:10px;text-transform:uppercase;font-weight:700;letter-spacing:0.5px;margin-bottom:4px">Diagnostic Query</div>
                <div style="position:relative">
                    <pre style="font-family:monospace;font-size:11px;color:#cbd5e1;background:#0f172a;padding:10px 12px;border-radius:6px;border:1px solid #1e293b;white-space:pre-wrap;line-height:1.6;overflow-x:auto" id="catq-${esc(evt.event_name).replace(/[^a-z0-9]/gi,'_')}">${esc(cat.fixQuery)}</pre>
                    <button onclick="navigator.clipboard.writeText(document.getElementById('catq-${esc(evt.event_name).replace(/[^a-z0-9]/gi,'_')}').innerText);this.textContent='Copied!';setTimeout(()=>this.textContent='Copy',1500)" style="position:absolute;top:6px;right:6px;background:#1e293b;color:#94a3b8;border:1px solid #334155;padding:2px 8px;border-radius:4px;font-size:10px;cursor:pointer">Copy</button>
                </div>
                ${cat.fixExpect ? `<div style="color:#4ade80;font-size:11px;margin-top:4px">Expect: ${esc(cat.fixExpect)}</div>` : ''}
                ${cat.fixAction ? `<div style="color:#38bdf8;font-size:11px;margin-top:2px">Action: ${esc(cat.fixAction)}</div>` : ''}
            </div>` : ''}
        </div>`;
    }).filter(Boolean).join('');

    if (catalogSections) {
        document.getElementById('rca-content').innerHTML += `
            <div class="mt-5 fade-in">
                <div style="font-size:13px;font-weight:800;color:#e2e8f0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px;display:flex;align-items:center;gap:8px">
                    <span style="display:inline-block;width:3px;height:14px;background:#38bdf8;border-radius:2px"></span>
                    Wait Event Diagnostics — Catalog-Driven Analysis
                </div>
                ${catalogSections}
            </div>`;
    }

    // === ADDM FINDINGS ===
    const addmFindings = (data.data||{}).addm_findings || [];
    if (addmFindings.length) {
        const addmHtml = addmFindings.slice(0, 8).map(f => `
            <div style="display:flex;align-items:flex-start;gap:10px;padding:10px 14px;background:rgba(15,23,42,0.6);border-radius:6px;border-left:3px solid ${f.impact > 20 ? '#ef4444' : f.impact > 5 ? '#f59e0b' : '#38bdf8'};margin-bottom:6px">
                <span style="font-size:12px;font-weight:800;color:${f.impact > 20 ? '#f87171' : f.impact > 5 ? '#fbbf24' : '#38bdf8'};min-width:50px">${num(f.impact||0,1)}%</span>
                <div>
                    <div style="color:#e2e8f0;font-size:12px;font-weight:700">${esc(f.type||f.finding||'Finding')}</div>
                    ${f.recommendation ? `<div style="color:#94a3b8;font-size:11px;margin-top:2px">${esc(f.recommendation)}</div>` : ''}
                </div>
            </div>`).join('');
        document.getElementById('rca-content').innerHTML += `
            <div class="mt-5 fade-in">
                <div style="font-size:13px;font-weight:800;color:#e2e8f0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px;display:flex;align-items:center;gap:8px">
                    <span style="display:inline-block;width:3px;height:14px;background:#f59e0b;border-radius:2px"></span>
                    ADDM Findings (${addmFindings.length} total)
                </div>
                ${addmHtml}
            </div>`;
    }

    // === INSIGHTS & RECOMMENDATIONS from backend ===
    const insights = (data.data||{}).insights || data.insights || [];
    const backendRecs = data.recommendations || [];
    if (insights.length || backendRecs.length) {
        const insightHtml = insights.slice(0,6).map(ins => `
            <div style="padding:8px 14px;background:rgba(56,189,248,0.06);border:1px solid rgba(56,189,248,0.15);border-radius:6px;margin-bottom:6px">
                <div style="color:#7dd3fc;font-size:12px">${esc(ins.message||ins.detail||ins)}</div>
            </div>`).join('');
        const recHtml = backendRecs.slice(0,6).map(rec => `
            <div style="padding:8px 14px;background:rgba(74,222,128,0.04);border:1px solid rgba(74,222,128,0.15);border-radius:6px;margin-bottom:6px;display:flex;gap:8px">
                <span style="color:#4ade80;font-size:12px;flex-shrink:0">✓</span>
                <div style="color:#a3e635;font-size:12px">${esc(rec.action||rec.message||rec)}</div>
            </div>`).join('');
        if (insightHtml || recHtml) {
            document.getElementById('rca-content').innerHTML += `
                <div class="mt-5 fade-in">
                    <div style="font-size:13px;font-weight:800;color:#e2e8f0;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:12px;display:flex;align-items:center;gap:8px">
                        <span style="display:inline-block;width:3px;height:14px;background:#4ade80;border-radius:2px"></span>
                        Engine Insights & Recommendations
                    </div>
                    ${insightHtml}${recHtml}
                </div>`;
        }
    }

    // (legacy disabled — renderSingleRCA body above handles this)
} // end _renderSingleRCA_LEGACY_DISABLED




// ============================================================================
// SINGLE AWR — PE ANALYSIS LAYERS
// Mirrors comparison-mode PE panels: Confidence Scorecard, Wait Causality,
// Dominant SQL Card, PE Narrative, KB Reference, Action Priority Queue.
// ============================================================================
function renderSinglePELayers(data) {
    const rca = data.rca || {};
    const v   = rca.verdict || {};
    const db  = rca.db_summary || {};
    const d   = data.data || {};
    const h   = data.health || {};

    const events  = d.wait_events || [];
    const sqls    = (d.sql_stats || []).slice(0, 15);
    const eff     = d.efficiency || {};
    const addm    = d.addm_findings || [];
    const aas     = db.aas || 0;
    const cpus    = db.cpus || 1;
    const score   = h.score || 0;
    const _snapB  = db.snap_id_begin  || db.snap_begin_id  || db.begin_snap || '<begin_snap>';
    const _snapE  = db.snap_id_end    || db.snap_end_id    || db.end_snap   || '<end_snap>';

    const f1s = v => (+v||0).toFixed(1);
    const n0  = v => Math.round(+v||0).toLocaleString();

    // --- pct helpers ---
    const sumPct = rx => events.filter(e => rx.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const _hwEnqPct   = sumPct(/enq:\s*HW\s*-\s*contention/i);
    const _txIdxPct   = sumPct(/enq:\s*TX\s*-\s*index contention/i);
    const _txRowPct   = sumPct(/enq:\s*TX\s*-\s*row lock/i);
    const _usEnqPct   = sumPct(/enq:\s*US\s*-\s*contention/i);
    const _freeBufPct = sumPct(/free buffer waits/i);
    const _bufBusyPct = sumPct(/buffer busy waits/i);
    const _fbEnqPct   = sumPct(/enq:\s*FB\s*-\s*contention/i);
    const _latchPct   = events.filter(e=>/latch|buffer busy|cursor.*pin|enq/i.test(e.event_name||'')).reduce((s,e)=>s+(e.pct_db_time||0),0);
    const dbCpuPct    = sumPct(/DB CPU/i);
    const ioPct       = sumPct(/db file|direct path|physical/i);
    const commitPct   = sumPct(/log file sync/i);

    const domSql    = sqls.length ? sqls[0] : null;
    const domSqlPct = domSql ? (domSql.pct_db_time || 0) : 0;
    const domSqlVerb = domSql ? ((domSql.sql_text||'').trim().match(/^\s*(INSERT|UPDATE|DELETE|MERGE|SELECT)/i)||['',''])[1].toUpperCase() : '';
    const domIsDML  = /^(INSERT|UPDATE|DELETE|MERGE)$/.test(domSqlVerb);

    // --- derive cause category ---
    let cat;
    if      (_hwEnqPct >= 10)                                      cat = 'HW_ENQUEUE_CONTENTION';
    else if (_txIdxPct >= 5)                                       cat = 'TX_INDEX_CONTENTION';
    else if (_txRowPct >= 8)                                       cat = 'TX_ROW_LOCK_CONTENTION';
    else if (_usEnqPct >= 8)                                       cat = 'UNDO_SEGMENT_EXTENSION';
    else if (_freeBufPct >= 12 && domSqlPct >= 20 && domIsDML)    cat = 'CONCURRENT_DML_BOTTLENECK';
    else if (_freeBufPct >= 10 || (_freeBufPct >= 6 && _bufBusyPct >= 4)) cat = 'BUFFER_WRITE_PRESSURE';
    else if (domSqlPct >= 25)                                      cat = 'SQL_DOMINANT';
    else if (dbCpuPct >= 40)                                       cat = 'CPU_SATURATION';
    else if (ioPct >= 25)                                          cat = 'IO_PRESSURE';
    else if (commitPct >= 10)                                      cat = 'REDO_COMMIT';
    else if (_latchPct >= 5)                                       cat = 'CONCURRENCY';
    else if (domSqlPct >= 15)                                      cat = 'SQL_DOMINANT';
    else                                                           cat = 'UNKNOWN';
    if (_latchPct < 5 && cat === 'CONCURRENCY') cat = dbCpuPct >= ioPct ? 'CPU_SATURATION' : 'IO_PRESSURE';

    const catLabels = {
        HW_ENQUEUE_CONTENTION:'Segment HWM Enqueue Contention', TX_INDEX_CONTENTION:'Hot Index Block Contention',
        TX_ROW_LOCK_CONTENTION:'Application Row-Lock Contention', UNDO_SEGMENT_EXTENSION:'Undo Segment Extension',
        CONCURRENT_DML_BOTTLENECK:'Concurrent DML / Buffer-Write Pressure', BUFFER_WRITE_PRESSURE:'DBWR Buffer-Write Pressure',
        SQL_DOMINANT:'Dominant SQL Workload', CPU_SATURATION:'CPU Saturation', IO_PRESSURE:'Physical I/O Pressure',
        REDO_COMMIT:'Commit / Redo Log Bottleneck', CONCURRENCY:'Concurrency Contention', UNKNOWN:'Mixed / Unclassified'
    };
    const catLabel = catLabels[cat] || cat;
    const _kbNar = (typeof KB_DETERMINISTIC !== 'undefined') ? (KB_DETERMINISTIC[cat] || null) : null;

    // --- severity & session risk ---
    const pTier  = score >= 80 ? 'HEALTHY' : score >= 60 ? 'DEGRADED' : score >= 40 ? 'WARNING' : 'CRITICAL';
    const pColor = score >= 80 ? '#10b981' : score >= 60 ? '#f59e0b' : '#ef4444';
    const aasRatio = cpus > 0 ? aas / cpus : 0;
    let sessionRisk = { label:'STABLE', color:'#10b981', detail:`AAS ${f1s(aas)} of ${cpus} CPUs` };
    if      (aasRatio >= 1.5) sessionRisk = { label:'SATURATED',       color:'#ef4444', detail:`AAS ${f1s(aas)} exceeds CPU count (${cpus})` };
    else if (aasRatio >= 1.0) sessionRisk = { label:'AT CAPACITY',     color:'#ef4444', detail:`AAS ${f1s(aas)} = CPU count (${cpus})` };
    else if (aasRatio >= 0.85)sessionRisk = { label:'<30 min HEADROOM',color:'#f59e0b', detail:`AAS ${f1s(aas)} of ${cpus} — ${Math.round((1-aasRatio)*100)}% headroom` };
    else if (aasRatio >= 0.7) sessionRisk = { label:'MONITORING',      color:'#f59e0b', detail:`AAS ${f1s(aas)} of ${cpus} CPUs — watch trend` };
    const confScore = v.confidence_score || 50;
    const confColor = confScore >= 80 ? '#10b981' : confScore >= 60 ? '#f59e0b' : '#ef4444';
    const confLabel = confScore >= 80 ? 'HIGH' : confScore >= 60 ? 'MEDIUM' : 'LOW';

    // ── 1. SCORECARD ──────────────────────────────────────────────────────────
    const tile = (lbl,val,sub,col) => `<div style="flex:1;min-width:150px;padding:10px 14px;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.18);border-left:3px solid ${col};border-radius:6px"><div style="font-size:9px;color:#94a3b8;font-weight:700;text-transform:uppercase;letter-spacing:0.6px">${lbl}</div><div style="font-size:17px;font-weight:900;color:${col};margin-top:3px;line-height:1.1">${val}</div><div style="font-size:9.5px;color:#64748b;margin-top:2px;line-height:1.4">${sub}</div></div>`;
    const scorecardHtml = `<div style="margin-bottom:14px;padding:12px;background:linear-gradient(135deg,rgba(8,12,28,0.95),rgba(15,23,42,0.85));border:1px solid rgba(99,102,241,0.25);border-radius:10px">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
            <div style="width:8px;height:8px;border-radius:50%;background:${pColor};box-shadow:0 0 8px ${pColor}"></div>
            <span style="font-size:10.5px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.7px">RCA Confidence Scorecard</span>
            <span style="font-size:9px;color:#64748b;margin-left:auto">${esc(db.db_name||'')} · Snap ${esc(String(_snapB))}–${esc(String(_snapE))}</span>
        </div>
        <div style="display:flex;gap:10px;flex-wrap:wrap">
            ${tile('Severity',      pTier,                `Health score ${score}`,                     pColor)}
            ${tile('Confidence',    confScore+'%',         confLabel+' · '+(v.primary_bottleneck||'?').toUpperCase()+' bottleneck', confColor)}
            ${tile('Session Risk',  sessionRisk.label,     sessionRisk.detail,                          sessionRisk.color)}
            ${tile('DB Time',       f1s((db.db_time_secs||0)/60)+' min', `${f1s(aas)} AAS · ${cpus} CPUs`, '#6366f1')}
        </div>
    </div>`;

    // ── 2. WAIT CAUSALITY STRIP ───────────────────────────────────────────────
    const _ws  = [...events].sort((a,b)=>(b.pct_db_time||0)-(a.pct_db_time||0));
    const _w0  = _ws[0]||null, _w1=_ws[1]||null, _w2=_ws[2]||null;
    const _wRow = (w, roleLbl, roleCol, label2) => !w ? '' : `<div style="display:grid;grid-template-columns:72px 1fr auto;gap:10px;align-items:center;padding:8px 12px;background:${roleCol}08;border:1px solid ${roleCol}30;border-left:4px solid ${roleCol};border-radius:0 6px 6px 0">
        <div><div style="font-size:12px;font-weight:900;color:${roleCol}">${f1s(w.pct_db_time||0)}%</div><div style="font-size:6px;color:${roleCol};font-weight:700;text-transform:uppercase">${roleLbl}</div></div>
        <div><div style="font-size:10px;color:#e2e8f0;font-weight:600">${esc(w.event_name||'')}${label2?` <span style="font-size:7.5px;color:${roleCol}">${label2}</span>`:''}</div><div style="font-size:8px;color:#94a3b8;margin-top:2px">${(typeof waitDiag==='function')?waitDiag(w.event_name||''):''}</div></div>
        <div style="font-size:9px;color:#64748b;font-family:monospace;white-space:nowrap">${f1s(w.avg_wait_ms||0)}ms avg</div>
    </div>`;
    const waitCausalityHtml = (_w0||_w1) ? `<div style="margin-bottom:14px">
        <div style="font-size:9px;color:#f59e0b;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">Wait Causality</div>
        <div style="display:flex;flex-direction:column;gap:4px">
            ${_wRow(_w0,'ROOT CAUSE','#ef4444','')}
            ${_wRow(_w1,'#2 WAIT','#f59e0b','')}
            ${_wRow(_w2,'MONITOR','#6366f1','')}
        </div>
    </div>` : '';

    // ── 3. DOMINANT SQL CARD ──────────────────────────────────────────────────
    const domSqlCardHtml = domSql ? (() => {
        const s = domSql;
        const epe = s.elapsed_per_exec!=null ? s.elapsed_per_exec : (s.elapsed_time_secs&&s.executions ? s.elapsed_time_secs/s.executions : 0);
        const gets = s.buffer_gets_per_exec || s.buffer_gets || 0;
        const badgeCol = domSqlPct >= 25 ? '#ef4444' : '#f59e0b';
        const majors = sqls.filter(sq=>(sq.pct_db_time||0)>=5 && sq.sql_id !== s.sql_id).slice(0,4);
        const minors = sqls.filter(sq=>(sq.pct_db_time||0)<5  && sq.sql_id !== s.sql_id).slice(0,5);
        return `<div style="margin-bottom:14px"><div style="font-size:9px;color:#818cf8;font-weight:800;text-transform:uppercase;letter-spacing:0.6px;margin-bottom:6px">Dominant SQL</div>
        <div style="padding:12px 16px;background:linear-gradient(135deg,rgba(168,85,247,0.06),rgba(99,102,241,0.03));border:1px solid ${badgeCol}35;border-left:4px solid ${badgeCol};border-radius:6px">
            <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
                <div style="display:flex;align-items:center;gap:8px">
                    <span style="font-family:monospace;font-size:13px;color:#a5b4fc;font-weight:900">${esc(s.sql_id||'–')}</span>
                    ${domSqlPct>=25?'<span style="background:rgba(239,68,68,0.15);color:#ef4444;font-size:7px;padding:1px 5px;border-radius:3px;font-weight:800">DOMINANT</span>':''}
                    ${s.module?`<span style="font-size:9px;color:#64748b">${esc(s.module)}</span>`:''}
                </div>
                <div style="font-size:20px;font-weight:900;color:${badgeCol}">${f1s(domSqlPct)}%<span style="font-size:9px;color:#475569;margin-left:3px">DB Time</span></div>
            </div>
            <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:8px">
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${f1s(epe)}s</div><div style="font-size:7px;color:#475569">Elapsed/Exec</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${n0(gets)}</div><div style="font-size:7px;color:#475569">Gets/Exec</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${n0(s.executions||0)}</div><div style="font-size:7px;color:#475569">Executions</div></div>
                <div style="text-align:center"><div style="font-size:13px;font-weight:800;color:#e2e8f0">${n0(s.disk_reads_per_exec||0)}</div><div style="font-size:7px;color:#475569">Disk/Exec</div></div>
            </div>
            ${majors.length?`<div style="margin-top:6px;padding-top:6px;border-top:1px solid rgba(255,255,255,0.05)"><div style="font-size:7px;color:#475569;font-weight:700;margin-bottom:4px">OTHER SQL &gt;5% DB TIME</div>${majors.map(sq=>`<div style="display:flex;align-items:center;gap:8px;font-size:8px;padding:2px 0"><span style="font-family:monospace;color:#a5b4fc;width:90px">${esc(sq.sql_id||'–')}</span><span style="color:#f59e0b;font-weight:700">${f1s(sq.pct_db_time||0)}%</span><span style="color:#64748b">${f1s(sq.elapsed_per_exec||0)}s/exec · ${n0(sq.executions||0)} execs${sq.module?' · '+esc(sq.module):''}</span></div>`).join('')}</div>`:''}
            ${minors.length?`<details style="margin-top:6px"><summary style="font-size:8px;color:#475569;cursor:pointer;user-select:none">Minor SQL &lt;5% DB Time — ${minors.length} statements</summary><div style="margin-top:4px">${minors.map(sq=>`<div style="display:flex;align-items:center;gap:8px;font-size:8px;padding:1px 4px;opacity:0.6"><span style="font-family:monospace;color:#64748b;width:90px">${esc(sq.sql_id||'–')}</span><span style="color:#64748b">${f1s(sq.pct_db_time||0)}%</span><span style="color:#475569">${f1s(sq.elapsed_per_exec||0)}s/exec</span></div>`).join('')}</div></details>`:''}
        </div></div>`;
    })() : '';

    // ── 4. PE NARRATIVE ───────────────────────────────────────────────────────
    const topWaitName = _w0 ? _w0.event_name : '';
    const topWaitPct  = _w0 ? (_w0.pct_db_time||0) : 0;
    const catWaitEv   = (typeof WAIT_EVENT_CATALOG!=='undefined') ? (WAIT_EVENT_CATALOG[topWaitName]||null) : null;

    let part1 = topWaitName ? `<b>${esc(topWaitName)}</b> is the top wait event, consuming <b>${f1s(topWaitPct)}%</b> of DB Time. ` : '';
    if (domSql && domSqlPct >= 10) {
        const epe = domSql.elapsed_per_exec!=null ? domSql.elapsed_per_exec : 0;
        part1 += `SQL <b style="font-family:monospace;color:#a5b4fc">${esc(domSql.sql_id)}</b> accounts for <b>${f1s(domSqlPct)}%</b> of DB Time (${f1s(epe)}s/exec, ${n0(domSql.executions||0)} executions). `;
    }
    part1 += `AAS is <b>${f1s(aas)}</b> against <b>${cpus}</b> CPUs${aasRatio>=1?' — <b style="color:#ef4444">instance is at or above capacity</b>':aasRatio>=0.8?' — headroom is narrow':''}.`;

    let part2 = '';
    if (_kbNar && _kbNar.mechanism) part2 = _kbNar.mechanism;
    else if (catWaitEv && catWaitEv.mechanism) part2 = catWaitEv.mechanism;
    else part2 = ({
        CPU_SATURATION: `DB CPU consumes ${f1s(dbCpuPct)}% of DB Time. The workload demands more compute than available CPU capacity. Sessions queue for CPU time slices — the processor is the primary resource constraint.`,
        IO_PRESSURE: `Physical I/O consumes ${f1s(ioPct)}% of DB Time. Sessions wait on storage reads — caused by buffer cache misses or SQL with no effective index forcing full segment scans.`,
        REDO_COMMIT: `log file sync consumes ${f1s(commitPct)}% of DB Time. Every COMMIT forces LGWR to flush redo to disk synchronously before the session continues. High commit frequency saturates LGWR I/O capacity.`,
        SQL_DOMINANT: `A single SQL statement accounts for ${f1s(domSqlPct)}% of all DB Time. Tuning this one statement will have a proportional impact on overall database throughput.`,
        CONCURRENCY: `Latch and lock waits indicate serialisation on shared Oracle in-memory structures. Sessions block each other on hot data blocks or library cache structures.`,
        HW_ENQUEUE_CONTENTION: `enq: HW - contention fires when sessions queue to format blocks above the segment high-water mark. Each INSERT must wait for the single session extending the HWM to complete before it can proceed.`,
        TX_INDEX_CONTENTION: `enq: TX - index contention fires when concurrent DML sessions modify the same index leaf block. Sequence-based right-growing keys concentrate all new inserts into the same rightmost leaf block.`,
        TX_ROW_LOCK_CONTENTION: `enq: TX - row lock contention fires when one session holds a row lock while another waits. The blocker is holding an uncommitted transaction for an extended period.`,
        UNDO_SEGMENT_EXTENSION: `enq: US - contention fires when the UNDO tablespace cannot allocate or extend fast enough for the concurrent DML rate.`,
        BUFFER_WRITE_PRESSURE: `Free buffer waits fire when sessions cannot find a free buffer in the database buffer cache because DBWR cannot flush dirty buffers to disk fast enough.`,
    }[cat] || `The ${catLabel} bottleneck is consuming a significant share of DB Time. Oracle internal wait structures show session serialisation at the identified resource.`);

    let part3 = aasRatio >= 1
        ? `With AAS (${f1s(aas)}) at or above CPU count (${cpus}), the instance is saturated. Any additional workload will queue immediately, causing cascading latency. Immediate intervention required.`
        : aasRatio >= 0.8
        ? `AAS (${f1s(aas)}) is approaching CPU capacity (${cpus}). Headroom is narrow — a moderate workload spike will saturate the instance.`
        : `Current load has ${Math.round((1-aasRatio)*100)}% CPU headroom. However, the identified bottleneck (${catLabel}) will worsen proportionally with any increase in workload volume.`;
    if (_kbNar && _kbNar.threshold) part3 += ` Oracle 19c threshold: ${_kbNar.threshold}.`;

    const _sHdr = (lbl,col,sub) => `<div style="display:flex;align-items:baseline;gap:10px;margin-bottom:7px;padding-bottom:5px;border-bottom:1px solid ${col}20"><span style="font-size:12px;font-weight:900;color:${col};text-transform:uppercase;letter-spacing:1.4px">${lbl}</span>${sub?`<span style="font-size:9px;color:${col}80;font-weight:600">${sub}</span>`:''}</div>`;
    const _kbBadge = (lbl,txt,col) => txt ? `<span style="display:inline-block;margin:4px 0;padding:4px 10px;background:rgba(15,23,42,0.7);border:1px solid ${col}30;border-left:3px solid ${col};border-radius:4px;font-size:9px;color:${col}cc;line-height:1.5"><b style="color:${col}">${lbl}: </b>${esc(txt)}</span>` : '';
    const kbCite = _kbNar && _kbNar.oracleRef ? `<span style="font-size:8px;color:#334155;font-style:italic"> [${esc(_kbNar.oracleRef)}]</span>` : '';

    const peNarrativeHtml = `<div style="font-size:13px;color:#cbd5e1;padding:16px 18px;background:linear-gradient(135deg,rgba(8,12,28,0.95),rgba(15,23,42,0.85));border:1px solid rgba(99,102,241,0.2);border-radius:10px;margin-bottom:14px">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:14px;padding-bottom:8px;border-bottom:1px solid rgba(99,102,241,0.12)">
            <span style="font-size:11px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.8px">OraVision PE Narrative</span>
            <span style="font-size:9px;color:#334155;margin-left:auto">${esc(catLabel)} · Oracle 19c PTG</span>
        </div>
        <div style="margin-bottom:16px;padding-left:12px;border-left:3px solid #38bdf8">
            ${_sHdr('What Happened','#38bdf8','observed symptom · primary signal')}
            <p style="margin:0;line-height:1.85;font-size:13px;color:#cbd5e1">${part1}</p>
        </div>
        <div style="margin-bottom:16px;padding-left:12px;border-left:3px solid #a5b4fc">
            ${_sHdr('Why It Happened','#a5b4fc','root cause mechanism · oracle internal')}
            <p style="margin:0 0 6px;line-height:1.85;font-size:13px;color:#cbd5e1">${esc(part2)}${kbCite}</p>
            ${_kbBadge('Oracle 19c threshold',_kbNar&&_kbNar.threshold,'#6366f1')}
            ${_kbBadge('Avoid',_kbNar&&_kbNar.antiPattern,'#ef4444')}
            ${_kbBadge('Stats check',_kbNar&&_kbNar.statisticsNote,'#4f46e5')}
        </div>
        <div style="margin-bottom:4px;padding-left:12px;border-left:3px solid #f59e0b">
            ${_sHdr('Risk \u0026 Escalation','#f59e0b','severity · if left unresolved')}
            <p style="margin:0;line-height:1.85;font-size:13px;color:#cbd5e1">${esc(part3)}</p>
        </div>
    </div>`;

    // ── 5. KB REFERENCE ───────────────────────────────────────────────────────
    const kbRefHtml = _kbNar ? `<details open style="margin-bottom:14px">
        <summary style="cursor:pointer;padding:10px 16px;background:rgba(16,185,129,0.06);border:1px solid rgba(16,185,129,0.2);border-radius:8px;font-size:10.5px;font-weight:800;color:#34d399;text-transform:uppercase;letter-spacing:0.6px;list-style:none">PE Knowledge Reference — ${esc(catLabel)} · ${esc((_kbNar.oracleRef||''))}</summary>
        <div style="padding:12px 16px;background:rgba(2,6,23,0.7);border:1px solid rgba(16,185,129,0.12);border-top:none;border-radius:0 0 8px 8px">
            ${_kbNar.threshold?`<div style="display:grid;grid-template-columns:110px 1fr;gap:8px;padding:6px 0;border-bottom:1px solid rgba(16,185,129,0.08)"><span style="font-size:9px;color:#64748b;font-weight:700;text-transform:uppercase">Threshold</span><span style="font-size:11px;color:#a5b4fc">${esc(_kbNar.threshold)}</span></div>`:''}
            ${_kbNar.antiPattern?`<div style="display:grid;grid-template-columns:110px 1fr;gap:8px;padding:6px 0;border-bottom:1px solid rgba(16,185,129,0.08)"><span style="font-size:9px;color:#64748b;font-weight:700;text-transform:uppercase">Avoid</span><span style="font-size:11px;color:#fca5a5">${esc(_kbNar.antiPattern)}</span></div>`:''}
            ${_kbNar.statisticsNote?`<div style="display:grid;grid-template-columns:110px 1fr;gap:8px;padding:6px 0"><span style="font-size:9px;color:#64748b;font-weight:700;text-transform:uppercase">Stats Check</span><span style="font-size:11px;color:#a5b4fc">${esc(_kbNar.statisticsNote)}</span></div>`:''}
        </div>
    </details>` : '';

    // ── 6. ACTION PRIORITY QUEUE ──────────────────────────────────────────────
    const _sB = String(_snapB), _sE = String(_snapE);
    let _acts = [];
    if (cat === 'HW_ENQUEUE_CONTENTION') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify segment causing HWM extension via ASH',
            sql:`SELECT s.current_obj# obj#, o.owner, o.object_name, o.object_type,\n       COUNT(*) waited_secs\nFROM   v$active_session_history s\nJOIN   dba_objects o ON o.object_id = s.current_obj#\nWHERE  s.event = 'enq: HW - contention'\nAND    s.sample_time >= SYSDATE - INTERVAL '1' HOUR\nGROUP  BY s.current_obj#, o.owner, o.object_name, o.object_type\nORDER  BY waited_secs DESC FETCH FIRST 5 ROWS ONLY;`,
            expect:'Returns owner/segment_name with most waited_secs — that segment IS the fix target.'});
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Pre-allocate extents to move HWM ahead of workload',
            sql:`ALTER TABLE <OWNER>.<TABLE_NAME> ALLOCATE EXTENT (SIZE 128M);\n-- Confirm:\nSELECT segment_name, extents, bytes/1024/1024 mb FROM dba_segments\nWHERE  segment_name = '<TABLE_NAME>';`,
            expect:'enq: HW waits drop to near-zero within one AWR interval after execution.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Check tablespace extent allocation strategy',
            sql:`SELECT tablespace_name, allocation_type, initial_extent/1024 init_kb, next_extent/1024 next_kb\nFROM   dba_tablespaces\nWHERE  tablespace_name = (SELECT tablespace_name FROM dba_segments WHERE segment_name='<TABLE_NAME>' AND rownum=1);`,
            expect:'allocation_type=SYSTEM means small autoallocate extents. Switch to UNIFORM SIZE 64M to prevent recurrence.'});
    } else if (cat === 'TX_INDEX_CONTENTION') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify hot index causing TX serialisation',
            sql:`SELECT s.current_obj# obj#, o.owner, o.object_name, o.object_type, COUNT(*) waited_secs\nFROM   v$active_session_history s\nJOIN   dba_objects o ON o.object_id = s.current_obj#\nWHERE  s.event = 'enq: TX - index contention'\nAND    s.sample_time >= SYSDATE - INTERVAL '1' HOUR\nGROUP  BY s.current_obj#, o.owner, o.object_name, o.object_type\nORDER  BY waited_secs DESC FETCH FIRST 5 ROWS ONLY;`,
            expect:'Returns the index with most contention. Validate it has a monotonic key (sequence, timestamp).'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Rebuild hot index as REVERSE KEY or HASH PARTITION',
            sql:`-- Reverse key (for monotonic b-tree indexes):\nALTER INDEX <OWNER>.<INDEX_NAME> REBUILD REVERSE;\n-- Or recreate as GLOBAL HASH PARTITIONED (4 or 8 partitions)`,
            expect:'Distributes inserts across leaf blocks. TX-index waits drop from current level to near-zero.'});
    } else if (cat === 'TX_ROW_LOCK_CONTENTION') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify blocking session tree from V$SESSION',
            sql:`SELECT w.sid waiter_sid, w.blocking_session blocker_sid,\n       w.sql_id, w.event, w.seconds_in_wait\nFROM   v$session w\nWHERE  w.event = 'enq: TX - row lock contention'\nAND    w.blocking_session IS NOT NULL\nORDER  BY w.seconds_in_wait DESC;`,
            expect:'blocker_sid with highest seconds_in_wait is the root holder. Review its open transaction and commit pattern.'});
    } else if (cat === 'UNDO_SEGMENT_EXTENSION') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Check UNDO tablespace pressure and stolen extents',
            sql:`SELECT begin_time, end_time, undoblks, txncount, maxquerylen,\n       nospaceerrcnt, ssolderrcnt, unexpiredstolen\nFROM   v$undostat ORDER BY begin_time DESC FETCH FIRST 10 ROWS ONLY;\n\nSELECT file_name, bytes/1024/1024 mb, autoextensible, maxbytes/1024/1024 max_mb\nFROM   dba_data_files WHERE tablespace_name =\n  (SELECT value FROM v$parameter WHERE name='undo_tablespace');`,
            expect:'UNEXPIREDSTOLEN > 0 = tablespace too small. AUTOEXTENSIBLE=NO = manual resize needed.'});
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Add UNDO datafile or extend current',
            sql:`ALTER TABLESPACE UNDOTBS1 ADD DATAFILE SIZE 4G AUTOEXTEND ON NEXT 512M MAXSIZE 20G;\nALTER SYSTEM SET undo_retention = 3600 SCOPE=BOTH; -- 1 hour`,
            expect:'nospaceerrcnt and unexpiredstolen trend to zero in V$UNDOSTAT within 30 minutes.'});
    } else if (cat === 'SQL_DOMINANT' && domSql) {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:`Display AWR execution plan for SQL ${domSql.sql_id}`,
            sql:`SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY_AWR('${domSql.sql_id}', NULL, NULL, 'ALL +PEEKED_BINDS'));`,
            expect:'Look for TABLE ACCESS FULL on large table, E-Rows vs A-Rows diverging 10x+, nested-loop inner loop with high probe count.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Refresh statistics on tables used by dominant SQL',
            sql:`SELECT DISTINCT object_owner, object_name FROM v$sql_plan\nWHERE  sql_id = '${domSql.sql_id}' AND object_owner IS NOT NULL;\n-- Then for each table:\nEXEC DBMS_STATS.GATHER_TABLE_STATS('<OWNER>','<TABLE>',CASCADE=>TRUE,NO_INVALIDATE=>FALSE);`,
            expect:'SQL reparsed with fresh stats. Elapsed/exec decreases if stale stats were causing plan suboptimality.'});
    } else if (cat === 'CPU_SATURATION') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify top CPU-consuming SQL in this window',
            sql:`SELECT sql_id, module, SUM(cpu_time_delta)/1e6 cpu_secs,\n       SUM(executions_delta) execs,\n       SUM(cpu_time_delta)/NULLIF(SUM(executions_delta),0)/1e6 cpu_per_exec\nFROM   dba_hist_sqlstat\nWHERE  snap_id BETWEEN ${_sB} AND ${_sE}\nGROUP  BY sql_id, module\nORDER  BY cpu_secs DESC FETCH FIRST 15 ROWS ONLY;`,
            expect:'Top sql_id by cpu_secs = primary CPU consumer. High cpu_per_exec = query-level fix needed.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Check hard parse rate (bind variable bypass)',
            sql:`SELECT name, value FROM v$sysstat\nWHERE  name IN ('parse count (hard)','parse count (total)',\n                'session logical reads','execute count')\nORDER  BY name;`,
            expect:'Hard parse rate > 100/s with identical SQL but different literals = missing bind variables.'});
    } else if (cat === 'IO_PRESSURE') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify top segments by physical reads (AWR)',
            sql:`SELECT sso.owner, sso.object_name, sso.object_type,\n       SUM(ss.physical_reads_delta) phys_reads\nFROM   dba_hist_seg_stat ss\nJOIN   dba_hist_seg_stat_obj sso USING (dataobj#, obj#)\nWHERE  ss.snap_id BETWEEN ${_sB} AND ${_sE}\nGROUP  BY sso.owner, sso.object_name, sso.object_type\nORDER  BY phys_reads DESC FETCH FIRST 10 ROWS ONLY;`,
            expect:'Top object = I/O hotspot. TABLE with no index → add index. INDEX already present + high reads → check storage latency.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Check storage read latency per datafile',
            sql:`SELECT d.name, s.phyrds, ROUND(s.readtim/NULLIF(s.phyrds,0),2) avg_read_ms\nFROM   v$filestat s, v$datafile d\nWHERE  s.file# = d.file#\nORDER  BY avg_read_ms DESC NULLS LAST FETCH FIRST 10 ROWS ONLY;`,
            expect:'avg_read_ms > 20ms = storage tier issue. < 10ms = read volume problem (fix SQL access path).'});
    } else if (cat === 'REDO_COMMIT') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Identify modules driving excessive commits via ASH',
            sql:`SELECT module, action, COUNT(*) samples,\n       ROUND(COUNT(*)*100.0/SUM(COUNT(*)) OVER(),1) pct\nFROM   dba_hist_active_sess_history\nWHERE  event = 'log file sync'\nAND    snap_id BETWEEN ${_sB} AND ${_sE}\nGROUP  BY module, action\nORDER  BY samples DESC FETCH FIRST 10 ROWS ONLY;`,
            expect:'High-sample module/action = source of excessive commits. That application layer needs batch-commit refactoring.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Check log file sync wait latency',
            sql:`SELECT event, time_waited, total_waits,\n       ROUND(time_waited/NULLIF(total_waits,0),2) avg_wait_ms\nFROM   v$system_event\nWHERE  event = 'log file sync';`,
            expect:'avg_wait_ms > 20ms → move redo logs to dedicated SSD. < 10ms → reduce commit frequency in application.'});
    } else if (cat === 'BUFFER_WRITE_PRESSURE' || cat === 'CONCURRENT_DML_BOTTLENECK') {
        _acts.push({ prio:'IMMEDIATE', col:'#ef4444', title:'Check DBWR throughput and free buffer wait rate',
            sql:`SELECT name, value FROM v$sysstat\nWHERE  name IN ('free buffer waits','free buffer requested',\n                'write requests','DBWR buffers scanned','DBWR checkpoint buffers written');`,
            expect:'High free buffer waits / free buffer requested = DBWR cannot flush fast enough. Increase db_writer_processes.'});
        _acts.push({ prio:'IMPORTANT', col:'#f59e0b', title:'Check dirty buffer ratio and cache sizing',
            sql:`SELECT ROUND(dirty/total*100,1) dirty_pct\nFROM (\n  SELECT SUM(DECODE(dirty,'Y',1,0)) dirty, COUNT(*) total FROM v$bh\n);\nSHOW PARAMETER db_writer_processes;\nSHOW PARAMETER db_cache_size;`,
            expect:'dirty_pct > 30% = cache pressure. Increase db_writer_processes (= n_CPUs/8). Raise db_cache_size if memory available.'});
    } else {
        _acts.push({ prio:'INVESTIGATE', col:'#06b6d4', title:'ASH dominant activity analysis',
            sql:`SELECT event, session_state, COUNT(*) samples,\n       ROUND(COUNT(*)*100.0/SUM(COUNT(*)) OVER(),1) pct\nFROM   dba_hist_active_sess_history\nWHERE  snap_id BETWEEN ${_sB} AND ${_sE}\nGROUP  BY event, session_state\nORDER  BY samples DESC FETCH FIRST 15 ROWS ONLY;`,
            expect:'Identifies Oracle wait events consuming most session time in this snapshot window.'});
    }
    // secondary wait monitor
    if (_w1) {
        _acts.push({ prio:'MONITOR', col:'#6366f1', title:`Track secondary wait: ${_w1.event_name}`,
            sql:`SELECT snap_id,\n       SUM(time_waited_micro/1e6) wait_secs,\n       SUM(total_waits) waits\nFROM   dba_hist_system_event\nWHERE  event_name = '${(_w1.event_name||'').replace(/'/g,"''")}'\nAND    snap_id BETWEEN ${_sB} AND ${_sE}\nGROUP  BY snap_id\nORDER  BY snap_id;`,
            expect:'Flat/declining trend = under control. Rising > 5% DB Time = re-run analysis — this is now the primary bottleneck.'});
    }

    let _queueHtml = '';
    try {
        const _dec = window.PEEngine.decorateActions(_acts, {}, {});
        _queueHtml = window.PEEngine.renderActionQueue(_dec);
    } catch(e) { console.warn('PEEngine single-mode renderActionQueue failed', e); _queueHtml = '<div style="color:#64748b;font-size:11px;padding:10px">Action queue unavailable.</div>'; }

    const actionQueueHtml = `<div style="padding:14px 18px;background:linear-gradient(135deg,rgba(15,23,42,0.85),rgba(8,12,28,0.7));border:1px solid rgba(99,102,241,0.18);border-radius:8px;border-left:3px solid #10b981">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding-bottom:8px;border-bottom:1px solid rgba(99,102,241,0.12)">
            <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="#34d399" stroke-width="1.5"><path stroke-linecap="round" stroke-linejoin="round" d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
            <span style="font-size:12.5px;font-weight:900;color:#34d399;text-transform:uppercase;letter-spacing:0.8px">Action Priority Queue — Recommended Fix</span>
            <span style="font-size:9px;color:#64748b;margin-left:auto">Verdict: ${esc(catLabel)} · Snap ${esc(_sB)}–${esc(_sE)}</span>
        </div>
        ${_queueHtml}
    </div>`;

    // ── INJECT ────────────────────────────────────────────────────────────────
    const _rcaEl = document.getElementById('rca-content');
    if (!_rcaEl) return;

    // ── Panel Evidence Strip — shows which panels contributed evidence ────────
    const _panelEvidence = [];
    if (events.length > 0) _panelEvidence.push({lbl:'Wait Events', col:'#ef4444', detail: events.slice(0,3).map(e=>(e.event_name||'').substring(0,20)+'…').join(', ')});
    if (sqls.length > 0)   _panelEvidence.push({lbl:'SQL Analysis', col:'#3b82f6', detail: sqls.slice(0,2).map(s=>s.sql_id).join(', ')});
    if (d.load_profile && d.load_profile.length > 0) _panelEvidence.push({lbl:'Load Profile', col:'#10b981', detail: d.load_profile.length + ' stats'});
    if (Object.keys(eff).length > 0) _panelEvidence.push({lbl:'Efficiency', col:'#f59e0b', detail: `Buffer ${f1s(eff.buffer_cache_hit||0)}%, Soft Parse ${f1s(eff.soft_parse||0)}%`});
    if (addm.length > 0) _panelEvidence.push({lbl:'ADDM', col:'#a855f7', detail: addm.length + ' findings'});
    if (d.time_model && d.time_model.length > 0) _panelEvidence.push({lbl:'Time Model', col:'#06b6d4', detail: d.time_model.length + ' entries'});
    const evidenceStripHtml = _panelEvidence.length > 0 ? `<div style="margin-bottom:14px;padding:10px 14px;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.18);border-radius:8px">
        <div style="font-size:9px;color:#64748b;font-weight:700;text-transform:uppercase;margin-bottom:6px">Evidence Sources — Panels Contributing to this Verdict</div>
        <div style="display:flex;flex-wrap:wrap;gap:6px">
            ${_panelEvidence.map(p => `<div title="${esc(p.detail)}" style="background:${p.col}12;border:1px solid ${p.col}35;border-radius:6px;padding:4px 10px;display:flex;align-items:center;gap:5px;cursor:default">
                <div style="width:6px;height:6px;border-radius:50%;background:${p.col}"></div>
                <span style="font-size:10px;color:${p.col};font-weight:700">${p.lbl}</span>
                <span style="font-size:9px;color:#64748b">${esc(p.detail)}</span>
            </div>`).join('')}
        </div>
    </div>` : '';

    // ── Corroborating Signals Table ─────────────────────────────────────────
    const _corrSignals = [];
    if (events.length > 0) {
        const top3 = events.filter(e => !/idle/i.test(e.wait_class||'')).slice(0,3);
        top3.forEach(e => {
            const pct = e.pct_db_time || 0;
            if (pct > 10) _corrSignals.push({badge:'DOMINANT', badgeCol:'#ef4444', metric: esc(e.event_name), detail: num(pct,1)+'% DB Time'});
            else if (pct > 5) _corrSignals.push({badge:'NOTABLE', badgeCol:'#f59e0b', metric: esc(e.event_name), detail: num(pct,1)+'% DB Time'});
        });
    }
    if ((eff.buffer_cache_hit||100) < 95) _corrSignals.push({badge:'EFF↓', badgeCol:'#f59e0b', metric:'Buffer Cache Hit', detail: f1s(eff.buffer_cache_hit)+'% (below 95%)'});
    if ((eff.soft_parse||100) < 90) _corrSignals.push({badge:'EFF↓', badgeCol:'#f59e0b', metric:'Soft Parse %', detail: f1s(eff.soft_parse)+'% (below 90%)'});
    if ((eff.execute_to_parse||100) < 80) _corrSignals.push({badge:'EFF↓', badgeCol:'#f59e0b', metric:'Execute to Parse %', detail: f1s(eff.execute_to_parse)+'% (below 80%)'});
    if (aas > cpus * 1.5) _corrSignals.push({badge:'SATURATED', badgeCol:'#ef4444', metric:'AAS / CPUs', detail: f1s(aas)+' / '+cpus+' — '+Math.round(aas/cpus*100)+'% utilisation'});

    const corrSignalsHtml = _corrSignals.length > 0 ? `<div style="margin-bottom:14px;padding:10px 14px;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.18);border-radius:8px">
        <div style="font-size:9px;color:#64748b;font-weight:700;text-transform:uppercase;margin-bottom:6px">Corroborating Signals</div>
        <div style="display:flex;flex-direction:column;gap:4px">
            ${_corrSignals.map(s => `<div style="display:flex;align-items:center;gap:8px;padding:3px 0;border-bottom:1px dotted rgba(71,85,105,0.2)">
                <span style="background:${s.badgeCol}22;color:${s.badgeCol};font-size:9px;padding:1px 6px;border-radius:3px;font-weight:800;min-width:65px;text-align:center">${s.badge}</span>
                <span style="font-size:10px;color:#cbd5e1;font-weight:600">${s.metric}</span>
                <span style="font-size:10px;color:#64748b;margin-left:auto">${s.detail}</span>
            </div>`).join('')}
        </div>
    </div>` : '';

    // ── Rich Session Intelligence (adapted from renderSessionRCADetail) ─────
    const _siInsights = [];
    // AAS Saturation insight
    if (aas > cpus) {
        const queue = aas - cpus;
        const cpuBound = dbCpuPct > 40;
        const waitBound = !cpuBound;
        _siInsights.push({
            icon: '🔥', sev: 'critical', col: '#ef4444',
            title: 'AAS Saturation',
            text: `AAS (${f1s(aas)}) exceeds CPU count (${cpus}) — ${n0(Math.round(queue))} sessions are queuing. ` +
                  (cpuBound ? `CPU-bound (${f1s(dbCpuPct)}% DB Time on CPU). Optimise top SQL to reduce CPU demand.`
                            : `Wait-bound (CPU only ${f1s(dbCpuPct)}%). Fix the dominant wait event first.`)
        });
    } else if (aas > cpus * 0.85) {
        _siInsights.push({icon: '⚠️', sev: 'warning', col: '#f59e0b',
            title: 'Near Capacity', text: `AAS (${f1s(aas)}) is ${Math.round(aas/cpus*100)}% of CPU count (${cpus}). Less than 15% headroom — workload growth will cause queuing.`
        });
    }
    // Logon Behaviour
    const _lpArr = d.load_profile || [];
    const _logonLp = _lpArr.find(r => (r.stat_name||r.name||'').toLowerCase().includes('logon'));
    const logonRate = _logonLp ? (_logonLp.per_sec || _logonLp.per_second || 0) : 0;
    if (logonRate > 10) {
        _siInsights.push({icon: '🔌', sev: 'critical', col: '#ef4444',
            title: 'Logon Storm', text: `${f1s(logonRate)} logons/sec — application is NOT using a connection pool. Each request opens a new session, burning CPU on authentication + hard parse.`
        });
    } else if (logonRate > 2) {
        _siInsights.push({icon: '🔌', sev: 'warning', col: '#f59e0b',
            title: 'Elevated Logon Rate', text: `${f1s(logonRate)} logons/sec — validate connection pool sizing. High logon rate adds parse + authentication overhead.`
        });
    }
    // Parse Efficiency
    if ((eff.soft_parse||100) < 90) {
        _siInsights.push({icon: '📝', sev: 'warning', col: '#f59e0b',
            title: 'Parse Efficiency', text: `Soft Parse % at ${f1s(eff.soft_parse)}% (below 90%) — indicates literal SQL without bind variables or shared pool pressure.`
        });
    }
    // Buffer Cache
    if ((eff.buffer_cache_hit||100) < 95) {
        _siInsights.push({icon: '💾', sev: 'warning', col: '#f59e0b',
            title: 'Buffer Cache Pressure', text: `Buffer Cache Hit at ${f1s(eff.buffer_cache_hit)}% (below 95%) — excessive physical reads from disk. Review SQL full table scans or increase buffer cache.`
        });
    }

    const sessionIntelHtml = _siInsights.length > 0 ? `<div style="margin-bottom:14px;padding:12px 16px;background:rgba(15,23,42,0.6);border:1px solid rgba(99,102,241,0.18);border-radius:8px">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px">
            <div style="width:8px;height:8px;border-radius:50%;background:${_siInsights[0].col};box-shadow:0 0 6px ${_siInsights[0].col}"></div>
            <span style="font-size:10px;font-weight:800;color:#94a3b8;text-transform:uppercase;letter-spacing:0.6px">Session Intelligence — ${_siInsights.filter(i=>i.sev==='critical').length > 0 ? 'ACTION REQUIRED' : 'MONITOR'}</span>
        </div>
        <div style="display:flex;flex-direction:column;gap:8px">
            ${_siInsights.map(ins => `<div style="display:flex;align-items:flex-start;gap:10px;padding:8px 12px;background:${ins.col}08;border-left:3px solid ${ins.col};border-radius:0 6px 6px 0">
                <span style="font-size:14px;flex-shrink:0">${ins.icon}</span>
                <div>
                    <div style="font-size:11px;font-weight:800;color:${ins.col};margin-bottom:2px">${ins.title}</div>
                    <div style="font-size:10.5px;color:#94a3b8;line-height:1.5">${ins.text}</div>
                </div>
            </div>`).join('')}
        </div>
    </div>` : '';

    _rcaEl.innerHTML += `
    <div style="margin-top:24px;padding-top:20px;border-top:1px solid rgba(99,102,241,0.12)">
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:16px">
            <span style="display:inline-block;width:3px;height:14px;background:#a5b4fc;border-radius:2px"></span>
            <span style="font-size:12.5px;font-weight:900;color:#a5b4fc;text-transform:uppercase;letter-spacing:0.8px">OraVision PE Analysis</span>
            <span style="font-size:9px;color:#334155">Deterministic · Oracle 19c PTG + Oracle 12c SQL Tuning</span>
        </div>
        ${evidenceStripHtml}
        ${corrSignalsHtml}
        ${sessionIntelHtml}
        ${scorecardHtml}
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:14px;margin-bottom:14px">
            <div>${waitCausalityHtml}</div>
            <div>${domSqlCardHtml}</div>
        </div>
        ${peNarrativeHtml}
        ${kbRefHtml}
        ${actionQueueHtml}
    </div>`;
}


