            if (_epe > 10) _peHints.push('\u{1F534} CRITICAL: >10s/exec. Run SQL Tuning Advisor: EXEC DBMS_SQLTUNE.CREATE_TUNING_TASK(sql_id=>\''+esc(c.sqlId)+'\');');
            else if (_epe > 2) _peHints.push('\u{1F7E1} SLOW: >2s/exec. Check execution plan for full table scans or missing indexes.');
