            if (_gpe > 50000 && _rows > 0 && (_gpe/Math.max(_rows,1)) > 500) _peHints.push('\u{1F4D0} CARDINALITY: Gets/Row='+comma(Math.round(_gpe/Math.max(_rows,1)))+'. Oracle row estimate may be wrong. Gather stats with histograms.');
